@contextmanager
def set_dtype(dtype):
    prev = torch.get_default_dtype()
    torch.set_default_dtype(dtype)
    try:
        yield
    finally:
        torch.set_default_dtype(prev)

def get_gpu_arch():
    if HAS_PYNVML:
        try:
            pynvml.nvmlInit()
            handle = pynvml.nvmlDeviceGetHandleByIndex(0)
            name = pynvml.nvmlDeviceGetName(handle).decode()
            pynvml.nvmlShutdown()
            if 'H100' in name:
                return 'H100'
            if 'A100' in name:
                return 'A100'
            if 'MI300' in name:
                return 'MI300X'
        except:
            pass
    return 'generic'

