# ============================================================================
# 14. MemoryConsolidation
# ============================================================================
# Sleep-style memory consolidation: a fast "episodic" buffer of recent content
# is periodically distilled into a slow "semantic" slot memory through a
# replay+merge step. Reads blend the two stores; writes go to the episodic
# buffer; a consolidation pass (callable or automatic every N steps) transfers
# stable patterns from episodic to semantic memory and decays the episodic
# trace. Models complementary-learning-systems (hippocampus/neocortex) ideas.
# ============================================================================
class MemoryConsolidation(ModuleUtilsMixin, nn.Module):
    def __init__(self, dim, episodic_slots=512, semantic_slots=2048, num_heads=8,
                 consolidate_every=0, consolidation_rate=0.1, episodic_decay=0.95,
                 dropout=0.0, init_scale=0.02, eps=1e-6):
        super().__init__()
        self.dim = dim
        self.episodic_slots = episodic_slots
        self.semantic_slots = semantic_slots
        self.num_heads = num_heads
        self.head_dim = dim // num_heads
        self.consolidate_every = consolidate_every
        self.consolidation_rate = consolidation_rate
        self.episodic_decay = episodic_decay
        self.eps = eps
        assert dim % num_heads == 0

        self.episodic = nn.Parameter(torch.randn(episodic_slots, dim) * init_scale)
        self.semantic = nn.Parameter(torch.randn(semantic_slots, dim) * init_scale)
        self.q_proj = Linear(dim, dim, bias=False)
        self.ke_proj = Linear(dim, dim, bias=False)
        self.ks_proj = Linear(dim, dim, bias=False)
        self.ve_proj = Linear(dim, dim, bias=False)
        self.vs_proj = Linear(dim, dim, bias=False)
        self.o_proj = Linear(dim, dim, bias=True)
        self.read_gate = nn.Sequential(Linear(dim * 2, dim), nn.SiLU(), Linear(dim, 2))
        self.write_gate = nn.Sequential(Linear(dim * 2, dim), nn.Sigmoid())
        self.norm = RMSNorm(dim)
        self.gate = nn.Parameter(torch.zeros(1))
        self.dropout = nn.Dropout(dropout) if dropout > 0 else nn.Identity()
        self.register_buffer("_step", torch.zeros(1, dtype=torch.long))
        self.register_buffer("episodic_strength", torch.ones(episodic_slots))

    def _read_store(self, x_flat, keys, vals):
        B = x_flat.size(0)
        q = self.q_proj(x_flat).view(B, self.num_heads, self.head_dim)
        k = keys.view(-1, self.num_heads, self.head_dim)
        v = vals.view(-1, self.num_heads, self.head_dim)
        scores = torch.einsum("bhd,mhd->bhm", q, k) / math.sqrt(self.head_dim)
        attn = F.softmax(scores, dim=-1)
        out = torch.einsum("bhm,mhd->bhd", attn, v).reshape(B, self.dim)
        return out

    def forward(self, x, write=None):
        if write is None:
            write = self.training
        B, S, D = x.shape
        x_flat = x.reshape(-1, D)
        epi = self._read_store(x_flat, self.ke_proj(self.episodic), self.ve_proj(self.episodic))
        sem = self._read_store(x_flat, self.ks_proj(self.semantic), self.vs_proj(self.semantic))
        # learned blend of episodic vs semantic
        blend = F.softmax(self.read_gate(torch.cat([epi, sem], dim=-1)), dim=-1)  # (N,2)
        read = blend[:, 0:1] * epi + blend[:, 1:2] * sem
        read = self.o_proj(read).view(B, S, D)
        out = self.norm(x + torch.sigmoid(self.gate) * self.dropout(read))

        if write:
            self._write_episodic(x_flat)
            self._step += 1
            if self.consolidate_every > 0 and int(self._step.item()) % self.consolidate_every == 0:
                self.consolidate()
        return out

    def _write_episodic(self, x_flat):
        with torch.no_grad():
            n = min(x_flat.size(0), self.episodic_slots)
            # write to weakest episodic slots
            _, idx = torch.topk(self.episodic_strength, n, largest=False)
            content = x_flat[:n]
            g = self.write_gate(torch.cat([content, self.episodic.data[idx]], dim=-1))
            self.episodic.data[idx] = (1 - g) * self.episodic.data[idx] + g * content
            self.episodic_strength.mul_(self.episodic_decay)
            self.episodic_strength[idx] = 1.0

    def consolidate(self):
        # Transfer stable episodic patterns into semantic memory (replay+merge),
        # then decay the episodic trace.
        with torch.no_grad():
            # pick the strongest episodic slots as "stable memories"
            n = min(self.semantic_slots, self.episodic_slots)
            strength, idx = torch.topk(self.episodic_strength, n, largest=True)
            patterns = self.episodic.data[idx]
            # find nearest semantic slot for each and merge
            sim = F.normalize(patterns, dim=-1) @ F.normalize(self.semantic.data, dim=-1).t()
            tgt = sim.argmax(dim=-1)
            r = self.consolidation_rate
            self.semantic.data[tgt] = (1 - r) * self.semantic.data[tgt] + r * patterns
            # decay episodic strength after consolidation
            self.episodic_strength.mul_(0.5)
            return n

    def memory_stats(self):
        return {"episodic_mean_strength": self.episodic_strength.mean().item(),
                "step": int(self._step.item())}

    def regularization_loss(self, diversity_weight=1.0):
        s = F.normalize(self.semantic, dim=-1)
        gram = s @ s.t()
        off = gram - torch.eye(self.semantic_slots, device=s.device)
        return diversity_weight * off.pow(2).mean()

    def reset_memory(self):
        with torch.no_grad():
            self.episodic_strength.fill_(1.0); self._step.zero_()

    def get_config(self):
        return {"dim": self.dim, "episodic_slots": self.episodic_slots,
                "semantic_slots": self.semantic_slots, "num_heads": self.num_heads,
                "consolidate_every": self.consolidate_every,
                "consolidation_rate": self.consolidation_rate}

    def count_parameters(self):
        return sum(p.numel() for p in self.parameters())

    def parameter_breakdown(self):
        return {n: p.numel() for n, p in self.named_parameters()}

    def parameter_groups(self, base_lr=1e-3, memory_lr_mult=2.0):
        mem_p, other_p = [], []
        for n, p in self.named_parameters():
            (mem_p if ("episodic" in n or "semantic" in n) else other_p).append(p)
        return [{"params": mem_p, "lr": base_lr * memory_lr_mult},
                {"params": other_p, "lr": base_lr}]

    def extra_repr(self):
        return (f"dim={self.dim}, episodic={self.episodic_slots}, "
                f"semantic={self.semantic_slots}, heads={self.num_heads}")

    def diagnostics(self):
        return {"num_params": self.count_parameters(), **self.memory_stats()}

    # ------------------------------------------------------------------ #
    # Advanced engineering utilities (injected; namespaced to avoid clashes)
    # ------------------------------------------------------------------ #




























    # ------------------------------------------------------------------ #
    # Advanced architectural / runtime capabilities (injected; `ar_` namespace)
    # ------------------------------------------------------------------ #













class MultiTaskPromptTuning(ModuleUtilsMixin, nn.Module):
    def __init__(self, dim, num_tasks=1000, prompt_len=32, num_prompts_per_task=8,
                 shared_prompts=4, router_temp=1.0, prompt_dropout=0.0,
                 init_scale=0.02, eps=1e-6):
        super().__init__()
        self.dim = dim
        self.num_tasks = num_tasks
        self.prompt_len = prompt_len
        self.num_prompts_per_task = num_prompts_per_task
        self.shared_prompts = shared_prompts
        self.router_temp = router_temp
        self.eps = eps

        self.prompt_embeddings = nn.Parameter(
            torch.randn(num_tasks, num_prompts_per_task, prompt_len, dim) * init_scale)
        self.shared_prompt_bank = nn.Parameter(
            torch.randn(shared_prompts, prompt_len, dim) * init_scale)
        self.task_embeddings = nn.Embedding(num_tasks, dim)
        self.router = Linear(dim, num_prompts_per_task + shared_prompts, bias=True)
        self.combiner = nn.Sequential(
            Linear(dim * 2, dim), nn.GELU(), Linear(dim, dim))
        self.prompt_norm = RMSNorm(dim)
        self.prompt_dropout = nn.Dropout(prompt_dropout) if prompt_dropout > 0 else nn.Identity()
        self.register_buffer("_task_usage", torch.zeros(num_tasks))

    def _resolve_task(self, task_id, B, device):
        if task_id is None:
            return torch.zeros(B, dtype=torch.long, device=device)
        if isinstance(task_id, int):
            return torch.full((B,), task_id, dtype=torch.long, device=device)
        t = task_id.to(device).long()
        if t.dim() == 0:
            t = t.expand(B)
        return t

    def build_prompt(self, x, task_id=None):
        # Returns just the prompt tensor (B, prompt_len, dim) without prepending.
        B, S, D = x.shape
        task = self._resolve_task(task_id, B, x.device)        # (B,)
        task_emb = self.task_embeddings(task)                  # (B, dim)

        per_task = self.prompt_embeddings[task]                # (B, P, L, D)
        shared = self.shared_prompt_bank.unsqueeze(0).expand(B, -1, -1, -1)  # (B,Sh,L,D)
        all_prompts = torch.cat([per_task, shared], dim=1)     # (B, P+Sh, L, D)

        route = F.softmax(self.router(x.mean(1)) / max(self.router_temp, 1e-4), dim=-1)  # (B, P+Sh)
        combined = (all_prompts * route.view(B, -1, 1, 1)).sum(1)  # (B, L, D)

        task_exp = task_emb.view(B, 1, D).expand(-1, self.prompt_len, -1)
        combined = self.combiner(torch.cat([combined, task_exp], dim=-1))
        combined = self.prompt_norm(self.prompt_dropout(combined))

        if self.training:
            with torch.no_grad():
                self._task_usage.index_add_(0, task, torch.ones_like(task, dtype=self._task_usage.dtype))
        return combined

    def forward(self, x, task_id=None, return_prompt=False):
        prompt = self.build_prompt(x, task_id)
        out = torch.cat([prompt, x], dim=1)
        if return_prompt:
            return out, prompt
        return out

    def trainable_prompt_parameters(self):
        # Convenience: the parameters one would actually optimize in prompt tuning.
        return [self.prompt_embeddings, self.shared_prompt_bank,
                *self.task_embeddings.parameters(), *self.router.parameters(),
                *self.combiner.parameters()]

    def num_prompt_parameters(self):
        return sum(p.numel() for p in self.trainable_prompt_parameters())

    def task_usage_report(self, topk=10):
        vals, idx = self._task_usage.topk(min(topk, self.num_tasks))
        return list(zip(idx.tolist(), vals.tolist()))

    def regularization_loss(self, l2_weight=1e-4, shared_diversity_weight=0.1):
        l2 = self.prompt_embeddings.pow(2).mean() + self.shared_prompt_bank.pow(2).mean()
        sp = self.shared_prompt_bank.reshape(self.shared_prompts, -1)
        sp = F.normalize(sp, dim=-1)
        gram = sp @ sp.t()
        div = (gram - torch.eye(self.shared_prompts, device=sp.device)).pow(2).mean()
        return l2_weight * l2 + shared_diversity_weight * div

    def reset_usage(self):
        with torch.no_grad():
            self._task_usage.zero_()

    def get_config(self):
        return {"dim": self.dim, "num_tasks": self.num_tasks, "prompt_len": self.prompt_len,
                "num_prompts_per_task": self.num_prompts_per_task,
                "shared_prompts": self.shared_prompts, "router_temp": self.router_temp}

    def count_parameters(self):
        return sum(p.numel() for p in self.parameters())

    def parameter_breakdown(self):
        return {n: p.numel() for n, p in self.named_parameters()}

    def parameter_groups(self, base_lr=1e-3, prompt_lr_mult=10.0):
        prompt_p, other_p = [], []
        for n, p in self.named_parameters():
            (prompt_p if "prompt" in n or "task_embeddings" in n else other_p).append(p)
        return [{"params": prompt_p, "lr": base_lr * prompt_lr_mult},
                {"params": other_p, "lr": base_lr}]

    def extra_repr(self):
        return (f"dim={self.dim}, num_tasks={self.num_tasks}, prompt_len={self.prompt_len}, "
                f"per_task={self.num_prompts_per_task}, shared={self.shared_prompts}")

    def diagnostics(self):
        return {"num_params": self.count_parameters(),
                "num_prompt_params": self.num_prompt_parameters(),
                "active_tasks": int((self._task_usage > 0).sum().item())}

