    # Advanced architectural / runtime capabilities (injected; `ar_` namespace)
    # ------------------------------------------------------------------ #

















# ============================================================================
# 16. AdaptiveMultiTaskPromptTuning
# ----------------------------------------------------------------------------
# Extends MultiTaskPromptTuning with input-adaptive prompt length: a small
# predictor estimates how many prompt tokens a given input actually needs, so
# easy inputs get short prompts (cheaper) and hard inputs get the full prompt.
# The length is chosen with a differentiable soft mask during training (so the
# predictor receives gradient) and hard-truncated at inference for speed.
# ============================================================================
class AdaptiveMultiTaskPromptTuning(MultiTaskPromptTuning):
    def __init__(self, dim, num_tasks=2000, prompt_len=48, num_prompts_per_task=10,
                 shared_prompts=8, dynamic_length=True, min_len=8, **kwargs):
        super().__init__(dim, num_tasks=num_tasks, prompt_len=prompt_len,
                         num_prompts_per_task=num_prompts_per_task,
                         shared_prompts=shared_prompts, **kwargs)
        self.dynamic_length = dynamic_length
        self.min_len = min_len
        self.length_predictor = nn.Sequential(
            Linear(dim, dim // 2), nn.GELU(), Linear(dim // 2, 1), nn.Sigmoid())

    def predict_length(self, x):
        ratio = self.length_predictor(x.mean(1)).mean()
        return ratio

    def forward(self, x, task_id=None, return_prompt=False):
        prompt = self.build_prompt(x, task_id)                 # (B, L, D)
        B, L, D = prompt.shape
        if self.dynamic_length:
            ratio = self.predict_length(x)
            if self.training:
                # differentiable soft length mask: positions beyond the predicted
                # length are smoothly attenuated so the predictor gets gradient
                pos = torch.arange(L, device=x.device).float() / max(L - 1, 1)
                target = ratio.clamp(self.min_len / max(L, 1), 1.0)
                mask = torch.sigmoid((target - pos) * 12.0).view(1, L, 1)
                prompt = prompt * mask
            else:
                actual = max(self.min_len, int(L * float(ratio)))
                prompt = prompt[:, :actual, :]
        out = torch.cat([prompt, x], dim=1)
        if return_prompt:
            return out, prompt
        return out

    def get_config(self):
        cfg = super().get_config()
        cfg.update({"dynamic_length": self.dynamic_length, "min_len": self.min_len})
        return cfg

    def diagnostics(self):
        d = super().diagnostics()
        d["dynamic_length"] = self.dynamic_length
        return d

    # ------------------------------------------------------------------ #
    # Advanced engineering utilities (injected; namespaced to avoid clashes)
    # ------------------------------------------------------------------ #




























    # ------------------------------------------------------------------ #
    # Advanced architectural / runtime capabilities (injected; `ar_` namespace)
    # ------------------------------------------------------------------ #

















# ============================================================================
# 17. FewShotAdapter
# ----------------------------------------------------------------------------
# A LoRA-style adapter designed for few-shot inner-loop adaptation. The base
# low-rank factors stay fixed (the meta-knowledge); a fast pair of factors is
# adapted on a small support set with a few SGD steps and then applied to
# query inputs. Supports a learnable per-rank scale, an optional
# meta-differentiable inner loop (so the base factors can be trained to enable
# fast adaptation), and a classification head for the support objective.
# ============================================================================
class FewShotAdapter(ModuleUtilsMixin, nn.Module):
    def __init__(self, dim, adapter_rank=32, inner_lr=1e-2, inner_steps=5,
                 num_classes=None, alpha=1.0, dropout=0.0, second_order=False,
                 init_scale=0.02, eps=1e-6):
        super().__init__()
        self.dim = dim
        self.adapter_rank = adapter_rank
        self.inner_lr = inner_lr
        self.inner_steps = inner_steps
        self.num_classes = num_classes
        self.alpha = alpha
        self.second_order = second_order
        self.eps = eps

        # base (slow) low-rank factors — meta-knowledge
        self.lora_A = nn.Parameter(torch.randn(dim, adapter_rank) * init_scale)
        self.lora_B = nn.Parameter(torch.zeros(adapter_rank, dim))
        self.scale = nn.Parameter(torch.ones(adapter_rank))
        self.dropout = nn.Dropout(dropout) if dropout > 0 else nn.Identity()
        self.norm = RMSNorm(dim)
        if num_classes is not None:
            self.classifier = Linear(dim, num_classes, bias=True)

    def _delta(self, x, A=None, B=None):
        A = self.lora_A if A is None else A
        B = self.lora_B if B is None else B
        h = self.dropout(x @ A)                                 # (..., rank)
        h = h * torch.sigmoid(self.scale)
        return self.alpha * (h @ B)

    def forward(self, x, A=None, B=None):
        return self.norm(x + self._delta(x, A, B))

    def adapt(self, support_x, support_labels, query_x, loss_fn=None):
        # Inner-loop few-shot adaptation. Clones the base factors, takes a few
        # gradient steps on the support set, returns adapted query outputs.
        A = self.lora_A.detach().clone().requires_grad_(True)
        B = self.lora_B.detach().clone().requires_grad_(True)
        params = [A, B]
        for _ in range(self.inner_steps):
            feat = self.forward(support_x, A=A, B=B)
            if self.num_classes is not None and loss_fn is None:
                logits = self.classifier(feat.mean(1)) if feat.dim() == 3 else self.classifier(feat)
                loss = F.cross_entropy(logits, support_labels)
            elif loss_fn is not None:
                loss = loss_fn(feat, support_labels)
            else:
                loss = (feat - support_labels).pow(2).mean()
            grads = torch.autograd.grad(loss, params, create_graph=self.second_order and self.training)
            A = A - self.inner_lr * grads[0]
            B = B - self.inner_lr * grads[1]
        return self.forward(query_x, A=A, B=B), (A, B)

    def adapt_and_classify(self, support_x, support_labels, query_x):
        assert self.num_classes is not None
        feat, (A, B) = self.adapt(support_x, support_labels, query_x)
        pooled = feat.mean(1) if feat.dim() == 3 else feat
        return self.classifier(pooled)

    def merged_weight(self):
        # Effective LoRA weight matrix W = alpha * A diag(sigmoid(scale)) B.
        return self.alpha * (self.lora_A * torch.sigmoid(self.scale)) @ self.lora_B

    def regularization_loss(self, l2_weight=1e-4):
        return l2_weight * (self.lora_A.pow(2).mean() + self.lora_B.pow(2).mean())

    def get_config(self):
        return {"dim": self.dim, "adapter_rank": self.adapter_rank, "inner_lr": self.inner_lr,
                "inner_steps": self.inner_steps, "num_classes": self.num_classes,
                "alpha": self.alpha, "second_order": self.second_order}

    def count_parameters(self):
        return sum(p.numel() for p in self.parameters())

    def parameter_breakdown(self):
        return {n: p.numel() for n, p in self.named_parameters()}

    def parameter_groups(self, base_lr=1e-3):
        return [{"params": list(self.parameters()), "lr": base_lr}]

    def extra_repr(self):
        return (f"dim={self.dim}, rank={self.adapter_rank}, "
                f"inner_steps={self.inner_steps}, classes={self.num_classes}")

    def diagnostics(self):
        return {"num_params": self.count_parameters(),
                "merged_weight_norm": self.merged_weight().norm().item(),
                "mean_scale": torch.sigmoid(self.scale).mean().item()}

