# ============================================================================
# 18. ResidualMetaAdapter
# ----------------------------------------------------------------------------
# A LoRA-style residual adapter with magnitude-aware (per-rank) scaling, an
# optional task-conditioned bias, dropout regularization, and a zero-init up
# projection so it starts as the identity (no disturbance to a pretrained
# backbone). Adds per-rank gating, an effective-rank diagnostic, and a merge
# utility to fold the adapter into a base weight for inference.
# ============================================================================
class ResidualMetaAdapter(ModuleUtilsMixin, nn.Module):
    def __init__(self, dim, rank=4, dropout=0.0, num_tasks=0, alpha_init=1.0,
                 use_gelu=True, eps=1e-6):
        super().__init__()
        self.dim = dim
        self.rank = rank
        self.use_task = num_tasks > 0
        self.use_gelu = use_gelu
        self.eps = eps

        self.down = Linear(dim, rank, bias=False)
        self.up = Linear(rank, dim, bias=False)
        self.drop = nn.Dropout(dropout) if dropout > 0 else nn.Identity()
        self.norm = RMSNorm(dim)
        self.alpha = nn.Parameter(torch.full((rank,), float(alpha_init)))
        if self.use_task:
            self.task_bias = nn.Embedding(num_tasks, rank)
            nn.init.zeros_(self.task_bias.weight)

        # zero-init up projection => starts as identity residual
        with torch.no_grad():
            self.up.weight.zero_()
            std = 1.0 / math.sqrt(dim)
            self.down.weight.normal_(0, std)

    def _resolve_task(self, task_id, x):
        if not self.use_task or task_id is None:
            return None
        if isinstance(task_id, int):
            return torch.full((x.size(0),), task_id, dtype=torch.long, device=x.device)
        return task_id.to(x.device).long()

    def forward(self, x, task_id=None):
        h = self.down(x)                                       # (..., rank)
        if self.use_gelu:
            h = F.gelu(h)
        h = self.drop(h)
        task = self._resolve_task(task_id, x)
        if task is not None:
            tb = self.task_bias(task)                          # (B, rank)
            shape = [x.size(0)] + [1] * (x.dim() - 2) + [self.rank]
            h = h + tb.view(*shape)
        h = h * torch.sigmoid(self.alpha)
        delta = self.up(h)
        return self.norm(x + delta)

    def merged_weight(self, base_weight=None):
        # Fold the adapter into a base weight matrix for zero-overhead inference:
        # W_eff = base + up @ diag(sigmoid(alpha)) @ down.
        adapter_w = self.up.weight @ (torch.sigmoid(self.alpha).unsqueeze(1) * self.down.weight)
        if base_weight is None:
            return adapter_w
        return base_weight + adapter_w

    def effective_rank(self):
        # Stable-rank of the adapter update (how many ranks are actually used).
        with torch.no_grad():
            w = self.merged_weight()
            sv = torch.linalg.svdvals(w.float())
            return (sv.sum() / (sv.max() + self.eps)).item()

    def regularization_loss(self, l2_weight=1e-4):
        return l2_weight * (self.down.weight.pow(2).mean() + self.up.weight.pow(2).mean())

    def get_config(self):
        return {"dim": self.dim, "rank": self.rank, "use_task": self.use_task,
                "use_gelu": self.use_gelu}

    def count_parameters(self):
        return sum(p.numel() for p in self.parameters())

    def parameter_breakdown(self):
        return {n: p.numel() for n, p in self.named_parameters()}

    def parameter_groups(self, base_lr=1e-3):
        return [{"params": list(self.parameters()), "lr": base_lr}]

    def extra_repr(self):
        return f"dim={self.dim}, rank={self.rank}, use_task={self.use_task}"

    def diagnostics(self):
        return {"num_params": self.count_parameters(),
                "effective_rank": self.effective_rank(),
                "mean_alpha": torch.sigmoid(self.alpha).mean().item()}

    # ------------------------------------------------------------------ #
    # Advanced engineering utilities (injected; namespaced to avoid clashes)
    # ------------------------------------------------------------------ #




























    # ------------------------------------------------------------------ #
    # Advanced architectural / runtime capabilities (injected; `ar_` namespace)
    # ------------------------------------------------------------------ #

















# ============================================================================
# 19. PredictiveCodingLayer
# ----------------------------------------------------------------------------
# Hierarchical predictive coding: a stack of predictors each tries to predict
# the next representation; the prediction error (optionally sparsified to its
# top-k channels) is projected and used to correct the running state. The
# accumulated error is returned as an auxiliary signal (useful as a loss or a
# surprise/uncertainty estimate). Models the brain-inspired idea that only
# prediction errors propagate forward.
# ============================================================================
class PredictiveCodingLayer(ModuleUtilsMixin, nn.Module):
    def __init__(self, dim, num_layers=4, hidden_mult=4, use_residual=True,
                 topk_sparse=0, error_norm=True, precision_weighting=True,
                 dropout=0.0, eps=1e-6):
        super().__init__()
        self.dim = dim
        self.num_layers = num_layers
        self.use_residual = use_residual
        self.topk_sparse = topk_sparse
        self.error_norm = error_norm
        self.precision_weighting = precision_weighting
        self.eps = eps

        self.predictors = nn.ModuleList([
            nn.Sequential(Linear(dim, dim * hidden_mult), nn.GELU(),
                          Linear(dim * hidden_mult, dim))
            for _ in range(num_layers)
        ])
        self.error_projs = nn.ModuleList([Linear(dim, dim) for _ in range(num_layers)])
        self.gates = nn.ParameterList([nn.Parameter(torch.zeros(1)) for _ in range(num_layers)])
        if precision_weighting:
            # learned precision (inverse-variance) per layer modulates how much
            # each layer's error is trusted
            self.log_precision = nn.Parameter(torch.zeros(num_layers))
        if error_norm:
            self.err_norms = nn.ModuleList([RMSNorm(dim) for _ in range(num_layers)])
        self.dropout = nn.Dropout(dropout) if dropout > 0 else nn.Identity()
        self.out_norm = RMSNorm(dim)

    def _sparsify(self, error):
        if self.topk_sparse <= 0 or self.topk_sparse >= self.dim:
            return error
        # keep only the top-k most-active channels (by mean abs over batch/seq)
        salience = error.abs().mean(dim=tuple(range(error.dim() - 1)))  # (D,)
        _, idx = salience.topk(self.topk_sparse)
        mask = torch.zeros_like(salience)
        mask[idx] = 1.0
        return error * mask

    def forward(self, x, next_input=None, return_error=True):
        if next_input is None:
            next_input = x
        out = x
        total_error = torch.zeros_like(x)
        layer_errors = []
        for i in range(self.num_layers):
            pred = self.predictors[i](out)
            error = next_input - pred
            error = self._sparsify(error)
            if self.error_norm:
                error = self.err_norms[i](error)
            correction = self.error_projs[i](error)
            if self.precision_weighting:
                prec = torch.exp(self.log_precision[i])
                correction = correction * prec
            g = torch.sigmoid(self.gates[i])
            out = out + g * self.dropout(correction)
            if self.use_residual:
                out = out + 0.0  # residual already maintained via additive update
            total_error = total_error + error.abs()
            layer_errors.append(error.abs().mean().detach())
        out = self.out_norm(out)
        mean_error = total_error / self.num_layers
        if return_error:
            return out, mean_error
        return out

    def surprise(self, x, next_input=None):
        # Scalar "surprise" = mean magnitude of unexplained prediction error.
        _, err = self.forward(x, next_input, return_error=True)
        return err.mean()

    def free_energy(self, x, next_input=None):
        # Precision-weighted prediction-error energy (a variational-free-energy
        # proxy): sum_i precision_i * ||error_i||^2.
        if next_input is None:
            next_input = x
        out = x
        energy = x.new_zeros(())
        for i in range(self.num_layers):
            pred = self.predictors[i](out)
            error = next_input - pred
            prec = torch.exp(self.log_precision[i]) if self.precision_weighting else 1.0
            energy = energy + prec * error.pow(2).mean()
            correction = self.error_projs[i](error)
            out = out + torch.sigmoid(self.gates[i]) * correction
        return energy

    def regularization_loss(self, precision_weight=1e-3):
        if self.precision_weighting:
            return precision_weight * self.log_precision.pow(2).mean()
        return next(self.parameters()).new_zeros(())

    def get_config(self):
        return {"dim": self.dim, "num_layers": self.num_layers,
                "use_residual": self.use_residual, "topk_sparse": self.topk_sparse,
                "error_norm": self.error_norm, "precision_weighting": self.precision_weighting}

    def count_parameters(self):
        return sum(p.numel() for p in self.parameters())

    def parameter_breakdown(self):
        return {n: p.numel() for n, p in self.named_parameters()}

    def parameter_groups(self, base_lr=1e-3):
        return [{"params": list(self.parameters()), "lr": base_lr}]

    def extra_repr(self):
        return (f"dim={self.dim}, num_layers={self.num_layers}, "
                f"topk_sparse={self.topk_sparse}, precision={self.precision_weighting}")

    def diagnostics(self):
        d = {"num_params": self.count_parameters(), "num_layers": self.num_layers}
        if self.precision_weighting:
            d["mean_precision"] = torch.exp(self.log_precision).mean().item()
        return d

