    # Advanced engineering utilities (injected; namespaced to avoid clashes)
    # ------------------------------------------------------------------ #




























    # ------------------------------------------------------------------ #
    # Advanced architectural / runtime capabilities (injected; `ar_` namespace)
    # ------------------------------------------------------------------ #

















# ============================================================================
# 20. AdaptiveLayerSkipping
# ----------------------------------------------------------------------------
# Learns, per input, how much of a precomputed FFN/sublayer output to actually
# apply — a soft, content-conditioned residual gate implemented as a small
# mixture of "skip experts". Each expert emits a scalar keep-probability; a
# router weights the experts; the weighted keep-probability scales the FFN
# contribution. A temperature controls sharpness, and a running skip-rate
# statistic tracks how aggressively the module is skipping.
# ============================================================================
class AdaptiveLayerSkipping(ModuleUtilsMixin, nn.Module):
    def __init__(self, dim, num_experts=8, temperature=1.0, learnable_temp=True,
                 target_skip_rate=None, dropout=0.0, eps=1e-6):
        super().__init__()
        self.dim = dim
        self.num_experts = num_experts
        self.target_skip_rate = target_skip_rate
        self.eps = eps

        self.router = nn.Sequential(
            Linear(dim * 2, dim), nn.GELU(), Linear(dim, num_experts))
        self.skip_experts = nn.ModuleList([
            nn.Sequential(Linear(dim, dim // 2), nn.GELU(),
                          Linear(dim // 2, 1), nn.Sigmoid())
            for _ in range(num_experts)
        ])
        if learnable_temp:
            self.log_temperature = nn.Parameter(torch.tensor(float(math.log(temperature))))
        else:
            self.register_buffer("log_temperature", torch.tensor(float(math.log(temperature))))
        self.output_scale = nn.Parameter(torch.ones(dim))
        self.dropout = nn.Dropout(dropout) if dropout > 0 else nn.Identity()
        self.register_buffer("running_skip_rate", torch.zeros(1))
        self.register_buffer("_step", torch.zeros(1, dtype=torch.long))

    def forward(self, x, ffn_out, return_gate=False):
        B, S, D = x.shape
        ctx = torch.cat([x.mean(1), ffn_out.mean(1)], dim=-1)  # (B, 2D)
        temp = torch.exp(self.log_temperature).clamp(0.1, 10.0)
        route = F.softmax(self.router(ctx) / temp, dim=-1)     # (B, num_experts)

        # each expert's keep probability (content-conditioned)
        keep = torch.stack([e(x.mean(1)) for e in self.skip_experts], dim=1).squeeze(-1)  # (B, E)
        keep_prob = (route * keep).sum(-1)                     # (B,)
        gate = keep_prob.view(B, 1, 1)

        out = x + gate * self.dropout(ffn_out)
        out = out * self.output_scale

        if self.training:
            with torch.no_grad():
                self.running_skip_rate.mul_(0.99).add_(0.01 * (1 - keep_prob.mean()))
                self._step += 1

        if return_gate:
            return out, keep_prob
        return out

    def skip_loss(self):
        # Optional loss to steer the module toward a target skip rate (for
        # explicit compute budgeting).
        if self.target_skip_rate is None:
            return self.output_scale.new_zeros(())
        return (self.running_skip_rate - self.target_skip_rate).pow(2).mean()

    def regularization_loss(self):
        return self.skip_loss()

    def get_config(self):
        return {"dim": self.dim, "num_experts": self.num_experts,
                "target_skip_rate": self.target_skip_rate}

    def count_parameters(self):
        return sum(p.numel() for p in self.parameters())

    def parameter_breakdown(self):
        return {n: p.numel() for n, p in self.named_parameters()}

    def parameter_groups(self, base_lr=1e-3):
        return [{"params": list(self.parameters()), "lr": base_lr}]

    def extra_repr(self):
        return f"dim={self.dim}, num_experts={self.num_experts}"

    def diagnostics(self):
        return {"num_params": self.count_parameters(), "step": int(self._step.item()),
                "running_skip_rate": self.running_skip_rate.item(),
                "temperature": torch.exp(self.log_temperature).item()}

    # ------------------------------------------------------------------ #
    # Advanced engineering utilities (injected; namespaced to avoid clashes)
    # ------------------------------------------------------------------ #




























    # ------------------------------------------------------------------ #
    # Advanced architectural / runtime capabilities (injected; `ar_` namespace)
    # ------------------------------------------------------------------ #














class UncertaintyHead(ModuleUtilsMixin, nn.Module):
    def __init__(self, dim, hidden_mult=2, mc_samples=8, dropout=0.1,
                 predict_aleatoric=True, calibrate=True, eps=1e-6):
        super().__init__()
        self.dim = dim
        self.mc_samples = mc_samples
        self.predict_aleatoric = predict_aleatoric
        self.eps = eps

        hidden = dim * hidden_mult
        self.backbone = nn.Sequential(
            Linear(dim, hidden), nn.GELU(), nn.Dropout(dropout),
            Linear(hidden, hidden), nn.GELU())
        self.confidence_head = nn.Sequential(Linear(hidden, 1), nn.Sigmoid())
        if predict_aleatoric:
            self.log_var_head = Linear(hidden, 1)
        self.mc_dropout = nn.Dropout(dropout)
        if calibrate:
            self.temperature = nn.Parameter(torch.ones(1))
        else:
            self.register_buffer("temperature", torch.ones(1))

    def forward(self, x):
        # Single deterministic pass -> bounded confidence in [0,1].
        h = self.backbone(x)
        conf = self.confidence_head(h).squeeze(-1)
        return conf / self.temperature.clamp_min(self.eps)

    def aleatoric(self, x):
        if not self.predict_aleatoric:
            return None
        h = self.backbone(x)
        log_var = self.log_var_head(h).squeeze(-1)
        return torch.exp(log_var.clamp(-8, 8))

    def epistemic(self, x):
        # MC-dropout: variance of the confidence across stochastic passes.
        was_training = self.training
        self.train()  # enable dropout
        with torch.no_grad():
            preds = []
            for _ in range(self.mc_samples):
                h = self.mc_dropout(self.backbone(x))
                preds.append(self.confidence_head(h).squeeze(-1))
            stacked = torch.stack(preds, 0)
        if not was_training:
            self.eval()
        return stacked.var(0)

    def full_uncertainty(self, x):
        out = {"confidence": self.forward(x)}
        if self.predict_aleatoric:
            out["aleatoric"] = self.aleatoric(x)
        out["epistemic"] = self.epistemic(x)
        out["total"] = out.get("aleatoric", 0.0) + out["epistemic"]
        return out

    def nll_loss(self, x, target):
        # Heteroscedastic Gaussian NLL using the predicted aleatoric variance:
        # 0.5*(log var + (pred-target)^2 / var). Trains calibrated uncertainty.
        h = self.backbone(x)
        pred = self.confidence_head(h).squeeze(-1)
        if self.predict_aleatoric:
            log_var = self.log_var_head(h).squeeze(-1).clamp(-8, 8)
            var = torch.exp(log_var)
            return (0.5 * (log_var + (pred - target).pow(2) / (var + self.eps))).mean()
        return F.mse_loss(pred, target)

    def regularization_loss(self, temp_weight=1e-3):
        return temp_weight * (self.temperature - 1.0).pow(2).mean()

    def get_config(self):
        return {"dim": self.dim, "mc_samples": self.mc_samples,
                "predict_aleatoric": self.predict_aleatoric}

    def count_parameters(self):
        return sum(p.numel() for p in self.parameters())

    def parameter_breakdown(self):
        return {n: p.numel() for n, p in self.named_parameters()}

    def parameter_groups(self, base_lr=1e-3):
        return [{"params": list(self.parameters()), "lr": base_lr}]

    def extra_repr(self):
        return f"dim={self.dim}, mc_samples={self.mc_samples}, aleatoric={self.predict_aleatoric}"

    def diagnostics(self):
        return {"num_params": self.count_parameters(),
                "temperature": self.temperature.item()}

    # ------------------------------------------------------------------ #
    # Advanced engineering utilities (injected; namespaced to avoid clashes)
    # ------------------------------------------------------------------ #




























