# ============================================================================
# 22. QualityAssessor
# ----------------------------------------------------------------------------
# A multi-criteria quality scorer for model outputs. Rather than a single
# scalar, it scores several interpretable axes (coherence, relevance,
# fluency, factuality, diversity) from a representation, combines them with a
# learned weighting into an overall score, and can compare two candidate
# outputs to produce a preference signal (useful for ranking / RLHF-style
# reward modeling). Self-contained and fully differentiable.
# ============================================================================
class QualityAssessor(ModuleUtilsMixin, nn.Module):
    def __init__(self, dim, hidden_mult=2, criteria=("coherence", "relevance",
                 "fluency", "factuality", "diversity"), pool="mean",
                 dropout=0.0, eps=1e-6):
        super().__init__()
        self.dim = dim
        self.criteria = tuple(criteria)
        self.num_criteria = len(criteria)
        self.pool = pool
        self.eps = eps

        hidden = dim * hidden_mult
        self.encoder = nn.Sequential(
            Linear(dim, hidden), nn.GELU(), nn.Dropout(dropout) if dropout > 0 else nn.Identity())
        self.criterion_heads = nn.ModuleList([
            nn.Sequential(Linear(hidden, hidden // 2), nn.GELU(),
                          Linear(hidden // 2, 1), nn.Sigmoid())
            for _ in self.criteria])
        # learned importance weights over criteria
        self.criterion_weights = nn.Parameter(torch.ones(self.num_criteria))
        # context-conditioned reweighting
        self.weight_modulator = nn.Sequential(
            Linear(dim, self.num_criteria), nn.Softmax(dim=-1))

    def _pool(self, x):
        if x.dim() == 2:
            return x
        if self.pool == "mean":
            return x.mean(1)
        elif self.pool == "max":
            return x.max(1).values
        elif self.pool == "last":
            return x[:, -1]
        return x.mean(1)

    def assess(self, model_output, return_breakdown=True):
        pooled = self._pool(model_output)
        h = self.encoder(pooled)
        scores = torch.cat([head(h) for head in self.criterion_heads], dim=-1)  # (B, C)
        # combine static + context-dependent weights
        static_w = F.softmax(self.criterion_weights, dim=-1)
        dynamic_w = self.weight_modulator(pooled)
        w = 0.5 * static_w.unsqueeze(0) + 0.5 * dynamic_w
        overall = (scores * w).sum(-1)
        if return_breakdown:
            return overall, {c: scores[:, i] for i, c in enumerate(self.criteria)}
        return overall

    def forward(self, model_output):
        return self.assess(model_output, return_breakdown=False)

    def compare(self, output_a, output_b):
        # Preference signal: probability that A is better than B (Bradley-Terry).
        qa = self.assess(output_a, return_breakdown=False)
        qb = self.assess(output_b, return_breakdown=False)
        return torch.sigmoid(qa - qb)

    def preference_loss(self, better, worse, margin=0.0):
        # Ranking loss encouraging quality(better) > quality(worse) + margin.
        qb = self.assess(better, return_breakdown=False)
        qw = self.assess(worse, return_breakdown=False)
        return F.relu(margin - (qb - qw)).mean()

    def regularization_loss(self, entropy_weight=1e-3):
        # encourage the static criterion weights not to collapse onto one axis
        w = F.softmax(self.criterion_weights, dim=-1)
        entropy = -(w * (w + self.eps).log()).sum()
        return -entropy_weight * entropy

    def get_config(self):
        return {"dim": self.dim, "criteria": self.criteria, "pool": self.pool}

    def count_parameters(self):
        return sum(p.numel() for p in self.parameters())

    def parameter_breakdown(self):
        return {n: p.numel() for n, p in self.named_parameters()}

    def parameter_groups(self, base_lr=1e-3):
        return [{"params": list(self.parameters()), "lr": base_lr}]

    def extra_repr(self):
        return f"dim={self.dim}, criteria={self.criteria}"

    def diagnostics(self):
        return {"num_params": self.count_parameters(),
                "criterion_weights": F.softmax(self.criterion_weights, dim=-1).tolist()}

