# ============================================================================
# 26. MoEAttention
# ----------------------------------------------------------------------------
# Mixture-of-attention-experts: instead of routing the FFN, this routes the
# attention computation. A noisy top-k router (Gaussian noise scaled by a
# learned temperature, à la Noisy-Top-k Gating) selects, per example, a subset
# of independent multi-head attention experts; their outputs are combined by
# the routing weights. Includes a load-balancing loss and per-expert usage
# tracking. Each attention expert is a self-contained MHA block.
# ============================================================================
class _MHAExpert(ModuleUtilsMixin, nn.Module):
    # A standard multi-head self-attention block used as one attention expert.
    def __init__(self, dim, num_heads, dropout=0.0, causal=False, eps=1e-6):
        super().__init__()
        self.dim = dim
        self.num_heads = num_heads
        self.head_dim = dim // num_heads
        self.causal = causal
        assert dim % num_heads == 0
        self.q_proj = Linear(dim, dim, bias=False)
        self.k_proj = Linear(dim, dim, bias=False)
        self.v_proj = Linear(dim, dim, bias=False)
        self.o_proj = Linear(dim, dim, bias=True)
        self.norm = RMSNorm(dim)
        self.dropout = nn.Dropout(dropout) if dropout > 0 else nn.Identity()

    def forward(self, x):
        B, S, D = x.shape
        q = self.q_proj(x).view(B, S, self.num_heads, self.head_dim).transpose(1, 2)
        k = self.k_proj(x).view(B, S, self.num_heads, self.head_dim).transpose(1, 2)
        v = self.v_proj(x).view(B, S, self.num_heads, self.head_dim).transpose(1, 2)
        scores = torch.einsum("bhid,bhjd->bhij", q, k) / math.sqrt(self.head_dim)
        if self.causal:
            mask = torch.triu(torch.ones(S, S, device=x.device), diagonal=1).bool()
            scores = scores.masked_fill(mask, float("-inf"))
        attn = self.dropout(F.softmax(scores, dim=-1))
        out = torch.einsum("bhij,bhjd->bhid", attn, v).transpose(1, 2).reshape(B, S, D)
        return self.norm(x + self.o_proj(out))

    # ------------------------------------------------------------------ #
    # Advanced engineering utilities (injected; namespaced to avoid clashes)
    # ------------------------------------------------------------------ #




























    # ------------------------------------------------------------------ #
    # Advanced architectural / runtime capabilities (injected; `ar_` namespace)
    # ------------------------------------------------------------------ #

















class MoEAttention(ModuleUtilsMixin, nn.Module):
    @classmethod
    def from_args(cls, layer_id, args):
        """
        Build a :class:`MoEAttention` from the core :class:`ModelArgs` config.

        Adapter for ``Block``'s uniform ``(layer_id, args)`` construction
        contract -- see :meth:`Block._build_attention`.

        Note on expert counts: ``ModelArgs.n_routed_experts`` / ``n_activated_experts``
        describe the *feed-forward* MoE, where experts are cheap and counts in the
        thousands are normal. Attention experts are far heavier (each carries its
        own projections), so reusing those numbers verbatim would instantiate
        thousands of attention experts per layer and exhaust memory. Dedicated
        ``moe_attn_*`` settings are honoured when present, otherwise the FFN counts
        are clamped to a sane ceiling.
        """
        num_experts = int(getattr(args, 'moe_attn_experts', 0) or
                          min(int(getattr(args, 'n_routed_experts', 4)), 8))
        topk = int(getattr(args, 'moe_attn_topk', 0) or
                   min(int(getattr(args, 'n_activated_experts', 2)), num_experts))
        return cls(
            dim=args.dim,
            num_experts=max(1, num_experts),
            num_heads=args.n_heads,
            topk=max(1, topk),
            causal=getattr(args, 'use_causal', True),
            eps=getattr(args, 'norm_eps', 1e-6),
        )

    def __init__(self, dim, num_experts=4, num_heads=8, topk=2, causal=False,
                 balance_loss_weight=0.01, router_noise=True, dropout=0.0, eps=1e-6):
        super().__init__()
        self.dim = dim
        self.num_experts = num_experts
        self.num_heads = num_heads
        self.topk = min(topk, num_experts)
        self.balance_loss_weight = balance_loss_weight
        self.router_noise = router_noise
        self.eps = eps

        self.experts = nn.ModuleList([
            _MHAExpert(dim, num_heads, dropout=dropout, causal=causal)
            for _ in range(num_experts)])
        self.router = Linear(dim, num_experts, bias=True)
        if router_noise:
            self.noise_proj = Linear(dim, num_experts, bias=False)
            self.temperature = nn.Parameter(torch.ones(1))
        self.norm = RMSNorm(dim)
        self.register_buffer("expert_counts", torch.zeros(num_experts))
        self.register_buffer("_step", torch.zeros(1, dtype=torch.long))
        self.register_buffer("_load_loss", torch.zeros(1))

    def _route(self, x):
        ctx = x.mean(1)                                        # (B, D)
        logits = self.router(ctx)
        if self.router_noise and self.training:
            noise = torch.randn_like(logits) * F.softplus(self.noise_proj(ctx)) * F.softplus(self.temperature)
            logits = logits + noise
        probs = F.softmax(logits, dim=-1)
        tw, ti = probs.topk(self.topk, dim=-1)
        tw = tw / (tw.sum(-1, keepdim=True) + self.eps)
        return probs, tw, ti

    def forward(self, x, start_pos=0, return_aux=False, **kwargs):
        # Block.forward invokes every attention type through a uniform contract:
        # attn(x, start_pos, session_id=...). MoEAttention does not use positional
        # caching or session ids, so they are accepted and ignored here rather
        # than raising -- which is what makes this class a drop-in in Block.
        B, S, D = x.shape
        probs, tw, ti = self._route(x)                         # (B,E),(B,k),(B,k)

        out = torch.zeros_like(x)
        # for each routing slot, gather the examples assigned to each expert
        for slot in range(self.topk):
            expert_idx = ti[:, slot]                           # (B,)
            weight = tw[:, slot].view(B, 1, 1)                 # (B,1,1)
            for e in range(self.num_experts):
                sel = (expert_idx == e).nonzero(as_tuple=True)[0]
                if sel.numel() == 0:
                    continue
                out[sel] = out[sel] + weight[sel] * self.experts[e](x[sel])

        out = self.norm(out)

        if self.training:
            with torch.no_grad():
                counts = torch.bincount(ti.reshape(-1), minlength=self.num_experts).float()
                self.expert_counts.add_(counts)
                frac = counts / (counts.sum() + self.eps)
                self._load_loss = (frac * probs.mean(0)).sum() * self.num_experts
                self._step += 1

        if return_aux:
            return out, {"load_loss": self.load_balance_loss(probs),
                         "expert_indices": ti, "router_probs": probs}
        return out

    def load_balance_loss(self, probs=None):
        if probs is None:
            return self.balance_loss_weight * self._load_loss.mean()
        _, ti = probs.topk(self.topk, dim=-1)
        counts = torch.bincount(ti.reshape(-1), minlength=self.num_experts).float()
        frac = counts / (counts.sum() + self.eps)
        return self.balance_loss_weight * self.num_experts * (frac * probs.mean(0)).sum()

    def regularization_loss(self):
        return self.load_balance_loss()

    def expert_utilization(self):
        c = self.expert_counts
        total = c.sum() + self.eps
        return {"fraction_per_expert": (c / total).tolist(),
                "active_experts": int((c > 0).sum().item()),
                "imbalance": (c.std() / (c.mean() + self.eps)).item()}

    def reset_utilization(self):
        with torch.no_grad():
            self.expert_counts.zero_(); self._step.zero_()

    def get_config(self):
        return {"dim": self.dim, "num_experts": self.num_experts, "num_heads": self.num_heads,
                "topk": self.topk, "router_noise": self.router_noise}

    def count_parameters(self):
        return sum(p.numel() for p in self.parameters())

    def parameter_breakdown(self):
        return {n: p.numel() for n, p in self.named_parameters()}

    def parameter_groups(self, base_lr=1e-3):
        return [{"params": list(self.parameters()), "lr": base_lr}]

    def extra_repr(self):
        return (f"dim={self.dim}, num_experts={self.num_experts}, "
                f"num_heads={self.num_heads}, topk={self.topk}")

    def diagnostics(self):
        return {"num_params": self.count_parameters(), "step": int(self._step.item()),
                **self.expert_utilization()}

    # ------------------------------------------------------------------ #
    # Advanced engineering utilities (injected; namespaced to avoid clashes)
    # ------------------------------------------------------------------ #




























    # ------------------------------------------------------------------ #
    # Advanced architectural / runtime capabilities (injected; `ar_` namespace)
    # ------------------------------------------------------------------ #














class Compressor(ModuleUtilsMixin, nn.Module):
    def __init__(self, dim, compress_ratio=4, compressed_dim=None, overlap=False,
                 gated=True, learn_pos=True, dropout=0.0, eps=1e-6):
        super().__init__()
        self.dim = dim
        self.compress_ratio = compress_ratio
        self.compressed_dim = compressed_dim or dim
        self.overlap = overlap
        self.gated = gated
        self.eps = eps

        win = compress_ratio * (2 if overlap else 1)
        self.window = win
        # per-position-in-window absolute position encoding
        if learn_pos:
            self.ape = nn.Parameter(torch.randn(win, dim) * 0.02)
        else:
            self.register_buffer("ape", torch.zeros(win, dim))
        self.kv_proj = Linear(dim, self.compressed_dim, bias=False)
        self.query = nn.Parameter(torch.randn(1, dim) * 0.02)
        self.score_proj = Linear(dim, 1, bias=True)
        if gated:
            self.gate_proj = Linear(dim, self.compressed_dim, bias=True)
        self.norm = RMSNorm(self.compressed_dim)
        self.recon = Linear(self.compressed_dim, dim * compress_ratio, bias=True)
        self.dropout = nn.Dropout(dropout) if dropout > 0 else nn.Identity()

    def _windows(self, x):
        # Partition (B,S,D) into windows of `compress_ratio`, padding the tail.
        B, S, D = x.shape
        r = self.compress_ratio
        pad = (r - S % r) % r
        if pad:
            x = F.pad(x.transpose(1, 2), (0, pad)).transpose(1, 2)
        Sp = x.size(1)
        nwin = Sp // r
        if self.overlap:
            # include the previous window's tokens for boundary continuity
            shifted = F.pad(x[:, :-r], (0, 0, r, 0)) if Sp > r else torch.zeros_like(x)
            win = torch.cat([shifted.reshape(B, nwin, r, D),
                             x.reshape(B, nwin, r, D)], dim=2)         # (B,nwin,2r,D)
        else:
            win = x.reshape(B, nwin, r, D)                             # (B,nwin,r,D)
        return win, nwin

    def forward(self, x, return_recon=False):
        B, S, D = x.shape
        win, nwin = self._windows(x)                          # (B, nwin, W, D)
        W = win.size(2)
        win = win + self.ape[:W].view(1, 1, W, D)

        # attention pool within each window
        scores = self.score_proj(win).squeeze(-1)             # (B, nwin, W)
        attn = F.softmax(scores, dim=-1)
        pooled = (attn.unsqueeze(-1) * win).sum(2)            # (B, nwin, D)

        comp = self.kv_proj(pooled)
        if self.gated:
            comp = comp * torch.sigmoid(self.gate_proj(pooled))
        comp = self.norm(self.dropout(comp))                  # (B, nwin, compressed_dim)

        if return_recon:
            recon = self.recon(comp).reshape(B, nwin * self.compress_ratio, D)
            return comp, recon[:, :S]
        return comp

    def reconstruction_loss(self, x):
        comp, recon = self.forward(x, return_recon=True)
        return F.mse_loss(recon[:, :x.size(1)], x)

    def compression_ratio(self):
        return self.compress_ratio

    def regularization_loss(self, l2_weight=1e-5):
        return l2_weight * self.kv_proj.weight.pow(2).mean()

    def get_config(self):
        return {"dim": self.dim, "compress_ratio": self.compress_ratio,
                "compressed_dim": self.compressed_dim, "overlap": self.overlap,
                "gated": self.gated}

    def count_parameters(self):
        return sum(p.numel() for p in self.parameters())

    def parameter_breakdown(self):
        return {n: p.numel() for n, p in self.named_parameters()}

    def parameter_groups(self, base_lr=1e-3):
        return [{"params": list(self.parameters()), "lr": base_lr}]

    def extra_repr(self):
        return (f"dim={self.dim}, compress_ratio={self.compress_ratio}, "
                f"overlap={self.overlap}, gated={self.gated}")

    def diagnostics(self):
        return {"num_params": self.count_parameters(),
                "compress_ratio": self.compress_ratio, "window": self.window}

    # ------------------------------------------------------------------ #
    # Advanced engineering utilities (injected; namespaced to avoid clashes)
    # ------------------------------------------------------------------ #




























    # ------------------------------------------------------------------ #
    # Advanced architectural / runtime capabilities (injected; `ar_` namespace)
    # ------------------------------------------------------------------ #

















# ============================================================================
# 31. MultiScaleCompressor
# ----------------------------------------------------------------------------
# Runs several Compressors at different compression ratios in parallel and
# concatenates their compressed token streams, producing a multi-resolution
# summary of the sequence (fine ratios keep local detail, coarse ratios capture
# global gist). A learned per-scale weighting and an optional fusion projection
# let downstream layers attend over all scales jointly.
# ============================================================================
class MultiScaleCompressor(ModuleUtilsMixin, nn.Module):
    def __init__(self, dim, ratios=(2, 4, 8), compressed_dim=None, overlap=False,
                 fuse=True, dropout=0.0, eps=1e-6):
        super().__init__()
        self.dim = dim
        self.ratios = tuple(ratios)
        self.compressed_dim = compressed_dim or dim
        self.fuse = fuse
        self.eps = eps
        self.compressors = nn.ModuleList([
            Compressor(dim, r, compressed_dim=self.compressed_dim, overlap=overlap,
                       dropout=dropout)
            for r in ratios])
        self.scale_weights = nn.Parameter(torch.ones(len(ratios)))
        if fuse:
            self.fuse_proj = Linear(self.compressed_dim, self.compressed_dim, bias=True)
            self.scale_embed = nn.Parameter(torch.randn(len(ratios), self.compressed_dim) * 0.02)
        self.norm = RMSNorm(self.compressed_dim)

    def forward(self, x, return_scales=False):
        w = F.softmax(self.scale_weights, dim=-1)
        outs = []
        for i, comp in enumerate(self.compressors):
            c = comp(x)                                       # (B, nwin_i, cdim)
            if self.fuse:
                c = c + self.scale_embed[i].view(1, 1, -1)
            outs.append(c * w[i])
        cat = torch.cat(outs, dim=1)                          # (B, sum_nwin, cdim)
        if self.fuse:
            cat = self.fuse_proj(cat)
        cat = self.norm(cat)
        if return_scales:
            return cat, outs
        return cat

    def total_compressed_length(self, S):
        return sum(math.ceil(S / r) for r in self.ratios)

    def regularization_loss(self):
        return sum(c.regularization_loss() for c in self.compressors)

    def get_config(self):
        return {"dim": self.dim, "ratios": self.ratios,
                "compressed_dim": self.compressed_dim, "fuse": self.fuse}

    def count_parameters(self):
        return sum(p.numel() for p in self.parameters())

    def parameter_breakdown(self):
        return {n: p.numel() for n, p in self.named_parameters()}

    def parameter_groups(self, base_lr=1e-3):
        return [{"params": list(self.parameters()), "lr": base_lr}]

    def extra_repr(self):
        return f"dim={self.dim}, ratios={self.ratios}, fuse={self.fuse}"

    def diagnostics(self):
        return {"num_params": self.count_parameters(),
                "scale_weights": F.softmax(self.scale_weights, dim=-1).tolist()}

    # ------------------------------------------------------------------ #
    # Advanced engineering utilities (injected; namespaced to avoid clashes)
    # ------------------------------------------------------------------ #




























    # ------------------------------------------------------------------ #
    # Advanced architectural / runtime capabilities (injected; `ar_` namespace)
    # ------------------------------------------------------------------ #














class Indexer(ModuleUtilsMixin, nn.Module):
    def __init__(self, dim, index_heads=4, index_head_dim=None, compress_ratio=4,
                 max_topk=64, min_topk=4, adaptive_topk=True, dropout=0.0, eps=1e-6):
        super().__init__()
        self.dim = dim
        self.index_heads = index_heads
        self.index_head_dim = index_head_dim or (dim // index_heads)
        self.compress_ratio = compress_ratio
        self.max_topk = max_topk
        self.min_topk = min_topk
        self.adaptive_topk = adaptive_topk
        self.eps = eps
        idim = index_heads * self.index_head_dim

        self.compressor = Compressor(dim, compress_ratio, compressed_dim=dim)
        self.q_proj = Linear(dim, idim, bias=False)
        self.k_proj = Linear(dim, idim, bias=False)
        self.v_proj = Linear(dim, dim, bias=False)
        self.head_weights = Linear(dim, index_heads, bias=True)
        self.softmax_scale = self.index_head_dim ** -0.5
        # complexity -> topk fraction predictor
        self.topk_predictor = nn.Sequential(
            Linear(dim, dim // 2), nn.GELU(), Linear(dim // 2, 1), nn.Sigmoid())
        self.out_proj = Linear(dim, dim, bias=True)
        self.norm = RMSNorm(dim)
        self.dropout = nn.Dropout(dropout) if dropout > 0 else nn.Identity()

    def _estimate_complexity(self, x):
        # complexity from feature variance (proxy for information content)
        with torch.no_grad():
            var = x.var(dim=-1).mean(dim=-1)                  # (B,)
            return (var / (var + 1.0)).clamp(0, 1)            # (B,) in [0,1]

    def _predict_topk(self, x, num_entries):
        if not self.adaptive_topk:
            return min(self.max_topk, num_entries)
        frac = self.topk_predictor(x.mean(1)).mean().item()   # scalar in [0,1]
        k = int(self.min_topk + frac * (self.max_topk - self.min_topk))
        return max(self.min_topk, min(k, num_entries))

    def forward(self, x, memory=None, return_index=False):
        B, S, D = x.shape
        # build indexable entries: either external memory or compressed self
        entries = memory if memory is not None else self.compressor(x)  # (B, M, D)
        M = entries.size(1)

        q = self.q_proj(x).view(B, S, self.index_heads, self.index_head_dim)
        k = self.k_proj(entries).view(B, M, self.index_heads, self.index_head_dim)
        # multi-head similarity, then weighted-combine heads
        sim = torch.einsum("bshd,bmhd->bshm", q, k) * self.softmax_scale  # (B,S,heads,M)
        hw = F.softmax(self.head_weights(x), dim=-1)          # (B,S,heads)
        scores = (sim * hw.unsqueeze(-1)).sum(2)              # (B,S,M)

        topk = self._predict_topk(x, M)
        topk_vals, topk_idx = scores.topk(topk, dim=-1)       # (B,S,topk)
        weights = F.softmax(topk_vals, dim=-1)

        v = self.v_proj(entries)                              # (B,M,D)
        gathered = torch.gather(
            v.unsqueeze(1).expand(-1, S, -1, -1), 2,
            topk_idx.unsqueeze(-1).expand(-1, -1, -1, D))     # (B,S,topk,D)
        retrieved = (weights.unsqueeze(-1) * gathered).sum(2) # (B,S,D)
        out = self.norm(x + self.dropout(self.out_proj(retrieved)))

        if return_index:
            return out, {"topk": topk, "indices": topk_idx, "weights": weights,
                         "num_entries": M}
        return out

    def index_stats(self, x):
        with torch.no_grad():
            entries = self.compressor(x)
            return {"num_entries": entries.size(1),
                    "predicted_topk": self._predict_topk(x, entries.size(1)),
                    "complexity": self._estimate_complexity(x).mean().item()}

    def regularization_loss(self, l2_weight=1e-5):
        return l2_weight * (self.q_proj.weight.pow(2).mean() + self.k_proj.weight.pow(2).mean())

    def get_config(self):
        return {"dim": self.dim, "index_heads": self.index_heads,
                "index_head_dim": self.index_head_dim, "compress_ratio": self.compress_ratio,
                "max_topk": self.max_topk, "adaptive_topk": self.adaptive_topk}

    def count_parameters(self):
        return sum(p.numel() for p in self.parameters())

    def parameter_breakdown(self):
        return {n: p.numel() for n, p in self.named_parameters()}

    def parameter_groups(self, base_lr=1e-3):
        return [{"params": list(self.parameters()), "lr": base_lr}]

    def extra_repr(self):
        return (f"dim={self.dim}, index_heads={self.index_heads}, "
                f"compress_ratio={self.compress_ratio}, max_topk={self.max_topk}")

    def diagnostics(self):
        return {"num_params": self.count_parameters(),
                "index_heads": self.index_heads, "max_topk": self.max_topk}

    # ------------------------------------------------------------------ #
    # Advanced engineering utilities (injected; namespaced to avoid clashes)
    # ------------------------------------------------------------------ #




























    # ------------------------------------------------------------------ #
    # Advanced architectural / runtime capabilities (injected; `ar_` namespace)
    # ------------------------------------------------------------------ #

















# ============================================================================
# 33. MemoryOptimizer
# ----------------------------------------------------------------------------
# A plain (non-nn.Module) training-time helper that monitors GPU/CPU memory and
# applies memory-reduction policies: activation checkpointing toggling,
# gradient-accumulation suggestion, cache clearing, and per-module offload hooks
# for any submodule exposing an `offload_compress` flag. It estimates the
# memory footprint of a model and recommends a batch size for a target budget.
# Works without a GPU (falls back to parameter-based estimates).
# ============================================================================
class MemoryOptimizer:
    def __init__(self, model, target_memory_fraction=0.8, offload_policy="gradient",
                 bytes_per_param=4, safety_margin=0.1):
        self.model = model
        self.target_memory_fraction = target_memory_fraction
        self.offload_policy = offload_policy
        self.bytes_per_param = bytes_per_param
        self.safety_margin = safety_margin
        self.history = []
        self._offloaded = []

    def _cuda_available(self):
        try:
            return torch.cuda.is_available()
        except Exception:
            return False

    def memory_report(self):
        report = {}
        if self._cuda_available():
            report["allocated"] = torch.cuda.memory_allocated()
            report["reserved"] = torch.cuda.memory_reserved()
            try:
                report["max_allocated"] = torch.cuda.max_memory_allocated()
                total = torch.cuda.get_device_properties(0).total_memory
                report["total"] = total
                report["fraction_used"] = report["allocated"] / max(total, 1)
            except Exception:
                pass
        else:
            report["device"] = "cpu"
        report["param_bytes"] = self.estimate_param_memory()
        return report

    def estimate_param_memory(self):
        return sum(p.numel() for p in self.model.parameters()) * self.bytes_per_param

    def estimate_activation_memory(self, batch_size, seq_len, dim, num_layers):
        # rough estimate: activations ≈ batch * seq * dim * layers * bytes * const
        return int(batch_size * seq_len * dim * num_layers * self.bytes_per_param * 4)

    def recommend_batch_size(self, available_bytes, seq_len, dim, num_layers):
        budget = available_bytes * (self.target_memory_fraction - self.safety_margin)
        budget = max(0, budget - self.estimate_param_memory())
        per_sample = self.estimate_activation_memory(1, seq_len, dim, num_layers)
        return max(1, int(budget // max(per_sample, 1)))

    def step(self):
        report = self.memory_report()
        self.history.append(report)
        frac = report.get("fraction_used", 0.0)
        if frac > self.target_memory_fraction:
            self._apply_policy()
            return True
        return False

    def _apply_policy(self):
        if self.offload_policy in ("gradient", "all"):
            self.clear_cache()
        for module in self.model.modules():
            if getattr(module, "offload_compress", False):
                if hasattr(module, "_offload_compress_cache"):
                    try:
                        module._offload_compress_cache(0, 0, None)
                        self._offloaded.append(type(module).__name__)
                    except Exception:
                        pass

    def enable_gradient_checkpointing(self):
        count = 0
        for module in self.model.modules():
            if hasattr(module, "gradient_checkpointing"):
                module.gradient_checkpointing = True
                count += 1
        return count

    def clear_cache(self):
        if self._cuda_available():
            torch.cuda.empty_cache()

    def peak_memory(self):
        if not self.history:
            return 0
        return max(h.get("allocated", 0) for h in self.history)

    def reset_history(self):
        self.history = []; self._offloaded = []

    def get_config(self):
        return {"target_memory_fraction": self.target_memory_fraction,
                "offload_policy": self.offload_policy,
                "bytes_per_param": self.bytes_per_param}

    def diagnostics(self):
        return {"param_bytes": self.estimate_param_memory(),
                "steps_recorded": len(self.history),
                "num_offloaded": len(self._offloaded),
                "peak_memory": self.peak_memory()}


# ============================================================================
# 34. CurriculumLearner
# ----------------------------------------------------------------------------
# A plain training helper that orders / paces training examples by difficulty.
# It scores each example with a provided difficulty function (or a learned
# difficulty predictor module), produces a curriculum that grows from easy to
# hard over training (competence-based pacing à la Platanios et al.), and
# exposes a sampler that draws batches respecting the current competence
# threshold. Tracks per-bucket statistics and supports self-paced reweighting.
# ============================================================================
class CurriculumLearner:
    def __init__(self, model, difficulty_fn=None, difficulty_predictor=None,
                 pacing="root", total_steps=10000, initial_competence=0.1,
                 num_buckets=10):
        self.model = model
        self.difficulty_fn = difficulty_fn
        self.difficulty_predictor = difficulty_predictor
        self.pacing = pacing
        self.total_steps = total_steps
        self.initial_competence = initial_competence
        self.num_buckets = num_buckets
        self.step_count = 0
        self.difficulties = None
        self.sorted_indices = None

    def _difficulty(self, item):
        if self.difficulty_fn is not None:
            return float(self.difficulty_fn(item))
        if self.difficulty_predictor is not None:
            with torch.no_grad():
                return float(self.difficulty_predictor(item).mean())
        raise ValueError("need difficulty_fn or difficulty_predictor")

    def build_curriculum(self, dataset):
        # Compute and store normalized difficulties and the easy->hard order.
        diffs = [self._difficulty(item) for item in dataset]
        d = torch.tensor(diffs, dtype=torch.float32)
        if d.numel() > 1 and (d.max() - d.min()) > 1e-8:
            d = (d - d.min()) / (d.max() - d.min())
        self.difficulties = d
        self.sorted_indices = torch.argsort(d).tolist()
        return self.sorted_indices

    def competence(self, step=None):
        # Fraction of the (sorted) data that is currently "unlocked".
        step = self.step_count if step is None else step
        t = min(1.0, step / max(1, self.total_steps))
        c0 = self.initial_competence
        if self.pacing == "linear":
            c = c0 + (1 - c0) * t
        elif self.pacing == "root":
            c = math.sqrt(c0 ** 2 + (1 - c0 ** 2) * t)
        elif self.pacing == "geometric":
            c = 2 ** (math.log2(c0) * (1 - t))
        else:
            c = c0 + (1 - c0) * t
        return min(1.0, max(c0, c))

    def available_indices(self, step=None):
        # The subset of example indices unlocked at the current competence.
        if self.sorted_indices is None:
            raise RuntimeError("call build_curriculum first")
        c = self.competence(step)
        n = max(1, int(c * len(self.sorted_indices)))
        return self.sorted_indices[:n]

    def sample_batch(self, batch_size, step=None, generator=None):
        avail = self.available_indices(step)
        idx = torch.randint(0, len(avail), (batch_size,), generator=generator)
        return [avail[i] for i in idx.tolist()]

    def self_paced_weights(self, losses, threshold):
        # Self-paced learning: examples with loss below threshold get weight 1,
        # others are down-weighted (soft version).
        losses = losses.detach()
        return torch.sigmoid((threshold - losses) * 4.0)

    def bucket_stats(self):
        if self.difficulties is None:
            return {}
        edges = torch.linspace(0, 1, self.num_buckets + 1)
        counts = torch.histc(self.difficulties, bins=self.num_buckets, min=0, max=1)
        return {"bucket_counts": counts.tolist(),
                "mean_difficulty": self.difficulties.mean().item()}

    def step(self):
        self.step_count += 1
        return self.competence()

    def reset(self):
        self.step_count = 0

    def get_config(self):
        return {"pacing": self.pacing, "total_steps": self.total_steps,
                "initial_competence": self.initial_competence,
                "num_buckets": self.num_buckets}

    def diagnostics(self):
        return {"step_count": self.step_count, "competence": self.competence(),
                "num_examples": len(self.sorted_indices) if self.sorted_indices else 0}


# ============================================================================
# 35. HyperParameterTuner
# ----------------------------------------------------------------------------
# A plain online hyper-parameter controller. It adapts the learning rate and
# regularization weights during training based on observed metrics, using a
# combination of plateau detection (reduce-on-plateau), warmup, cosine decay,
# and a simple bandit over candidate weight-decay values. It writes the chosen
# values straight into the optimizer's parameter groups each step. Self-paced,
# stateful, and serializable.
# ============================================================================
class HyperParameterTuner:
    def __init__(self, model, base_lr=1e-3, weight_decay=0.01, q_l2_weight=0.0,
                 warmup_steps=1000, total_steps=100000, min_lr=1e-6,
                 plateau_patience=500, plateau_factor=0.5, wd_candidates=None):
        self.model = model
        self.base_lr = base_lr
        self.weight_decay = weight_decay
        self.q_l2_weight = q_l2_weight
        self.warmup_steps = warmup_steps
        self.total_steps = total_steps
        self.min_lr = min_lr
        self.plateau_patience = plateau_patience
        self.plateau_factor = plateau_factor
        self.wd_candidates = wd_candidates or [weight_decay]
        self.trial_counter = 0
        self.best_metric = float("inf")
        self.steps_since_improve = 0
        self.lr_scale = 1.0
        self._wd_rewards = {wd: 0.0 for wd in self.wd_candidates}
        self._wd_counts = {wd: 0 for wd in self.wd_candidates}
        self.current_wd = self.weight_decay
        self.history = []

    def _scheduled_lr(self):
        t = self.trial_counter
        if t < self.warmup_steps:
            lr = self.base_lr * (t + 1) / max(1, self.warmup_steps)
        else:
            progress = (t - self.warmup_steps) / max(1, self.total_steps - self.warmup_steps)
            progress = min(1.0, progress)
            lr = self.min_lr + 0.5 * (self.base_lr - self.min_lr) * (1 + math.cos(math.pi * progress))
        return lr * self.lr_scale

    def _select_wd(self):
        # epsilon-greedy bandit over weight-decay candidates
        eps = 0.1
        if torch.rand(1).item() < eps or all(c == 0 for c in self._wd_counts.values()):
            return self.wd_candidates[torch.randint(0, len(self.wd_candidates), (1,)).item()]
        avg = {wd: (self._wd_rewards[wd] / self._wd_counts[wd]) if self._wd_counts[wd] > 0 else 0.0
               for wd in self.wd_candidates}
        return max(avg, key=avg.get)

    def step(self, metric, optimizer):
        # Update LR/WD based on the latest validation/training metric (lower is
        # better) and write them into the optimizer.
        improved = metric < self.best_metric - 1e-6
        if improved:
            self.best_metric = metric
            self.steps_since_improve = 0
        else:
            self.steps_since_improve += 1
            if self.steps_since_improve >= self.plateau_patience:
                self.lr_scale *= self.plateau_factor
                self.steps_since_improve = 0

        # bandit reward = improvement (negative metric delta)
        reward = -metric
        self._wd_rewards[self.current_wd] += reward
        self._wd_counts[self.current_wd] += 1
        self.current_wd = self._select_wd()

        lr = max(self.min_lr, self._scheduled_lr())
        for group in optimizer.param_groups:
            group["lr"] = lr
            group["weight_decay"] = self.current_wd

        self.trial_counter += 1
        rec = {"step": self.trial_counter, "lr": lr, "wd": self.current_wd, "metric": metric}
        self.history.append(rec)
        return rec

    def current_lr(self):
        return max(self.min_lr, self._scheduled_lr())

    def best_wd(self):
        avg = {wd: (self._wd_rewards[wd] / self._wd_counts[wd]) if self._wd_counts[wd] > 0 else 0.0
               for wd in self.wd_candidates}
        return max(avg, key=avg.get)

    def state_dict(self):
        return {"trial_counter": self.trial_counter, "best_metric": self.best_metric,
                "lr_scale": self.lr_scale, "current_wd": self.current_wd,
                "wd_rewards": dict(self._wd_rewards), "wd_counts": dict(self._wd_counts)}

    def load_state_dict(self, state):
        self.trial_counter = state["trial_counter"]
        self.best_metric = state["best_metric"]
        self.lr_scale = state["lr_scale"]
        self.current_wd = state["current_wd"]
        self._wd_rewards = state["wd_rewards"]
        self._wd_counts = state["wd_counts"]

    def reset(self):
        self.trial_counter = 0; self.best_metric = float("inf")
        self.steps_since_improve = 0; self.lr_scale = 1.0; self.history = []

    def get_config(self):
        return {"base_lr": self.base_lr, "weight_decay": self.weight_decay,
                "warmup_steps": self.warmup_steps, "total_steps": self.total_steps,
                "wd_candidates": self.wd_candidates}

    def diagnostics(self):
        return {"trial_counter": self.trial_counter, "best_metric": self.best_metric,
                "lr_scale": self.lr_scale, "current_lr": self.current_lr(),
                "current_wd": self.current_wd}


# ============================================================================
# Internal helper: AdaGN (Adaptive Group Normalization)
# ----------------------------------------------------------------------------
# GroupNorm whose per-channel scale/shift are predicted from a conditioning
# embedding (style / timestep / class). This is the FiLM-on-GroupNorm primitive
# used throughout modern diffusion / StyleGAN-style image decoders. Kept here
# (not in the 48 count) because several vision blocks below depend on it.
# ============================================================================
class _AdaGN(ModuleUtilsMixin, nn.Module):
    def __init__(self, num_channels, emb_dim, num_groups=32, eps=1e-5):
        super().__init__()
        ng = math.gcd(num_groups, num_channels)
        ng = max(1, ng)
        self.norm = nn.GroupNorm(ng, num_channels, eps=eps, affine=False)
        self.to_scale_shift = Linear(emb_dim, num_channels * 2)
        # init to identity modulation
        nn.init.zeros_(self.to_scale_shift.weight)
        if self.to_scale_shift.bias is not None:
            nn.init.zeros_(self.to_scale_shift.bias)
        self.num_channels = num_channels

    def forward(self, x, emb):
        # x: (B, C, H, W); emb: (B, emb_dim)
        h = self.norm(x)
        ss = self.to_scale_shift(emb)                          # (B, 2C)
        scale, shift = ss.chunk(2, dim=-1)
        scale = scale.view(-1, self.num_channels, 1, 1)
        shift = shift.view(-1, self.num_channels, 1, 1)
        return h * (1 + scale) + shift

    # ------------------------------------------------------------------ #
    # Advanced engineering utilities (injected; namespaced to avoid clashes)
    # ------------------------------------------------------------------ #




























    # ------------------------------------------------------------------ #
    # Advanced architectural / runtime capabilities (injected; `ar_` namespace)
    # ------------------------------------------------------------------ #

















def _stochastic_depth_2d(x, p, training):
    # Per-sample drop of the residual branch (a.k.a. drop-path).
    if not training or p <= 0.0:
        return x
    keep = 1.0 - p
    mask = torch.empty(x.shape[0], 1, 1, 1, device=x.device, dtype=x.dtype).bernoulli_(keep)
    return x * mask / keep


# ============================================================================
# 36. ResidualBlock2d
# ----------------------------------------------------------------------------
# A conditioned 2-D residual block: two 3x3 convolutions each followed by
# adaptive group-norm (conditioned on an embedding), a squeeze-excitation
# channel-attention gate, optional blur-pool anti-aliased downsampling (a small
# built-in low-pass filter, so no external antialiased_cnns dependency), and
# stochastic-depth drop-path. The workhorse block of a conditioned image
# encoder/decoder.
# ============================================================================
class ResidualBlock2d(ModuleUtilsMixin, nn.Module):
    def __init__(self, in_ch, out_ch, emb_dim, stride=1, se_ratio=0.25,
                 stochastic_depth=0.0, use_aa=True, num_groups=32, act="gelu"):
        super().__init__()
        self.in_ch = in_ch
        self.out_ch = out_ch
        self.stride = stride
        self.stochastic_depth = stochastic_depth
        self.use_aa = use_aa and stride > 1

        self.conv1 = nn.Conv2d(in_ch, out_ch, 3, 1 if self.use_aa else stride, 1, bias=False)
        self.norm1 = _AdaGN(out_ch, emb_dim, num_groups)
        self.conv2 = nn.Conv2d(out_ch, out_ch, 3, 1, 1, bias=False)
        self.norm2 = _AdaGN(out_ch, emb_dim, num_groups)
        self.act = nn.GELU() if act == "gelu" else nn.SiLU()

        if in_ch != out_ch or stride != 1:
            self.skip = nn.Conv2d(in_ch, out_ch, 1, stride, bias=False)
        else:
            self.skip = nn.Identity()

        # squeeze-and-excitation
        if se_ratio > 0:
            hidden = max(1, int(out_ch * se_ratio))
            self.se = nn.Sequential(
                nn.AdaptiveAvgPool2d(1),
                nn.Conv2d(out_ch, hidden, 1), nn.ReLU(inplace=True),
                nn.Conv2d(hidden, out_ch, 1), nn.Sigmoid())
        else:
            self.se = None

        # built-in blur-pool low-pass kernel for anti-aliased stride-2 downsample
        if self.use_aa:
            k = torch.tensor([1., 3., 3., 1.])
            k = (k[:, None] * k[None, :])
            k = k / k.sum()
            self.register_buffer("blur_kernel", k.view(1, 1, 4, 4))

    def _blur_pool(self, x):
        B, C, H, W = x.shape
        w = self.blur_kernel.expand(C, 1, 4, 4)
        x = F.pad(x, (1, 2, 1, 2), mode="reflect")
        return F.conv2d(x, w, stride=2, groups=C)

    def forward(self, x, emb):
        h = self.act(self.norm1(self.conv1(x), emb))
        if self.use_aa:
            h = self._blur_pool(h)
        h = self.norm2(self.conv2(h), emb)
        if self.se is not None:
            h = h * self.se(h)
        h = _stochastic_depth_2d(h, self.stochastic_depth, self.training)
        return self.act(h + self.skip(x))

    def get_config(self):
        return {"in_ch": self.in_ch, "out_ch": self.out_ch, "stride": self.stride,
                "stochastic_depth": self.stochastic_depth, "use_aa": self.use_aa}

    def count_parameters(self):
        return sum(p.numel() for p in self.parameters())

    def parameter_breakdown(self):
        return {n: p.numel() for n, p in self.named_parameters()}

    def parameter_groups(self, base_lr=1e-3):
        return [{"params": list(self.parameters()), "lr": base_lr}]

    def regularization_loss(self):
        return next(self.parameters()).new_zeros(())

    def extra_repr(self):
        return f"in_ch={self.in_ch}, out_ch={self.out_ch}, stride={self.stride}, aa={self.use_aa}"

    def diagnostics(self):
        return {"num_params": self.count_parameters(), "has_se": self.se is not None}

    # ------------------------------------------------------------------ #
    # Advanced engineering utilities (injected; namespaced to avoid clashes)
    # ------------------------------------------------------------------ #




























    # ------------------------------------------------------------------ #
    # Advanced architectural / runtime capabilities (injected; `ar_` namespace)
    # ------------------------------------------------------------------ #














class CrossAttentionBlock(ModuleUtilsMixin, nn.Module):
    def __init__(self, dim, context_dim=None, num_heads=8, ffn_mult=4,
                 gated=True, dropout=0.0, eps=1e-6):
        super().__init__()
        self.dim = dim
        self.context_dim = context_dim or dim
        self.num_heads = num_heads
        self.head_dim = dim // num_heads
        self.gated = gated
        self.eps = eps
        assert dim % num_heads == 0

        self.q_proj = Linear(dim, dim, bias=False)
        self.k_proj = Linear(self.context_dim, dim, bias=False)
        self.v_proj = Linear(self.context_dim, dim, bias=False)
        self.o_proj = Linear(dim, dim, bias=True)
        self.norm1 = RMSNorm(dim)
        self.norm2 = RMSNorm(dim)
        self.ffn = nn.Sequential(Linear(dim, dim * ffn_mult), nn.GELU(),
                                 Linear(dim * ffn_mult, dim))
        if gated:
            self.gate = Linear(dim, dim, bias=True)
        self.dropout = nn.Dropout(dropout) if dropout > 0 else nn.Identity()

    def forward(self, x, context, key_padding_mask=None, return_attn=False):
        B, S, D = x.shape
        Sc = context.size(1)
        q = self.q_proj(x).view(B, S, self.num_heads, self.head_dim).transpose(1, 2)
        k = self.k_proj(context).view(B, Sc, self.num_heads, self.head_dim).transpose(1, 2)
        v = self.v_proj(context).view(B, Sc, self.num_heads, self.head_dim).transpose(1, 2)
        scores = torch.einsum("bhid,bhjd->bhij", q, k) / math.sqrt(self.head_dim)
        if key_padding_mask is not None:
            # key_padding_mask: (B, Sc) with True at padded positions
            scores = scores.masked_fill(key_padding_mask.view(B, 1, 1, Sc), float("-inf"))
        attn = F.softmax(scores, dim=-1)
        attn = self.dropout(attn)
        out = torch.einsum("bhij,bhjd->bhid", attn, v).transpose(1, 2).reshape(B, S, D)
        out = self.o_proj(out)
        if self.gated:
            out = out * torch.sigmoid(self.gate(x))
        x = self.norm1(x + self.dropout(out))
        x = self.norm2(x + self.dropout(self.ffn(x)))
        if return_attn:
            return x, attn
        return x

    def regularization_loss(self, l2_weight=1e-5):
        return l2_weight * sum(p.pow(2).mean() for p in self.ffn.parameters())

    def get_config(self):
        return {"dim": self.dim, "context_dim": self.context_dim,
                "num_heads": self.num_heads, "gated": self.gated}

    def count_parameters(self):
        return sum(p.numel() for p in self.parameters())

    def parameter_breakdown(self):
        return {n: p.numel() for n, p in self.named_parameters()}

    def parameter_groups(self, base_lr=1e-3):
        return [{"params": list(self.parameters()), "lr": base_lr}]

    def extra_repr(self):
        return (f"dim={self.dim}, context_dim={self.context_dim}, "
                f"num_heads={self.num_heads}, gated={self.gated}")

    def diagnostics(self):
        return {"num_params": self.count_parameters()}

    # ------------------------------------------------------------------ #
    # Advanced engineering utilities (injected; namespaced to avoid clashes)
    # ------------------------------------------------------------------ #




























    # ------------------------------------------------------------------ #
    # Advanced architectural / runtime capabilities (injected; `ar_` namespace)
    # ------------------------------------------------------------------ #

















# ============================================================================
# 28. RationaleDecoder
# ----------------------------------------------------------------------------
# An autoregressive decoder that generates a short natural-language-style
# rationale (token sequence) conditioned on a memory/representation. Uses a
# stack of Transformer-style decoder layers (self-attention + cross-attention
# to the memory), a length predictor for adaptive rationale length, and both a
# teacher-forced training path (parallel, with a causal mask) and an
# incremental greedy/sampling generation path. Self-contained decoder layers.
# ============================================================================
class _DecoderLayer(ModuleUtilsMixin, nn.Module):
    def __init__(self, dim, num_heads, ffn_mult=4, dropout=0.0, eps=1e-6):
        super().__init__()
        self.num_heads = num_heads
        self.head_dim = dim // num_heads
        self.dim = dim
        self.sq = Linear(dim, dim, bias=False); self.sk = Linear(dim, dim, bias=False)
        self.sv = Linear(dim, dim, bias=False); self.so = Linear(dim, dim, bias=True)
        self.cq = Linear(dim, dim, bias=False); self.ck = Linear(dim, dim, bias=False)
        self.cv = Linear(dim, dim, bias=False); self.co = Linear(dim, dim, bias=True)
        self.n1 = RMSNorm(dim); self.n2 = RMSNorm(dim); self.n3 = RMSNorm(dim)
        self.ffn = nn.Sequential(Linear(dim, dim * ffn_mult), nn.GELU(), Linear(dim * ffn_mult, dim))
        self.dropout = nn.Dropout(dropout) if dropout > 0 else nn.Identity()

    def _mha(self, q, k, v, qp, kp, vp, op, causal=False):
        B, Sq, D = q.shape
        Sk = k.size(1)
        Q = qp(q).view(B, Sq, self.num_heads, self.head_dim).transpose(1, 2)
        K = kp(k).view(B, Sk, self.num_heads, self.head_dim).transpose(1, 2)
        V = vp(v).view(B, Sk, self.num_heads, self.head_dim).transpose(1, 2)
        scores = torch.einsum("bhid,bhjd->bhij", Q, K) / math.sqrt(self.head_dim)
        if causal:
            mask = torch.triu(torch.ones(Sq, Sk, device=q.device), diagonal=1).bool()
            scores = scores.masked_fill(mask, float("-inf"))
        attn = F.softmax(scores, dim=-1)
        out = torch.einsum("bhij,bhjd->bhid", attn, V).transpose(1, 2).reshape(B, Sq, D)
        return op(out)

    def forward(self, x, memory):
        x = self.n1(x + self.dropout(self._mha(x, x, x, self.sq, self.sk, self.sv, self.so, causal=True)))
        x = self.n2(x + self.dropout(self._mha(x, memory, memory, self.cq, self.ck, self.cv, self.co)))
        x = self.n3(x + self.dropout(self.ffn(x)))
        return x

    # ------------------------------------------------------------------ #
    # Advanced engineering utilities (injected; namespaced to avoid clashes)
    # ------------------------------------------------------------------ #




























    # ------------------------------------------------------------------ #
    # Advanced architectural / runtime capabilities (injected; `ar_` namespace)
    # ------------------------------------------------------------------ #

















class RationaleDecoder(ModuleUtilsMixin, nn.Module):
    def __init__(self, dim, vocab_size, max_len=32, num_layers=4, num_heads=8,
                 dropout=0.0, eps=1e-6):
        super().__init__()
        self.dim = dim
        self.vocab_size = vocab_size
        self.max_len = max_len
        self.eps = eps
        self.start_token = nn.Parameter(torch.randn(1, 1, dim) * 0.02)
        self.embed = nn.Embedding(vocab_size, dim)
        self.pos_embed = nn.Parameter(torch.randn(1, max_len + 1, dim) * 0.02)
        self.layers = nn.ModuleList([
            _DecoderLayer(dim, num_heads, dropout=dropout) for _ in range(num_layers)])
        self.out_norm = RMSNorm(dim)
        self.out_proj = Linear(dim, vocab_size, bias=True)
        self.length_predictor = nn.Sequential(Linear(dim, dim // 2), nn.GELU(),
                                              Linear(dim // 2, 1), nn.Sigmoid())

    def _decode(self, tgt, memory):
        h = tgt + self.pos_embed[:, :tgt.size(1)]
        for layer in self.layers:
            h = layer(h, memory)
        return self.out_norm(h)

    def forward(self, memory, target_tokens=None):
        # Training path: if target_tokens given, teacher-force in parallel.
        B = memory.size(0)
        if target_tokens is not None:
            start = self.start_token.expand(B, 1, -1)
            tok_emb = self.embed(target_tokens)
            tgt = torch.cat([start, tok_emb], dim=1)[:, :self.max_len]
            h = self._decode(tgt, memory)
            return self.out_proj(h)
        # Inference path: incremental greedy generation.
        tgt = self.start_token.expand(B, 1, -1)
        logits_all = []
        for _ in range(self.max_len):
            h = self._decode(tgt, memory)
            logits = self.out_proj(h[:, -1:, :])
            logits_all.append(logits)
            token = logits.argmax(-1)
            tgt = torch.cat([tgt, self.embed(token)], dim=1)
        return torch.cat(logits_all, dim=1)

    @torch.no_grad()
    def generate(self, memory, temperature=1.0, top_k=0, greedy=True):
        B = memory.size(0)
        tgt = self.start_token.expand(B, 1, -1)
        tokens = []
        pred_len = int(self.max_len * self.length_predictor(memory.mean(1)).mean().item())
        pred_len = max(1, min(self.max_len, pred_len))
        for _ in range(pred_len):
            h = self._decode(tgt, memory)
            logits = self.out_proj(h[:, -1, :]) / max(temperature, 1e-4)
            if top_k > 0:
                v, _ = logits.topk(top_k, dim=-1)
                logits = logits.masked_fill(logits < v[:, -1:], float("-inf"))
            if greedy:
                token = logits.argmax(-1, keepdim=True)
            else:
                token = torch.multinomial(F.softmax(logits, dim=-1), 1)
            tokens.append(token)
            tgt = torch.cat([tgt, self.embed(token)], dim=1)
        return torch.cat(tokens, dim=1)

    def predicted_length(self, memory):
        return self.length_predictor(memory.mean(1)).squeeze(-1)

    def regularization_loss(self, l2_weight=1e-5):
        return l2_weight * self.out_proj.weight.pow(2).mean()

    def get_config(self):
        return {"dim": self.dim, "vocab_size": self.vocab_size, "max_len": self.max_len}

    def count_parameters(self):
        return sum(p.numel() for p in self.parameters())

    def parameter_breakdown(self):
        return {n: p.numel() for n, p in self.named_parameters()}

    def parameter_groups(self, base_lr=1e-3):
        return [{"params": list(self.parameters()), "lr": base_lr}]

    def extra_repr(self):
        return f"dim={self.dim}, vocab_size={self.vocab_size}, max_len={self.max_len}"

    def diagnostics(self):
        return {"num_params": self.count_parameters()}

    # ------------------------------------------------------------------ #
    # Advanced engineering utilities (injected; namespaced to avoid clashes)
    # ------------------------------------------------------------------ #




























    # ------------------------------------------------------------------ #
    # Advanced architectural / runtime capabilities (injected; `ar_` namespace)
    # ------------------------------------------------------------------ #

















# ============================================================================
# 29. SparseAttentionBlock2d
# ----------------------------------------------------------------------------
# Spatial self-attention over a 2-D feature map with top-k sparsification:
# each spatial location attends only to its top-k most similar locations
# (sparse global attention), which keeps the effective attention O(N·k) in
# selectivity while staying full-resolution. Uses 1x1 convs for q/k/v/proj,
# multi-head attention, a learned residual scale, and an optional relative
# bias. Returns the input plus the attended update (residual). Self-contained.
# ============================================================================
class SparseAttentionBlock2d(ModuleUtilsMixin, nn.Module):
    def __init__(self, dim, topk=64, num_heads=8, residual_scale=True,
                 use_rel_bias=False, max_hw=32, dropout=0.0, eps=1e-6):
        super().__init__()
        self.dim = dim
        self.num_heads = num_heads
        self.head_dim = dim // num_heads
        self.topk = topk
        self.scale = self.head_dim ** -0.5
        self.use_rel_bias = use_rel_bias
        self.eps = eps
        assert dim % num_heads == 0

        self.qkv = nn.Conv2d(dim, dim * 3, 1)
        self.proj = nn.Conv2d(dim, dim, 1)
        self.norm = nn.GroupNorm(min(8, dim), dim)
        self.dropout = nn.Dropout(dropout) if dropout > 0 else nn.Identity()
        if residual_scale:
            self.gamma = nn.Parameter(torch.zeros(1))
        else:
            self.register_buffer("gamma", torch.ones(1))
        if use_rel_bias:
            self.rel_bias = nn.Parameter(torch.zeros(num_heads, max_hw * max_hw, 1))

    def forward(self, x, return_attn=False):
        B, C, H, W = x.shape
        N = H * W
        xn = self.norm(x)
        qkv = self.qkv(xn).reshape(B, 3, self.num_heads, self.head_dim, N)
        qkv = qkv.permute(1, 0, 2, 4, 3)                       # (3, B, heads, N, hd)
        q, k, v = qkv[0], qkv[1], qkv[2]                       # each (B, heads, N, hd)

        attn = (q @ k.transpose(-2, -1)) * self.scale         # (B, heads, N, N)
        if self.use_rel_bias and N <= self.rel_bias.size(1):
            attn = attn + self.rel_bias[:, :N, :].transpose(-1, -2).unsqueeze(0)

        topk = min(self.topk, N)
        if topk < N:
            topk_vals, topk_idx = attn.topk(topk, dim=-1)
            sparse = torch.full_like(attn, float("-inf"))
            sparse.scatter_(-1, topk_idx, topk_vals)
            attn = sparse
        attn = attn.softmax(dim=-1)
        attn = self.dropout(attn)

        out = attn @ v                                         # (B, heads, N, hd)
        out = out.transpose(-1, -2).reshape(B, C, H, W)        # back to map
        out = self.proj(out)
        result = x + self.gamma * out
        if return_attn:
            return result, attn
        return result

    def attention_sparsity(self, x):
        with torch.no_grad():
            B, C, H, W = x.shape
            N = H * W
            return min(self.topk, N) / N

    def regularization_loss(self, l2_weight=1e-5):
        return l2_weight * (self.proj.weight.pow(2).mean())

    def get_config(self):
        return {"dim": self.dim, "topk": self.topk, "num_heads": self.num_heads,
                "use_rel_bias": self.use_rel_bias}

    def count_parameters(self):
        return sum(p.numel() for p in self.parameters())

    def parameter_breakdown(self):
        return {n: p.numel() for n, p in self.named_parameters()}

    def parameter_groups(self, base_lr=1e-3):
        return [{"params": list(self.parameters()), "lr": base_lr}]

    def extra_repr(self):
        return f"dim={self.dim}, topk={self.topk}, num_heads={self.num_heads}"

    def diagnostics(self):
        return {"num_params": self.count_parameters(), "gamma": float(self.gamma.mean().item())}

    # ------------------------------------------------------------------ #
    # Advanced engineering utilities (injected; namespaced to avoid clashes)
    # ------------------------------------------------------------------ #




























    # ------------------------------------------------------------------ #
    # Advanced architectural / runtime capabilities (injected; `ar_` namespace)
    # ------------------------------------------------------------------ #






























class StyledResBlock(ModuleUtilsMixin, nn.Module):
    def __init__(self, in_ch, out_ch, style_dim, stride=1, noise=True,
                 num_groups=32, act="silu"):
        super().__init__()
        self.in_ch = in_ch
        self.out_ch = out_ch
        self.stride = stride
        self.noise = noise
        self.conv1 = nn.Conv2d(in_ch, out_ch, 3, stride, 1, bias=False)
        self.norm1 = _AdaGN(out_ch, style_dim, num_groups)
        self.conv2 = nn.Conv2d(out_ch, out_ch, 3, 1, 1, bias=False)
        self.norm2 = _AdaGN(out_ch, style_dim, num_groups)
        if in_ch != out_ch or stride != 1:
            self.skip = nn.Conv2d(in_ch, out_ch, 1, stride, bias=False)
        else:
            self.skip = nn.Identity()
        self.act = nn.SiLU() if act == "silu" else nn.GELU()
        if noise:
            self.noise_scale1 = nn.Parameter(torch.zeros(1, out_ch, 1, 1))
            self.noise_scale2 = nn.Parameter(torch.zeros(1, out_ch, 1, 1))

    def _inject_noise(self, h, scale, external_noise=None):
        if not self.noise:
            return h
        if external_noise is None:
            external_noise = torch.randn(h.size(0), 1, h.size(2), h.size(3),
                                         device=h.device, dtype=h.dtype)
        return h + scale * external_noise

    def forward(self, x, style, noise1=None, noise2=None):
        h = self.norm1(self.conv1(x), style)
        h = self._inject_noise(h, self.noise_scale1 if self.noise else None, noise1)
        h = self.act(h)
        h = self.norm2(self.conv2(h), style)
        h = self._inject_noise(h, self.noise_scale2 if self.noise else None, noise2)
        return self.act(h + self.skip(x))

    def get_config(self):
        return {"in_ch": self.in_ch, "out_ch": self.out_ch, "stride": self.stride,
                "noise": self.noise}

    def count_parameters(self):
        return sum(p.numel() for p in self.parameters())

    def parameter_breakdown(self):
        return {n: p.numel() for n, p in self.named_parameters()}

    def parameter_groups(self, base_lr=1e-3):
        return [{"params": list(self.parameters()), "lr": base_lr}]

    def regularization_loss(self):
        return next(self.parameters()).new_zeros(())

    def extra_repr(self):
        return f"in_ch={self.in_ch}, out_ch={self.out_ch}, stride={self.stride}, noise={self.noise}"

    def diagnostics(self):
        d = {"num_params": self.count_parameters()}
        if self.noise:
            d["noise_scale1"] = self.noise_scale1.abs().mean().item()
        return d

    # ------------------------------------------------------------------ #
    # Advanced engineering utilities (injected; namespaced to avoid clashes)
    # ------------------------------------------------------------------ #




























    # ------------------------------------------------------------------ #
    # Advanced architectural / runtime capabilities (injected; `ar_` namespace)
    # ------------------------------------------------------------------ #

















# ============================================================================
# 38. StyledUpsampleBlock
# ----------------------------------------------------------------------------
# Upsamples a feature map by 2x and refines it with a styled residual block.
# Two upsampling paths are supported: bilinear-upsample + conv, or a
# pixel-shuffle (sub-pixel convolution) path that learns the upsampling filters
# and avoids checkerboard artifacts. Style-conditioned throughout.
# ============================================================================
class StyledUpsampleBlock(ModuleUtilsMixin, nn.Module):
    def __init__(self, in_ch, out_ch, style_dim, use_pixel_shuffle=False,
                 hidden_ch=None, num_groups=32):
        super().__init__()
        self.in_ch = in_ch
        self.out_ch = out_ch
        self.use_pixel_shuffle = use_pixel_shuffle
        hidden = hidden_ch or max(out_ch, 64)
        self.hidden = hidden

        if use_pixel_shuffle:
            self.pre_conv = nn.Conv2d(in_ch, hidden * 4, 3, padding=1, bias=False)
            self.pre_norm = _AdaGN(hidden * 4, style_dim, num_groups)
            self.shuffle = nn.PixelShuffle(2)
            self.act = nn.SiLU()
        else:
            self.up = nn.Upsample(scale_factor=2, mode="bilinear", align_corners=False)
            self.pre_conv = nn.Conv2d(in_ch, hidden, 3, padding=1, bias=False)
            self.pre_norm = _AdaGN(hidden, style_dim, num_groups)
            self.act = nn.SiLU()
        self.res_block = StyledResBlock(hidden, out_ch, style_dim, num_groups=num_groups)

    def forward(self, x, style):
        if self.use_pixel_shuffle:
            h = self.pre_norm(self.pre_conv(x), style)
            h = self.act(h)
            h = self.shuffle(h)                               # 2x spatial, /4 channels
        else:
            h = self.up(x)
            h = self.act(self.pre_norm(self.pre_conv(h), style))
        return self.res_block(h, style)

    def get_config(self):
        return {"in_ch": self.in_ch, "out_ch": self.out_ch,
                "use_pixel_shuffle": self.use_pixel_shuffle, "hidden": self.hidden}

    def count_parameters(self):
        return sum(p.numel() for p in self.parameters())

    def parameter_breakdown(self):
        return {n: p.numel() for n, p in self.named_parameters()}

    def parameter_groups(self, base_lr=1e-3):
        return [{"params": list(self.parameters()), "lr": base_lr}]

    def regularization_loss(self):
        return next(self.parameters()).new_zeros(())

    def extra_repr(self):
        return (f"in_ch={self.in_ch}, out_ch={self.out_ch}, "
                f"pixel_shuffle={self.use_pixel_shuffle}")

    def diagnostics(self):
        return {"num_params": self.count_parameters(),
                "upsample_mode": "pixel_shuffle" if self.use_pixel_shuffle else "bilinear"}

    # ------------------------------------------------------------------ #
    # Advanced engineering utilities (injected; namespaced to avoid clashes)
    # ------------------------------------------------------------------ #




























    # ------------------------------------------------------------------ #
    # Advanced architectural / runtime capabilities (injected; `ar_` namespace)
    # ------------------------------------------------------------------ #

















# ============================================================================
# 39. SuperResolutionStage
# ----------------------------------------------------------------------------
# One stage of a progressive super-resolution decoder: upsample 2x (styled),
# refine with a stack of styled residual blocks, apply 2-D sparse self-attention
# for long-range coherence, then a styled tail producing the output image
# channels in [0,1]. Composes the styled blocks and the SparseAttentionBlock2d
# defined earlier into a coherent SR module conditioned on a style vector.
# ============================================================================
class SuperResolutionStage(ModuleUtilsMixin, nn.Module):
    def __init__(self, in_ch, mid_ch, out_ch, style_dim, num_blocks=4,
                 use_attention=True, attn_topk=None, num_groups=32,
                 final_activation="sigmoid"):
        super().__init__()
        self.in_ch = in_ch
        self.mid_ch = mid_ch
        self.out_ch = out_ch
        self.num_blocks = num_blocks
        self.use_attention = use_attention

        self.upsample = StyledUpsampleBlock(in_ch, mid_ch, style_dim, num_groups=num_groups)
        self.blocks = nn.ModuleList([
            StyledResBlock(mid_ch, mid_ch, style_dim, num_groups=num_groups)
            for _ in range(num_blocks)])
        if use_attention:
            topk = attn_topk or max(1, mid_ch // 2)
            self.attn = SparseAttentionBlock2d(mid_ch, topk=topk,
                                               num_heads=max(1, mid_ch // 16))
        self.tail_block = StyledResBlock(mid_ch, out_ch, style_dim, num_groups=num_groups)
        self.tail_conv = nn.Conv2d(out_ch, out_ch, 3, padding=1)
        if final_activation == "sigmoid":
            self.final = nn.Sigmoid()
        elif final_activation == "tanh":
            self.final = nn.Tanh()
        else:
            self.final = nn.Identity()

    def forward(self, x, style):
        x = self.upsample(x, style)
        for blk in self.blocks:
            x = blk(x, style)
        if self.use_attention:
            x = self.attn(x)
        x = self.tail_block(x, style)
        x = self.tail_conv(x)
        return self.final(x)

    def get_config(self):
        return {"in_ch": self.in_ch, "mid_ch": self.mid_ch, "out_ch": self.out_ch,
                "num_blocks": self.num_blocks, "use_attention": self.use_attention}

    def count_parameters(self):
        return sum(p.numel() for p in self.parameters())

    def parameter_breakdown(self):
        return {n: p.numel() for n, p in self.named_parameters()}

    def parameter_groups(self, base_lr=1e-3):
        return [{"params": list(self.parameters()), "lr": base_lr}]

    def regularization_loss(self):
        return next(self.parameters()).new_zeros(())

    def extra_repr(self):
        return (f"in_ch={self.in_ch}, mid_ch={self.mid_ch}, out_ch={self.out_ch}, "
                f"num_blocks={self.num_blocks}, attn={self.use_attention}")

    def diagnostics(self):
        return {"num_params": self.count_parameters(), "num_blocks": self.num_blocks}

    # ------------------------------------------------------------------ #
    # Advanced engineering utilities (injected; namespaced to avoid clashes)
    # ------------------------------------------------------------------ #




























    # ------------------------------------------------------------------ #
    # Advanced architectural / runtime capabilities (injected; `ar_` namespace)
    # ------------------------------------------------------------------ #

















# ============================================================================
# Internal helper: a minimal pre-norm transformer encoder block
# ----------------------------------------------------------------------------
# Self-contained (no dependency on the host model's Block / decoder-args), used
# by StyleEncoder below. Standard MHSA + GELU-MLP with RMSNorm and residuals.
# ============================================================================
class _EncoderBlock(ModuleUtilsMixin, nn.Module):
    def __init__(self, dim, num_heads=8, mlp_mult=4, dropout=0.0):
        super().__init__()
        self.num_heads = num_heads
        self.head_dim = dim // num_heads
        self.dim = dim
        self.norm1 = RMSNorm(dim)
        self.norm2 = RMSNorm(dim)
        self.q = Linear(dim, dim, bias=False)
        self.k = Linear(dim, dim, bias=False)
        self.v = Linear(dim, dim, bias=False)
        self.o = Linear(dim, dim, bias=True)
        self.mlp = nn.Sequential(Linear(dim, dim * mlp_mult), nn.GELU(),
                                 Linear(dim * mlp_mult, dim))
        self.dropout = nn.Dropout(dropout) if dropout > 0 else nn.Identity()

    def forward(self, x, key_padding_mask=None):
        B, S, D = x.shape
        h = self.norm1(x)
        q = self.q(h).view(B, S, self.num_heads, self.head_dim).transpose(1, 2)
        k = self.k(h).view(B, S, self.num_heads, self.head_dim).transpose(1, 2)
        v = self.v(h).view(B, S, self.num_heads, self.head_dim).transpose(1, 2)
        scores = torch.einsum("bhid,bhjd->bhij", q, k) / math.sqrt(self.head_dim)
        if key_padding_mask is not None:
            scores = scores.masked_fill(key_padding_mask[:, None, None, :], float("-inf"))
        attn = F.softmax(scores, dim=-1)
        out = torch.einsum("bhij,bhjd->bhid", attn, v).transpose(1, 2).reshape(B, S, D)
        x = x + self.dropout(self.o(out))
        x = x + self.dropout(self.mlp(self.norm2(x)))
        return x

    # ------------------------------------------------------------------ #
    # Advanced engineering utilities (injected; namespaced to avoid clashes)
    # ------------------------------------------------------------------ #




























    # ------------------------------------------------------------------ #
    # Advanced architectural / runtime capabilities (injected; `ar_` namespace)
    # ------------------------------------------------------------------ #

















# ============================================================================
# 40. StyleEncoder
# ----------------------------------------------------------------------------
# Encodes a text / conditioning embedding sequence into a single style vector
# used to modulate styled image blocks. A small self-contained transformer
# processes the projected input; the sequence is pooled (mean + learned CLS) to
# a style vector. Optionally produces an L2-normalized, temperature-scaled
# embedding for contrastive (CLIP-style) training of the style space.
# ============================================================================
class StyleEncoder(ModuleUtilsMixin, nn.Module):
    def __init__(self, input_dim, style_dim=512, num_layers=4, num_heads=8,
                 contrastive=False, max_seq_len=256, dropout=0.0, eps=1e-6):
        super().__init__()
        self.input_dim = input_dim
        self.style_dim = style_dim
        self.contrastive = contrastive
        self.eps = eps

        self.proj_in = Linear(input_dim, style_dim)
        self.cls = nn.Parameter(torch.randn(1, 1, style_dim) * 0.02)
        self.pos = nn.Parameter(torch.randn(1, max_seq_len + 1, style_dim) * 0.02)
        self.blocks = nn.ModuleList([
            _EncoderBlock(style_dim, num_heads, dropout=dropout) for _ in range(num_layers)])
        self.norm = RMSNorm(style_dim)
        self.proj_out = Linear(style_dim, style_dim)
        if contrastive:
            self.temperature = nn.Parameter(torch.tensor(0.07))

    def forward(self, text_emb, key_padding_mask=None, return_contrastive=False):
        if text_emb.dim() == 2:
            text_emb = text_emb.unsqueeze(1)                  # (B, 1, input_dim)
        B, S, _ = text_emb.shape
        x = self.proj_in(text_emb)                            # (B, S, style_dim)
        cls = self.cls.expand(B, -1, -1)
        x = torch.cat([cls, x], dim=1)                        # prepend CLS
        x = x + self.pos[:, :S + 1]
        if key_padding_mask is not None:
            # pad mask covers the real tokens; CLS is never masked
            kpm = torch.cat([torch.zeros(B, 1, dtype=torch.bool, device=x.device),
                             key_padding_mask], dim=1)
        else:
            kpm = None
        for blk in self.blocks:
            x = blk(x, key_padding_mask=kpm)
        x = self.norm(x)
        # style = CLS token blended with mean pooling
        style = self.proj_out(x[:, 0] + x[:, 1:].mean(dim=1))
        if return_contrastive and self.contrastive:
            return F.normalize(style, dim=-1) * self.temperature.exp()
        return style

    def encode_contrastive(self, text_emb):
        s = self.forward(text_emb, return_contrastive=True)
        return s

    def get_config(self):
        return {"input_dim": self.input_dim, "style_dim": self.style_dim,
                "contrastive": self.contrastive, "num_blocks": len(self.blocks)}

    def count_parameters(self):
        return sum(p.numel() for p in self.parameters())

    def parameter_breakdown(self):
        return {n: p.numel() for n, p in self.named_parameters()}

    def parameter_groups(self, base_lr=1e-3):
        return [{"params": list(self.parameters()), "lr": base_lr}]

    def regularization_loss(self):
        return next(self.parameters()).new_zeros(())

    def extra_repr(self):
        return (f"input_dim={self.input_dim}, style_dim={self.style_dim}, "
                f"blocks={len(self.blocks)}, contrastive={self.contrastive}")

    def diagnostics(self):
        return {"num_params": self.count_parameters(), "style_dim": self.style_dim}

    # ------------------------------------------------------------------ #
    # Advanced engineering utilities (injected; namespaced to avoid clashes)
    # ------------------------------------------------------------------ #




























    # ------------------------------------------------------------------ #
    # Advanced architectural / runtime capabilities (injected; `ar_` namespace)
    # ------------------------------------------------------------------ #

















# ============================================================================
# 41. SinglePanelGenerator
# ----------------------------------------------------------------------------
# A self-contained styled image generator: maps a latent vector + style vector
# (optionally cross-attended with character/condition embeddings and a text
# prompt) into an image panel. It projects the conditioning into a small
# spatial feature map and progressively upsamples it with styled blocks to the
# target resolution. Replaces the host-model UltraImageDecoder dependency with
# a fully self-contained synthesis stack.
# ============================================================================
class SinglePanelGenerator(ModuleUtilsMixin, nn.Module):
    def __init__(self, latent_dim, style_dim=512, out_channels=3, base_channels=256,
                 base_res=4, target_res=64, text_ctx_dim=None, use_char_attn=True,
                 num_heads=4, num_groups=32):
        super().__init__()
        self.latent_dim = latent_dim
        self.style_dim = style_dim
        self.out_channels = out_channels
        self.base_channels = base_channels
        self.base_res = base_res
        self.target_res = target_res
        self.use_char_attn = use_char_attn

        # number of 2x upsampling stages to reach target resolution
        num_up = max(0, int(round(math.log2(target_res / base_res))))
        self.num_up = num_up

        # project latent+style into the initial spatial feature map
        self.to_spatial = Linear(latent_dim, base_channels * base_res * base_res)
        self.style_map = nn.Sequential(Linear(style_dim, style_dim), nn.SiLU(),
                                       Linear(style_dim, style_dim))

        # character / condition cross-attention on the conditioning vector
        if use_char_attn:
            self.char_q = Linear(style_dim, style_dim, bias=False)
            self.char_k = Linear(style_dim, style_dim, bias=False)
            self.char_v = Linear(style_dim, style_dim, bias=False)
            self.char_o = Linear(style_dim, style_dim, bias=True)
            self.char_norm = RMSNorm(style_dim)
            self.num_heads = num_heads

        # optional text-prompt projection added to the style
        if text_ctx_dim is not None:
            self.text_proj = Linear(text_ctx_dim, style_dim)
        self.text_ctx_dim = text_ctx_dim

        # styled upsampling trunk
        ch = base_channels
        ups = []
        for i in range(num_up):
            out_ch = max(base_channels // (2 ** (i + 1)), 32)
            ups.append(StyledUpsampleBlock(ch, out_ch, style_dim, num_groups=num_groups))
            ch = out_ch
        self.ups = nn.ModuleList(ups)
        self.final_ch = ch
        self.to_rgb = nn.Sequential(
            nn.Conv2d(ch, out_channels, 3, padding=1), nn.Sigmoid())

    def _char_attend(self, cond, char_emb):
        # cond: (B, style_dim); char_emb: (B, T, style_dim)
        B = cond.size(0)
        H = self.num_heads
        hd = self.style_dim // H
        q = self.char_q(cond).view(B, 1, H, hd).transpose(1, 2)
        k = self.char_k(char_emb).view(B, -1, H, hd).transpose(1, 2)
        v = self.char_v(char_emb).view(B, -1, H, hd).transpose(1, 2)
        scores = torch.einsum("bhid,bhjd->bhij", q, k) / math.sqrt(hd)
        attn = F.softmax(scores, dim=-1)
        out = torch.einsum("bhij,bhjd->bhid", attn, v).transpose(1, 2).reshape(B, self.style_dim)
        return self.char_norm(cond + self.char_o(out))

    def forward(self, latent, style_emb, char_emb=None, text_prompt=None):
        B = latent.size(0)
        style = self.style_map(style_emb)
        if self.text_ctx_dim is not None and text_prompt is not None:
            if text_prompt.dim() == 3:
                text_prompt = text_prompt.mean(dim=1)
            style = style + self.text_proj(text_prompt)
        if self.use_char_attn and char_emb is not None:
            if char_emb.dim() == 2:
                char_emb = char_emb.unsqueeze(1)
            style = self._char_attend(style, char_emb)

        x = self.to_spatial(latent).view(B, self.base_channels, self.base_res, self.base_res)
        for up in self.ups:
            x = up(x, style)
        return self.to_rgb(x)

    def generate(self, latent, style_emb, **kwargs):
        was_training = self.training
        self.eval()
        try:
            with torch.no_grad():
                return self.forward(latent, style_emb, **kwargs)
        finally:
            self.train(was_training)

    def get_config(self):
        return {"latent_dim": self.latent_dim, "style_dim": self.style_dim,
                "out_channels": self.out_channels, "base_channels": self.base_channels,
                "base_res": self.base_res, "target_res": self.target_res,
                "num_up": self.num_up}

    def count_parameters(self):
        return sum(p.numel() for p in self.parameters())

    def parameter_breakdown(self):
        return {n: p.numel() for n, p in self.named_parameters()}

    def parameter_groups(self, base_lr=1e-3):
        return [{"params": list(self.parameters()), "lr": base_lr}]

    def regularization_loss(self):
        return next(self.parameters()).new_zeros(())

    def extra_repr(self):
        return (f"latent_dim={self.latent_dim}, style_dim={self.style_dim}, "
                f"target_res={self.target_res}, num_up={self.num_up}")

    def diagnostics(self):
        return {"num_params": self.count_parameters(), "num_upsample_stages": self.num_up,
                "final_channels": self.final_ch}

