# ============================================================================
# 42. PageComposer
# ----------------------------------------------------------------------------
# Composes multiple generated panels onto a single canvas at given layout
# coordinates, with a learned edge-blend at panel boundaries and optional
# learned alpha-blending where panels overlap existing content, then optionally
# runs styled super-resolution stages to refine the full page. Designed for
# comic / multi-panel page synthesis. Fully self-contained.
# ============================================================================
class PageComposer(ModuleUtilsMixin, nn.Module):
    def __init__(self, canvas_size=256, out_channels=3, style_dim=512,
                 sr_stages=(), use_smart_blend=True, num_groups=32):
        super().__init__()
        self.canvas_size = canvas_size
        self.out_channels = out_channels
        self.use_smart_blend = use_smart_blend

        self.edge_blend = nn.Conv2d(out_channels, out_channels, 3, padding=1, bias=False)
        nn.init.dirac_(self.edge_blend.weight)                # init to identity passthrough

        if use_smart_blend:
            self.blend_net = nn.Sequential(
                nn.Conv2d(out_channels * 2, 32, 3, padding=1), nn.ReLU(inplace=True),
                nn.Conv2d(32, out_channels, 3, padding=1), nn.Sigmoid())

        self.sr_stages = nn.ModuleList([
            SuperResolutionStage(out_channels, 64, out_channels, style_dim,
                                 num_blocks=2, num_groups=num_groups)
            for _ in sr_stages])

    def compose(self, panels, layout_coords):
        # panels: list of (B, C, ph, pw) tensors; layout_coords: (B, num_panels, 4)
        # with normalized (x1, y1, x2, y2) in [0,1].
        B = panels[0].size(0)
        C = self.out_channels
        S = self.canvas_size
        canvas = torch.ones(B, C, S, S, device=panels[0].device, dtype=panels[0].dtype)
        for i, panel in enumerate(panels):
            coords = layout_coords[:, i, :]
            for b in range(B):
                x1 = int(coords[b, 0].item() * S); y1 = int(coords[b, 1].item() * S)
                x2 = int(coords[b, 2].item() * S); y2 = int(coords[b, 3].item() * S)
                x1 = max(0, min(x1, S - 1)); y1 = max(0, min(y1, S - 1))
                x2 = max(x1 + 1, min(x2, S)); y2 = max(y1 + 1, min(y2, S))
                w, h = x2 - x1, y2 - y1
                resized = F.interpolate(panel[b:b + 1], size=(h, w),
                                        mode="bilinear", align_corners=False)
                if self.use_smart_blend:
                    region = canvas[b:b + 1, :, y1:y2, x1:x2]
                    mask = self.blend_net(torch.cat([region, resized], dim=1))
                    resized = resized * mask + region * (1 - mask)
                canvas = canvas.clone()
                canvas[b:b + 1, :, y1:y2, x1:x2] = resized
        return canvas

    def forward(self, panels, layout_coords, style_emb=None):
        canvas = self.compose(panels, layout_coords)
        canvas = self.edge_blend(canvas)
        for sr in self.sr_stages:
            canvas = sr(canvas, style_emb)
        return canvas

    def get_config(self):
        return {"canvas_size": self.canvas_size, "out_channels": self.out_channels,
                "use_smart_blend": self.use_smart_blend, "num_sr_stages": len(self.sr_stages)}

    def count_parameters(self):
        return sum(p.numel() for p in self.parameters())

    def parameter_breakdown(self):
        return {n: p.numel() for n, p in self.named_parameters()}

    def parameter_groups(self, base_lr=1e-3):
        return [{"params": list(self.parameters()), "lr": base_lr}]

    def regularization_loss(self):
        return next(self.parameters()).new_zeros(())

    def extra_repr(self):
        return (f"canvas_size={self.canvas_size}, smart_blend={self.use_smart_blend}, "
                f"sr_stages={len(self.sr_stages)}")

    def diagnostics(self):
        return {"num_params": self.count_parameters(), "num_sr_stages": len(self.sr_stages)}

    # ------------------------------------------------------------------ #
    # Advanced engineering utilities (injected; namespaced to avoid clashes)
    # ------------------------------------------------------------------ #




























    # ------------------------------------------------------------------ #
    # Advanced architectural / runtime capabilities (injected; `ar_` namespace)
    # ------------------------------------------------------------------ #

















# ============================================================================
# Internal helper: a self-contained pre-norm transformer Block
# ----------------------------------------------------------------------------
# Standard decoder-style block (causal self-attention + SwiGLU FFN with RMSNorm
# residuals). Stands in for the host model's `Block` so MTPBlock below is fully
# self-contained. Operates on (B, S, D); supports an optional additive task
# embedding and a causal mask. Not counted among the 48.
# ============================================================================
class _Block(ModuleUtilsMixin, nn.Module):
    def __init__(self, dim, num_heads=8, ffn_mult=4, causal=True, dropout=0.0, eps=1e-6):
        super().__init__()
        self.dim = dim
        self.num_heads = num_heads
        self.head_dim = dim // num_heads
        self.causal = causal
        self.attn_norm = RMSNorm(dim, eps)
        self.ffn_norm = RMSNorm(dim, eps)
        self.q = Linear(dim, dim, bias=False)
        self.k = Linear(dim, dim, bias=False)
        self.v = Linear(dim, dim, bias=False)
        self.o = Linear(dim, dim, bias=True)
        hidden = int(ffn_mult * dim)
        self.w1 = Linear(dim, hidden, bias=False)
        self.w3 = Linear(dim, hidden, bias=False)
        self.w2 = Linear(hidden, dim, bias=False)
        self.dropout = nn.Dropout(dropout) if dropout > 0 else nn.Identity()

    def _attn(self, x):
        B, S, D = x.shape
        h = self.attn_norm(x)
        q = self.q(h).view(B, S, self.num_heads, self.head_dim).transpose(1, 2)
        k = self.k(h).view(B, S, self.num_heads, self.head_dim).transpose(1, 2)
        v = self.v(h).view(B, S, self.num_heads, self.head_dim).transpose(1, 2)
        scores = torch.einsum("bhid,bhjd->bhij", q, k) / math.sqrt(self.head_dim)
        if self.causal:
            mask = torch.triu(torch.ones(S, S, device=x.device, dtype=torch.bool), diagonal=1)
            scores = scores.masked_fill(mask, float("-inf"))
        attn = F.softmax(scores, dim=-1)
        out = torch.einsum("bhij,bhjd->bhid", attn, v).transpose(1, 2).reshape(B, S, D)
        return self.o(out)

    def forward(self, x, task_emb=None):
        if task_emb is not None:
            if task_emb.dim() == 2:
                task_emb = task_emb.unsqueeze(1)
            x = x + task_emb
        x = x + self.dropout(self._attn(x))
        h = self.ffn_norm(x)
        x = x + self.dropout(self.w2(F.silu(self.w1(h)) * self.w3(h)))
        return x

    # ------------------------------------------------------------------ #
    # Advanced engineering utilities (injected; namespaced to avoid clashes)
    # ------------------------------------------------------------------ #




























    # ------------------------------------------------------------------ #
    # Advanced architectural / runtime capabilities (injected; `ar_` namespace)
    # ------------------------------------------------------------------ #

















# ============================================================================
# 43. MTPBlock
# ----------------------------------------------------------------------------
# Multi-Token Prediction block (à la DeepSeek-V3): instead of predicting only
# the next token, it predicts several future tokens in parallel. It fuses the
# token embedding of the current position with the running hidden state through
# a learned gate, refines the fused representation, expands it into `n_predict`
# parallel prediction streams, runs them through a transformer block, and emits
# logits for each future offset. Includes a dynamic-depth gate that adapts how
# much it leans on the embedding vs. the hidden state, plus an optional
# auxiliary head. Fully self-contained (own embedding/head, no host model).
# ============================================================================
class MTPBlock(_Block):
    @classmethod
    def from_args(cls, layer_id, args, **overrides):
        """
        Build a multi-token-prediction block from the core :class:`ModelArgs`.

        Bugfix: ``Transformer`` constructed these as ``mtp_class(layer_id, args)``,
        assuming the same ``(layer_id, args)`` contract used elsewhere. But this
        class takes ``(dim, vocab_size, ...)``, so ``layer_id`` was bound to
        ``dim`` and the ``ModelArgs`` object to ``vocab_size`` -- which then blew
        up inside ``nn.Embedding``. Since ``n_mtp_layers`` defaults to 24, this
        fired on every default construction.

        ``layer_id`` is accepted for interface symmetry with the other block
        factories, even though MTP blocks are configured identically at each depth.
        """
        kwargs = dict(
            dim=args.dim,
            vocab_size=args.vocab_size,
            n_predict=int(getattr(args, 'n_predict', 2)),
            num_heads=int(getattr(args, 'n_heads', 8)),
            mtp_drop_rate=float(getattr(args, 'mtp_drop_rate', 0.0)),
            mtp_aux_head=bool(getattr(args, 'mtp_aux_head', False)),
            tie_embeddings=bool(getattr(args, 'tie_embeddings', True)),
            eps=float(getattr(args, 'norm_eps', 1e-6)),
        )
        kwargs.update(overrides)
        return cls(**kwargs)

    def __init__(self, dim, vocab_size, n_predict=2, num_heads=8, ffn_mult=4,
                 mtp_drop_rate=0.0, mtp_aux_head=False, tie_embeddings=True,
                 dropout=0.0, eps=1e-6):
        super().__init__(dim, num_heads=num_heads, ffn_mult=ffn_mult,
                         causal=True, dropout=dropout, eps=eps)
        self.vocab_size = vocab_size
        self.n_predict = n_predict
        self.mtp_drop_rate = mtp_drop_rate
        self.mtp_aux_head = mtp_aux_head
        self.tie_embeddings = tie_embeddings

        self.embed = nn.Embedding(vocab_size, dim)
        self.e_proj = Linear(dim, dim)
        self.h_proj = Linear(dim, dim)
        self.enorm = RMSNorm(dim, eps)
        self.hnorm = RMSNorm(dim, eps)
        self.comb_norm = RMSNorm(dim, eps)
        self.final_norm = RMSNorm(dim, eps)
        self.gate = nn.Parameter(torch.zeros(1))
        self.dynamic_depth_threshold = nn.Parameter(torch.tensor(0.0))
        self.embed_refiner = nn.Sequential(Linear(dim, dim), nn.GELU(), Linear(dim, dim))

        # per-future-offset prediction heads
        self.offset_embed = nn.Parameter(torch.randn(n_predict, dim) * 0.02)
        if tie_embeddings:
            self.head_bias = nn.Parameter(torch.zeros(vocab_size))
        else:
            self.head = Linear(dim, vocab_size, bias=True)
        if mtp_aux_head:
            self.aux_head = Linear(dim, vocab_size)

        self.register_buffer("step_count", torch.zeros(1, dtype=torch.long))
        self.register_buffer("skip_gate_ema", torch.zeros(1))

    def _project_logits(self, h):
        if self.tie_embeddings:
            return F.linear(h, self.embed.weight, self.head_bias)
        return self.head(h)

    def forward(self, x, input_ids, task_emb=None, meta_inner_loss=None):
        # x: (B, S, D) running hidden state; input_ids: (B, S) current tokens
        B, S, D = x.shape
        e = self.enorm(self.embed(input_ids))
        x_h = self.hnorm(x)
        gate_val = torch.sigmoid(self.gate + self.dynamic_depth_threshold)
        combined = gate_val * self.e_proj(e) + (1 - gate_val) * self.h_proj(x_h)
        combined = self.comb_norm(self.embed_refiner(combined))

        # MTP drop: occasionally skip the heavy block and predict from `combined`
        if self.training and self.mtp_drop_rate > 0 and torch.rand(1).item() < self.mtp_drop_rate:
            streams = combined.unsqueeze(2) + self.offset_embed.view(1, 1, self.n_predict, D)
            logits = self._project_logits(self.final_norm(streams))
            return logits

        # expand into n_predict parallel streams, each offset by a learned vector
        all_logits = []
        for i in range(self.n_predict):
            stream = combined + self.offset_embed[i].view(1, 1, D)
            blk = super().forward(stream, task_emb=task_emb)
            all_logits.append(self._project_logits(self.final_norm(blk)))
        logits = torch.stack(all_logits, dim=2)               # (B, S, n_predict, vocab)

        # dynamic-depth adaptation from a meta inner-loss signal
        if meta_inner_loss is not None and self.training:
            with torch.no_grad():
                self.step_count += 1
                self.skip_gate_ema.mul_(0.99).add_(0.01 * float(meta_inner_loss))
                self.dynamic_depth_threshold.add_(-0.01 if self.skip_gate_ema.item() < 0.1 else 0.01)

        if self.mtp_aux_head and self.training:
            aux = self.aux_head(combined)
            return logits, aux
        return logits

    def predict_offsets(self, x, input_ids):
        # Convenience: return per-offset argmax predictions.
        with torch.no_grad():
            logits = self.forward(x, input_ids)
            if isinstance(logits, tuple):
                logits = logits[0]
            return logits.argmax(dim=-1)                      # (B, S, n_predict)

    def get_config(self):
        return {"dim": self.dim, "vocab_size": self.vocab_size, "n_predict": self.n_predict,
                "mtp_aux_head": self.mtp_aux_head, "tie_embeddings": self.tie_embeddings}

    def count_parameters(self):
        return sum(p.numel() for p in self.parameters())

    def parameter_breakdown(self):
        return {n: p.numel() for n, p in self.named_parameters()}

    def parameter_groups(self, base_lr=1e-3, embed_lr_mult=1.0):
        embed_p, other_p = [], []
        for n, p in self.named_parameters():
            (embed_p if "embed" in n else other_p).append(p)
        return [{"params": embed_p, "lr": base_lr * embed_lr_mult},
                {"params": other_p, "lr": base_lr}]

    def regularization_loss(self):
        return next(self.parameters()).new_zeros(())

    def extra_repr(self):
        return (f"dim={self.dim}, vocab_size={self.vocab_size}, "
                f"n_predict={self.n_predict}, aux_head={self.mtp_aux_head}")

    def diagnostics(self):
        return {"num_params": self.count_parameters(), "step": int(self.step_count.item()),
                "skip_gate_ema": self.skip_gate_ema.item(),
                "depth_threshold": self.dynamic_depth_threshold.item()}

    # ------------------------------------------------------------------ #
    # Advanced engineering utilities (injected; namespaced to avoid clashes)
    # ------------------------------------------------------------------ #




























    # ------------------------------------------------------------------ #
    # Advanced architectural / runtime capabilities (injected; `ar_` namespace)
    # ------------------------------------------------------------------ #

















# ============================================================================
# 44. MTPBlockWithCheckpoint
# ----------------------------------------------------------------------------
# An MTPBlock variant that wraps the heavy forward pass in gradient
# checkpointing during training (trading compute for memory by recomputing
# activations in the backward pass). Behaviorally identical to MTPBlock; only
# the training-time memory profile differs.
# ============================================================================
class MTPBlockWithCheckpoint(MTPBlock):
    def __init__(self, *args, use_checkpoint=True, **kwargs):
        super().__init__(*args, **kwargs)
        self.use_checkpoint = use_checkpoint

    def forward(self, x, input_ids, task_emb=None, meta_inner_loss=None):
        if self.training and self.use_checkpoint:
            def run(x_, ids_):
                return MTPBlock.forward(self, x_, ids_, task_emb=task_emb)
            return torch.utils.checkpoint.checkpoint(run, x, input_ids, use_reentrant=False)
        return super().forward(x, input_ids, task_emb=task_emb, meta_inner_loss=meta_inner_loss)

    def get_config(self):
        cfg = super().get_config()
        cfg["use_checkpoint"] = self.use_checkpoint
        return cfg

    # ------------------------------------------------------------------ #
    # Advanced engineering utilities (injected; namespaced to avoid clashes)
    # ------------------------------------------------------------------ #




























    # ------------------------------------------------------------------ #
    # Advanced architectural / runtime capabilities (injected; `ar_` namespace)
    # ------------------------------------------------------------------ #

















# ============================================================================
# Internal helper: IterativeThinking
# ----------------------------------------------------------------------------
# A self-contained iterative-refinement reasoner standing in for the host
# model's UltraAdvancedThinking: it maintains a set of learned "thought
# vectors" that repeatedly cross-attend to the input and to each other,
# refining a working representation over several steps with a confidence gate.
# RecursiveThoughtMachine below wraps this with an outer recursion + memory.
# ============================================================================
class _IterativeThinking(ModuleUtilsMixin, nn.Module):
    def __init__(self, dim, refine_steps=4, num_thought_vectors=16, num_heads=8,
                 dropout=0.0, eps=1e-6):
        super().__init__()
        self.dim = dim
        self.refine_steps = refine_steps
        self.num_thought_vectors = num_thought_vectors
        self.num_heads = num_heads
        self.head_dim = dim // num_heads
        self.thoughts = nn.Parameter(torch.randn(num_thought_vectors, dim) * 0.02)

        self.q = Linear(dim, dim, bias=False)
        self.k = Linear(dim, dim, bias=False)
        self.v = Linear(dim, dim, bias=False)
        self.o = Linear(dim, dim, bias=True)
        self.refine = nn.Sequential(Linear(dim, dim * 4), nn.GELU(), Linear(dim * 4, dim))
        self.norm1 = RMSNorm(dim)
        self.norm2 = RMSNorm(dim)
        self.norm3 = RMSNorm(dim)
        self.confidence = nn.Sequential(Linear(dim, dim // 2), nn.SiLU(),
                                        Linear(dim // 2, 1), nn.Sigmoid())
        self.dropout = nn.Dropout(dropout) if dropout > 0 else nn.Identity()
        self.gate = nn.Parameter(torch.zeros(1))

    def _cross_attend(self, q_src, kv_src):
        B, Sq, D = q_src.shape
        Sk = kv_src.size(1)
        q = self.q(q_src).view(B, Sq, self.num_heads, self.head_dim).transpose(1, 2)
        k = self.k(kv_src).view(B, Sk, self.num_heads, self.head_dim).transpose(1, 2)
        v = self.v(kv_src).view(B, Sk, self.num_heads, self.head_dim).transpose(1, 2)
        scores = torch.einsum("bhid,bhjd->bhij", q, k) / math.sqrt(self.head_dim)
        attn = F.softmax(scores, dim=-1)
        out = torch.einsum("bhij,bhjd->bhid", attn, v).transpose(1, 2).reshape(B, Sq, D)
        return self.o(out)

    def forward(self, x, confidence=None):
        B, S, D = x.shape
        thoughts = self.thoughts.unsqueeze(0).expand(B, -1, -1).contiguous()
        out = x
        for step in range(self.refine_steps):
            # thoughts read from the working representation
            thoughts = self.norm1(thoughts + self.dropout(self._cross_attend(thoughts, out)))
            # working representation reads from thoughts
            update = self._cross_attend(out, thoughts)
            c = self.confidence(out) if confidence is None else confidence
            out = self.norm2(out + torch.sigmoid(self.gate) * c * self.dropout(update))
            out = self.norm3(out + self.dropout(self.refine(out)))
        return out

    # ------------------------------------------------------------------ #
    # Advanced engineering utilities (injected; namespaced to avoid clashes)
    # ------------------------------------------------------------------ #




























    # ------------------------------------------------------------------ #
    # Advanced architectural / runtime capabilities (injected; `ar_` namespace)
    # ------------------------------------------------------------------ #

















# ============================================================================
# 45. RecursiveThoughtMachine
# ----------------------------------------------------------------------------
# Stacks iterative "thinking" with an outer recursion loop and a persistent
# memory bank: at each recursion level it refines the representation via the
# iterative thinker, writes/reads a RecurrentMemoryBank, and consults a meta-
# controller that decides (softly) how many recursion levels to apply per
# input. Models deliberate, multi-pass reasoning with externalized memory.
# ============================================================================
class RecursiveThoughtMachine(_IterativeThinking):
    def __init__(self, dim, refine_steps=4, num_thought_vectors=16, recursion_depth=3,
                 memory_size=512, num_heads=8, adaptive_recursion=True, dropout=0.0, eps=1e-6):
        super().__init__(dim, refine_steps=refine_steps,
                         num_thought_vectors=num_thought_vectors,
                         num_heads=num_heads, dropout=dropout, eps=eps)
        self.recursion_depth = recursion_depth
        self.adaptive_recursion = adaptive_recursion
        self.memory_bank = RecurrentMemoryBank(dim, memory_size=memory_size,
                                               num_heads=num_heads,
                                               topk_retrieval=min(64, memory_size))
        self.meta_controller = nn.Sequential(
            Linear(dim, dim // 2), nn.SiLU(), Linear(dim // 2, recursion_depth))
        self.level_norm = RMSNorm(dim)
        self.register_buffer("avg_recursion", torch.zeros(1))

    def forward(self, x, confidence=None, write_memory=None):
        if write_memory is None:
            write_memory = self.training
        B, S, D = x.shape
        # meta-controller decides per-level weighting (soft adaptive depth)
        level_logits = self.meta_controller(x.mean(dim=1))         # (B, recursion_depth)
        level_weights = F.softmax(level_logits, dim=-1)

        out = x
        accumulated = torch.zeros_like(x)
        for level in range(self.recursion_depth):
            out = super().forward(out, confidence)
            out = self.memory_bank(out, write=write_memory)
            out = self.level_norm(out)
            if self.adaptive_recursion:
                w = level_weights[:, level].view(B, 1, 1)
                accumulated = accumulated + w * out
            else:
                accumulated = out

        result = accumulated if self.adaptive_recursion else out
        if self.training:
            with torch.no_grad():
                eff = (level_weights * torch.arange(1, self.recursion_depth + 1,
                       device=x.device, dtype=level_weights.dtype)).sum(-1).mean()
                self.avg_recursion.mul_(0.99).add_(0.01 * eff)
        return result

    def get_config(self):
        return {"dim": self.dim, "refine_steps": self.refine_steps,
                "num_thought_vectors": self.num_thought_vectors,
                "recursion_depth": self.recursion_depth,
                "adaptive_recursion": self.adaptive_recursion}

    def count_parameters(self):
        return sum(p.numel() for p in self.parameters())

    def parameter_breakdown(self):
        return {n: p.numel() for n, p in self.named_parameters()}

    def parameter_groups(self, base_lr=1e-3):
        return [{"params": list(self.parameters()), "lr": base_lr}]

    def regularization_loss(self):
        return next(self.parameters()).new_zeros(())

    def extra_repr(self):
        return (f"dim={self.dim}, refine_steps={self.refine_steps}, "
                f"recursion_depth={self.recursion_depth}")

    def diagnostics(self):
        return {"num_params": self.count_parameters(),
                "avg_recursion": self.avg_recursion.item(),
                "recursion_depth": self.recursion_depth}

    # ------------------------------------------------------------------ #
    # Advanced engineering utilities (injected; namespaced to avoid clashes)
    # ------------------------------------------------------------------ #




























    # ------------------------------------------------------------------ #
