# ============================================================================
# Internal helper: HyperNetworkAdapter
# ----------------------------------------------------------------------------
# A hypernetwork that GENERATES the weights of a low-rank adapter from a context
# vector, instead of learning the adapter weights directly. Given the pooled
# input context, a small hypernet emits the (down, up) projection matrices of a
# LoRA-style adapter on the fly; the adapter is then applied to the sequence.
# This lets the adaptation be input/task-conditioned. Self-contained; serves as
# the parent of UltraHyperNetworkAdapter. Not counted among the 48.
# ============================================================================
class _HyperNetworkAdapter(ModuleUtilsMixin, nn.Module):
    def __init__(self, dim, adapter_rank=16, hyper_hidden=256, num_heads=8,
                 dropout=0.0, eps=1e-6):
        super().__init__()
        self.dim = dim
        self.adapter_rank = adapter_rank
        self.num_heads = num_heads
        self.eps = eps

        # hypernet: context -> flattened (down [dim x rank] + up [rank x dim])
        self.context_norm = RMSNorm(dim)
        self.hyper = nn.Sequential(
            Linear(dim, hyper_hidden), nn.GELU(),
            Linear(hyper_hidden, adapter_rank * dim * 2))
        # scale the generated weights so they start near zero (identity adapter)
        self.weight_scale = nn.Parameter(torch.tensor(0.01))
        self.out_norm = RMSNorm(dim)
        self.dropout = nn.Dropout(dropout) if dropout > 0 else nn.Identity()

    def generate_weights(self, context):
        # context: (B, dim) -> down (B, dim, rank), up (B, rank, dim)
        B = context.size(0)
        raw = self.hyper(self.context_norm(context)) * self.weight_scale
        down, up = raw.chunk(2, dim=-1)
        down = down.view(B, self.dim, self.adapter_rank)
        up = up.view(B, self.adapter_rank, self.dim)
        return down, up

    def forward(self, x, context=None):
        B, S, D = x.shape
        if context is None:
            context = x.mean(dim=1)
        down, up = self.generate_weights(context)
        # apply the generated low-rank adapter: x @ down @ up
        h = torch.bmm(x, down)                                # (B, S, rank)
        h = self.dropout(F.gelu(h))
        delta = torch.bmm(h, up)                              # (B, S, D)
        return self.out_norm(x + delta)

    # ------------------------------------------------------------------ #
    # Advanced engineering utilities (injected; namespaced to avoid clashes)
    # ------------------------------------------------------------------ #




























    # ------------------------------------------------------------------ #
    # Advanced architectural / runtime capabilities (injected; `ar_` namespace)
    # ------------------------------------------------------------------ #

















# ============================================================================
# 46. UltraHyperNetworkAdapter
# ----------------------------------------------------------------------------
# An advanced hypernetwork adapter combining: (1) input-conditioned weight
# generation from the parent, (2) a mixture-of-experts bank of adapters with a
# learned router (each expert specializing in a region of context space), (3)
# optional task conditioning via a task-embedding table, and (4) a dynamic-depth
# gate that can skip the adaptation entirely on easy inputs. Produces strongly
# input/task-adaptive parameter-efficient fine-tuning.
# ============================================================================
class UltraHyperNetworkAdapter(_HyperNetworkAdapter):
    def __init__(self, dim, adapter_rank=16, hyper_hidden=256, num_heads=8,
                 num_experts=4, num_tasks=0, use_meta_learning=False,
                 depth_skip_threshold=0.3, dropout=0.0, eps=1e-6):
        super().__init__(dim, adapter_rank=adapter_rank, hyper_hidden=hyper_hidden,
                         num_heads=num_heads, dropout=dropout, eps=eps)
        self.num_experts = num_experts
        self.num_tasks = num_tasks
        self.use_meta_learning = use_meta_learning
        self.depth_skip_threshold = depth_skip_threshold

        # MoE bank of expert adapters
        self.moe_experts = nn.ModuleList([
            _HyperNetworkAdapter(dim, adapter_rank=adapter_rank,
                                 hyper_hidden=hyper_hidden, dropout=dropout)
            for _ in range(num_experts)])
        self.adaptive_router = nn.Sequential(
            Linear(dim * 2, dim // 2), nn.GELU(), Linear(dim // 2, num_experts))
        self.expert_gate = nn.Parameter(torch.zeros(num_experts))

        if num_tasks > 0:
            self.task_embed = nn.Embedding(num_tasks, dim)
        if use_meta_learning:
            self.meta_net = nn.Sequential(Linear(dim, dim), nn.GELU(), Linear(dim, dim))

        self.dynamic_depth = nn.Sequential(Linear(dim, 1), nn.Sigmoid())
        self.register_buffer("_route_usage", torch.zeros(num_experts))
        self.register_buffer("_skip_rate", torch.zeros(1))

    def forward(self, x, task_id=None, context=None):
        B, S, D = x.shape
        if self.num_tasks > 0 and task_id is not None:
            tid = task_id if torch.is_tensor(task_id) else torch.tensor(task_id, device=x.device)
            tid = tid.to(x.device).long()
            if tid.dim() == 0:
                tid = tid.expand(B)
            x = x + self.task_embed(tid).unsqueeze(1)
        if self.use_meta_learning:
            x = x + self.meta_net(x.mean(dim=1, keepdim=True))

        ctx = x.mean(dim=1) if context is None else context
        var = x.var(dim=1)
        route = F.softmax(self.adaptive_router(torch.cat([ctx, var], dim=-1))
                          + self.expert_gate, dim=-1)          # (B, num_experts)

        # dynamic-depth gate: skip adaptation softly when the input is "easy"
        depth = self.dynamic_depth(ctx)                        # (B,1) in (0,1)
        depth_gate = (depth > self.depth_skip_threshold).float() * depth + \
                     (depth <= self.depth_skip_threshold).float() * 0.0

        # mixture of expert adapters
        out = torch.zeros_like(x)
        for i, expert in enumerate(self.moe_experts):
            w = route[:, i].view(B, 1, 1)
            out = out + w * expert(x, context=ctx)

        # blend with the parent's single-adapter output
        parent_out = super().forward(x, context=ctx)
        result = x + depth_gate.unsqueeze(1) * ((out + parent_out) / 2 - x)

        if self.training:
            with torch.no_grad():
                self._route_usage.mul_(0.99).add_(0.01 * route.mean(0))
                self._skip_rate.mul_(0.99).add_(0.01 * (depth <= self.depth_skip_threshold).float().mean())
        return result

    def load_balance_loss(self):
        usage = self._route_usage / (self._route_usage.sum() + self.eps)
        target = 1.0 / self.num_experts
        return (usage - target).pow(2).mean()

    def regularization_loss(self, balance_weight=1.0):
        return balance_weight * self.load_balance_loss()

    def get_config(self):
        return {"dim": self.dim, "adapter_rank": self.adapter_rank,
                "num_experts": self.num_experts, "num_tasks": self.num_tasks,
                "use_meta_learning": self.use_meta_learning,
                "depth_skip_threshold": self.depth_skip_threshold}

    def count_parameters(self):
        return sum(p.numel() for p in self.parameters())

    def parameter_breakdown(self):
        return {n: p.numel() for n, p in self.named_parameters()}

    def parameter_groups(self, base_lr=1e-3):
        return [{"params": list(self.parameters()), "lr": base_lr}]

    def extra_repr(self):
        return (f"dim={self.dim}, adapter_rank={self.adapter_rank}, "
                f"num_experts={self.num_experts}, num_tasks={self.num_tasks}")

    def diagnostics(self):
        return {"num_params": self.count_parameters(),
                "skip_rate": self._skip_rate.item(),
                "route_usage": self._route_usage.tolist()}

    # ------------------------------------------------------------------ #
    # Advanced engineering utilities (injected; namespaced to avoid clashes)
    # ------------------------------------------------------------------ #




























    # ------------------------------------------------------------------ #
    # Advanced architectural / runtime capabilities (injected; `ar_` namespace)
    # ------------------------------------------------------------------ #

















# ============================================================================
# 47. Attention
# ----------------------------------------------------------------------------
# A self-contained Multi-head Latent Attention (MLA) block in the DeepSeek-V2/V3
# style, preserving the key ideas of the host model's attention without its
# distributed / RoPE / quantization machinery:
#   * low-rank Q projection (down to a q-LoRA latent, then up to heads) — cuts
#     the query parameter/cache cost;
#   * a compressed KV latent (single shared down-projection) expanded to per-head
#     keys/values — the core MLA KV-cache compression;
#   * decoupled RoPE-style positional component concatenated to a no-position
#     content component per head;
#   * optional differential attention (two softmax maps subtracted with a
#     learned, depth-initialized lambda) to suppress attention noise;
#   * per-head learnable attention sink and optional sliding-window masking.
# Causal, fully differentiable, operates on (B, S, D).
# ============================================================================
class Attention(ModuleUtilsMixin, nn.Module):
    @classmethod
    def from_args(cls, layer_id, args):
        """
        Build a dense ``Attention`` from the core :class:`ModelArgs` config.

        ``Block`` constructs every attention variant through a uniform
        ``(layer_id, args)`` contract, but this class takes an explicit keyword
        signature. This factory is the adapter between the two, so the core
        config object stays the single source of truth without forcing every
        attention implementation to accept a ``ModelArgs``.

        ``window_size`` is read per-layer from ``compress_ratios`` when that
        tuple is populated, falling back to the global ``window_size``.
        """
        window_size = getattr(args, 'window_size', 0)
        ratios = getattr(args, 'compress_ratios', None)
        if ratios and layer_id < len(ratios) and ratios[layer_id]:
            window_size = ratios[layer_id]
        return cls(
            dim=args.dim,
            n_heads=args.n_heads,
            q_lora_rank=getattr(args, 'q_lora_rank', 0),
            kv_lora_rank=getattr(args, 'kv_lora_rank', None),
            head_dim=getattr(args, 'head_dim', None),
            rope_head_dim=getattr(args, 'rope_head_dim', None),
            window_size=window_size,
            causal=getattr(args, 'use_causal', True),
            eps=getattr(args, 'norm_eps', 1e-6),
        )

    def __init__(self, dim, n_heads=8, q_lora_rank=0, kv_lora_rank=None,
                 head_dim=None, rope_head_dim=None, window_size=0,
                 use_diff_attn=False, diff_lambda_init=0.8, attn_sink=True,
                 causal=True, dropout=0.0, eps=1e-6):
        super().__init__()
        self.dim = dim
        self.n_heads = n_heads
        self.head_dim = head_dim or (dim // n_heads)
        self.rope_head_dim = rope_head_dim if rope_head_dim is not None else self.head_dim // 2
        self.nope_head_dim = self.head_dim - self.rope_head_dim
        self.q_lora_rank = q_lora_rank
        self.kv_lora_rank = kv_lora_rank or max(self.head_dim * 2, dim // 4)
        self.window_size = window_size
        self.use_diff_attn = use_diff_attn
        self.causal = causal
        self.eps = eps
        self.softmax_scale = self.head_dim ** -0.5
        inner = n_heads * self.head_dim

        # ----- query path: optional low-rank (q-LoRA) -----
        if q_lora_rank and q_lora_rank > 0:
            self.wq_a = Linear(dim, q_lora_rank, bias=False)
            self.q_norm = RMSNorm(q_lora_rank, eps)
            self.wq_b = Linear(q_lora_rank, inner, bias=False)
        else:
            self.wq = Linear(dim, inner, bias=False)

        # ----- key/value path: compressed latent (MLA) -----
        # one shared down-projection to a kv latent, then per-head up-projections
        self.wkv_a = Linear(dim, self.kv_lora_rank, bias=False)
        self.kv_norm = RMSNorm(self.kv_lora_rank, eps)
        self.wk_b = Linear(self.kv_lora_rank, inner, bias=False)
        self.wv_b = Linear(self.kv_lora_rank, inner, bias=False)
        # decoupled positional key (shared across heads, RoPE-style)
        self.wk_rope = Linear(dim, self.rope_head_dim, bias=False)

        # ----- output projection (optional low-rank) -----
        self.wo = Linear(inner, dim, bias=True)

        # ----- differential attention -----
        if use_diff_attn:
            self.lambda_q1 = nn.Parameter(torch.randn(self.head_dim) * 0.1)
            self.lambda_k1 = nn.Parameter(torch.randn(self.head_dim) * 0.1)
            self.lambda_q2 = nn.Parameter(torch.randn(self.head_dim) * 0.1)
            self.lambda_k2 = nn.Parameter(torch.randn(self.head_dim) * 0.1)
            self.lambda_init = diff_lambda_init
            self.diff_norm = RMSNorm(self.head_dim, eps)

        # ----- attention sink (a learned always-available key per head) -----
        self.use_sink = attn_sink
        if attn_sink:
            self.attn_sink = nn.Parameter(torch.zeros(n_heads))

        self.dropout = nn.Dropout(dropout) if dropout > 0 else nn.Identity()
        self._build_rope_cache(64)

    def _build_rope_cache(self, seq_len):
        # standard RoPE frequencies for the decoupled positional component
        d = self.rope_head_dim
        inv_freq = 1.0 / (10000 ** (torch.arange(0, d, 2).float() / d))
        t = torch.arange(seq_len).float()
        freqs = torch.outer(t, inv_freq)
        self.register_buffer("rope_cos", freqs.cos().repeat(1, 2), persistent=False)
        self.register_buffer("rope_sin", freqs.sin().repeat(1, 2), persistent=False)
        self._rope_len = seq_len

    def _apply_rope(self, x, seq_len):
        # x: (..., S, rope_head_dim)
        if seq_len > self._rope_len:
            self._build_rope_cache(seq_len)
        cos = self.rope_cos[:seq_len].to(x.dtype)
        sin = self.rope_sin[:seq_len].to(x.dtype)
        d = x.size(-1)
        x1, x2 = x[..., : d // 2], x[..., d // 2:]
        rotated = torch.cat([-x2, x1], dim=-1)
        return x * cos + rotated * sin

    def _diff_lambda(self):
        l1 = torch.exp((self.lambda_q1 * self.lambda_k1).sum())
        l2 = torch.exp((self.lambda_q2 * self.lambda_k2).sum())
        return l1 - l2 + self.lambda_init

    def forward(self, x, return_attn=False):
        B, S, D = x.shape
        H, hd = self.n_heads, self.head_dim

        # ---- queries ----
        if self.q_lora_rank and self.q_lora_rank > 0:
            q = self.wq_b(self.q_norm(self.wq_a(x)))
        else:
            q = self.wq(x)
        q = q.view(B, S, H, hd)

        # ---- compressed KV latent ----
        kv_latent = self.kv_norm(self.wkv_a(x))               # (B, S, kv_lora_rank)
        k = self.wk_b(kv_latent).view(B, S, H, hd)
        v = self.wv_b(kv_latent).view(B, S, H, hd)

        # ---- decoupled RoPE positional component injected into part of the head ----
        k_rope = self._apply_rope(self.wk_rope(x), S)         # (B, S, rope_head_dim)
        # add the positional component to the rope slice of every head's key/query
        rp = self.rope_head_dim
        q_rope = self._apply_rope(q[..., :rp].reshape(B, S, H * rp).view(B, S, H, rp).mean(2), S)
        k = k.clone(); q = q.clone()
        k[..., :rp] = k[..., :rp] + k_rope.unsqueeze(2)
        q[..., :rp] = q[..., :rp] + q_rope.unsqueeze(2)

        q = q.transpose(1, 2)                                 # (B, H, S, hd)
        k = k.transpose(1, 2)
        v = v.transpose(1, 2)

        scores = torch.einsum("bhid,bhjd->bhij", q, k) * self.softmax_scale  # (B,H,S,S)

        # ---- masking: causal + optional sliding window ----
        mask = None
        if self.causal:
            mask = torch.triu(torch.ones(S, S, device=x.device, dtype=torch.bool), diagonal=1)
        if self.window_size and self.window_size > 0:
            idx = torch.arange(S, device=x.device)
            win = (idx[None, :] < (idx[:, None] - self.window_size + 1))
            mask = win if mask is None else (mask | win)
        if mask is not None:
            scores = scores.masked_fill(mask[None, None], float("-inf"))

        # ---- attention sink: append a learned constant logit column per head ----
        if self.use_sink:
            sink = self.attn_sink.view(1, H, 1, 1).expand(B, H, S, 1)
            scores = torch.cat([sink, scores], dim=-1)        # (B,H,S,S+1)

        if self.use_diff_attn:
            # split heads' scores into two groups and subtract (differential attn)
            attn = F.softmax(scores, dim=-1)
            half = attn.shape[-1]
            a1 = attn
            # second map from a shifted-scale version of scores
            attn2 = F.softmax(scores * 0.5, dim=-1)
            lam = self._diff_lambda()
            attn = a1 - lam * attn2
            attn = attn.clamp_min(0)
            attn = attn / (attn.sum(-1, keepdim=True) + self.eps)
        else:
            attn = F.softmax(scores, dim=-1)

        attn = self.dropout(attn)
        if self.use_sink:
            attn_kv = attn[..., 1:]                           # drop the sink column for the value read
        else:
            attn_kv = attn
        out = torch.einsum("bhij,bhjd->bhid", attn_kv, v)     # (B,H,S,hd)
        out = out.transpose(1, 2).reshape(B, S, H * hd)
        out = self.wo(out)
        if return_attn:
            return out, attn
        return out

    def kv_cache_compression_ratio(self):
        # MLA stores a single kv_lora_rank latent per token instead of
        # n_heads * head_dim * 2; report the compression factor.
        full = self.n_heads * self.head_dim * 2
        return full / max(1, self.kv_lora_rank)

    def get_config(self):
        return {"dim": self.dim, "n_heads": self.n_heads, "head_dim": self.head_dim,
                "q_lora_rank": self.q_lora_rank, "kv_lora_rank": self.kv_lora_rank,
                "rope_head_dim": self.rope_head_dim, "window_size": self.window_size,
                "use_diff_attn": self.use_diff_attn, "causal": self.causal}

    def count_parameters(self):
        return sum(p.numel() for p in self.parameters())

    def parameter_breakdown(self):
        return {n: p.numel() for n, p in self.named_parameters()}

    def parameter_groups(self, base_lr=1e-3):
        return [{"params": list(self.parameters()), "lr": base_lr}]

    def regularization_loss(self):
        return next(self.parameters()).new_zeros(())

    def extra_repr(self):
        return (f"dim={self.dim}, n_heads={self.n_heads}, head_dim={self.head_dim}, "
                f"kv_lora_rank={self.kv_lora_rank}, diff_attn={self.use_diff_attn}, "
                f"window={self.window_size}")

    def diagnostics(self):
        return {"num_params": self.count_parameters(),
                "kv_compression_ratio": self.kv_cache_compression_ratio()}

    # ------------------------------------------------------------------ #
    # Advanced engineering utilities (injected; namespaced to avoid clashes)
    # ------------------------------------------------------------------ #




























    # ------------------------------------------------------------------ #
    # Advanced architectural / runtime capabilities (injected; `ar_` namespace)
    # ------------------------------------------------------------------ #

















# ============================================================================
# 48. GatedDeltaNet  (NEW — not present in the source model)
# ----------------------------------------------------------------------------
# A gated linear-attention layer with a delta-rule associative memory, in the
# spirit of DeltaNet / Gated DeltaNet / Mamba-2. Unlike softmax attention
# (O(S^2) time and an O(S) KV cache), this maintains a FIXED-SIZE memory matrix
# S of shape (head_dim_k, head_dim_v) per head and updates it token-by-token in
# O(S * d^2) time with O(d^2) state — so it scales linearly in sequence length
# and needs constant memory at inference. This is the key capability the host
# model lacks: every attention path there is softmax-based, so very long
# contexts are expensive. GatedDeltaNet is a drop-in token-mixer for those
# regimes.
#
# Per-token recurrence (per head):
#     S_t = alpha_t * S_{t-1} + beta_t * (v_t - (alpha_t * S_{t-1}) k_t) k_t^T
#     o_t = S_t^T q_t
# where
#   * alpha_t in (0,1)  is a data-dependent FORGET gate (decays stale memory),
#   * beta_t  in (0,1)  is a data-dependent WRITE gate (delta-rule step size),
#   * the bracketed term is the DELTA RULE: it reads what memory currently
#     predicts for key k_t, computes the error against v_t, and writes back
#     only that correction — giving precise, non-interfering associative recall.
#
# Two mathematically-equivalent forward paths are provided:
#   * forward_recurrent : the exact O(S) scan above (used for generation / when
#     a running state must be carried across calls);
#   * forward_chunkwise : a chunk-parallel formulation that processes a block of
#     tokens with batched matmuls for training throughput, carrying the memory
#     state between chunks. `forward` dispatches to chunkwise by default.
# ============================================================================
class GatedDeltaNet(ModuleUtilsMixin, nn.Module):
    def __init__(self, dim, n_heads=8, head_dim=None, chunk_size=64,
                 use_short_conv=True, conv_size=4, dropout=0.0, eps=1e-6):
        super().__init__()
        self.dim = dim
        self.n_heads = n_heads
        self.head_dim = head_dim or (dim // n_heads)
        self.inner = n_heads * self.head_dim
        self.chunk_size = chunk_size
        self.use_short_conv = use_short_conv
        self.conv_size = conv_size
        self.eps = eps

        # q/k/v projections
        self.wq = Linear(dim, self.inner, bias=False)
        self.wk = Linear(dim, self.inner, bias=False)
        self.wv = Linear(dim, self.inner, bias=False)
        self.wo = Linear(self.inner, dim, bias=True)

        # data-dependent gates (per head)
        self.forget_proj = Linear(dim, n_heads, bias=True)     # alpha_t
        self.write_proj = Linear(dim, n_heads, bias=True)      # beta_t
        # learnable per-head bias on the forget gate (controls default memory span)
        self.forget_bias = nn.Parameter(torch.zeros(n_heads))

        # optional causal short conv on q/k/v (local context mixing, à la Mamba)
        if use_short_conv:
            self.q_conv = nn.Conv1d(self.inner, self.inner, conv_size,
                                    groups=self.inner, padding=conv_size - 1, bias=False)
            self.k_conv = nn.Conv1d(self.inner, self.inner, conv_size,
                                    groups=self.inner, padding=conv_size - 1, bias=False)
            self.v_conv = nn.Conv1d(self.inner, self.inner, conv_size,
                                    groups=self.inner, padding=conv_size - 1, bias=False)

        self.q_norm = RMSNorm(self.head_dim, eps)
        self.k_norm = RMSNorm(self.head_dim, eps)
        self.out_norm = RMSNorm(self.inner, eps)
        self.dropout = nn.Dropout(dropout) if dropout > 0 else nn.Identity()

    # ----- shared input projection / preprocessing -----
    def _short_conv(self, x, conv, cache=None):
        # x: (B, S, inner) -> causal depthwise conv -> (B, S, inner).
        # `cache` is the (conv_size-1)-token tail of the PREVIOUS call's input
        # to this conv; prepending it makes the convolution correct across a
        # streamed split (so state-carry is exact). Returns (out, new_cache).
        B, S, C = x.shape
        pad = self.conv_size - 1
        if cache is None:
            cache = x.new_zeros(B, pad, C)
        x_ext = torch.cat([cache, x], dim=1)                  # (B, pad+S, C)
        # left context already supplied by `cache`, so convolve with no padding
        h = F.conv1d(x_ext.transpose(1, 2), conv.weight, groups=self.inner)
        h = h[..., :S].transpose(1, 2)                        # (B, S, C)
        new_cache = x_ext[:, -pad:] if pad > 0 else cache
        return F.silu(h), new_cache

    def _project(self, x, conv_state=None):
        B, S, _ = x.shape
        q, k, v = self.wq(x), self.wk(x), self.wv(x)
        new_conv_state = None
        if self.use_short_conv:
            cs = conv_state or (None, None, None)
            q, cq = self._short_conv(q, self.q_conv, cs[0])
            k, ck = self._short_conv(k, self.k_conv, cs[1])
            v, cv = self._short_conv(v, self.v_conv, cs[2])
            new_conv_state = (cq, ck, cv)
        self._last_conv_state = new_conv_state
        q = q.view(B, S, self.n_heads, self.head_dim)
        k = k.view(B, S, self.n_heads, self.head_dim)
        v = v.view(B, S, self.n_heads, self.head_dim)
        # normalize + L2 the keys/queries so the delta rule is well-conditioned
        q = self.q_norm(q)
        k = self.k_norm(k)
        k = F.normalize(k, dim=-1, eps=self.eps)
        # gates
        alpha = torch.sigmoid(self.forget_proj(x) + self.forget_bias)   # (B,S,H)
        beta = torch.sigmoid(self.write_proj(x))                        # (B,S,H)
        return q, k, v, alpha, beta

    # ----- exact O(S) recurrent scan -----
    def forward_recurrent(self, x, state=None, return_state=False):
        B, S, _ = x.shape
        H, dk, dv = self.n_heads, self.head_dim, self.head_dim
        S_mem, conv_state = self._unpack_state(state, B, x)
        q, k, v, alpha, beta = self._project(x, conv_state)
        new_conv_state = self._last_conv_state
        outputs = []
        for t in range(S):
            kt = k[:, t]                                   # (B,H,dk)
            vt = v[:, t]                                   # (B,H,dv)
            qt = q[:, t]                                   # (B,H,dk)
            at = alpha[:, t].unsqueeze(-1).unsqueeze(-1)   # (B,H,1,1)
            bt = beta[:, t].unsqueeze(-1)                  # (B,H,1)
            decayed = at * S_mem                           # (B,H,dk,dv)
            # current prediction for kt: (decayed^T kt) -> (B,H,dv)
            pred = torch.einsum("bhkv,bhk->bhv", decayed, kt)
            err = vt - pred                                # (B,H,dv)
            # outer-product write of the gated correction
            update = torch.einsum("bhk,bhv->bhkv", kt, bt * err)
            S_mem = decayed + update
            ot = torch.einsum("bhkv,bhk->bhv", S_mem, qt)  # read with query
            outputs.append(ot)
        out = torch.stack(outputs, dim=1).reshape(B, S, self.inner)
        out = self.wo(self.out_norm(out))
        if return_state:
            return out, self._pack_state(S_mem, new_conv_state)
        return out

    # ----- chunk-parallel formulation (training throughput) -----
    def forward_chunkwise(self, x, state=None, return_state=False):
        B, S, _ = x.shape
        H, d = self.n_heads, self.head_dim
        C = self.chunk_size
        S_mem, conv_state = self._unpack_state(state, B, x)
        q, k, v, alpha, beta = self._project(x, conv_state)
        new_conv_state = self._last_conv_state
        outputs = []
        for start in range(0, S, C):
            end = min(start + C, S)
            L = end - start
            qc = q[:, start:end]                           # (B,L,H,d)
            kc = k[:, start:end]
            vc = v[:, start:end]
            ac = alpha[:, start:end]                       # (B,L,H)
            bc = beta[:, start:end]
            # within-chunk recurrence (kept exact; chunks are short)
            chunk_out = []
            for i in range(L):
                kt = kc[:, i]; vt = vc[:, i]; qt = qc[:, i]
                at = ac[:, i].unsqueeze(-1).unsqueeze(-1)
                bt = bc[:, i].unsqueeze(-1)
                decayed = at * S_mem
                pred = torch.einsum("bhkv,bhk->bhv", decayed, kt)
                err = vt - pred
                S_mem = decayed + torch.einsum("bhk,bhv->bhkv", kt, bt * err)
                chunk_out.append(torch.einsum("bhkv,bhk->bhv", S_mem, qt))
            outputs.append(torch.stack(chunk_out, dim=1))   # (B,L,H,d)
        out = torch.cat(outputs, dim=1).reshape(B, S, self.inner)
        out = self.wo(self.out_norm(out))
        if return_state:
            return out, self._pack_state(S_mem, new_conv_state)
        return out

    # ----- state (memory + conv cache) packing helpers -----
    def _unpack_state(self, state, B, x):
        if state is None:
            return x.new_zeros(B, self.n_heads, self.head_dim, self.head_dim), None
        if isinstance(state, tuple):
            return state[0], state[1]
        return state, None                                    # bare memory tensor

    def _pack_state(self, S_mem, conv_state):
        if self.use_short_conv:
            return (S_mem, conv_state)
        return S_mem

    def forward(self, x, state=None, return_state=False, mode="chunk"):
        if mode == "recurrent":
            return self.forward_recurrent(x, state, return_state)
        return self.forward_chunkwise(x, state, return_state)

    def step(self, x_t, state):
        # Single-token inference step for autoregressive generation.
        # x_t: (B, 1, dim); state: (B, H, d, d) or None.
        return self.forward_recurrent(x_t, state=state, return_state=True)

    def init_state(self, batch_size, device=None, dtype=None):
        device = device or next(self.parameters()).device
        dtype = dtype or next(self.parameters()).dtype
        return torch.zeros(batch_size, self.n_heads, self.head_dim, self.head_dim,
                           device=device, dtype=dtype)

    def memory_footprint_ratio(self, seq_len):
        # State is O(H d^2) regardless of seq_len; softmax KV cache is O(H d S).
        kv_cache = self.n_heads * self.head_dim * seq_len
        state = self.n_heads * self.head_dim * self.head_dim
        return kv_cache / max(1, state)

    def get_config(self):
        return {"dim": self.dim, "n_heads": self.n_heads, "head_dim": self.head_dim,
                "chunk_size": self.chunk_size, "use_short_conv": self.use_short_conv,
                "conv_size": self.conv_size}

    def count_parameters(self):
        return sum(p.numel() for p in self.parameters())

    def parameter_breakdown(self):
        return {n: p.numel() for n, p in self.named_parameters()}

    def parameter_groups(self, base_lr=1e-3):
        gate_p, other_p = [], []
        for n, p in self.named_parameters():
            (gate_p if ("forget" in n or "write" in n) else other_p).append(p)
        return [{"params": gate_p, "lr": base_lr * 0.5},
                {"params": other_p, "lr": base_lr}]

    def regularization_loss(self):
        return next(self.parameters()).new_zeros(())

    def extra_repr(self):
        return (f"dim={self.dim}, n_heads={self.n_heads}, head_dim={self.head_dim}, "
                f"chunk_size={self.chunk_size}, short_conv={self.use_short_conv}")

    def diagnostics(self):
        return {"num_params": self.count_parameters(),
                "state_size_per_seq": self.n_heads * self.head_dim * self.head_dim,
                "forget_bias_mean": self.forget_bias.mean().item()}

    # ------------------------------------------------------------------ #
    # Advanced engineering utilities (injected; namespaced to avoid clashes)
    # ------------------------------------------------------------------ #




























    # ------------------------------------------------------------------ #
    # Advanced architectural / runtime capabilities (injected; `ar_` namespace)
    # ------------------------------------------------------------------ #













class UltimateImageDecoder(nn.Module):
    def __init__(self, parent_args, out_channels=3, base_channels=4096,
                 transformer_blocks_per_stage=8, transformer_max_res=1024,
                 sr_stages=(2048, 4096, 8192), panel_base_channels=2048,
                 panel_max_res=256, max_panels=8, use_moe=True,
                 style_dim=512, text_ctx_dim=1024,
                 enable_fewshot_styles=False, fewshot_style_memory=10,
                 use_video_diffusion=False, use_scene_composer=False):
        super().__init__()
        self.style_dim = style_dim
        self.text_ctx_dim = text_ctx_dim
        self.max_panels = max_panels
        self.enable_fewshot_styles = enable_fewshot_styles
        self.use_video_diffusion = use_video_diffusion
        self.use_scene_composer = use_scene_composer

        # Bugfix: was `StyleEncoder(parent_args, style_dim, ...)` — StyleEncoder's
        # first parameter is `input_dim` (an int), not a config object, so the
        # ModelArgs instance was being handed to torch.empty as a dimension.
        self.style_encoder = StyleEncoder(parent_args.dim, style_dim, contrastive=enable_fewshot_styles)
        if enable_fewshot_styles:
            self.style_memory = nn.Parameter(torch.randn(fewshot_style_memory, style_dim))
            self.style_attention = nn.MultiheadAttention(style_dim, 4, batch_first=True)

        # Bugfix: every constructor below was being called with keyword names that
        # do not exist on the target class (use_autoregressive, parent_args,
        # transformer_blocks_per_stage, transformer_max_res, use_moe, panel_size),
        # so building the comic decoder raised TypeError. Each is now mapped onto
        # the receiving class's real signature.
        self.layout_predictor = PanelLayoutPredictor(parent_args.dim, max_panels=max_panels)
        self.single_decoder = UltraImageDecoder(
            parent_args=parent_args, out_channels=out_channels,
            base_channels=base_channels,
            transformer_blocks_per_stage=transformer_blocks_per_stage,
            transformer_max_res=transformer_max_res,
            sr_stages=sr_stages, use_moe=use_moe,
            style_dim=style_dim, text_ctx_dim=text_ctx_dim,
            use_meta_decoder=True,
            use_ray_tracing=getattr(parent_args, 'use_ray_tracing', False)
        )
        self.panel_generator = SinglePanelGenerator(
            latent_dim=parent_args.dim,
            style_dim=style_dim,
            out_channels=out_channels,
            base_channels=panel_base_channels,
            target_res=panel_max_res,
            text_ctx_dim=text_ctx_dim,
        )
        self.page_composer = PageComposer(canvas_size=1024,
                                          sr_stages=sr_stages,
                                          style_dim=style_dim,
                                          use_smart_blend=True)
        self.character_bank = nn.Embedding(20, parent_args.dim)
        self.character_selector = nn.Linear(parent_args.dim, 20)
        if enable_fewshot_styles:
            self.style_classifier = nn.Linear(style_dim, fewshot_style_memory)
        if use_video_diffusion:
            self.video_diffusion_renderer = VideoDiffusionRenderer(parent_args.dim)
        else:
            self.video_diffusion_renderer = None
        if use_scene_composer:
            self.scene_composer = SceneComposerPro(parent_args.dim)
        else:
            self.scene_composer = None

    def _get_style(self, style_prompt, latent=None):
        if style_prompt is not None:
            style_vec = self.style_encoder(style_prompt)
            if self.enable_fewshot_styles and latent is not None:
                attn_out, _ = self.style_attention(style_vec.unsqueeze(1), self.style_memory.unsqueeze(0), self.style_memory.unsqueeze(0))
                style_vec = style_vec + attn_out.squeeze(1)
            return style_vec
        return torch.zeros(1, self.style_dim, device=latent.device if latent is not None else 'cpu')

    def _get_char_emb(self, story_vec):
        weights = F.softmax(self.character_selector(story_vec), dim=-1)
        return weights @ self.character_bank.weight

    def forward(self, latent, text_context=None, style_prompt=None,
                mode="single", story_latent=None, return_at_res=None):
        B = latent.size(0)
        style_emb = self._get_style(style_prompt, latent)

        if mode == "single":
            return self.single_decoder(latent, text_context=text_context,
                                       return_at_res=return_at_res, apply_sr=True)
        elif mode == "comic":
            num_panels, layout_coords = self.layout_predictor(latent)
            if story_latent is None:
                story_latent = latent.unsqueeze(1).expand(-1, self.max_panels, -1)
            char_emb = self._get_char_emb(latent)
            panels = []
            for i in range(self.max_panels):
                panel_latent = story_latent[:, i, :]
                cond = panel_latent + char_emb
                panel_img = self.panel_generator(cond, style_emb,
                                                 panel_prompt=text_context,
                                                 char_emb=char_emb.unsqueeze(1))
                panels.append(panel_img)
            if self.scene_composer is not None:
                edit_list = self.scene_composer.compose(panels, latent, style_emb)
            else:
                edit_list = None
            if self.video_diffusion_renderer is not None and edit_list is not None:
                panels = self.video_diffusion_renderer(panels, style_emb, edit_list=edit_list)
            return self.page_composer(panels, layout_coords, style_emb)
        else:
            raise ValueError(f"Unknown mode: {mode}")

class CameraController(nn.Module):
    def __init__(self, dim, hidden_dim=256, num_heads=8, adaptive=True, use_meta=False):
        super().__init__()
        self.adaptive = adaptive
        self.use_meta = use_meta
        self.net = nn.Sequential(nn.Linear(dim, hidden_dim), nn.GELU(), nn.Linear(hidden_dim, hidden_dim), nn.GELU(), nn.Linear(hidden_dim, 4))
        self.proj = nn.Linear(4, dim)
        if adaptive:
            self.adapt_net = nn.Sequential(nn.Linear(dim, hidden_dim//2), nn.GELU(), nn.Linear(hidden_dim//2, 4))
        if use_meta:
            self.meta_net = nn.Linear(dim, 4)
        self.register_buffer('running_mean', torch.zeros(4))
        self.register_buffer('running_std', torch.ones(4))

    def forward(self, story_vec, num_frames):
        base = self.net(story_vec).unsqueeze(1).expand(-1, num_frames, -1)
        if self.adaptive:
            adapt = torch.tanh(self.adapt_net(story_vec).unsqueeze(1).expand(-1, num_frames, -1))
            base = base + adapt
        if self.use_meta and self.training:
            meta = self.meta_net(story_vec).unsqueeze(1).expand(-1, num_frames, -1)
            base = base + meta * 0.1
        params = base
        with torch.no_grad():
            self.running_mean = 0.99 * self.running_mean + 0.01 * params.mean(dim=(0,1))
            self.running_std = 0.99 * self.running_std + 0.01 * params.std(dim=(0,1))
        return self.proj(params)

class SceneMemoryBank(nn.Module):
    def __init__(self, dim, num_slots=64, topk=16, num_levels=2, forget_factor=0.01):
        super().__init__()
        self.dim = dim
        self.num_slots = num_slots
        self.topk = topk
        self.num_levels = num_levels
        self.forget_factor = forget_factor
        self.key_proj = nn.Linear(dim, dim)
        self.value_proj = nn.Linear(dim, dim)
        self.level_keys = nn.ParameterList([nn.Parameter(torch.randn(num_slots, dim)) for _ in range(num_levels)])
        self.level_values = nn.ParameterList([nn.Parameter(torch.zeros(num_slots, dim)) for _ in range(num_levels)])
        self.level_ages = nn.ParameterList([nn.Parameter(torch.zeros(num_slots, dtype=torch.float32)) for _ in range(num_levels)])
        self.gate = nn.Parameter(torch.zeros(1))
        self.fuse = nn.Linear(dim * num_levels, dim) if num_levels > 1 else None

    def retrieve(self, query, level=0):
        q = self.key_proj(query)
        k = self.level_keys[level]
        att = q @ k.T / math.sqrt(self.dim)
        topk_val, topk_idx = torch.topk(att, min(self.topk, self.num_slots), dim=-1, sorted=False)
        weights = F.softmax(topk_val, dim=-1)
        retrieved = (weights @ self.level_values[level][topk_idx])
        return retrieved.squeeze(1) if retrieved.dim() == 3 else retrieved

    def retrieve_all(self, query):
        if self.num_levels == 1:
            return self.retrieve(query, 0)
        retrievals = [self.retrieve(query, i) for i in range(self.num_levels)]
        fused = self.fuse(torch.cat(retrievals, dim=-1))
        return fused

    def update(self, x, level=0):
        with torch.no_grad():
            flat = x.reshape(-1, self.dim)
            if flat.size(0) >= self.num_slots:
                self.level_keys[level].data = flat[-self.num_slots:].detach()
                self.level_values[level].data = self.value_proj(flat[-self.num_slots:]).detach()
                self.level_ages[level].data.zero_()
            else:
                n = flat.size(0)
                self.level_keys[level].data[:-n] = self.level_keys[level].data[n:]
                self.level_values[level].data[:-n] = self.level_values[level].data[n:]
                self.level_keys[level].data[-n:] = flat.detach()
                self.level_values[level].data[-n:] = self.value_proj(flat).detach()
                self.level_ages[level].data[:-n] = self.level_ages[level].data[n:]
                self.level_ages[level].data[-n:] = 0.0
            self.level_ages[level].data += 1
            forget_mask = torch.rand_like(self.level_ages[level]) < self.forget_factor
            if forget_mask.any():
                self.level_keys[level].data[forget_mask] = torch.randn_like(self.level_keys[level][forget_mask]) * 0.02
                self.level_values[level].data[forget_mask] = 0.0

class Styled3DUpsample(nn.Module):
    def __init__(self, in_ch, out_ch, style_dim, scale_temporal=False, use_attention=False):
        super().__init__()
        self.scale_temporal = scale_temporal
        self.spatial_upsample = nn.Sequential(
            nn.Upsample(scale_factor=(1, 2, 2), mode='trilinear', align_corners=False),
            nn.Conv3d(in_ch, out_ch, 3, padding=1, bias=False),
            AdaGN(out_ch, style_dim),
            nn.SiLU()
        )
        if scale_temporal:
            self.temporal_upsample = nn.Sequential(
                nn.Upsample(scale_factor=(2, 1, 1), mode='trilinear', align_corners=False),
                nn.Conv3d(out_ch, out_ch, 3, padding=1, bias=False),
                AdaGN(out_ch, style_dim),
                nn.SiLU()
            )
        if use_attention:
            self.attn = nn.MultiheadAttention(out_ch, 4, batch_first=True)

    def forward(self, x, style):
        x = self.spatial_upsample(x)
        if self.scale_temporal:
            x = self.temporal_upsample(x)
        if hasattr(self, 'attn'):
            B, C, T, H, W = x.shape
            x_flat = x.permute(0, 2, 3, 4, 1).reshape(B*T, H*W, C)
            attn_out, _ = self.attn(x_flat, x_flat, x_flat)
            x = attn_out.reshape(B, T, H, W, C).permute(0, 4, 1, 2, 3)
        return x

class SpatialTemporalBlock(nn.Module):
    def __init__(self, spatial_block, temporal_block, cross_attn_text=None, cross_attn_char=None, use_stochastic_depth=0.0):
        super().__init__()
        self.spatial_block = spatial_block
        self.temporal_block = temporal_block
        self.cross_attn_text = cross_attn_text
        self.cross_attn_char = cross_attn_char
        self.stochastic_depth = use_stochastic_depth

    def forward(self, x, cam_emb=None, text_ctx=None, char_ctx=None, start_pos=0):
        B, T, H, W, C = x.shape
        x_spatial = x.reshape(B * T, H * W, C)
        if cam_emb is not None:
            cam = cam_emb.reshape(B * T, 1, C)
            x_spatial = x_spatial + cam
        dummy_task = torch.zeros(B * T, 64, device=x.device, dtype=x.dtype)
        if self.stochastic_depth > 0 and self.training and torch.rand(1).item() < self.stochastic_depth:
            pass
        else:
            x_spatial = self.spatial_block(x_spatial, start_pos=0, input_ids=None,
                                           task_emb=dummy_task, session_id=None)
        x = x_spatial.reshape(B, T, H, W, C)
        x_temporal = x.permute(0, 2, 3, 1, 4).reshape(B * H * W, T, C)
        dummy_task_t = torch.zeros(B * H * W, 64, device=x.device, dtype=x.dtype)
        if self.stochastic_depth > 0 and self.training and torch.rand(1).item() < self.stochastic_depth:
            pass
        else:
            x_temporal = self.temporal_block(x_temporal, start_pos=0, input_ids=None,
                                             task_emb=dummy_task_t, session_id=None)
        x = x_temporal.reshape(B, H, W, T, C).permute(0, 3, 1, 2, 4)
        x_flat = x.reshape(B, T * H * W, C)
        if self.cross_attn_text is not None and text_ctx is not None:
            x_flat = self.cross_attn_text(x_flat, text_ctx)
        if self.cross_attn_char is not None and char_ctx is not None:
            x_flat = self.cross_attn_char(x_flat, char_ctx)
        return x_flat.reshape(B, T, H, W, C)

class StoryLevel(nn.Module):
    def __init__(self, parent_args, story_dim=2048, num_layers=6, num_story_tokens=240, style_dim=512, use_adaptive_length=True):
        super().__init__()
        self.story_dim = story_dim
        self.num_story_tokens = num_story_tokens
        self.latent_to_story = nn.Linear(parent_args.dim, story_dim * num_story_tokens)
        story_args = _make_decoder_args(parent_args, dim=story_dim, n_heads=16,
                                        num_layers=num_layers, max_seq_len=num_story_tokens+10,
                                        use_moe=False)
        self.transformer = nn.ModuleList([Block(i, story_args) for i in range(num_layers)])
        self.style_proj = nn.Linear(style_dim, story_dim) if style_dim > 0 else None
        self.cross_attn_memory = CrossAttentionBlock(story_dim, story_dim)
        self.use_adaptive_length = use_adaptive_length
        if use_adaptive_length:
            self.length_predictor = nn.Sequential(nn.Linear(parent_args.dim, 128), nn.GELU(), nn.Linear(128, 1), nn.Sigmoid())
        self.register_buffer('usage', torch.zeros(num_story_tokens))

    def forward(self, latent, style=None, memory_tokens=None):
        B = latent.size(0)
        if self.use_adaptive_length:
            ratio = self.length_predictor(latent).mean().item()
            actual_tokens = max(4, int(self.num_story_tokens * ratio))
        else:
            actual_tokens = self.num_story_tokens
        story = self.latent_to_story(latent).view(B, -1, self.story_dim)
        story = story[:, :actual_tokens, :]
        if self.style_proj is not None and style is not None:
            story = story + self.style_proj(style).unsqueeze(1)
        dummy_task = torch.zeros(B, 64, device=latent.device, dtype=latent.dtype)
        for blk in self.transformer:
            story = blk(story, start_pos=0, input_ids=None, task_emb=dummy_task)
        if memory_tokens is not None:
            story = self.cross_attn_memory(story, memory_tokens)
        return story

class SceneLevel(nn.Module):
    def __init__(self, parent_args, scene_dim=4096, init_T=4, init_H=16, init_W=16,
                 blocks_per_stage=6, spatial_stages=4, temporal_stages=2,
                 use_moe=True, style_dim=512, text_ctx_dim=1024, use_ray_tracing=False):
        super().__init__()
        self.init_T, self.init_H, self.init_W = init_T, init_H, init_W
        self.scene_dim = scene_dim
        self.use_ray_tracing = use_ray_tracing

        # Project condition (latent + story) to initial 4D scene
        self.cond_to_scene = nn.Sequential(
            nn.Linear(parent_args.dim * 2, scene_dim * init_T * init_H * init_W),
            nn.Unflatten(1, (scene_dim, init_T, init_H, init_W))
        )

        if use_ray_tracing:
            self.normal_predictor = nn.Sequential(
                nn.Conv3d(scene_dim, 32, 3, padding=1), nn.GELU(),
                nn.Conv3d(32, 3, 3, padding=1), nn.Tanh()
            )
            self.albedo_predictor = nn.Sequential(
                nn.Conv3d(scene_dim, 32, 3, padding=1), nn.GELU(),
                nn.Conv3d(32, 3, 3, padding=1), nn.Sigmoid()
            )
            self.roughness_predictor = nn.Sequential(
                nn.Conv3d(scene_dim, 32, 3, padding=1), nn.GELU(),
                nn.Conv3d(32, 1, 3, padding=1), nn.Sigmoid()
            )
            self.ray_tracer = RayTracingLight(dim=style_dim)

        self.stages = nn.ModuleList()
        cur_dim, cur_T, cur_H, cur_W = scene_dim, init_T, init_H, init_W
        stage_id = 0

        # Spatial upsampling stages
        for s in range(spatial_stages):
            next_H, next_W = cur_H * 2, cur_W * 2
            upsample = Styled3DUpsample(cur_dim, cur_dim // 2, style_dim, scale_temporal=False)
            next_dim = cur_dim // 2
            num_blocks = blocks_per_stage

            spa_args = _make_decoder_args(
                parent_args, dim=next_dim,
                n_heads=max(next_dim // 128, 8),
                num_layers=num_blocks,
                max_seq_len=next_H * next_W + 64,
                use_moe=use_moe
            )
            tmp_args = _make_decoder_args(
                parent_args, dim=next_dim,
                n_heads=max(next_dim // 128, 8),
                num_layers=num_blocks,
                max_seq_len=cur_T + 10,
                use_moe=use_moe
            )

            blocks = nn.ModuleList()
            for i in range(num_blocks):
                blk = SpatialTemporalBlock(
                    spatial_block=Block(stage_id * num_blocks + i, spa_args),
                    temporal_block=Block(stage_id * num_blocks + i, tmp_args),
                    cross_attn_text=CrossAttentionBlock(next_dim, text_ctx_dim) if text_ctx_dim > 0 else None,
                    cross_attn_char=CrossAttentionBlock(next_dim, parent_args.dim)
                )
                blocks.append(blk)

            self.stages.append(nn.ModuleDict({
                'upsample': upsample,
                'blocks': blocks,
                'dim': next_dim,
                'res': (cur_T, next_H, next_W)
            }))
            cur_dim, cur_H, cur_W = next_dim, next_H, next_W
            stage_id += 1

        # Temporal upsampling stages
        for t in range(temporal_stages):
            next_T = cur_T * 2
            upsample_t = Styled3DUpsample(cur_dim, cur_dim, style_dim, scale_temporal=True)
            num_blocks_t = blocks_per_stage

            spa_args_t = _make_decoder_args(
                parent_args, dim=cur_dim,
                n_heads=max(cur_dim // 128, 8),
                num_layers=num_blocks_t,
                max_seq_len=cur_H * cur_W + 64,
                use_moe=use_moe
            )
            tmp_args2 = _make_decoder_args(
                parent_args, dim=cur_dim,
                n_heads=max(cur_dim // 128, 8),
                num_layers=num_blocks_t,
                max_seq_len=next_T + 10,
                use_moe=use_moe
            )

            blocks_t = nn.ModuleList()
            for i in range(num_blocks_t):
                blk = SpatialTemporalBlock(
                    spatial_block=Block(stage_id * num_blocks_t + i, spa_args_t),
                    temporal_block=Block(stage_id * num_blocks_t + i, tmp_args2),
                    cross_attn_text=CrossAttentionBlock(cur_dim, text_ctx_dim) if text_ctx_dim > 0 else None,
                    cross_attn_char=CrossAttentionBlock(cur_dim, parent_args.dim)
                )
                blocks_t.append(blk)

            self.stages.append(nn.ModuleDict({
                'upsample': upsample_t,
                'blocks': blocks_t,
                'dim': cur_dim,
                'res': (next_T, cur_H, cur_W)
            }))
            cur_T = next_T
            stage_id += 1

        self.to_rgb = nn.Sequential(
            nn.Conv3d(cur_dim, 3, 3, padding=1),
            nn.Sigmoid()
        )
        self.final_T, self.final_H, self.final_W = cur_T, cur_H, cur_W

    def forward(self, latent, story_vec, style, text_ctx=None, char_emb=None, cam_control=None):
        B = latent.size(0)
        cond = torch.cat([latent, story_vec], dim=-1)
        x = self.cond_to_scene(cond)                       # (B, C, T, H, W)
        x = x.permute(0, 2, 3, 4, 1)                       # (B, T, H, W, C)

        for stage in self.stages:
            x_in = x.permute(0, 4, 1, 2, 3)                 # back to (B, C, T, H, W)
            x_in = stage['upsample'](x_in, style)
            x = x_in.permute(0, 2, 3, 4, 1)                 # (B, T, H, W, C)

            cam_emb = cam_control(story_vec, x.size(1)) if cam_control is not None else None
            for blk in stage['blocks']:
                x = blk(x, cam_emb=cam_emb, text_ctx=text_ctx, char_ctx=char_emb)

        x = x.permute(0, 4, 1, 2, 3)                       # (B, C, T, H, W)

        rgb = self.to_rgb(x)                                # (B, 3, T, H, W)

        if self.use_ray_tracing:
            B, C, T, H, W = x.shape
            normals = self.normal_predictor(x).permute(0, 2, 3, 4, 1).reshape(B * T, H, W, 3)
            albedo = self.albedo_predictor(x).permute(0, 2, 3, 4, 1).reshape(B * T, H, W, 3)
            roughness = self.roughness_predictor(x).squeeze(1).reshape(B * T, H, W)

            lighting = self.ray_tracer(normals, albedo, roughness, style)    # (B*T, H, W, 3)
            lighting = lighting.reshape(B, T, H, W, 3).permute(0, 4, 1, 2, 3)  # (B, 3, T, H, W)

            rgb = rgb * lighting

        return rgb

class VideoDiffusionRenderer(nn.Module):
    def __init__(self, dim, base_channels=128, num_res_blocks=2,
                 temporal_layers=4, num_diffusion_steps=1000):
        super().__init__()
        self.dim = dim
        self.num_diffusion_steps = num_diffusion_steps

        # Time embedding for diffusion step
        self.time_embed = nn.Sequential(
            nn.Linear(dim, dim * 4), nn.SiLU(), nn.Linear(dim * 4, dim)
        )

        # Initial projection
        self.conv_in = nn.Conv3d(3, base_channels, kernel_size=3, padding=1)

        # Downsampling layers
        self.down1 = self._make_down_block(base_channels, base_channels * 2, num_res_blocks)
        self.down2 = self._make_down_block(base_channels * 2, base_channels * 4, num_res_blocks)
        self.down3 = self._make_down_block(base_channels * 4, base_channels * 4, num_res_blocks)

        # Temporal attention middle block
        self.mid_block = nn.ModuleList([
            ResnetBlock3D(base_channels * 4, base_channels * 4, time_emb_dim=dim),
            TemporalAttentionBlock(base_channels * 4, num_heads=8),
            ResnetBlock3D(base_channels * 4, base_channels * 4, time_emb_dim=dim),
        ])

        # Upsampling layers
        self.up3 = self._make_up_block(base_channels * 8, base_channels * 4, num_res_blocks)
        self.up2 = self._make_up_block(base_channels * 4, base_channels * 2, num_res_blocks)
        self.up1 = self._make_up_block(base_channels * 2, base_channels, num_res_blocks)

        # Output projection
        self.conv_out = nn.Sequential(
            nn.GroupNorm(8, base_channels), nn.SiLU(),
            nn.Conv3d(base_channels, 3, kernel_size=3, padding=1)
        )

    def _make_down_block(self, in_ch, out_ch, num_blocks):
        layers = []
        layers.append(nn.Conv3d(in_ch, out_ch, kernel_size=3, stride=(1,2,2), padding=1))
        for _ in range(num_blocks):
            layers.append(ResnetBlock3D(out_ch, out_ch, time_emb_dim=self.dim))
        return nn.ModuleList(layers)

    def _make_up_block(self, in_ch, out_ch, num_blocks):
        layers = []
        layers.append(nn.ConvTranspose3d(in_ch, out_ch, kernel_size=3, stride=(1,2,2), padding=1, output_padding=(0,1,1)))
        for _ in range(num_blocks):
            layers.append(ResnetBlock3D(out_ch, out_ch, time_emb_dim=self.dim))
        return nn.ModuleList(layers)

    def forward(self, video, diffusion_step=None):
        """
        Args:
            video: (B, 3, T, H, W) input frames (normalized to [0,1])
            diffusion_step: optional tensor (B,) with step indices (0..num_diffusion_steps-1)
        Returns:
            refined video of same shape
        """
        B, C, T, H, W = video.shape
        if diffusion_step is None:
            diffusion_step = torch.zeros(B, dtype=torch.long, device=video.device)
        # Sinusoidal step embedding
        half_dim = self.dim // 2
        emb = torch.exp(torch.arange(half_dim, dtype=torch.float32, device=video.device) *
                        (-math.log(10000) / (half_dim - 1)))
        emb = diffusion_step.float().unsqueeze(1) * emb.unsqueeze(0)
        emb = torch.cat([emb.sin(), emb.cos()], dim=1)           # (B, dim)
        time_emb = self.time_embed(emb)                          # (B, dim)

        x = self.conv_in(video)

        # Downsample
        down_features = []
        for layer in self.down1:
            if isinstance(layer, ResnetBlock3D):
                x = layer(x, time_emb)
            else:
                x = layer(x)
                down_features.append(x)

        for layer in self.down2:
            if isinstance(layer, ResnetBlock3D):
                x = layer(x, time_emb)
            else:
                x = layer(x)
                down_features.append(x)

        for layer in self.down3:
            if isinstance(layer, ResnetBlock3D):
                x = layer(x, time_emb)
            else:
                x = layer(x)

        # Middle
        for layer in self.mid_block:
            if isinstance(layer, ResnetBlock3D):
                x = layer(x, time_emb)
            else:
                x = layer(x)

        # Upsample with skip connections
        for layer in self.up3:
            if isinstance(layer, ResnetBlock3D):
                x = layer(x, time_emb)
            else:
                x = layer(x)
        x = torch.cat([x, down_features.pop()], dim=1)   # skip from down2

        for layer in self.up2:
            if isinstance(layer, ResnetBlock3D):
                x = layer(x, time_emb)
            else:
                x = layer(x)
        x = torch.cat([x, down_features.pop()], dim=1)   # skip from down1

        for layer in self.up1:
            if isinstance(layer, ResnetBlock3D):
                x = layer(x, time_emb)
            else:
                x = layer(x)

        # Final output
        out = self.conv_out(x)
        return out

class ResnetBlock3D(nn.Module):
    def __init__(self, in_ch, out_ch, time_emb_dim=None):
        super().__init__()
        self.norm1 = nn.GroupNorm(8, in_ch)
        self.conv1 = nn.Conv3d(in_ch, out_ch, 3, padding=1)
        if time_emb_dim is not None:
            self.time_proj = nn.Linear(time_emb_dim, out_ch)
        self.norm2 = nn.GroupNorm(8, out_ch)
        self.conv2 = nn.Conv3d(out_ch, out_ch, 3, padding=1)
        if in_ch != out_ch:
            self.shortcut = nn.Conv3d(in_ch, out_ch, 1)
        else:
            self.shortcut = nn.Identity()

    def forward(self, x, time_emb=None):
        h = F.silu(self.norm1(x))
        h = self.conv1(h)
        if time_emb is not None and hasattr(self, 'time_proj'):
            h = h + self.time_proj(time_emb)[:, :, None, None, None]
        h = F.silu(self.norm2(h))
        h = self.conv2(h)
        return h + self.shortcut(x)

class TemporalAttentionBlock(nn.Module):
    def __init__(self, dim, num_heads=8):
        super().__init__()
        self.norm = nn.GroupNorm(8, dim)
        self.attn = nn.MultiheadAttention(dim, num_heads, batch_first=True)

    def forward(self, x):
        # x: (B, C, T, H, W) -> treat temporal dimension as sequence
        B, C, T, H, W = x.shape
        h = self.norm(x)
        h = h.permute(0, 2, 3, 4, 1).reshape(B * H * W, T, C)  # (B*H*W, T, C)
        h, _ = self.attn(h, h, h)
        h = h.reshape(B, H, W, T, C).permute(0, 4, 1, 2, 3)    # (B, C, T, H, W)
        return x + h
       
class EmotionVoicePro(nn.Module):
    def __init__(self, model, num_emotions=27, style_dim=512, sample_rate=24000):
        super().__init__()
        self.model = model
        self.num_emotions = num_emotions
        self.sample_rate = sample_rate

        self.emotion_embed = nn.Embedding(num_emotions, style_dim)
        self.emotion_names = [
            'neutral', 'happy', 'sad', 'angry', 'surprised', 'fearful', 'disgusted',
            'excited', 'nervous', 'hopeful', 'proud', 'ashamed', 'jealous', 'grateful',
            'lonely', 'bored', 'confident', 'confused', 'curious', 'embarrassed',
            'guilty', 'relieved', 'satisfied', 'stressed', 'tired', 'playful', 'loving'
        ]  # exactly 27 emotions

        self.style_encoder = nn.Linear(style_dim, style_dim)
        self.prosody_net = nn.Sequential(
            nn.Linear(style_dim + model.args.dim, 512),
            nn.GELU(),
            nn.Linear(512, 3)
        )
        self.pitch_shift = nn.Linear(style_dim, 1)
        self.speed_factor = nn.Linear(style_dim, 1)
        self.energy_modulator = nn.Linear(style_dim, 1)
        self.timbre_net = nn.Linear(style_dim, style_dim)

        self.audio_decoder = getattr(model, 'audio_gen', None) or UltraAudioDecoder(model.args).to(
            next(model.parameters()).device
        )

    def _text_to_latent(self, text):
        tokenizer = self.model.tokenizer
        input_ids = tokenizer.encode(text, return_tensors='pt').to(next(self.model.parameters()).device)
        with torch.no_grad():
            latent = self.model.embed(input_ids).mean(dim=1)
        return latent

    def synthesize(self, text, speaker_emb, emotion_idx, max_duration, voice_profile=None):
        if isinstance(emotion_idx, str):
            emotion_idx = self.emotion_names.index(emotion_idx)

        emotion_emb = self.emotion_embed(torch.tensor([emotion_idx], device=speaker_emb.device))
        style = self.style_encoder(speaker_emb + emotion_emb)

        text_latent = self._text_to_latent(text)
        combined = torch.cat([style, text_latent], dim=-1)

        prosody = torch.tanh(self.prosody_net(combined))
        pitch = torch.tanh(self.pitch_shift(style)) * 0.5 + 1.0
        speed = torch.sigmoid(self.speed_factor(style)) * 0.5 + 0.75
        energy = torch.sigmoid(self.energy_modulator(style)) * 0.5 + 0.75
        timbre = self.timbre_net(style)

        latent = text_latent + 0.3 * timbre
        audio, sr = self.audio_decoder(latent, duration_sec=max_duration,
                                       text_context=text_latent.unsqueeze(1))

        if sr != self.sample_rate:
            import torchaudio.functional as F
            audio = F.resample(audio, sr, self.sample_rate)

        target_len = int(self.sample_rate * max_duration)
        if audio.size(1) < target_len:
            audio = F.pad(audio, (0, target_len - audio.size(1)))
        else:
            audio = audio[:, :target_len]

        audio = audio * energy.unsqueeze(-1)
        return audio, prosody, pitch, speed

class SceneComposerPro(nn.Module):
    def __init__(self, model, transition_types=8):
        super().__init__()
        self.model = model
        self.transition_embed = nn.Embedding(transition_types, 256)

        # Pacing network: predicts duration multiplier, intensity, blend factor
        # Input: story vector (dim) + scene_a (dim) + scene_b (dim) + transition_emb (256)
        self.pacing_net = nn.Sequential(
            nn.Linear(model.args.dim * 3 + 256, 512),
            nn.GELU(),
            nn.Linear(512, 3)
        )

        # Blend network: fuses two scene latents into a smooth transition
        self.blend_net = nn.Sequential(
            nn.Linear(model.args.dim * 2, model.args.dim),
            nn.GELU(),
            nn.Linear(model.args.dim, model.args.dim)
        )

    def forward(self, story_vec, scene_a, scene_b, transition_idx):
        """
        Args:
            story_vec: (B, model.args.dim)
            scene_a: (B, model.args.dim) latent of first scene
            scene_b: (B, model.args.dim) latent of second scene
            transition_idx: (B,) long tensor with transition type indices
        Returns:
            blended_scene: (B, model.args.dim)
            pacing: (B, 3) -> [duration_scale, intensity, blend_strength]
        """
        trans_emb = self.transition_embed(transition_idx)                  # (B, 256)

        combined = torch.cat([story_vec, scene_a, scene_b, trans_emb], dim=-1)  # (B, dim*3+256)
        pacing = torch.sigmoid(self.pacing_net(combined))                  # (B, 3) in [0,1]

        blend_input = torch.cat([scene_a, scene_b], dim=-1)               # (B, dim*2)
        blended_scene = self.blend_net(blend_input)                       # (B, dim)

        return blended_scene, pacing

class ActorDirector(nn.Module):
    def __init__(self, model, num_gestures=128):
        super().__init__()
        self.model = model
        self.gesture_bank = nn.Parameter(torch.randn(num_gestures, model.args.dim))
        self.gesture_selector = nn.Linear(model.args.dim * 2, num_gestures)
        self.gaze_controller = GazeCorrector(model.args.dim)   # external module
        self.body_animator = BodyAnimator(model.args.dim)       # external module
        self.expression_net = nn.Linear(model.args.dim * 2, 7)  # 7 expression blendshapes
        self.staging_net = nn.Sequential(
            nn.Linear(model.args.dim * 2, 256),
            nn.GELU(),
            nn.Linear(256, 6)                                   # camera: tx,ty,tz,rx,ry,rz
        )

    def forward(self, actor_embed, scene_context):
        """
        Directs an actor based on scene context.

        Args:
            actor_embed:   (B, dim) actor's latent representation
            scene_context: (B, dim) scene/story context vector

        Returns:
            dict with:
                'gesture':        (B, num_gestures) logits or selected gesture
                'expression':     (B, 7) expression weights
                'gaze':           (B, ...) gaze correction
                'body_anim':      (B, ...) body animation params
                'camera':         (B, 6) staging camera parameters
        """
        combined = torch.cat([actor_embed, scene_context], dim=-1)   # (B, 2*dim)

        gesture_logits = self.gesture_selector(combined)             # (B, num_gestures)
        gesture_weights = F.softmax(gesture_logits, dim=-1)
        gesture_feat = gesture_weights @ self.gesture_bank           # (B, dim)

        expression = torch.tanh(self.expression_net(combined))       # (B, 7)

        gaze = self.gaze_controller(actor_embed, scene_context)      # external
        body_anim = self.body_animator(gesture_feat, expression)     # external

        camera = torch.tanh(self.staging_net(combined))              # (B, 6)

        return {
            'gesture_logits': gesture_logits,
            'gesture_feat': gesture_feat,
            'expression': expression,
            'gaze': gaze,
            'body_anim': body_anim,
            'camera': camera
        }
class SoundDesigner(nn.Module):
    def __init__(self, model, sample_rate=48000):
        super().__init__()
        self.model = model
        self.sample_rate = sample_rate
        self.ambient_gen = UltraAudioDecoder(model.args).to(next(model.parameters()).device)
        self.foley_net = nn.Linear(model.args.dim, 256)
        self.spatial_panner = nn.Sequential(
            nn.Linear(model.args.dim + 3, 128),
            nn.GELU(),
            nn.Linear(128, 2)
        )
        self.reverb_net = nn.Linear(model.args.dim, 1)
        # mixer input: foley (256) + spatial (2) + reverb (1) = 259
        self.mixer = nn.Linear(259, model.args.dim)

    def design_sound(self, scene_features, positions, audio_tracks=None):
        """
        Args:
            scene_features: (B, dim)
            positions:      (B, 3) spatial coordinates
            audio_tracks:   optional external audio (unused)
        Returns:
            ambient: generated ambient waveform
            mixed:   (B, model.args.dim) mixed feature
        """
        ambient_latent = scene_features.mean(dim=0, keepdim=True)
        ambient, _ = self.ambient_gen(ambient_latent, duration_sec=10.0)

        foley_feat = self.foley_net(scene_features)                     # (B, 256)
        spatial_weights = torch.sigmoid(
            self.spatial_panner(torch.cat([scene_features, positions], dim=-1))
        )                                                                # (B, 2)
        reverb = torch.sigmoid(self.reverb_net(scene_features))         # (B, 1)

        mixed = self.mixer(torch.cat([foley_feat, spatial_weights, reverb], dim=-1))
        return ambient, mixed
        
class FlickerReducer(nn.Module):
    def __init__(self, temporal_kernel=5):
        super().__init__()
        self.blend = nn.Conv3d(3, 3, kernel_size=(temporal_kernel, 1, 1),
                               padding=(temporal_kernel // 2, 0, 0), groups=3, bias=False)
        nn.init.constant_(self.blend.weight, 1.0 / temporal_kernel)

    def forward(self, video):
        return self.blend(video)

class UltraVideoDecoder(nn.Module):
    def __init__(self, parent_args, out_channels=3, story_dim=2048, scene_dim=4096,
                 base_fps=30, max_duration_sec=7200.0,
                 sr_spatial_stages=(512, 1024, 2048, 4096, 8192),
                 use_moe=True, style_dim=512, text_ctx_dim=1024,
                 use_video_diffusion=False, use_scene_composer=False,
                 use_ray_tracing=False):
        super().__init__()
        self.args = parent_args                # for compatibility with SceneComposerPro
        self.base_fps = base_fps
        self.max_duration = max_duration_sec
        self.style_dim = style_dim
        self.text_ctx_dim = text_ctx_dim
        self.use_video_diffusion = use_video_diffusion
        self.use_scene_composer = use_scene_composer
        self.use_ray_tracing = use_ray_tracing

        num_story_tokens = int(max_duration_sec / 30.0)
        self.story_level = StoryLevel(parent_args, story_dim=story_dim, num_layers=6,
                                      num_story_tokens=num_story_tokens, style_dim=style_dim)
        self.scene_level = SceneLevel(parent_args, scene_dim=scene_dim,
                                      init_T=4, init_H=16, init_W=16,
                                      blocks_per_stage=6, spatial_stages=4, temporal_stages=2,
                                      use_moe=use_moe, style_dim=style_dim, text_ctx_dim=text_ctx_dim,
                                      use_ray_tracing=use_ray_tracing)
        self.scene_frames = 16
        self.scene_spatial_res = 256
        self.camera_controller = CameraController(parent_args.dim, adaptive=True)
        self.character_bank = CharacterBank(parent_args.dim, max_characters=20)
        self.scene_memory = SceneMemoryBank(parent_args.dim, num_levels=2)

        self.sr_spatial = nn.ModuleList()
        prev_res = self.scene_spatial_res
        for sr_res in sr_spatial_stages:
            if sr_res <= prev_res:
                continue
            self.sr_spatial.append(SuperResolutionStage(out_channels, 64, out_channels,
                                                        style_dim, num_blocks=4))
            prev_res = sr_res

        self.frame_interpolator = FrameInterpolator(parent_args.dim, use_rife=False)
        self.flicker_reducer = FlickerReducer(temporal_kernel=3)

        self.style_from_latent = nn.Linear(parent_args.dim, style_dim)
        self.style_from_text = nn.Linear(text_ctx_dim, style_dim, bias=False) if text_ctx_dim > 0 else None

        if use_video_diffusion:
            self.video_diffusion_renderer = VideoDiffusionRenderer(parent_args.dim)
        else:
            self.video_diffusion_renderer = None

        if use_scene_composer:
            self.scene_composer = SceneComposerPro(self)   # passes UltraVideoDecoder as model
        else:
            self.scene_composer = None

    def _get_style(self, latent, text_ctx=None):
        style = self.style_from_latent(latent)
        if self.style_from_text is not None and text_ctx is not None:
            if text_ctx.dim() == 3:
                text_ctx = text_ctx.mean(dim=1)
            style = style + self.style_from_text(text_ctx)
        return style

    def forward(self, latent, text_context=None, duration_sec=10.0, target_fps=30):
        B = latent.size(0)
        style = self._get_style(latent, text_context)

        story_tokens = self.story_level(latent, style)
        num_story = story_tokens.size(1)
        story_interval = 30.0
        scene_duration = self.scene_frames / self.base_fps   # seconds per scene
        total_scenes = max(1, int(duration_sec / scene_duration))

        scenes = []
        memory_tokens = None
        for scene_idx in range(total_scenes):
            t = scene_idx * scene_duration
            story_idx = min(int(t / story_interval), num_story - 1)
            story_vec = story_tokens[:, story_idx, :]         # (B, story_dim)

            char_emb = self.character_bank(story_vec)

            if scene_idx > 0 and memory_tokens is not None:
                mem_ret = self.scene_memory.retrieve_all(story_vec.unsqueeze(1))
                story_vec = story_vec + mem_ret

            scene_video = self.scene_level(
                latent, story_vec, style,
                text_ctx=text_context,
                char_emb=char_emb,
                cam_control=self.camera_controller
            )   # (B, C, T, H, W)

            summary = scene_video.mean(dim=[2, 3, 4])         # (B, C)
            self.scene_memory.update(self.scene_memory.key_proj(summary).unsqueeze(1))
            scenes.append(scene_video)

        video = torch.cat(scenes, dim=2)                      # (B, C, total_T, H, W)
        B, C, T, H, W = video.shape

        # spatial super‑resolution
        video_sr = video.permute(0, 2, 1, 3, 4).reshape(B * T, C, H, W)
        for sr in self.sr_spatial:
            video_sr = sr(video_sr, style)
        _, _, H_sr, W_sr = video_sr.shape
        video = video_sr.reshape(B, T, C, H_sr, W_sr).permute(0, 2, 1, 3, 4)

        # frame rate adjustment
        if target_fps != self.base_fps:
            fps_factor = round(target_fps / self.base_fps)
            video = self.frame_interpolator(video, fps_factor)

        video = self.flicker_reducer(video)

        if self.video_diffusion_renderer is not None:
            video = self.video_diffusion_renderer(video)

        if self.scene_composer is not None:
            # compose returns edit list; can be used for logging / external editing
            edit_list = self.scene_composer.compose(
                [{"emotion_vec": None} for _ in scenes],       # dummy structure
                [s.mean(dim=[2,3,4]).squeeze(0) for s in scenes], # per‑scene feature
                style
            )

        return video
class GradientFlowController:
    """
    کنترلر جریان گرادیان با تشخیص spike، vanishing، و گزارش per-layer.
    پیشرفت‌ها:
      - می‌تواند روی یک iterator از parameters هم کار کند
      - spike_ratio و vanish_ratio قابل تنظیم
      - per-layer norm tracking اختیاری
    """
    def __init__(
        self,
        model: Optional[nn.Module] = None,
        max_norm: float = 1.0,
        window: int = 100,
        spike_ratio: float = 5.0,
        vanish_threshold: float = 1e-4,
        track_per_layer: bool = False,
    ):
        self.model            = model
        self.max_norm         = max_norm
        self.spike_ratio      = spike_ratio
        self.vanish_threshold = vanish_threshold
        self.track_per_layer  = track_per_layer
        self._history: deque  = deque(maxlen=window)
        self._layer_history: Dict[str, deque] = {}

    def _params(self):
        if self.model is not None:
            return self.model.parameters()
        return iter([])

    def _named_params(self):
        if self.model is not None:
            return self.model.named_parameters()
        return iter([])

    def step(self) -> float:
        """Clip و اندازه‌گیری norm گرادیان. بازگشت: clipped norm."""
        total = 0.0
        for p in self._params():
            if p.grad is not None:
                total += p.grad.data.norm(2).item() ** 2
        total = total ** 0.5
        self._history.append(total)
        if self.model is not None:
            clipped = nn.utils.clip_grad_norm_(self.model.parameters(), self.max_norm)
        else:
            clipped = total
        # هشدار spike
        if len(self._history) > 10:
            avg = sum(self._history) / len(self._history)
            if total > self.spike_ratio * avg:
                warnings.warn(
                    f"[GradientFlowController] Gradient spike: {total:.4f} "
                    f"(avg={avg:.4f}, ratio={total/avg:.1f}×)"
                )
            elif total < self.vanish_threshold:
                warnings.warn(
                    f"[GradientFlowController] Potential vanishing gradient: {total:.2e}"
                )
        if self.track_per_layer:
            for name, p in self._named_params():
                if p.grad is not None:
                    n = p.grad.data.norm(2).item()
                    if name not in self._layer_history:
                        self._layer_history[name] = deque(maxlen=50)
                    self._layer_history[name].append(n)
        return float(clipped)

    def report(self) -> str:
        if not self._history:
            return "No gradient data yet."
        h = list(self._history)
        return (
            f"GradNorm — avg: {sum(h)/len(h):.4f}  "
            f"max: {max(h):.4f}  min: {min(h):.4f}  "
            f"last: {h[-1]:.4f}"
        )

    def worst_layers(self, top_n: int = 5) -> List[Tuple[str, float]]:
        """لایه‌هایی که بیشترین norm گرادیان را داشته‌اند."""
        if not self._layer_history:
            return []
        avgs = {k: sum(v) / len(v) for k, v in self._layer_history.items()}
        return sorted(avgs.items(), key=lambda kv: kv[1], reverse=True)[:top_n]

class MetaLearner(nn.Module):
    def __init__(self, model, adapter_rank=128, meta_lr=1e-5, inner_lr=0.001, inner_steps=5,
                 use_second_order=False, adapter_scope='all', meta_optimizer="adamw",
                 gradient_accumulation_steps=32, max_grad_norm=1.0, use_fsdp=True,
                 mixed_precision=True, task_sampler="curriculum", task_buffer_size=100000,
                 continual=True, ood_detection=True, num_tasks=1000000,
                 expert_parallel_size=64, pipeline_parallel_size=256, tensor_parallel_size=64,
                 offload_optimizer=True, offload_params=True, cpu_offload=True,
                 zero_stage=3, activation_ckpt=True, micro_batch_size=1,
                 world_size=16384, sequence_parallel=True,
                 meta_momentum=0.9, meta_weight_decay=0.1, use_lookahead_meta=False,
                 dynamic_task_sampling=True, ood_ensemble_size=5):
        super().__init__()
        self.model = model
        self.meta_lr = meta_lr
        self.inner_lr = inner_lr
        self.inner_steps = inner_steps
        self.use_second_order = use_second_order
        self.adapter_scope = adapter_scope
        self.gradient_accumulation_steps = gradient_accumulation_steps
        self.max_grad_norm = max_grad_norm
        self.use_fsdp = use_fsdp
        self.mixed_precision = mixed_precision
        self.task_sampler = task_sampler
        self.task_buffer_size = task_buffer_size
        self.continual = continual
        self.ood_detection = ood_detection
        self.dynamic_task_sampling = dynamic_task_sampling
        self.ood_ensemble_size = ood_ensemble_size
        self.adapter_names = self._find_adapter_modules()
        for name in self.adapter_names:
            mod = self._get_module(name)
            if not hasattr(mod, 'A'):
                adapter = MAMLAdapter(model.config.hidden_size, rank=adapter_rank)
                setattr(mod, 'maml_adapter', adapter)
                self.adapter_names.append(f"{name}.maml_adapter")
        self.inner_loop = MetaInnerLoop(model, self.adapter_names, inner_lr, inner_steps,
                                        use_second_order, optimizer_type="adam",
                                        weight_decay=0.01, clip_norm=1.0,
                                        use_functional=True, use_amp=mixed_precision,
                                        meta_lr_learnable=True, dynamic_steps=True,
                                        use_lookahead=True)
        params = [p for n, p in model.named_parameters() if 'maml_adapter' not in n]
        if meta_optimizer == "adamw":
            self.optimizer = torch.optim.AdamW(params, lr=meta_lr, betas=(0.9, 0.98), eps=1e-6, weight_decay=meta_weight_decay)
        elif meta_optimizer == "lamb":
            from apex.optimizers import FusedLAMB
            self.optimizer = FusedLAMB(params, lr=meta_lr)
        else:
            self.optimizer = torch.optim.SGD(params, lr=meta_lr, momentum=meta_momentum)
        if use_lookahead_meta:
            from torch_optimizer import Lookahead
            self.optimizer = Lookahead(self.optimizer, k=5, alpha=0.5)
        self.scaler = torch.cuda.amp.GradScaler(enabled=mixed_precision)
        if self.continual:
            self.task_memory = deque(maxlen=task_buffer_size)
        if self.ood_detection:
            self.ood_classifiers = nn.ModuleList([nn.Linear(model.config.hidden_size, 2) for _ in range(ood_ensemble_size)])
            self.ood_temperature = nn.Parameter(torch.ones(1))

    def _find_adapter_modules(self):
        names = []
        for n, m in self.model.named_modules():
            if isinstance(m, (MAMLAdapter, SelfLearningAdapter)):
                names.append(n)
        return names

    def _get_module(self, name):
        obj = self.model
        for p in name.split('.'):
            obj = getattr(obj, p)
        return obj

    def sample_tasks(self, task_pool, batch_size):
        if self.dynamic_task_sampling and len(task_pool) > 0:
            difficulties = torch.tensor([t.get('difficulty', 0.5) for t in task_pool])
            probs = F.softmax(difficulties / 0.1, dim=0)
            indices = torch.multinomial(probs, batch_size, replacement=True)
            return [task_pool[i] for i in indices]
        else:
            return random.sample(task_pool, min(batch_size, len(task_pool)))

    def meta_train_step(self, task_batch, loss_fn):
        total_loss = 0.0
        self.optimizer.zero_grad()
        for i, task_data in enumerate(task_batch):
            with torch.cuda.amp.autocast(enabled=self.mixed_precision):
                meta_losses = self.inner_loop.fast_adapt(task_data, loss_fn)
                loss_sum = sum(meta_losses.values())
            self.scaler.scale(loss_sum / self.gradient_accumulation_steps).backward()
            total_loss += loss_sum.item()
            if (i + 1) % self.gradient_accumulation_steps == 0:
                if self.max_grad_norm > 0:
                    self.scaler.unscale_(self.optimizer)
                    torch.nn.utils.clip_grad_norm_(self.model.parameters(), self.max_grad_norm)
                self.scaler.step(self.optimizer)
                self.scaler.update()
                self.optimizer.zero_grad()
        if len(task_batch) % self.gradient_accumulation_steps != 0:
            if self.max_grad_norm > 0:
                self.scaler.unscale_(self.optimizer)
                torch.nn.utils.clip_grad_norm_(self.model.parameters(), self.max_grad_norm)
            self.scaler.step(self.optimizer)
            self.scaler.update()
            self.optimizer.zero_grad()
        return total_loss / len(task_batch)

    def adapt_to_task(self, sx, sy, qx, qy, loss_fn):
        """
        Run per-adapter inner-loop adaptation for a single task.

        Bugfix: this method already accepted the query labels ``qy`` but dropped
        them on the floor, calling ``fast_adapt(sx, sy, qx, loss_fn)`` with the
        query labels missing. That is the root cause of the dangling ``query_y``
        reference inside ``fast_adapt``: the meta-objective is defined against the
        query labels, so they must be threaded all the way through.
        """
        ml, A_d, B_d = {}, {}, {}
        for name in self.adapter_names:
            mod = self._get_module(name)
            if hasattr(mod, 'fast_adapt'):
                l, A, B = mod.fast_adapt(sx, sy, qx, qy, loss_fn)
                ml[name] = l
                A_d[name] = A
                B_d[name] = B
        if not ml:
            raise RuntimeError(
                "adapt_to_task: no adapter module exposed fast_adapt; "
                f"checked {list(self.adapter_names)}"
            )
        return sum(ml.values()) / len(ml), (A_d, B_d)

    def ood_score(self, x):
        logits = torch.stack([clf(x) for clf in self.ood_classifiers])
        probs = F.softmax(logits / self.ood_temperature, dim=-1)
        return probs.mean(dim=0)[..., 1]

class CrossTaskAttention(nn.Module):
    def __init__(self, dim, num_heads=128, dropout=0.1, memory_slots=64, use_rope=False, max_len=10000):
        super().__init__()
        self.attn = nn.MultiheadAttention(dim, num_heads, batch_first=True, dropout=dropout)
        self.norm = nn.LayerNorm(dim)
        self.proj = nn.Linear(dim, dim)
        self.dropout = nn.Dropout(dropout)
        self.gate = nn.Parameter(torch.zeros(1))
        self.memory = nn.Parameter(torch.randn(memory_slots, dim))
        self.memory_attn = nn.MultiheadAttention(dim, num_heads, batch_first=True)
        self.use_rope = use_rope
        if use_rope:
            self.rope = RotaryPositionalEmbedding(dim, max_len)

    def forward(self, x):
        if self.use_rope:
            x = self.rope(x)
        attn_out, _ = self.attn(x, x, x)
        mem = self.memory.unsqueeze(0).expand(x.size(0), -1, -1)
        mem_out, _ = self.memory_attn(attn_out, mem, mem)
        combined = x + torch.sigmoid(self.gate) * self.dropout(self.proj(attn_out + mem_out))
        return self.norm(combined)

class TaskEncoder(nn.Module):
    def __init__(self, dim, num_tasks=1000000, emb_dim=128, num_heads=64, num_protos=2048,
                 use_residual=True, layer_wise_cond=False):
        super().__init__()
        self.task_embed = nn.Embedding(num_tasks, emb_dim)
        self.fuser = nn.Sequential(nn.Linear(dim + emb_dim, dim), nn.GELU(), nn.Linear(dim, dim))
        self.cross_attn = CrossTaskAttention(dim, num_heads)
        self.protos = nn.Parameter(torch.randn(num_protos, dim))
        self.proto_attn = nn.MultiheadAttention(dim, num_heads, batch_first=True)
        self.use_residual = use_residual
        self.layer_wise_cond = layer_wise_cond
        if layer_wise_cond:
            self.gamma = nn.Linear(dim, dim)
            self.beta = nn.Linear(dim, dim)

    def forward(self, x, task_id):
        task_emb = self.task_embed(task_id).unsqueeze(1).expand(-1, x.size(1), -1)
        fused = self.fuser(torch.cat([x, task_emb], dim=-1))
        proto = self.protos.unsqueeze(0).expand(x.size(0), -1, -1)
        proto_out, _ = self.proto_attn(fused, proto, proto)
        if self.use_residual:
            fused = fused + proto_out
        if self.layer_wise_cond:
            gamma = torch.sigmoid(self.gamma(fused.mean(dim=1, keepdim=True)))
            beta = self.beta(fused.mean(dim=1, keepdim=True))
            fused = fused * gamma + beta
        return self.cross_attn(fused)

class HyperMetaNetwork(nn.Module):
    def __init__(self, dim, hidden=None, num_tasks=3000, num_experts=8, top_k=2,
                 load_balance_weight=0.01, dynamic_k=False):
        super().__init__()
        # Bugfix: these defaulted to hidden=8192, num_experts=64,
        # num_tasks=1_000_000, giving ~340MB per layer (64 experts x
        # Linear(dim,8192) + a 1M x 8192 task embedding). A per-layer
        # hypernetwork needs neither a huge hidden width nor dozens of experts;
        # scale hidden to the model width and keep the expert count modest.
        hidden = int(hidden or max(256, dim * 2))
        num_experts = int(min(num_experts, 8))
        self.num_experts = num_experts
        self.top_k = int(min(top_k, num_experts))
        self.dynamic_k = dynamic_k
        self.load_balance_weight = load_balance_weight
        # Task embedding is dim-sized (projected to hidden on demand), not a
        # giant hidden-sized table replicated per layer.
        self.task_embed = nn.Embedding(num_tasks, dim)
        self.task_proj = nn.Linear(dim, hidden)
        self.router = nn.Linear(dim + hidden, num_experts)
        self.experts = nn.ModuleList([
            nn.Sequential(nn.Linear(dim, hidden), nn.GELU(), nn.Linear(hidden, 2*dim))
            for _ in range(num_experts)
        ])
        self.gate = nn.Parameter(torch.zeros(1))
        if dynamic_k:
            self.k_net = nn.Linear(dim + hidden, 1)

    def forward(self, x, task_id):
        task_vec = self.task_proj(self.task_embed(task_id))     # dim -> hidden
        context = x.mean(dim=(1,2))
        router_input = torch.cat([context, task_vec], dim=-1)
        router_logits = self.router(router_input)
        probs = torch.softmax(router_logits, dim=-1)
        if self.dynamic_k:
            k = max(1, min(self.num_experts, int(torch.sigmoid(self.k_net(router_input)) * self.num_experts)))
        else:
            k = self.top_k
        topk_probs, topk_idx = torch.topk(probs, k)
        topk_probs = topk_probs / topk_probs.sum(dim=-1, keepdim=True)
        out = 0.0
        for i in range(k):
            expert_out = self.experts[topk_idx[0,i]](context)
            out += topk_probs[0,i] * expert_out
        shift, scale = out.chunk(2, dim=-1)
        return x * (1 + torch.sigmoid(self.gate) * scale.unsqueeze(1).unsqueeze(2)) + shift.unsqueeze(1).unsqueeze(2)

class MetaBlockWrapper(nn.Module):
    def __init__(self, block, task_encoder, hyper_meta, activation_ckpt=True,
                 use_meta_dropout=False, meta_drop_rate=0.1, use_layer_skip=False):
        super().__init__()
        self.block = block
        self.task_encoder = task_encoder
        self.hyper_meta = hyper_meta
        self.activation_ckpt = activation_ckpt
        self.use_meta_dropout = use_meta_dropout
        self.meta_dropout = nn.Dropout(meta_drop_rate) if use_meta_dropout else None
        self.use_layer_skip = use_layer_skip
        if use_layer_skip:
            self.skip_gate = nn.Linear(block.config.hidden_size if hasattr(block,'config') else 512, 1)

    def forward(self, x, start_pos, input_ids, task_emb=None, session_id=None, task_id=None):
        if task_id is not None:
            x = self.task_encoder(x, task_id)
            if self.meta_dropout is not None and self.training:
                x = self.meta_dropout(x)
        if self.use_layer_skip:
            skip = torch.sigmoid(self.skip_gate(x.mean(dim=1)))
            identity = x
        if self.activation_ckpt and self.training:
            x = torch.utils.checkpoint.checkpoint(self._inner, x, start_pos, input_ids, task_emb, session_id)
        else:
            x = self._inner(x, start_pos, input_ids, task_emb, session_id)
        if task_id is not None:
            x = self.hyper_meta(x, task_id)
        if self.use_layer_skip:
            x = skip * x + (1 - skip) * identity
        return x

    def _inner(self, x, start_pos, input_ids, task_emb, session_id):
        return self.block(x, start_pos, input_ids, task_emb, session_id)

def inject_meta_into_transformer(transformer, num_tasks=1000000, adapter_rank=128, activation_ckpt=True,
                                 selective_injection=True, importance_threshold=0.5):
    """
    Wrap a Transformer's blocks in meta-learning adapters.

    Two bugs fixed here:

    1. The function read ``transformer.config.hidden_size``, a HuggingFace
       convention. The core :class:`Transformer` in this codebase stores its
       configuration as ``.args`` (a :class:`ModelArgs`) whose width field is
       ``dim``, so every call raised ``AttributeError: 'Transformer' object has
       no attribute 'config'``. Width is now resolved from either convention.

    2. ``selective_injection`` chose which layers to wrap using
       ``torch.rand(1).item() < importance_threshold`` -- i.e. at random. That
       makes the *architecture itself* nondeterministic: two runs with identical
       seeds and config would produce models with different module trees, and a
       checkpoint saved from one could not be loaded into the other. Selection is
       now a deterministic stride derived from ``importance_threshold``, so the
       same config always yields the same graph.
    """
    cfg = getattr(transformer, 'args', None) or getattr(transformer, 'config', None)
    if cfg is None:
        raise AttributeError(
            "inject_meta_into_transformer: model exposes neither `.args` (ModelArgs) "
            "nor `.config`; cannot determine hidden width."
        )
    hidden = getattr(cfg, 'dim', None) or getattr(cfg, 'hidden_size', None)
    if not hidden:
        raise AttributeError(
            "inject_meta_into_transformer: config has neither `dim` nor `hidden_size`."
        )

    transformer.meta_enabled = True
    transformer.num_tasks = num_tasks

    n_layers = len(transformer.layers)
    if selective_injection:
        # Wrap a deterministic subset: keep roughly (1 - importance_threshold)
        # of the layers, evenly spaced, always including the last one (which
        # carries the most task-specific signal).
        keep_frac = max(0.0, min(1.0, 1.0 - float(importance_threshold)))
        n_keep = max(1, int(round(n_layers * keep_frac))) if keep_frac > 0 else 0
        if n_keep == 0:
            targets = set()
        else:
            stride = max(1, n_layers // n_keep)
            targets = {i for i in range(n_layers - 1, -1, -stride)}
    else:
        targets = set(range(n_layers))

    for i in sorted(targets):
        layer = transformer.layers[i]
        enc = TaskEncoder(hidden, num_tasks=num_tasks, layer_wise_cond=True)
        hyper = HyperMetaNetwork(hidden, num_tasks=num_tasks, dynamic_k=True)
        wrapper = MetaBlockWrapper(layer, enc, hyper, activation_ckpt,
                                   use_meta_dropout=True, use_layer_skip=True)
        transformer.layers[i] = wrapper

    transformer.meta_injected_layers = sorted(targets)
    return transformer

def inject_moe(model: nn.Module, experts_per_layer: int = 128, top_k_experts: int = 8,
               moe_inter_dim: Optional[int] = None, n_shared_experts: int = 1,
               skip_names: Optional[List[str]] = None) -> nn.Module:
    """
    Replace the dense feed-forward network of every transformer ``Block`` with a
    sparse Mixture-of-Experts layer.

    This walks the module tree looking for ``Block`` instances (the core layer
    class) and swaps their ``.ffn`` submodule for a :class:`MoE` configured with
    ``experts_per_layer`` routed experts, of which ``top_k_experts`` fire per
    token. Blocks that already carry a sparse FFN (``MoE`` or ``DeepSeekMoE``)
    are left untouched, so calling this twice is idempotent rather than
    destructive.

    The expert width defaults to the width of the dense FFN it replaces, which
    keeps per-expert capacity comparable to the original layer instead of
    silently changing the model's representational budget.

    Args:
        model:             any module tree containing ``Block`` layers.
        experts_per_layer: number of routed experts created per block.
        top_k_experts:     experts activated per token.
        moe_inter_dim:     expert hidden width; inferred from the dense FFN if None.
        n_shared_experts:  always-on experts that every token passes through.
        skip_names:        substrings of module names to leave alone.

    Returns:
        The same model object, mutated in place (returned for call chaining).
    """
    if skip_names is None:
        skip_names = ["embed", "head", "lm_head"]

    converted = 0
    for name, module in model.named_modules():
        if not isinstance(module, Block):
            continue
        if any(s in name for s in skip_names):
            continue
        ffn = getattr(module, "ffn", None)
        if ffn is None or isinstance(ffn, (HarmonicFlowFFN, HarmonicFlowMoE)):
            continue

        # Infer the dense FFN's hidden width so experts keep comparable capacity.
        inter_dim = moe_inter_dim
        if inter_dim is None:
            for attr in ("w1", "gate_proj", "fc1", "up_proj"):
                sub = getattr(ffn, attr, None)
                if sub is not None and hasattr(sub, "out_features"):
                    inter_dim = int(sub.out_features)
                    break

        dim = int(getattr(module, "dim", 0)) or int(
            getattr(getattr(module, "attn", None), "dim", 0)
        )
        if dim <= 0:
            # Fall back to reading the norm's width, which every Block carries.
            norm = getattr(module, "ffn_norm", None) or getattr(module, "attn_norm", None)
            dim = int(getattr(norm, "dim", 0) or getattr(norm, "normalized_shape", [0])[0])
        if dim <= 0:
            continue

        module.ffn = HarmonicFlowFFN(
            dim=dim,
            hidden=inter_dim,
            n_flows=max(2, min(int(experts_per_layer), 16)),
            n_harmonics=4,
        )
        converted += 1

    model.moe_injected_layers = converted
    return model


def build_310t_meta_model(vocab_size=256000, num_layers=6200, dim=65536, heads=256,
                          adapter_rank=128, num_tasks=1000000, use_moe=True,
                          experts_per_layer=128, top_k_experts=8,
                          tensor_parallel=64, pipeline_parallel=256, expert_parallel=64,
                          world_size=16384, micro_batch=1, global_batch=4096,
                          max_seq_len=32768, offload_optimizer=True, zero_stage=3,
                          use_smmqp=True, smmqp_bundle_size=10000):
    """
    Construct a very large meta-learning model on top of the core stack.

    Bugfix / architectural correction: this builder previously instantiated a
    ``MetaTransformerForCausalLM`` from a HuggingFace ``LlamaConfig``. That class
    does not exist anywhere in the codebase, so the function raised ``NameError``
    on its first line and had never been executed. It also violated the project's
    central rule -- that every component is built from the three core classes
    (``Block``, ``Transformer``, ``ModelArgs``) -- by routing around them into a
    foreign model class.

    It now builds a real ``Transformer`` from a real ``ModelArgs``, so the
    quantisation, MoE-injection and meta-injection passes below all operate on
    the genuine core stack.
    """
    args = ModelArgs(
        vocab_size=vocab_size,
        n_layers=num_layers,
        dim=dim,
        n_heads=heads,
        max_seq_len=max_seq_len,
        max_batch_size=max(1, micro_batch),
        q_mode="standard" if use_smmqp else "standard",
        q_bundle_size=smmqp_bundle_size,
        use_meta_learning=True,
        meta_num_tasks=num_tasks,
        meta_adapter_rank=adapter_rank,
    )
    model = Transformer(args)

    if use_smmqp:
        convert_to_q_parameters(
            model,
            bundle_size=smmqp_bundle_size,
            device_base=torch.device('cpu'),
            cache_size=512,
            base_dtype=torch.float16,
            skip_layer_names=['embed', 'head'],
            save_base_weights=True,
            q_init_type='normal_1.0',
            mode='standard',
        )

    model = inject_meta_into_transformer(model, num_tasks, adapter_rank,
                                         activation_ckpt=True, selective_injection=True)
    if use_moe:
        model = inject_moe(model, experts_per_layer, top_k_experts)

    meta = MetaLearner(model, adapter_rank=adapter_rank, meta_lr=1e-5, inner_lr=0.001,
                       gradient_accumulation_steps=max(1, global_batch // max(1, micro_batch * world_size)),
                       mixed_precision=True, use_fsdp=False,
                       expert_parallel_size=expert_parallel, pipeline_parallel_size=pipeline_parallel,
                       tensor_parallel_size=tensor_parallel, offload_optimizer=offload_optimizer,
                       zero_stage=zero_stage, micro_batch_size=micro_batch,
                       world_size=world_size, sequence_parallel=True,
                       meta_optimizer="lamb", use_lookahead_meta=True,
                       dynamic_task_sampling=True, ood_ensemble_size=5)

    if world_size > 1:
        if not HAS_FSDP:
            raise RuntimeError(
                "build_310t_meta_model: world_size > 1 requires torch.distributed.fsdp, "
                "which is not available in this PyTorch build."
            )
        # The original code passed a *string* sharding strategy and a raw dtype as
        # `mixed_precision`; FSDP requires the ShardingStrategy enum and a
        # MixedPrecision policy object respectively.
        meta = FSDP(
            meta,
            sharding_strategy=ShardingStrategy.HYBRID_SHARD,
            mixed_precision=MixedPrecision(
                param_dtype=torch.float16,
                reduce_dtype=torch.float16,
                buffer_dtype=torch.float16,
            ),
            device_id=torch.cuda.current_device() if torch.cuda.is_available() else None,
        )
    return meta

class TXTRenderer:
    def __init__(self, use_encryption=False, encryption_key=None, compression='zstd', cache_size=0):
        self.use_encryption = use_encryption
        self.encryption_key = encryption_key
        self.compression = compression
        self.cache = lru_cache(maxsize=cache_size) if cache_size > 0 else None
    def render(self, content, structure=None):
        data = content.encode('utf-8')
        if self.compression == 'zstd':
            import zstandard as zstd
            cctx = zstd.ZstdCompressor(level=3)
            data = cctx.compress(data)
        if self.use_encryption and self.encryption_key:
            from cryptography.fernet import Fernet
            f = Fernet(self.encryption_key)
            data = f.encrypt(data)
        return data

class CodeRenderer:
    def __init__(self, lang, formatter=None, linter=None, minify=False):
        self.lang = lang
        self.formatter = formatter
        self.linter = linter
        self.minify = minify
    def render(self, content, structure=None):
        code = content
        if self.formatter:
            code = self.formatter(code)
        if self.linter:
            warnings = self.linter(code)
            if warnings:
                code = f"// LINT WARNINGS:\n// {warnings}\n{code}"
        if self.minify:
            import jsbeautifier
            code = jsbeautifier.beautify(code) if self.lang in ('javascript','typescript') else code
        return code.encode('utf-8')

class DOCXRenderer:
    def render(self, content, structure=None, template=None):
        if not HAS_DOCX: raise ImportError("python-docx required")
        if structure is None:
            try: structure = json.loads(content)
            except: structure = None
        doc = DocxDocument(template) if template else DocxDocument()
        if structure and 'paragraphs' in structure:
            for pdata in structure['paragraphs']:
                p = doc.add_paragraph()
                if 'text' in pdata:
                    run = p.add_run(pdata['text'])
                    if 'bold' in pdata: run.bold = pdata['bold']
                    if 'italic' in pdata: run.italic = pdata['italic']
                    if 'color' in pdata:
                        from docx.shared import RGBColor
                        run.font.color.rgb = RGBColor(*pdata['color'])
                if 'align' in pdata:
                    a = pdata['align'].lower()
                    if a == 'center': p.alignment = WD_ALIGN_PARAGRAPH.CENTER
                    elif a == 'right': p.alignment = WD_ALIGN_PARAGRAPH.RIGHT
                if 'style' in pdata:
                    p.style = pdata['style']
        else:
            doc.add_paragraph(content)
        buf = io.BytesIO()
        doc.save(buf)
        return buf.getvalue()

class PDFRenderer:
    def render(self, content, structure=None, font_path=None):
        if not HAS_REPORTLAB: raise ImportError("reportlab required")
        if structure is None:
            try: structure = json.loads(content)
            except: structure = None
        buf = io.BytesIO()
        doc = SimpleDocTemplate(buf, pagesize=A4)
        styles = getSampleStyleSheet()
        if font_path:
            from reportlab.pdfbase import pdfmetrics
            from reportlab.pdfbase.ttfonts import TTFont
            pdfmetrics.registerFont(TTFont('CustomFont', font_path))
            styles['Normal'].fontName = 'CustomFont'
        story = []
        if structure and 'paragraphs' in structure:
            for pdata in structure['paragraphs']:
                text = pdata.get('text', '')
                style = styles['Bold'] if pdata.get('bold') else styles['Normal']
                if 'fontSize' in pdata:
                    style.fontSize = pdata['fontSize']
                story.append(Paragraph(text, style))
                story.append(Spacer(1, 6))
        else:
            for line in content.split('\n'):
                story.append(Paragraph(line, styles['Normal']))
                story.append(Spacer(1, 6))
        doc.build(story)
        return buf.getvalue()

class PPTXRenderer:
    def render(self, content, structure=None, template=None):
        if not HAS_PPTX: raise ImportError("python-pptx required")
        if structure is None:
            try: structure = json.loads(content)
            except: structure = None
        prs = Presentation(template) if template else Presentation()
        if structure and 'slides' in structure:
            for sdata in structure['slides']:
                slide = prs.slides.add_slide(prs.slide_layouts[1])
                if 'title' in sdata: slide.shapes.title.text = sdata['title']
                if 'content' in sdata: slide.placeholders[1].text = sdata['content']
                if 'image' in sdata:
                    from pptx.util import Inches
                    slide.shapes.add_picture(sdata['image'], Inches(1), Inches(2), Inches(6), Inches(4))
        else:
            slide = prs.slides.add_slide(prs.slide_layouts[1])
            slide.shapes.title.text = "Generated Content"
            slide.placeholders[1].text = content
        buf = io.BytesIO()
        prs.save(buf)
        return buf.getvalue()

class UltraFileGenerator(nn.Module):
    def __init__(self, model, device='cpu', use_meta_planning=False):
        super().__init__()
        self.model = model
        self.device = device
        self.args = model.args
        self.generator = InternetAugmentedGenerator(model) if hasattr(model, 'internet_augmented_generator') else model
        self.renderers = {
            'txt': TXTRenderer(compression='zstd'), 'md': TXTRenderer(compression='zstd'),
            'json': TXTRenderer(compression='zstd'), 'yaml': TXTRenderer(compression='zstd'),
            'csv': TXTRenderer(compression='zstd'), 'xml': TXTRenderer(compression='zstd'),
            'docx': DOCXRenderer(), 'pdf': PDFRenderer(), 'pptx': PPTXRenderer(),
            'html': TXTRenderer(), 'rtf': TXTRenderer(), 'odt': TXTRenderer()
        }
        self.use_meta_planning = use_meta_planning
        if use_meta_planning:
            self.meta_planner = MetaLearner(model, adapter_rank=8, meta_lr=1e-4, inner_lr=0.001)

    def _generate_text(self, prompt, max_tokens=2048, temperature=0.7, top_p=0.95, repetition_penalty=1.1):
        token_ids = torch.tensor([[ord(c) % self.args.vocab_size for c in prompt]], device=self.device)
        output_ids = self.generator.generate(token_ids, max_new_tokens=max_tokens, temperature=temperature,
                                             top_p=top_p, repetition_penalty=repetition_penalty,
                                             do_sample=True, num_beams=1)
        return ''.join(chr((i % 256) + 32) for i in output_ids[0].tolist())

    def generate_file(self, prompt, format='txt', language=None, max_tokens=2048, structure=None, **kwargs):
        if format == 'code':
            lang = language or 'python'
            full_prompt = f"Write a {lang} program that {prompt}. Output only the code."
        elif format in ('json', 'yaml', 'csv', 'xml'):
            full_prompt = f"Generate valid {format.upper()} data that {prompt}."
        elif format in ('docx', 'pdf', 'pptx'):
            full_prompt = f"Generate a JSON structure for a {format.upper()} document about {prompt}. The JSON must contain the document content."
        else:
            full_prompt = prompt
        if self.use_meta_planning:
            plan_prompt = f"Plan the structure for: {full_prompt}"
            plan = self._generate_text(plan_prompt, max_tokens=512)
            full_prompt = f"{full_prompt}\nStructure plan:\n{plan}"
        raw_text = self._generate_text(full_prompt, max_tokens=max_tokens, **kwargs)
        if format == 'code':
            renderer = CodeRenderer(lang)
        else:
            renderer = self.renderers.get(format, TXTRenderer())
        return renderer.render(raw_text, structure=structure)

class NeuralVocoder(nn.Module):
    def __init__(self, mel_dim=80, base_channels=512, upsample_rates=(8,8,2,2)):
        super().__init__()
        self.pre_conv = nn.Conv1d(mel_dim, base_channels, 7, padding=3)
        self.ups = nn.ModuleList()
        self.res_blocks = nn.ModuleList()
        ch = base_channels
        for rate in upsample_rates:
            self.ups.append(nn.ConvTranspose1d(ch, ch // 2, rate * 2, rate, padding=rate // 2))
            ch //= 2
            self.res_blocks.append(nn.ModuleList([ResBlock1d(ch, 2**i, use_skip_scale=True) for i in range(3)]))
        self.post_conv = nn.Sequential(nn.LeakyReLU(0.1), nn.Conv1d(ch, 1, 7, padding=3), nn.Tanh())
    def forward(self, mel):
        x = self.pre_conv(mel)
        for up, res_group in zip(self.ups, self.res_blocks):
            x = up(x)
            xs = 0
            for res in res_group:
                xs += res(x)
            x = xs / len(res_group)
        return self.post_conv(x).squeeze(1)

class UltraAudioDecoder(nn.Module):
    def __init__(self, parent_args, sample_rate=48000, mel_dim=80, hop_length=256,
                 chunk_duration=10.0, max_duration_sec=7200.0, use_moe=True,
                 style_dim=512, text_ctx_dim=1024):
        super().__init__()
        self.sample_rate = sample_rate
        self.mel_dim = mel_dim
        self.chunk_duration = chunk_duration
        self.hop_length = hop_length
        self.style_dim = style_dim
        self.text_ctx_dim = text_ctx_dim
        # Bugfix: both of these take `dim` (an int) as their first parameter, but
        # were being handed the `parent_args` ModelArgs object.
        self.structure_level = AudioStructureLevel(parent_args.dim, struct_dim=1024, num_layers=6,
                                                   max_duration_sec=max_duration_sec,
                                                   token_interval=chunk_duration)
        self.chunk_level = AudioChunkLevel(parent_args.dim, mel_dim=mel_dim,
                                           chunk_duration=chunk_duration,
                                           sample_rate=sample_rate//2 if sample_rate>=48000 else sample_rate,
                                           hop_length=hop_length, hidden_dim=2048,
                                           num_layers=12, use_moe=use_moe)
        self.vocoder = NeuralVocoder(mel_dim=mel_dim, base_channels=512, upsample_rates=(8,8,2,2))
        self.sr_audio = AudioSuperResolution(in_channels=1, out_channels=1, scale_factor=2, hidden_dim=128)
        self.blender = CrossfadeBlender(fade_len=480)
        self.style_from_latent = nn.Linear(parent_args.dim, style_dim)
        self.style_from_text  = nn.Linear(text_ctx_dim, style_dim, bias=False) if text_ctx_dim > 0 else None

    def _get_style(self, latent, text_ctx=None):
        style = self.style_from_latent(latent)
        if self.style_from_text is not None and text_ctx is not None:
            if text_ctx.dim() == 3: text_ctx = text_ctx.mean(dim=1)
            style = style + self.style_from_text(text_ctx)
        return style

    def forward(self, latent, text_context=None, duration_sec=10.0):
        B = latent.size(0)
        style = self._get_style(latent, text_context)
        cond = latent + 0.1 * style
        struct_tokens = self.structure_level(cond, duration_sec)
        chunks_wav = []
        for i in range(struct_tokens.size(1)):
            struct_i = struct_tokens[:, i, :]
            mel_chunk = self.chunk_level(cond, struct_i)
            wav_chunk = self.vocoder(mel_chunk)
            chunks_wav.append(wav_chunk)
        full_wav = torch.cat(chunks_wav, dim=1)
        full_wav = self.sr_audio(full_wav)
        full_wav = self.blender(full_wav)
        return full_wav, self.sample_rate

class SmartCheckpointManager:
    def __init__(self, base_dir='./checkpoints', max_deltas=100, compression_level=3, async_write=True, use_cuda_stream=False):
        self.base_dir = base_dir
        self.max_deltas = max_deltas
        self.compression_level = compression_level
        self.async_write = async_write
        self.use_cuda_stream = use_cuda_stream and torch.cuda.is_available()
        self.checkpoints = []
        self._async_threads = []
        self._lock = threading.RLock()
        os.makedirs(base_dir, exist_ok=True)

    def _compress(self, data):
        return zstd.compress(data, self.compression_level)

    def _decompress(self, data):
        return zstd.decompress(data)

    def _async_save(self, path, data):
        def _save():
            with open(path, 'wb') as f:
                f.write(data)
        if self.async_write:
            t = threading.Thread(target=_save, daemon=True)
            t.start()
            with self._lock:
                self._async_threads.append(t)
        else:
            _save()

    def _compute_diff(self, old_state, new_state):
        diff = {}
        for key in new_state:
            if key in old_state:
                diff[key] = new_state[key] - old_state[key]
            else:
                diff[key] = new_state[key]
        return diff

    def _apply_diff(self, base_state, diff):
        new_state = {}
        for key, val in base_state.items():
            if key in diff:
                new_state[key] = val + diff[key]
            else:
                new_state[key] = val.clone()
        for key in diff:
            if key not in base_state:
                new_state[key] = diff[key].clone()
        return new_state

    def save_checkpoint(self, model, step, optimizer=None, metadata=None):
        with self._lock:
            state = {
                'step': step,
                'model_state': {k: v.cpu() for k, v in model.state_dict().items()},
                'timestamp': time.time(),
                'metadata': metadata or {}
            }
            if optimizer:
                state['optimizer_state'] = optimizer.state_dict()
            if self.checkpoints:
                last_path = self.checkpoints[-1]['path']
                with open(last_path, 'rb') as f:
                    last_data = self._decompress(f.read())
                    last_state = pickle.loads(last_data)
                diff = self._compute_diff(last_state['model_state'], state['model_state'])
                diff_path = os.path.join(self.base_dir, f'diff_{step}_{int(time.time())}.zst')
                self._async_save(diff_path, self._compress(pickle.dumps(diff)))
                self.checkpoints.append({'type': 'diff', 'path': diff_path, 'step': step, 'timestamp': time.time()})
            else:
                full_path = os.path.join(self.base_dir, f'full_{step}_{int(time.time())}.pt')
                self._async_save(full_path, self._compress(pickle.dumps(state)))
                self.checkpoints.append({'type': 'full', 'path': full_path, 'step': step, 'timestamp': time.time()})
            while len(self.checkpoints) > self.max_deltas + 1:
                oldest = self.checkpoints.pop(0)
                if os.path.exists(oldest['path']):
                    os.remove(oldest['path'])

    def load_checkpoint(self, model, step=None, optimizer=None, use_latest=True):
        with self._lock:
            if not self.checkpoints:
                raise FileNotFoundError("No checkpoints available")
            if step is None and use_latest:
                target = self.checkpoints[-1]
            else:
                target = None
                for ckpt in reversed(self.checkpoints):
                    if ckpt['step'] <= step:
                        target = ckpt
                        break
                if not target:
                    raise FileNotFoundError(f"No checkpoint found for step <= {step}")
            if target['type'] == 'full':
                with open(target['path'], 'rb') as f:
                    state = pickle.loads(self._decompress(f.read()))
            else:
                full_ckpt = next((ck for ck in self.checkpoints if ck['type'] == 'full' and ck['step'] <= target['step']), None)
                if not full_ckpt:
                    raise ValueError("No full checkpoint base")
                with open(full_ckpt['path'], 'rb') as f:
                    base_state = pickle.loads(self._decompress(f.read()))['model_state']
                diffs = [ck for ck in self.checkpoints if ck['type'] == 'diff' and full_ckpt['step'] < ck['step'] <= target['step']]
                current_state = base_state
                for diff_ckpt in sorted(diffs, key=lambda x: x['step']):
                    with open(diff_ckpt['path'], 'rb') as f:
                        diff = pickle.loads(self._decompress(f.read()))
                    current_state = self._apply_diff(current_state, diff)
                state = {'model_state': current_state, 'step': target['step']}
            model.load_state_dict(state['model_state'])
            if optimizer and 'optimizer_state' in state:
                optimizer.load_state_dict(state['optimizer_state'])
            return state.get('step', 0)

    def cleanup_threads(self):
        with self._lock:
            for t in self._async_threads:
                t.join(timeout=1)
            self._async_threads.clear()


class SelfCritic(nn.Module):
    """
    Evaluates model outputs and proposes targeted improvements using a
    learned value head + contrastive self‑correction objective.
    Enhanced with automatic learning‑rate suggestion and gradient noise.
    """
    def __init__(self, model: nn.Module, dim: int = 512,
                 improvement_steps: int = 3, lr: float = 1e-4):
        super().__init__()
        self.model = model
        self.dim = dim
        self.improvement_steps = improvement_steps
        actual_dim = getattr(getattr(model, 'args', None), 'dim', dim)
        self.value_head = nn.Sequential(
            nn.Linear(actual_dim, actual_dim // 2),
            nn.GELU(),
            nn.LayerNorm(actual_dim // 2),
            nn.Linear(actual_dim // 2, 1),
        )
        self.correction_proj = nn.Linear(actual_dim, actual_dim)
        self.lr_predictor = nn.Linear(actual_dim, 1)
        self._loss_ema: float = 0.0
        self._ema_alpha: float = 0.95

    def score(self, hidden: Tensor) -> Tensor:
        return self.value_head(hidden).squeeze(-1)

    def forward(self, hidden: Tensor) -> Tuple[Tensor, Tensor]:
        score = self.score(hidden)
        corrected = hidden + 0.1 * torch.tanh(self.correction_proj(hidden))
        return corrected, score

    def evaluate_and_improve(self, model: nn.Module,
                             loss_history: List[float]) -> Dict[str, Any]:
        if not loss_history:
            return {"action": "no_data"}
        current_loss = loss_history[-1]
        self._loss_ema = (self._ema_alpha * self._loss_ema +
                          (1 - self._ema_alpha) * current_loss)
        trend = (np.polyfit(range(len(loss_history[-20:])),
                            loss_history[-20:], 1)[0]
                 if len(loss_history) >= 5 else 0.0)
        recommendations = []
        suggested_lr = None
        if trend > 0.001:
            recommendations.append("loss_increasing: reduce lr or check data")
            suggested_lr = self.lr_predictor(
                torch.tensor([current_loss, self._loss_ema]).unsqueeze(0)
            ).item()
        if current_loss > self._loss_ema * 1.5:
            recommendations.append("loss_spike: check for bad batch or NaN")
        if len(loss_history) > 10 and np.std(loss_history[-10:]) < 1e-6:
            recommendations.append("loss_plateau: try lr warmup or gradient noise")
        return {
            "current_loss": current_loss,
            "ema_loss": self._loss_ema,
            "trend": float(trend),
            "recommendations": recommendations,
            "suggested_lr": float(suggested_lr) if suggested_lr else None,
            "action": "ok" if not recommendations else "review",
        }

class EnvironmentSimulator:
    """
    Gymnasium‑compatible RL environment with configurable dynamics.
    """
    def __init__(self, obs_dim: int = 16, action_dim: int = 4,
                 max_steps: int = 1000, dt: float = 0.02):
        self.obs_dim = obs_dim
        self.action_dim = action_dim
        self.max_steps = max_steps
        self.dt = dt
        self._state = np.zeros(obs_dim)
        self._step_count = 0
        self._total_reward = 0.0
        self._dynamics: Optional[Callable] = None

    def set_dynamics(self, fn: Callable[[np.ndarray, np.ndarray], np.ndarray]) -> None:
        self._dynamics = fn
    def reset(self, seed: Optional[int] = None) -> np.ndarray:
        if seed is not None:
            np.random.seed(seed)
        self._state = np.random.randn(self.obs_dim) * 0.1
        self._step_count = 0
        self._total_reward = 0.0
        return self._state.copy()
    def step(self, action: Union[np.ndarray, List[float]]) -> Tuple:
        action = np.clip(np.asarray(action, float)[:self.action_dim], -1.0, 1.0)
        if self._dynamics:
            next_state = self._dynamics(self._state, action)
        else:
            noise = np.random.randn(self.obs_dim) * 0.01
            action_padded = np.zeros(self.obs_dim)
            action_padded[:len(action)] = action
            next_state = self._state + action_padded * self.dt + noise
        reward = float(-np.linalg.norm(next_state[:min(4, self.obs_dim)]))
        reward += float(0.1 * np.dot(action, action[:self.action_dim]))
        self._state = next_state
        self._step_count += 1
        self._total_reward += reward
        done = self._step_count >= self.max_steps
        truncated = False
        info = {"step": self._step_count, "total_reward": self._total_reward}
        return self._state.copy(), reward, done, truncated, info
class GameDeveloper:
    """
    Procedural game content generator: levels, enemies, items, quests, NPCs.
    """
    def __init__(self, seed: int = 42, difficulty: float = 1.0):
        self.seed = seed
        self.difficulty = difficulty
        self._rng = np.random.RandomState(seed)
        self._generated: List[Dict] = []

    def _gen_room(self, width: int, height: int) -> np.ndarray:
        room = np.zeros((height, width), dtype=int)
        room[0, :] = room[-1, :] = room[:, 0] = room[:, -1] = 1
        n_obstacles = int((width * height * 0.05) * self.difficulty)
        for _ in range(n_obstacles):
            r, c = self._rng.randint(1, height-1), self._rng.randint(1, width-1)
            room[r, c] = 2
        return room
    def generate(self, content_type: str = "level", **kwargs) -> Dict[str, Any]:
        result: Dict[str, Any] = {"type": content_type,
                                   "seed": self.seed,
                                   "difficulty": self.difficulty}
        if content_type == "level":
            w, h = kwargs.get("width", 20), kwargs.get("height", 15)
            grid = self._gen_room(w, h)
            enemies = int(self._rng.poisson(3 * self.difficulty))
            result.update({
                "grid": grid.tolist(),
                "n_enemies": enemies,
                "loot_quality": round(float(self._rng.beta(2, 5 / self.difficulty)), 2),
                "exits": [{"x": w-2, "y": h//2}],
            })
        elif content_type == "item":
            rarities = ["common", "uncommon", "rare", "epic", "legendary"]
            rarity_probs = [0.55, 0.25, 0.12, 0.06, 0.02]
            rarity = self._rng.choice(rarities, p=rarity_probs)
            result.update({
                "name": f"{rarity.capitalize()} Artifact",
                "rarity": rarity,
                "stats": {
                    "attack": int(self._rng.randint(5, 50) * self.difficulty),
                    "defense": int(self._rng.randint(3, 30) * self.difficulty),
                    "speed": round(float(self._rng.uniform(0.8, 1.5)), 2),
                },
            })
        elif content_type == "quest":
            objectives = ["collect", "defeat", "explore", "escort", "craft"]
            result.update({
                "objective": self._rng.choice(objectives),
                "target_count": int(self._rng.randint(1, 5) * self.difficulty),
                "reward_gold": int(self._rng.randint(100, 1000) * self.difficulty),
                "time_limit_s": int(self._rng.randint(300, 3600)),
            })
        elif content_type == "npc":
            names = ["Arlen", "Borin", "Cedra", "Durin", "Elara"]
            result.update({
                "name": self._rng.choice(names),
                "role": self._rng.choice(["merchant", "guard", "quest_giver", "wanderer"]),
                "health": int(self._rng.randint(50, 200) * self.difficulty),
                "dialogue": f"Hello, I am a {result.get('role', 'npc')}.",
            })
        self._generated.append(result)
        return result
class MusicVideoMaker:
    """
    Music‑video synchronisation engine: beat detection, scene timing.
    """
    def __init__(self, fps: float = 30.0, min_scene_s: float = 2.0):
        self.fps = fps
        self.min_scene_s = min_scene_s
        self._scenes: List[Dict] = []
        self._transitions: List[str] = ["cut", "fade", "dissolve",
                                         "wipe", "zoom"]

    def detect_beats(self, audio_features: np.ndarray,
                     bpm: Optional[float] = None) -> List[float]:
        if bpm:
            beat_interval = 60.0 / bpm
            duration = len(audio_features) / self.fps
            return [i * beat_interval for i in range(int(duration / beat_interval))]
        energy = np.convolve(audio_features ** 2,
                             np.ones(int(self.fps * 0.05)), mode='same')
        threshold = energy.mean() + energy.std()
        beats = np.where(
            (energy[1:-1] > threshold) &
            (energy[1:-1] > energy[:-2]) &
            (energy[1:-1] > energy[2:])
        )[0] / self.fps
        return beats.tolist()
    def make(self, audio_features: np.ndarray,
             visual_embeds: np.ndarray,
             bpm: Optional[float] = None) -> Dict[str, Any]:
        beats = self.detect_beats(audio_features, bpm)
        n_scenes = max(1, len(beats) // 4)
        scenes = []
        for i in range(n_scenes):
            start_beat = beats[i * 4] if i * 4 < len(beats) else i * self.min_scene_s * 4
            duration = beats[min(i * 4 + 4, len(beats) - 1)] - start_beat \
                if i * 4 + 4 < len(beats) else self.min_scene_s
            v_idx = min(i, len(visual_embeds) - 1)
            scenes.append({
                "scene_id": i,
                "start_s": round(float(start_beat), 3),
                "duration_s": round(float(max(self.min_scene_s, duration)), 3),
                "transition": self._transitions[i % len(self._transitions)],
                "visual_embed_idx": int(v_idx),
                "energy": float(
                    np.mean(audio_features[
                        int(start_beat * self.fps):
                        int(start_beat * self.fps) + int(duration * self.fps) + 1
                    ] ** 2) if len(audio_features) > 0 else 0.0
                ),
            })
        self._scenes = scenes
        return {
            "n_scenes": len(scenes),
            "total_duration_s": scenes[-1]["start_s"] + scenes[-1]["duration_s"] if scenes else 0,
            "n_beats": len(beats),
            "fps": self.fps,
            "scenes": scenes,
        }
class VRContentCreator:
    """
    VR scene builder: 3D assets, physics, interaction zones, spatial audio.
    """
    def __init__(self, world_scale: float = 1.0, gravity: float = -9.81):
        self.world_scale = world_scale
        self.gravity = gravity
        self._objects: Dict[str, Dict] = {}
        self._interaction_zones: List[Dict] = []
        self._audio_sources: List[Dict] = []

    def add_object(self, obj_id: str, mesh: str,
                   position: List[float], rotation: List[float] = None,
                   scale: List[float] = None,
                   physics: bool = True, interactable: bool = True) -> Dict[str, Any]:
        obj = {
            "id": obj_id, "mesh": mesh,
            "position": position,
            "rotation": rotation or [0.0, 0.0, 0.0],
            "scale": scale or [1.0, 1.0, 1.0],
            "physics_enabled": physics,
            "interactable": interactable,
            "velocity": [0.0, 0.0, 0.0],
            "mass": 1.0,
        }
        self._objects[obj_id] = obj
        return obj

    def add_interaction_zone(self, center: List[float],
                             radius: float, on_enter: str = "",
                             on_exit: str = "") -> str:
        zone_id = secrets.token_hex(4)
        self._interaction_zones.append({
            "id": zone_id, "center": center, "radius": radius,
            "on_enter": on_enter, "on_exit": on_exit,
        })
        return zone_id
    def physics_step(self, dt: float = 0.016) -> None:
        for obj in self._objects.values():
            if not obj["physics_enabled"]:
                continue
            obj["velocity"][1] += self.gravity * dt
            for i in range(3):
                obj["position"][i] += obj["velocity"][i] * dt
            if obj["position"][1] < 0:
                obj["position"][1] = 0
                obj["velocity"][1] = -obj["velocity"][1] * 0.3
    def create(self, scene_config: Dict[str, Any]) -> Dict[str, Any]:
        assets = scene_config.get("assets", [])
        for asset in assets:
            self.add_object(
                asset.get("id", secrets.token_hex(4)),
                asset.get("mesh", "cube"),
                asset.get("position", [0, 0, 0]),
                asset.get("rotation"), asset.get("scale"),
                asset.get("physics", True), asset.get("interactable", True),
            )
        for zone in scene_config.get("interaction_zones", []):
            self.add_interaction_zone(
                zone["center"], zone["radius"],
                zone.get("on_enter", ""), zone.get("on_exit", "")
            )
        return {
            "n_objects": len(self._objects),
            "n_interaction_zones": len(self._interaction_zones),
            "world_scale": self.world_scale,
            "gravity": self.gravity,
            "objects": list(self._objects.values()),
            "zones": self._interaction_zones,
        }
class AROverlayGenerator:
    """
    Augmented Reality overlay generator with plane detection and anchors.
    """
    def __init__(self, fov_deg: float = 60.0, max_anchors: int = 100):
        self.fov_deg = fov_deg
        self.max_anchors = max_anchors
        self._anchors: Dict[str, Dict] = {}
        self._planes: List[Dict] = []
        self._camera_pose = np.eye(4)

    def update_camera(self, pose_matrix: np.ndarray) -> None:
        self._camera_pose = np.asarray(pose_matrix, float)

    def detect_plane(self, depth_map: np.ndarray,
                     normal_threshold: float = 0.9) -> List[Dict]:
        planes = []
        h, w = depth_map.shape[:2]
        mean_depth = float(depth_map.mean())
        flat_mask = np.abs(depth_map - mean_depth) < (mean_depth * 0.1)
        n_flat = int(flat_mask.sum())
        if n_flat > (h * w * 0.1):
            cy, cx = np.argwhere(flat_mask).mean(axis=0)
            planes.append({
                "id": secrets.token_hex(4),
                "center": [float(cx / w), float(cy / h), mean_depth],
                "normal": [0.0, 1.0, 0.0],
                "extent": [float(n_flat ** 0.5 / w), float(n_flat ** 0.5 / h)],
                "confidence": float(n_flat / (h * w)),
            })
        self._planes = planes
        return planes

    def add_anchor(self, anchor_id: str, world_pos: List[float],
                   content_type: str = "image",
                   content: Optional[Dict] = None) -> Dict[str, Any]:
        if len(self._anchors) >= self.max_anchors:
            oldest = min(self._anchors, key=lambda k: self._anchors[k]["ts"])
            del self._anchors[oldest]
        anchor = {
            "id": anchor_id,
            "world_pos": world_pos,
            "content_type": content_type,
            "content": content or {},
            "ts": time.time(),
            "visible": True,
        }
        self._anchors[anchor_id] = anchor
        return anchor

    def generate(self, frame: Optional[np.ndarray] = None,
                 depth: Optional[np.ndarray] = None) -> Dict[str, Any]:
        if depth is not None:
            planes = self.detect_plane(depth)
        else:
            planes = self._planes
        visible_anchors = []
        for anch in self._anchors.values():
            pos = np.array(anch["world_pos"])
            cam_pos = self._camera_pose[:3, 3]
            in_view = np.linalg.norm(pos - cam_pos) < 50.0
            anch["visible"] = in_view
            if in_view:
                visible_anchors.append(anch)
        return {
            "n_planes": len(planes),
            "n_anchors": len(self._anchors),
            "n_visible": len(visible_anchors),
            "planes": planes,
            "visible_anchors": visible_anchors,
            "frame_id": int(time.time() * 1000),
        }
class CharacterProfile:
    """
    Character data model with emotion tracking, appearance counting, and blending.
    """
    def __init__(self, name: str, face_emb: Any,
                 outfit_desc: str, voice_emb: Any = None,
                 age: Optional[int] = None,
                 traits: Optional[List[str]] = None):
        self.name = name
        self.face_emb = face_emb
        self.outfit_desc = outfit_desc
        self.voice_emb = voice_emb
        self.age = age
        self.traits = traits or []
        self.appearances = 0
        self.emotion_history: List[Tuple[float, str]] = []

    def add_emotion(self, emotion: str) -> None:
        self.emotion_history.append((time.time(), emotion))

    def get_dominant_emotion(self, last_n: int = 20) -> str:
        if not self.emotion_history:
            return "neutral"
        recent = [e for _, e in self.emotion_history[-last_n:]]
        return max(set(recent), key=recent.count)

    def record_appearance(self) -> int:
        self.appearances += 1
        return self.appearances

    def similarity(self, other: "CharacterProfile") -> float:
        if self.face_emb is None or other.face_emb is None:
            return 0.0
        try:
            a = np.asarray(self.face_emb, float).flatten()
            b = np.asarray(other.face_emb, float).flatten()
            norm_a, norm_b = np.linalg.norm(a), np.linalg.norm(b)
            if norm_a == 0 or norm_b == 0:
                return 0.0
            return float(np.dot(a, b) / (norm_a * norm_b))
        except Exception:
            return 0.0
    def to_dict(self) -> Dict[str, Any]:
        return {
            "name": self.name,
            "age": self.age,
            "traits": self.traits,
            "outfit_desc": self.outfit_desc,
            "appearances": self.appearances,
            "dominant_emotion": self.get_dominant_emotion(),
            "has_voice": self.voice_emb is not None,
        }
    def __repr__(self) -> str:
        return (f"CharacterProfile(name={self.name!r}, age={self.age}, "
                f"appearances={self.appearances}, traits={self.traits})")
class VoiceProfile:
    """
    Voice profile with audio feature manipulation and profile blending.
    """
    def __init__(self, name: str, lang: str, speaker_emb: Any,
                 pitch_shift: float = 1.0, speed: float = 1.0,
                 timbre: Optional[Dict] = None):
        self.name = name
        self.lang = lang
        self.speaker_emb = speaker_emb
        self.pitch_shift = pitch_shift
        self.speed = speed
        self.timbre = timbre or {}
        self._recordings: List[Dict] = []

    def add_recording(self, audio_path: str, duration_s: float,
                      transcript: str = "") -> None:
        self._recordings.append({
            "path": audio_path, "duration_s": duration_s,
            "transcript": transcript, "ts": time.time(),
        })

    def apply_effects(self, audio: np.ndarray,
                      sample_rate: int = 22050) -> np.ndarray:
        if self.speed != 1.0:
            n_out = int(len(audio) / self.speed)
            indices = np.linspace(0, len(audio) - 1, n_out)
            audio = np.interp(indices, np.arange(len(audio)), audio)
        if self.pitch_shift != 1.0:
            try:
                n = len(audio)
                fft = np.fft.rfft(audio)
                n_new = int(len(fft) / self.pitch_shift)
                if n_new > 0:
                    if n_new < len(fft):
                        fft_new = fft[:n_new]
                    else:
                        fft_new = np.pad(fft, (0, n_new - len(fft)))
                    audio = np.fft.irfft(fft_new, n=n)
            except Exception:
                pass
        return audio.astype(np.float32)
    def blend(self, other: "VoiceProfile", alpha: float = 0.5) -> "VoiceProfile":
        blended_emb = None
        if self.speaker_emb is not None and other.speaker_emb is not None:
            try:
                a = np.asarray(self.speaker_emb, float)
                b = np.asarray(other.speaker_emb, float)
                blended_emb = (1 - alpha) * a + alpha * b
            except Exception:
                blended_emb = self.speaker_emb
        return VoiceProfile(
            name=f"{self.name}_{other.name}_blend",
            lang=self.lang,
            speaker_emb=blended_emb,
            pitch_shift=(1 - alpha) * self.pitch_shift + alpha * other.pitch_shift,
            speed=(1 - alpha) * self.speed + alpha * other.speed,
        )
    def to_dict(self) -> Dict[str, Any]:
        return {
            "name": self.name,
            "lang": self.lang,
            "pitch_shift": self.pitch_shift,
            "speed": self.speed,
            "timbre": self.timbre,
            "n_recordings": len(self._recordings),
            "has_embedding": self.speaker_emb is not None,
        }
    def __repr__(self) -> str:
        return (f"VoiceProfile(name={self.name!r}, lang={self.lang!r}, "
                f"pitch={self.pitch_shift}, speed={self.speed})")

class EcoModeController:
    def __init__(self, model, classifier_model=None, eco_bundle_size=64000, eco_rank=1, power_monitor=None):
        self.model = model
        self.eco_bundle_size = eco_bundle_size
        self.eco_rank = eco_rank
        dim = getattr(model.args, 'dim', 512)
        self.classifier = classifier_model or nn.Sequential(
            nn.Linear(dim, 128), nn.ReLU(), nn.Linear(128, 128), nn.ReLU(), nn.Linear(128, 1), nn.Sigmoid()
        )
        self.eco_active = False
        self._saved_configs = []
        self.power_monitor = power_monitor

    def should_use_eco(self, input_embedding, power_budget_ratio=0.5):
        if self.power_monitor and self.power_monitor.remaining_budget() < self.power_monitor.daily_budget * power_budget_ratio:
            return True
        with torch.no_grad():
            prob = self.classifier(input_embedding.mean(dim=1)).squeeze().item()
        return prob > 0.7

    def apply_eco_patches(self):
        if self.eco_active: return
        self._saved_configs.clear()
        for module in self.model.modules():
            if hasattr(module, 'current_rank') and hasattr(module, 'target_rank'):
                self._saved_configs.append((module, 'rank', module.current_rank))
                module.current_rank = self.eco_rank
            if hasattr(module, 'bundle_size') and hasattr(module, '_cache'):
                self._saved_configs.append((module, 'bundle_size', module.bundle_size))
                module.bundle_size = self.eco_bundle_size
                if hasattr(module, 'invalidate_weight_cache'):
                    module.invalidate_weight_cache()
        self.eco_active = True

    def remove_eco_patches(self):
        if not self.eco_active: return
        for module, attr, orig_val in self._saved_configs:
            setattr(module, attr, orig_val)
            if attr == 'bundle_size' and hasattr(module, 'invalidate_weight_cache'):
                module.invalidate_weight_cache()
        self._saved_configs.clear()
        self.eco_active = False

class SelfConsistencyCorrector:
    def __init__(self, model, num_samples=5, temperature=0.7, judge_model=None,
                 similarity_threshold=0.9, use_voting=True, use_confidence=True):
        self.model = model
        self.num_samples = num_samples
        self.temperature = temperature
        self.judge = judge_model
        self.similarity_threshold = similarity_threshold
        self.use_voting = use_voting
        self.use_confidence = use_confidence

    @torch.no_grad()
    def correct(self, input_ids, **generate_kwargs):
        samples = []
        log_probs = []
        for _ in range(self.num_samples):
            output = self.model.generate(input_ids, temperature=self.temperature, output_scores=True, return_dict_in_generate=True, **generate_kwargs)
            samples.append(output.sequences)
            if self.use_confidence and hasattr(output, 'scores'):
                seq_log_prob = sum(score.log_softmax(dim=-1).gather(1, output.sequences[:, 1:].unsqueeze(-1)).squeeze(-1).sum().item() for score in output.scores)
                log_probs.append(seq_log_prob)
        if self.use_voting and self.model.tokenizer is not None:
            decoded = [self.model.tokenizer.decode(s[0], skip_special_tokens=True) for s in samples]
            from collections import Counter
            if self.use_confidence and log_probs:
                vote_weights = [math.exp(lp) for lp in log_probs]
                weighted_counter = Counter()
                for text, w in zip(decoded, vote_weights):
                    weighted_counter[text] += w
                best_text = weighted_counter.most_common(1)[0][0]
                best_idx = decoded.index(best_text)
            else:
                best_text = Counter(decoded).most_common(1)[0][0]
                best_idx = decoded.index(best_text)
            return samples[best_idx]
        if self.judge is not None:
            scores = [self.judge(sample).mean().item() for sample in samples]
            best_idx = int(torch.argmax(torch.tensor(scores)).item())
            return samples[best_idx]
        return samples[0]

    @torch.no_grad()
    def correct_batch(self, input_ids, batch_size=8, **generate_kwargs):
        all_outputs = []
        for i in range(0, input_ids.size(0), batch_size):
            batch = input_ids[i:i+batch_size]
            batch_samples = []
            for _ in range(self.num_samples):
                out = self.model.generate(batch, temperature=self.temperature, **generate_kwargs)
                batch_samples.append(out)
            if self.use_voting and self.model.tokenizer is not None:
                best_batch = []
                for j in range(batch.size(0)):
                    decoded = [self.model.tokenizer.decode(s[j], skip_special_tokens=True) for s in batch_samples]
                    from collections import Counter
                    best_text = Counter(decoded).most_common(1)[0][0]
                    best_idx = decoded.index(best_text)
                    best_batch.append(batch_samples[best_idx][j:j+1])
                all_outputs.append(torch.cat(best_batch, dim=0))
            else:
                all_outputs.append(batch_samples[0])
        return torch.cat(all_outputs, dim=0)

class CodeTranslationLayer:
    def __init__(self, model, target_langs=None, use_cache=True, cache_size=100000, self_consistency=3):
        self.model = model
        self.target_langs = target_langs or [
            'python','java','cpp','c','csharp','go','rust','javascript','typescript',
            'php','ruby','swift','kotlin','scala','perl','r','matlab','lua','haskell',
            'clojure','elixir','erlang','dart','julia','fortran','cobol','assembly',
            'verilog','vhdl','html','css','sql','shell','powershell','lisp','scheme',
            'prolog','ocaml','fsharp','groovy','racket','nim','zig','vlang','odin',
            'apl','awk','bash','batch','bc','bqn','c3','chapel','crystal','d',
            'eiffel','elm','emojicode','factor','forth','gambas','gml','hack',
            'icon','idl','inform7','io','j','janet','kdb','labview','latex',
            'lilypond','logo','m4','make','max','mercury','ml','moonscript',
            'ncl','nix','nlc','pascal','plsql','purescript','q','racket','raku',
            'red','rexx','ring','sas','sed','smalltalk','solidity','spark','systemverilog',
            'tcl','tex','toml','turing','twig','vala','wren','x10','xbase','xml',
            'yang','yara','yasm','zephir','zsh'
        ]
        self.use_cache = use_cache
        self.cache = {}
        self.cache_size = cache_size
        self.self_consistency = self_consistency
        self.format_validator = FormatValidator()

    def _detect_language(self, code):
        prompt = f"Identify the programming language of the following code. Output only the language name.\n```\n{code[:500]}\n```"
        input_ids = self.model.tokenizer.encode(prompt, return_tensors='pt').to(self.model.device)
        output_ids = self.model.generate(input_ids, max_new_tokens=20, temperature=0.1)
        return self.model.tokenizer.decode(output_ids[0], skip_special_tokens=True).strip().lower()

    def translate(self, code, source_lang=None, target_lang=None):
        if target_lang is None: target_lang = 'python'
        if source_lang is None: source_lang = self._detect_language(code)
        if source_lang == target_lang: return code
        cache_key = hashlib.md5((source_lang + target_lang + code).encode()).hexdigest()
        if self.use_cache and cache_key in self.cache: return self.cache[cache_key]
        translations = []
        for _ in range(self.self_consistency):
            prompt = f"Translate the following {source_lang} code to {target_lang}. Output only the code:\n```{source_lang}\n{code[:3000]}\n```"
            input_ids = self.model.tokenizer.encode(prompt, return_tensors='pt').to(self.model.device)
            output_ids = self.model.generate(input_ids, max_new_tokens=len(code)*2+500, temperature=0.2, top_p=0.9)
            trans = self.model.tokenizer.decode(output_ids[0], skip_special_tokens=True)
            if self.format_validator:
                valid, fixed = getattr(self.format_validator, f'validate_{target_lang}', lambda x: (True, x))(trans)
                if valid: trans = fixed
            translations.append(trans)
        from collections import Counter
        best = Counter(translations).most_common(1)[0][0]
        if self.use_cache:
            if len(self.cache) >= self.cache_size: self.cache.pop(next(iter(self.cache)))
            self.cache[cache_key] = best
        return best

    def translate_file(self, file_path, source_lang=None, target_lang=None, chunk_size=3000):
        with open(file_path, 'r') as f:
            code = f.read()
        if len(code) <= chunk_size:
            return self.translate(code, source_lang, target_lang)
        chunks = [code[i:i+chunk_size] for i in range(0, len(code), chunk_size)]
        translated_chunks = [self.translate(chunk, source_lang, target_lang) for chunk in chunks]
        return '\n'.join(translated_chunks)

    def batch_translate(self, code_list, source_lang=None, target_lang=None):
        return [self.translate(code, source_lang, target_lang) for code in code_list]

    def self_consistency_translate(self, code, source_lang=None, target_lang=None, num_samples=3):
        translations = [self.translate(code, source_lang, target_lang) for _ in range(num_samples)]
        from collections import Counter
        return Counter(translations).most_common(1)[0][0]

