class EpisodeRecapGenerator(nn.Module):
    def __init__(self, dim: int, num_heads: int = 16, num_layers: int = 4,
                 max_episodes: int = 512, dropout: float = 0.1,
                 use_cross_attn: bool = True, use_hierarchical: bool = True,
                 use_temporal_decay: bool = True, use_importance_weighting: bool = True,
                 memory_slots: int = 128, recap_styles: int = 8):
        super().__init__()
        self.dim = dim
        self.num_heads = num_heads
        self.max_episodes = max_episodes
        self.use_cross_attn = use_cross_attn
        self.use_hierarchical = use_hierarchical
        self.use_temporal_decay = use_temporal_decay
        self.use_importance_weighting = use_importance_weighting
        self.memory_slots = memory_slots
        self.recap_styles = recap_styles

        self.episode_pos_embed = nn.Embedding(max_episodes, dim)
        self.temporal_decay_net = nn.Sequential(
            nn.Linear(1, dim // 4), nn.SiLU(),
            nn.Linear(dim // 4, dim // 2), nn.SiLU(),
            nn.Linear(dim // 2, dim), nn.Sigmoid()
        ) if use_temporal_decay else None

        self.importance_scorer = nn.Sequential(
            nn.Linear(dim, dim * 2), nn.GELU(),
            nn.Linear(dim * 2, dim), nn.GELU(),
            nn.Linear(dim, 1), nn.Sigmoid()
        ) if use_importance_weighting else None

        self.style_embed = nn.Embedding(recap_styles, dim)
        self.style_router = nn.Sequential(
            nn.Linear(dim, dim // 2), nn.GELU(),
            nn.Linear(dim // 2, recap_styles)
        )

        encoder_layer = nn.TransformerEncoderLayer(
            d_model=dim, nhead=num_heads, dim_feedforward=dim * 4,
            dropout=dropout, activation='gelu', batch_first=True,
            norm_first=True
        )
        self.episode_encoder = nn.TransformerEncoder(encoder_layer, num_layers=num_layers)

        if use_cross_attn:
            self.cross_attn_layers = nn.ModuleList([
                nn.MultiheadAttention(dim, num_heads, dropout=dropout, batch_first=True)
                for _ in range(num_layers)
            ])
            self.cross_norms = nn.ModuleList([nn.LayerNorm(dim) for _ in range(num_layers)])

        self.memory_keys = nn.Parameter(torch.randn(memory_slots, dim) * 0.02)
        self.memory_values = nn.Parameter(torch.randn(memory_slots, dim) * 0.02)
        self.memory_attn = nn.MultiheadAttention(dim, num_heads, batch_first=True)

        if use_hierarchical:
            self.local_compressor = nn.Sequential(
                nn.Linear(dim, dim * 2), nn.GELU(), nn.Linear(dim * 2, dim)
            )
            self.global_compressor = nn.Sequential(
                nn.Linear(dim, dim * 2), nn.GELU(), nn.Linear(dim * 2, dim)
            )
            self.hierarchy_gate = nn.Sequential(
                nn.Linear(dim * 2, dim), nn.Sigmoid()
            )

        self.conflict_detector = nn.Sequential(
            nn.Linear(dim * 2, dim), nn.GELU(),
            nn.Linear(dim, 1), nn.Sigmoid()
        )

        self.entity_tracker = nn.GRU(dim, dim, num_layers=2, batch_first=True,
                                     bidirectional=True, dropout=dropout)
        self.entity_proj = nn.Linear(dim * 2, dim)

        self.recap_head = nn.Sequential(
            nn.LayerNorm(dim),
            nn.Linear(dim, dim * 4), nn.GELU(),
            nn.Dropout(dropout),
            nn.Linear(dim * 4, dim * 2), nn.GELU(),
            nn.Linear(dim * 2, dim)
        )
        self.output_norm = nn.LayerNorm(dim)
        self.output_gate = nn.Parameter(torch.zeros(1))

        self.temporal_attn = nn.MultiheadAttention(dim, num_heads, batch_first=True)
        self.temporal_norm = nn.LayerNorm(dim)

        self.salience_predictor = nn.Sequential(
            nn.Linear(dim, dim), nn.GELU(),
            nn.Linear(dim, dim // 2), nn.GELU(),
            nn.Linear(dim // 2, 1)
        )

        self.register_buffer('episode_counter', torch.zeros(1, dtype=torch.long))
        self.register_buffer('recap_ema', torch.zeros(dim))

    def _apply_temporal_decay(self, x: Tensor, positions: Tensor) -> Tensor:
        if self.temporal_decay_net is None:
            return x
        B, T, D = x.shape
        pos_norm = positions.float().unsqueeze(-1) / max(self.max_episodes, 1)
        decay = self.temporal_decay_net(pos_norm)
        if decay.dim() == 2:
            decay = decay.unsqueeze(0).expand(B, -1, -1)
        return x * decay

    def _compute_importance(self, x: Tensor) -> Tensor:
        if self.importance_scorer is None:
            return torch.ones(x.shape[0], x.shape[1], 1, device=x.device)
        return self.importance_scorer(x)

    def _detect_conflicts(self, x: Tensor) -> Tensor:
        B, T, D = x.shape
        x_i = x.unsqueeze(2).expand(-1, -1, T, -1)
        x_j = x.unsqueeze(1).expand(-1, T, -1, -1)
        pairs = torch.cat([x_i, x_j], dim=-1).view(B * T * T, D * 2)
        conflict_scores = self.conflict_detector(pairs).view(B, T, T)
        return conflict_scores

    def _memory_augment(self, x: Tensor) -> Tensor:
        B = x.shape[0]
        keys_exp = self.memory_keys.unsqueeze(0).expand(B, -1, -1)
        vals_exp = self.memory_values.unsqueeze(0).expand(B, -1, -1)
        mem_out, _ = self.memory_attn(x, keys_exp, vals_exp)
        return x + mem_out

    def _hierarchical_compress(self, x: Tensor) -> Tensor:
        if not self.use_hierarchical:
            return x
        local_feat = self.local_compressor(x)
        global_feat = self.global_compressor(x.mean(dim=1, keepdim=True).expand_as(x))
        gate = self.hierarchy_gate(torch.cat([local_feat, global_feat], dim=-1))
        return gate * local_feat + (1 - gate) * global_feat

    def forward(self, previous_summary: Tensor,
                episode_positions: Optional[Tensor] = None,
                context: Optional[Tensor] = None,
                style_id: Optional[int] = None,
                mask: Optional[Tensor] = None) -> Tensor:
        B = previous_summary.shape[0]
        is_sequence = previous_summary.dim() == 3
        if not is_sequence:
            previous_summary = previous_summary.unsqueeze(1)
        T = previous_summary.shape[1]

        if episode_positions is None:
            episode_positions = torch.arange(T, device=previous_summary.device)

        pos_emb = self.episode_pos_embed(episode_positions.clamp(0, self.max_episodes - 1))
        if pos_emb.dim() == 2:
            pos_emb = pos_emb.unsqueeze(0).expand(B, -1, -1)
        x = previous_summary + pos_emb

        if self.use_temporal_decay:
            x = self._apply_temporal_decay(x, episode_positions)

        importance = self._compute_importance(x)
        x = x * importance

        x = self._memory_augment(x)

        encoded = self.episode_encoder(x, src_key_padding_mask=mask)

        if self.use_cross_attn and context is not None:
            for cross_attn, cross_norm in zip(self.cross_attn_layers, self.cross_norms):
                attn_out, _ = cross_attn(encoded, context, context)
                encoded = cross_norm(encoded + attn_out)

        entity_out, _ = self.entity_tracker(encoded)
        entity_feat = self.entity_proj(entity_out)
        encoded = encoded + entity_feat

        encoded = self._hierarchical_compress(encoded)

        temp_out, _ = self.temporal_attn(encoded, encoded, encoded)
        encoded = self.temporal_norm(encoded + temp_out)

        salience = self.salience_predictor(encoded)
        salience_weights = F.softmax(salience.squeeze(-1), dim=-1).unsqueeze(-1)
        pooled = (encoded * salience_weights).sum(dim=1)

        if style_id is not None:
            style_vec = self.style_embed(torch.tensor(style_id, device=x.device))
            style_logits = self.style_router(pooled)
            style_probs = F.softmax(style_logits, dim=-1)
            pooled = pooled + (style_probs @ self.style_embed.weight)
        else:
            style_logits = self.style_router(pooled)
            style_probs = F.softmax(style_logits, dim=-1)
            pooled = pooled + (style_probs @ self.style_embed.weight)

        recap = self.recap_head(pooled)
        gate = torch.sigmoid(self.output_gate)

        with torch.no_grad():
            self.recap_ema = 0.999 * self.recap_ema + 0.001 * recap.detach().mean(0)

        out = self.output_norm(gate * recap + (1 - gate) * pooled)
        return out

class SubtitleLocalizer(nn.Module):
    def __init__(self, dim: int, num_languages: int = 200, num_heads: int = 16,
                 num_layers: int = 6, dropout: float = 0.1,
                 max_seq_len: int = 2048, use_phonetic: bool = True,
                 use_cultural_adapter: bool = True, use_timing_predictor: bool = True,
                 use_formality_control: bool = True, char_vocab_size: int = 65536,
                 subword_vocab_size: int = 32000, num_dialects: int = 500):
        super().__init__()
        self.dim = dim
        self.num_languages = num_languages
        self.use_phonetic = use_phonetic
        self.use_cultural_adapter = use_cultural_adapter
        self.use_timing_predictor = use_timing_predictor
        self.use_formality_control = use_formality_control
        self.num_dialects = num_dialects

        self.lang_embed = nn.Embedding(num_languages, dim)
        self.dialect_embed = nn.Embedding(num_dialects, dim // 4)
        self.script_embed = nn.Embedding(50, dim // 4)

        self.lang_adapter_bank = nn.ParameterList([
            nn.Parameter(torch.randn(dim, dim) * 0.01)
            for _ in range(min(num_languages, 64))
        ])
        self.lang_adapter_gate = nn.Sequential(
            nn.Linear(dim, 64), nn.Sigmoid()
        )

        self.pos_embed = nn.Embedding(max_seq_len, dim)
        self.char_embed = nn.Embedding(char_vocab_size, dim // 2)
        self.subword_embed = nn.Embedding(subword_vocab_size, dim // 2)

        encoder_layer = nn.TransformerEncoderLayer(
            d_model=dim, nhead=num_heads, dim_feedforward=dim * 4,
            dropout=dropout, activation='gelu', batch_first=True, norm_first=True
        )
        self.encoder = nn.TransformerEncoder(encoder_layer, num_layers=num_layers)

        decoder_layer = nn.TransformerDecoderLayer(
            d_model=dim, nhead=num_heads, dim_feedforward=dim * 4,
            dropout=dropout, activation='gelu', batch_first=True, norm_first=True
        )
        self.decoder = nn.TransformerDecoder(decoder_layer, num_layers=num_layers)

        if use_phonetic:
            self.phonetic_encoder = nn.Sequential(
                nn.Linear(dim, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, dim)
            )
            self.phonetic_cross_attn = nn.MultiheadAttention(dim, num_heads, batch_first=True)
            self.phonetic_norm = nn.LayerNorm(dim)

        if use_cultural_adapter:
            self.cultural_context_net = nn.Sequential(
                nn.Linear(dim * 2, dim * 4), nn.GELU(),
                nn.Linear(dim * 4, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, dim)
            )
            self.cultural_gate = nn.Sequential(
                nn.Linear(dim, dim), nn.Sigmoid()
            )
            self.idiom_detector = nn.Sequential(
                nn.Linear(dim, dim), nn.GELU(),
                nn.Linear(dim, 1), nn.Sigmoid()
            )
            self.idiom_replacer = nn.Sequential(
                nn.Linear(dim * 2, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, dim)
            )

        if use_timing_predictor:
            self.reading_speed_net = nn.Sequential(
                nn.Linear(dim + 1, dim), nn.GELU(),
                nn.Linear(dim, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, 2)
            )
            self.pause_predictor = nn.Sequential(
                nn.Linear(dim, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, 1), nn.Sigmoid()
            )
            self.duration_net = nn.GRU(dim, dim // 2, batch_first=True, bidirectional=True)
            self.duration_proj = nn.Linear(dim, 1)

        if use_formality_control:
            self.formality_levels = 5
            self.formality_embed = nn.Embedding(self.formality_levels, dim // 4)
            self.formality_net = nn.Sequential(
                nn.Linear(dim + dim // 4, dim), nn.GELU(),
                nn.Linear(dim, dim)
            )

        self.rtl_detector = nn.Sequential(
            nn.Linear(dim, dim // 2), nn.GELU(),
            nn.Linear(dim // 2, 1), nn.Sigmoid()
        )
        self.cjk_handler = nn.Sequential(
            nn.Linear(dim, dim * 2), nn.GELU(),
            nn.Linear(dim * 2, dim)
        )

        self.line_break_predictor = nn.Sequential(
            nn.Linear(dim, dim // 2), nn.GELU(),
            nn.Linear(dim // 2, 1), nn.Sigmoid()
        )
        self.segment_splitter = nn.GRU(dim, dim // 2, batch_first=True, bidirectional=True)

        self.translation_quality_estimator = nn.Sequential(
            nn.Linear(dim * 2, dim), nn.GELU(),
            nn.Linear(dim, 1), nn.Sigmoid()
        )

        self.output_proj = nn.Linear(dim, dim)
        self.output_norm = nn.LayerNorm(dim)
        self.output_gate = nn.Parameter(torch.zeros(1))

        self.back_translation_encoder = nn.Sequential(
            nn.Linear(dim, dim * 2), nn.GELU(),
            nn.Linear(dim * 2, dim)
        )
        self.back_translation_attn = nn.MultiheadAttention(dim, num_heads, batch_first=True)

        self.register_buffer('lang_usage', torch.zeros(num_languages))
        self.register_buffer('quality_history', torch.zeros(100))
        self._quality_idx = 0

    def _apply_lang_adapter(self, x: Tensor, lang_id: int) -> Tensor:
        gate_weights = self.lang_adapter_gate(x)
        adapter_idx = lang_id % len(self.lang_adapter_bank)
        W = self.lang_adapter_bank[adapter_idx]
        adapted = torch.einsum('bsd,dd->bsd', x.float(), W.float()).to(x.dtype)
        return x + (gate_weights.mean(dim=-1, keepdim=True) * adapted)

    def _handle_cultural_idioms(self, x: Tensor, lang_emb: Tensor) -> Tensor:
        if not self.use_cultural_adapter:
            return x
        idiom_scores = self.idiom_detector(x)
        idiom_mask = (idiom_scores > 0.5).float()
        cultural_ctx = self.cultural_context_net(
            torch.cat([x, lang_emb.unsqueeze(1).expand_as(x)], dim=-1)
        )
        replaced = self.idiom_replacer(torch.cat([x, cultural_ctx], dim=-1))
        gate = self.cultural_gate(x)
        out = x + gate * idiom_mask * (replaced - x)
        return out

    def _predict_timing(self, x: Tensor, lang_id_tensor: Tensor) -> Dict[str, Tensor]:
        if not self.use_timing_predictor:
            return {}
        dur_out, _ = self.duration_net(x)
        durations = torch.relu(self.duration_proj(dur_out))
        lang_feat = lang_id_tensor.float().unsqueeze(-1).unsqueeze(-1).expand(
            x.shape[0], x.shape[1], 1
        )
        speed_input = torch.cat([x, lang_feat], dim=-1)
        speed_params = self.reading_speed_net(speed_input)
        reading_speed = torch.sigmoid(speed_params[..., :1]) * 20 + 5
        pause_prob = self.pause_predictor(x)
        return {
            'duration': durations.squeeze(-1),
            'reading_speed': reading_speed.squeeze(-1),
            'pause_prob': pause_prob.squeeze(-1)
        }

    def forward(self, text: Tensor, lang: Union[int, Tensor],
                source_lang: Optional[Union[int, Tensor]] = None,
                dialect_id: Optional[int] = None,
                script_id: Optional[int] = None,
                formality_level: int = 2,
                context: Optional[Tensor] = None,
                src_mask: Optional[Tensor] = None,
                tgt_mask: Optional[Tensor] = None) -> Union[Tensor, Dict[str, Tensor]]:
        B, T, D = text.shape if text.dim() == 3 else (text.shape[0], text.shape[1] if text.dim() == 2 else 1, self.dim)
        if text.dim() == 2:
            text = text.unsqueeze(0)
            B, T, D = text.shape

        lang_id = lang if isinstance(lang, int) else int(lang.item()) if lang.numel() == 1 else 0
        lang_id_clamped = min(lang_id, self.num_languages - 1)
        lang_emb = self.lang_embed(torch.tensor(lang_id_clamped, device=text.device))

        pos = torch.arange(T, device=text.device)
        pos_emb = self.pos_embed(pos.clamp(0, 1999)).unsqueeze(0).expand(B, -1, -1)
        x = text + pos_emb

        if dialect_id is not None:
            dial_emb = self.dialect_embed(
                torch.tensor(min(dialect_id, self.num_dialects - 1), device=text.device)
            )
            x = x + F.pad(dial_emb, (0, D - dial_emb.shape[-1])).unsqueeze(0).unsqueeze(0)

        x = self._apply_lang_adapter(x, lang_id_clamped)

        encoded = self.encoder(x, src_key_padding_mask=src_mask)

        if self.use_phonetic:
            phon_feat = self.phonetic_encoder(encoded)
            phon_out, _ = self.phonetic_cross_attn(encoded, phon_feat, phon_feat)
            encoded = self.phonetic_norm(encoded + phon_out)

        encoded = self._handle_cultural_idioms(encoded, lang_emb)

        tgt = encoded.clone()
        decoded = self.decoder(tgt, encoded, tgt_key_padding_mask=tgt_mask)

        if self.use_formality_control:
            form_emb = self.formality_embed(
                torch.tensor(min(formality_level, self.formality_levels - 1), device=text.device)
            )
            form_expand = form_emb.unsqueeze(0).unsqueeze(0).expand(B, T, -1)
            form_input = torch.cat([
                decoded,
                F.pad(form_expand, (0, D - form_expand.shape[-1]))
            ], dim=-1)
            decoded = self.formality_net(form_input)

        rtl_prob = self.rtl_detector(decoded).mean()
        if rtl_prob > 0.5:
            decoded = self.cjk_handler(decoded)

        line_breaks = self.line_break_predictor(decoded)
        seg_out, _ = self.segment_splitter(decoded)

        if context is not None:
            back_enc = self.back_translation_encoder(decoded)
            back_out, _ = self.back_translation_attn(decoded, context, context)
            decoded = decoded + back_out * 0.1

        quality_src = encoded.mean(dim=1)
        quality_tgt = decoded.mean(dim=1)
        quality = self.translation_quality_estimator(
            torch.cat([quality_src, quality_tgt], dim=-1)
        )

        out = self.output_proj(decoded)
        gate = torch.sigmoid(self.output_gate)
        out = self.output_norm(gate * out + (1 - gate) * decoded)

        with torch.no_grad():
            self.lang_usage[lang_id_clamped] += 1

        lang_id_tensor = torch.tensor(lang_id_clamped, device=text.device).unsqueeze(0).unsqueeze(0).expand(B, T)
        timing = self._predict_timing(out, lang_id_tensor)

        return {
            'translation': out,
            'quality': quality,
            'line_breaks': line_breaks.squeeze(-1),
            'rtl': rtl_prob,
            **timing
        }

class AudienceFeedbackSimulator(nn.Module):
    def __init__(self, dim: int, num_demographics: int = 64,
                 num_emotion_classes: int = 27, num_reaction_types: int = 16,
                 num_heads: int = 16, num_layers: int = 4,
                 memory_size: int = 512, use_temporal_dynamics: bool = True,
                 use_social_contagion: bool = True, use_cultural_bias: bool = True,
                 use_attention_modeling: bool = True, dropout: float = 0.1,
                 batch_effects: int = 8, platform_types: int = 12):
        super().__init__()
        self.dim = dim
        self.num_demographics = num_demographics
        self.num_emotion_classes = num_emotion_classes
        self.num_reaction_types = num_reaction_types
        self.use_temporal_dynamics = use_temporal_dynamics
        self.use_social_contagion = use_social_contagion
        self.use_cultural_bias = use_cultural_bias
        self.use_attention_modeling = use_attention_modeling

        self.demographic_embed = nn.Embedding(num_demographics, dim)
        self.platform_embed = nn.Embedding(platform_types, dim // 4)
        self.batch_effect_embed = nn.Embedding(batch_effects, dim // 4)

        self.demographic_mixer = nn.Sequential(
            nn.Linear(dim, dim * 2), nn.GELU(),
            nn.Linear(dim * 2, dim)
        )

        self.content_encoder = nn.Sequential(
            nn.Linear(dim, dim * 4), nn.GELU(),
            nn.Dropout(dropout),
            nn.Linear(dim * 4, dim * 2), nn.GELU(),
            nn.Linear(dim * 2, dim)
        )

        encoder_layer = nn.TransformerEncoderLayer(
            d_model=dim, nhead=num_heads, dim_feedforward=dim * 4,
            dropout=dropout, activation='gelu', batch_first=True, norm_first=True
        )
        self.context_transformer = nn.TransformerEncoder(encoder_layer, num_layers=num_layers)

        self.emotion_classifier = nn.Sequential(
            nn.Linear(dim, dim * 2), nn.GELU(),
            nn.Dropout(dropout),
            nn.Linear(dim * 2, dim), nn.GELU(),
            nn.Linear(dim, num_emotion_classes)
        )
        self.emotion_intensity = nn.Sequential(
            nn.Linear(dim, dim // 2), nn.GELU(),
            nn.Linear(dim // 2, num_emotion_classes), nn.Sigmoid()
        )

        self.reaction_head = nn.Sequential(
            nn.Linear(dim, dim * 2), nn.GELU(),
            nn.Linear(dim * 2, num_reaction_types)
        )

        self.engagement_predictor = nn.Sequential(
            nn.Linear(dim, dim * 2), nn.GELU(),
            nn.Linear(dim * 2, dim), nn.GELU(),
            nn.Linear(dim, 6)
        )

        self.sentiment_head = nn.Sequential(
            nn.Linear(dim, dim), nn.GELU(),
            nn.Linear(dim, 3)
        )

        self.virality_predictor = nn.Sequential(
            nn.Linear(dim, dim * 2), nn.GELU(),
            nn.Linear(dim * 2, dim), nn.GELU(),
            nn.Linear(dim, 1), nn.Sigmoid()
        )

        self.retention_curve = nn.Sequential(
            nn.Linear(dim, dim), nn.GELU(),
            nn.Linear(dim, 100), nn.Sigmoid()
        )

        if use_temporal_dynamics:
            self.temporal_rnn = nn.LSTM(dim, dim, num_layers=2,
                                        batch_first=True, dropout=dropout)
            self.temporal_attn = nn.MultiheadAttention(dim, num_heads, batch_first=True)
            self.recency_bias = nn.Parameter(torch.ones(1))
            self.temporal_proj = nn.Linear(dim, dim)

        if use_social_contagion:
            self.contagion_net = nn.Sequential(
                nn.Linear(dim * 2, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, dim)
            )
            self.peer_influence = nn.Parameter(torch.zeros(1))
            self.social_norm_embed = nn.Embedding(10, dim // 4)
            self.contagion_gate = nn.Sequential(nn.Linear(dim, dim), nn.Sigmoid())

        if use_cultural_bias:
            self.cultural_calibrator = nn.Sequential(
                nn.Linear(dim * 2, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, dim)
            )
            self.culture_prior = nn.Embedding(num_demographics, dim)
            self.cultural_gate = nn.Sequential(nn.Linear(dim, dim), nn.Sigmoid())

        if use_attention_modeling:
            self.attention_span_net = nn.Sequential(
                nn.Linear(dim, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, 1), nn.Sigmoid()
            )
            self.cognitive_load_estimator = nn.Sequential(
                nn.Linear(dim, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, 1), nn.Sigmoid()
            )
            self.flow_state_predictor = nn.Sequential(
                nn.Linear(dim * 2, dim), nn.GELU(),
                nn.Linear(dim, 1), nn.Sigmoid()
            )

        self.persona_memory = nn.Parameter(torch.randn(memory_size, dim) * 0.02)
        self.persona_attn = nn.MultiheadAttention(dim, num_heads, batch_first=True)
        self.persona_norm = nn.LayerNorm(dim)

        self.nps_head = nn.Sequential(
            nn.Linear(dim, dim // 2), nn.GELU(),
            nn.Linear(dim // 2, 11)
        )

        self.star_rating_head = nn.Sequential(
            nn.Linear(dim, dim // 2), nn.GELU(),
            nn.Linear(dim // 2, 5)
        )

        self.comment_sentiment = nn.Sequential(
            nn.Linear(dim, dim // 2), nn.GELU(),
            nn.Linear(dim // 2, 3)
        )

        self.rewatch_predictor = nn.Sequential(
            nn.Linear(dim, dim // 2), nn.GELU(),
            nn.Linear(dim // 2, 1), nn.Sigmoid()
        )

        self.output_proj = nn.Linear(dim, dim)
        self.output_norm = nn.LayerNorm(dim)
        self.uncertainty_head = nn.Sequential(
            nn.Linear(dim, dim // 2), nn.GELU(),
            nn.Linear(dim // 2, 1), nn.Softplus()
        )

        self.register_buffer('feedback_history', torch.zeros(1000, dim))
        self.register_buffer('history_ptr', torch.tensor(0, dtype=torch.long))
        self.register_buffer('demographic_priors', torch.zeros(num_demographics, dim))

    def _simulate_social_contagion(self, x: Tensor, peer_responses: Optional[Tensor]) -> Tensor:
        if not self.use_social_contagion or peer_responses is None:
            return x
        peer_influence = torch.sigmoid(self.peer_influence)
        contagion = self.contagion_net(torch.cat([x, peer_responses], dim=-1))
        gate = self.contagion_gate(x)
        return x + peer_influence * gate * (contagion - x)

    def _apply_cultural_bias(self, x: Tensor, demo_id: int) -> Tensor:
        if not self.use_cultural_bias:
            return x
        prior = self.culture_prior(torch.tensor(
            min(demo_id, self.num_demographics - 1), device=x.device
        ))
        prior_expand = prior.unsqueeze(0).unsqueeze(0).expand_as(x)
        calibrated = self.cultural_calibrator(torch.cat([x, prior_expand], dim=-1))
        gate = self.cultural_gate(x)
        return gate * calibrated + (1 - gate) * x

    def forward(self, content: Tensor,
                demographic_id: Optional[Union[int, Tensor]] = None,
                platform_id: Optional[int] = None,
                peer_responses: Optional[Tensor] = None,
                temporal_history: Optional[Tensor] = None,
                social_norm_id: int = 0) -> Dict[str, Tensor]:
        B = content.shape[0]
        is_seq = content.dim() == 3
        if not is_seq:
            content = content.unsqueeze(1)

        x = self.content_encoder(content)

        demo_id = 0
        if demographic_id is not None:
            demo_id = demographic_id if isinstance(demographic_id, int) else int(demographic_id.flatten()[0].item())
            demo_id = min(demo_id, self.num_demographics - 1)
            demo_emb = self.demographic_embed(torch.tensor(demo_id, device=content.device))
            demo_emb = self.demographic_mixer(demo_emb)
            x = x + demo_emb.unsqueeze(0).unsqueeze(0).expand_as(x)

        if platform_id is not None:
            plat_emb = self.platform_embed(torch.tensor(min(platform_id, 11), device=content.device))
            x = x + F.pad(plat_emb, (0, self.dim - plat_emb.shape[-1])).unsqueeze(0).unsqueeze(0).expand_as(x)

        x = self.context_transformer(x)

        persona_keys = self.persona_memory.unsqueeze(0).expand(B, -1, -1)
        persona_out, _ = self.persona_attn(x, persona_keys, persona_keys)
        x = self.persona_norm(x + persona_out)

        if self.use_temporal_dynamics and temporal_history is not None:
            if temporal_history.dim() == 2:
                temporal_history = temporal_history.unsqueeze(0).expand(B, -1, -1)
            combined = torch.cat([temporal_history, x], dim=1)
            temporal_out, _ = self.temporal_rnn(combined)
            temp_attn_out, _ = self.temporal_attn(x, temporal_out, temporal_out)
            x = x + torch.sigmoid(self.recency_bias) * self.temporal_proj(temp_attn_out)

        x = self._simulate_social_contagion(x, peer_responses)
        x = self._apply_cultural_bias(x, demo_id)

        pooled = x.mean(dim=1)

        emotion_logits = self.emotion_classifier(pooled)
        emotion_probs = F.softmax(emotion_logits, dim=-1)
        emotion_intensity = self.emotion_intensity(pooled)

        reaction_logits = self.reaction_head(pooled)
        reaction_probs = F.softmax(reaction_logits, dim=-1)

        engagement = torch.sigmoid(self.engagement_predictor(pooled))
        sentiment = F.softmax(self.sentiment_head(pooled), dim=-1)
        virality = self.virality_predictor(pooled)
        retention = self.retention_curve(pooled)
        nps = F.softmax(self.nps_head(pooled), dim=-1)
        star_rating = F.softmax(self.star_rating_head(pooled), dim=-1)
        comment_sent = F.softmax(self.comment_sentiment(pooled), dim=-1)
        rewatch = self.rewatch_predictor(pooled)
        uncertainty = self.uncertainty_head(pooled)

        attention_metrics = {}
        if self.use_attention_modeling:
            attention_span = self.attention_span_net(pooled)
            cognitive_load = self.cognitive_load_estimator(pooled)
            flow_state = self.flow_state_predictor(
                torch.cat([pooled, pooled * engagement.mean(dim=-1, keepdim=True)], dim=-1)
            )
            attention_metrics = {
                'attention_span': attention_span,
                'cognitive_load': cognitive_load,
                'flow_state': flow_state
            }

        overall_score = (
            emotion_intensity.max(dim=-1).values * 0.3 +
            engagement.mean(dim=-1) * 0.3 +
            virality.squeeze(-1) * 0.2 +
            sentiment[:, 2] * 0.2
        )

        output = self.output_norm(self.output_proj(pooled))

        with torch.no_grad():
            ptr = self.history_ptr.item()
            batch_size = min(B, 1000 - ptr)
            if batch_size > 0:
                self.feedback_history[ptr:ptr + batch_size] = output[:batch_size].detach()
                self.history_ptr = torch.tensor((ptr + batch_size) % 1000, dtype=torch.long)

        return {
            'overall_score': overall_score,
            'emotion_probs': emotion_probs,
            'emotion_intensity': emotion_intensity,
            'reaction_probs': reaction_probs,
            'engagement': engagement,
            'sentiment': sentiment,
            'virality': virality,
            'retention_curve': retention,
            'nps': nps,
            'star_rating': star_rating,
            'comment_sentiment': comment_sent,
            'rewatch_probability': rewatch,
            'uncertainty': uncertainty,
            'embedding': output,
            **attention_metrics
        }

class SentimentTrader(nn.Module):
    def __init__(self, dim: int, num_assets: int = 10000,
                 num_sentiment_sources: int = 32, num_heads: int = 16,
                 num_layers: int = 8, dropout: float = 0.1,
                 use_temporal_attention: bool = True,
                 use_cross_asset_correlation: bool = True,
                 use_macro_conditioning: bool = True,
                 use_regime_detection: bool = True,
                 use_options_flow: bool = True,
                 use_dark_pool: bool = True,
                 window_sizes: Optional[List[int]] = None,
                 num_regimes: int = 6, prediction_horizons: int = 5):
        super().__init__()
        self.dim = dim
        self.num_assets = num_assets
        self.num_sentiment_sources = num_sentiment_sources
        self.prediction_horizons = prediction_horizons
        self.use_cross_asset_correlation = use_cross_asset_correlation
        self.use_temporal_attention = use_temporal_attention
        self.use_macro_conditioning = use_macro_conditioning
        self.use_regime_detection = use_regime_detection
        self.use_options_flow = use_options_flow
        self.use_dark_pool = use_dark_pool
        self.window_sizes = window_sizes or [5, 10, 20, 60, 120, 240]
        self.num_regimes = num_regimes

        self.asset_embed = nn.Embedding(num_assets, dim)
        self.source_embed = nn.Embedding(num_sentiment_sources, dim // 4)

        self.sentiment_encoder = nn.Sequential(
            nn.Linear(dim, dim * 4), nn.GELU(),
            nn.Dropout(dropout),
            nn.Linear(dim * 4, dim * 2), nn.GELU(),
            nn.Linear(dim * 2, dim)
        )

        self.multi_scale_convs = nn.ModuleList([
            nn.Sequential(
                nn.Conv1d(dim, dim, kernel_size=w, padding=w // 2),
                nn.GELU(),
                nn.Conv1d(dim, dim, kernel_size=1)
            )
            for w in [1, 3, 7, 15]
        ])
        self.scale_fusion = nn.Linear(dim * 4, dim)

        encoder_layer = nn.TransformerEncoderLayer(
            d_model=dim, nhead=num_heads, dim_feedforward=dim * 4,
            dropout=dropout, activation='gelu', batch_first=True, norm_first=True
        )
        self.news_transformer = nn.TransformerEncoder(encoder_layer, num_layers=num_layers)

        if use_temporal_attention:
            self.temporal_self_attn = nn.MultiheadAttention(dim, num_heads, batch_first=True)
            self.temporal_norm = nn.LayerNorm(dim)
            self.temporal_rnn = nn.LSTM(dim, dim, num_layers=2, batch_first=True,
                                        bidirectional=True, dropout=dropout)
            self.temporal_proj = nn.Linear(dim * 2, dim)
            self.causal_mask_cache: Dict[int, Tensor] = {}

        if use_cross_asset_correlation:
            self.correlation_net = nn.Sequential(
                nn.Linear(dim * 2, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, dim)
            )
            self.correlation_attn = nn.MultiheadAttention(dim, num_heads, batch_first=True)
            self.correlation_norm = nn.LayerNorm(dim)

        if use_macro_conditioning:
            self.macro_encoder = nn.Sequential(
                nn.Linear(dim, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, dim)
            )
            self.macro_cross_attn = nn.MultiheadAttention(dim, num_heads, batch_first=True)
            self.macro_norm = nn.LayerNorm(dim)

        if use_regime_detection:
            self.regime_detector = nn.Sequential(
                nn.Linear(dim, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, num_regimes)
            )
            self.regime_embed = nn.Embedding(num_regimes, dim)
            self.regime_conditioner = nn.Sequential(
                nn.Linear(dim * 2, dim), nn.GELU(),
                nn.Linear(dim, dim)
            )

        if use_options_flow:
            self.options_encoder = nn.Sequential(
                nn.Linear(dim, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, dim)
            )
            self.put_call_ratio_net = nn.Sequential(
                nn.Linear(dim, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, 1), nn.Sigmoid()
            )
            self.gamma_exposure_net = nn.Sequential(
                nn.Linear(dim, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, 1)
            )

        if use_dark_pool:
            self.dark_pool_encoder = nn.Sequential(
                nn.Linear(dim, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, dim)
            )
            self.institutional_flow_detector = nn.Sequential(
                nn.Linear(dim, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, 1), nn.Sigmoid()
            )

        self.direction_head = nn.Sequential(
            nn.LayerNorm(dim),
            nn.Linear(dim, dim * 2), nn.GELU(),
            nn.Dropout(dropout),
            nn.Linear(dim * 2, 3)
        )

        self.magnitude_head = nn.Sequential(
            nn.LayerNorm(dim),
            nn.Linear(dim, dim * 2), nn.GELU(),
            nn.Linear(dim * 2, prediction_horizons)
        )

        self.volatility_head = nn.Sequential(
            nn.LayerNorm(dim),
            nn.Linear(dim, dim), nn.GELU(),
            nn.Linear(dim, prediction_horizons), nn.Softplus()
        )

        self.confidence_head = nn.Sequential(
            nn.Linear(dim, dim // 2), nn.GELU(),
            nn.Linear(dim // 2, 1), nn.Sigmoid()
        )

        self.risk_score_head = nn.Sequential(
            nn.Linear(dim, dim // 2), nn.GELU(),
            nn.Linear(dim // 2, 1), nn.Sigmoid()
        )

        self.sharpe_predictor = nn.Sequential(
            nn.Linear(dim, dim // 2), nn.GELU(),
            nn.Linear(dim // 2, prediction_horizons)
        )

        self.position_sizer = nn.Sequential(
            nn.Linear(dim, dim // 2), nn.GELU(),
            nn.Linear(dim // 2, 1), nn.Sigmoid()
        )

        self.stop_loss_predictor = nn.Sequential(
            nn.Linear(dim, dim // 2), nn.GELU(),
            nn.Linear(dim // 2, 1), nn.Softplus()
        )

        self.take_profit_predictor = nn.Sequential(
            nn.Linear(dim, dim // 2), nn.GELU(),
            nn.Linear(dim // 2, 1), nn.Softplus()
        )

        self.output_norm = nn.LayerNorm(dim)
        self.output_proj = nn.Linear(dim, dim)

        self.register_buffer('sentiment_running_mean', torch.zeros(dim))
        self.register_buffer('sentiment_running_var', torch.ones(dim))
        self.register_buffer('regime_history', torch.zeros(1000, dtype=torch.long))
        self._regime_ptr = 0

    def _get_causal_mask(self, T: int, device: torch.device) -> Tensor:
        if T not in self.causal_mask_cache:
            mask = torch.triu(torch.ones(T, T, device=device), diagonal=1).bool()
            self.causal_mask_cache[T] = mask
        return self.causal_mask_cache[T].to(device)

    def _multi_scale_encode(self, x: Tensor) -> Tensor:
        B, T, D = x.shape
        x_t = x.transpose(1, 2)
        scale_outs = []
        for conv in self.multi_scale_convs:
            out = conv(x_t)
            out = out[:, :, :T]
            scale_outs.append(out.transpose(1, 2))
        fused = torch.cat(scale_outs, dim=-1)
        return self.scale_fusion(fused)

    def forward(self, news: Tensor,
                asset_ids: Optional[Tensor] = None,
                macro_features: Optional[Tensor] = None,
                options_flow: Optional[Tensor] = None,
                dark_pool_data: Optional[Tensor] = None,
                peer_assets: Optional[Tensor] = None,
                temporal_mask: Optional[Tensor] = None) -> Dict[str, Tensor]:
        B = news.shape[0]
        is_seq = news.dim() == 3
        if not is_seq:
            news = news.unsqueeze(1)

        x = self.sentiment_encoder(news)

        if asset_ids is not None:
            asset_emb = self.asset_embed(asset_ids.clamp(0, self.num_assets - 1))
            if asset_emb.dim() == 2:
                asset_emb = asset_emb.unsqueeze(1).expand_as(x)
            x = x + asset_emb

        x = x + self._multi_scale_encode(x)
        x = self.news_transformer(x)

        if self.use_temporal_attention:
            T = x.shape[1]
            causal_mask = self._get_causal_mask(T, x.device) if T > 1 else None
            temp_out, _ = self.temporal_self_attn(x, x, x, attn_mask=causal_mask)
            x = self.temporal_norm(x + temp_out)
            rnn_out, _ = self.temporal_rnn(x)
            x = x + self.temporal_proj(rnn_out)

        if self.use_cross_asset_correlation and peer_assets is not None:
            if peer_assets.dim() == 2:
                peer_assets = peer_assets.unsqueeze(1).expand_as(x)
            corr_out, _ = self.correlation_attn(x, peer_assets, peer_assets)
            x = self.correlation_norm(x + corr_out)

        if self.use_macro_conditioning and macro_features is not None:
            if macro_features.dim() == 2:
                macro_features = macro_features.unsqueeze(1)
            macro_enc = self.macro_encoder(macro_features)
            macro_out, _ = self.macro_cross_attn(x, macro_enc, macro_enc)
            x = self.macro_norm(x + macro_out)

        if self.use_options_flow and options_flow is not None:
            if options_flow.dim() == 2:
                options_flow = options_flow.unsqueeze(1).expand_as(x)
            opt_enc = self.options_encoder(options_flow)
            x = x + opt_enc * 0.1

        if self.use_dark_pool and dark_pool_data is not None:
            if dark_pool_data.dim() == 2:
                dark_pool_data = dark_pool_data.unsqueeze(1).expand_as(x)
            dp_enc = self.dark_pool_encoder(dark_pool_data)
            x = x + dp_enc * 0.05

        pooled = x.mean(dim=1)

        regime_logits, regime_embed_out = None, None
        if self.use_regime_detection:
            regime_logits = self.regime_detector(pooled)
            regime_id = regime_logits.argmax(dim=-1)
            regime_emb = self.regime_embed(regime_id)
            pooled = self.regime_conditioner(torch.cat([pooled, regime_emb], dim=-1))

        direction_logits = self.direction_head(pooled)
        direction_probs = F.softmax(direction_logits, dim=-1)

        magnitude = self.magnitude_head(pooled)
        volatility = self.volatility_head(pooled)
        confidence = self.confidence_head(pooled)
        risk_score = self.risk_score_head(pooled)
        sharpe = self.sharpe_predictor(pooled)
        position_size = self.position_sizer(pooled)
        stop_loss = self.stop_loss_predictor(pooled)
        take_profit = self.take_profit_predictor(pooled)

        expected_return = magnitude * (direction_probs[:, 2:3] - direction_probs[:, 0:1])

        out = self.output_norm(self.output_proj(pooled))

        result = {
            'direction': direction_probs,
            'magnitude': magnitude,
            'volatility': volatility,
            'confidence': confidence,
            'risk_score': risk_score,
            'sharpe_prediction': sharpe,
            'position_size': position_size,
            'stop_loss_pct': stop_loss,
            'take_profit_pct': take_profit,
            'expected_return': expected_return,
            'embedding': out
        }
        if regime_logits is not None:
            result['regime'] = F.softmax(regime_logits, dim=-1)
        if self.use_options_flow and options_flow is not None:
            result['put_call_ratio'] = self.put_call_ratio_net(pooled)
            result['gamma_exposure'] = self.gamma_exposure_net(pooled)
        if self.use_dark_pool and dark_pool_data is not None:
            result['institutional_flow'] = self.institutional_flow_detector(pooled)
        return result

class LiveTranslatorCall(nn.Module):
    def __init__(self, dim: int, num_languages: int = 200, num_heads: int = 16,
                 num_encoder_layers: int = 8, num_decoder_layers: int = 8,
                 dropout: float = 0.1, use_streaming: bool = True,
                 use_voice_conversion: bool = True, use_speaker_diarization: bool = True,
                 use_noise_cancellation: bool = True, chunk_size_ms: int = 250,
                 use_ctc: bool = True, use_attention_alignment: bool = True,
                 vocabulary_size: int = 50000, use_prosody_transfer: bool = True,
                 use_gender_neutral_option: bool = True, latency_target_ms: int = 300):
        super().__init__()
        self.dim = dim
        self.num_languages = num_languages
        self.use_streaming = use_streaming
        self.use_voice_conversion = use_voice_conversion
        self.use_speaker_diarization = use_speaker_diarization
        self.use_noise_cancellation = use_noise_cancellation
        self.chunk_size_ms = chunk_size_ms
        self.use_ctc = use_ctc
        self.use_attention_alignment = use_attention_alignment
        self.vocabulary_size = vocabulary_size
        self.use_prosody_transfer = use_prosody_transfer
        self.latency_target_ms = latency_target_ms

        self.lang_embed = nn.Embedding(num_languages, dim)
        self.lang_pair_embed = nn.Embedding(num_languages * num_languages, dim // 4)

        self.acoustic_encoder = nn.Sequential(
            nn.Conv1d(80, dim // 2, kernel_size=3, padding=1), nn.GELU(),
            nn.Conv1d(dim // 2, dim, kernel_size=3, padding=1), nn.GELU(),
            nn.Conv1d(dim, dim, kernel_size=3, stride=2, padding=1), nn.GELU()
        )

        self.acoustic_transformer_layer = nn.TransformerEncoderLayer(
            d_model=dim, nhead=num_heads, dim_feedforward=dim * 4,
            dropout=dropout, activation='gelu', batch_first=True, norm_first=True
        )
        self.acoustic_transformer = nn.TransformerEncoder(
            self.acoustic_transformer_layer, num_layers=num_encoder_layers
        )

        if use_noise_cancellation:
            self.noise_estimator = nn.Sequential(
                nn.Conv1d(dim, dim, 3, padding=1), nn.GELU(),
                nn.Conv1d(dim, dim, 3, padding=1), nn.Sigmoid()
            )
            self.noise_suppressor = nn.Sequential(
                nn.Linear(dim, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, dim)
            )

        if use_speaker_diarization:
            self.speaker_encoder = nn.Sequential(
                nn.Linear(dim, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, dim)
            )
            self.speaker_separator = nn.GRU(dim, dim, num_layers=2,
                                             batch_first=True, bidirectional=True)
            self.speaker_proj = nn.Linear(dim * 2, dim)
            self.num_speakers_head = nn.Sequential(
                nn.Linear(dim, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, 10)
            )

        self.asr_head = nn.Linear(dim, vocabulary_size)

        if use_ctc:
            self.ctc_proj = nn.Linear(dim, vocabulary_size + 1)

        decoder_layer = nn.TransformerDecoderLayer(
            d_model=dim, nhead=num_heads, dim_feedforward=dim * 4,
            dropout=dropout, activation='gelu', batch_first=True, norm_first=True
        )
        self.translation_decoder = nn.TransformerDecoder(
            decoder_layer, num_layers=num_decoder_layers
        )

        self.tgt_token_embed = nn.Embedding(vocabulary_size, dim)
        self.tgt_pos_embed = nn.Embedding(4096, dim)

        if use_attention_alignment:
            self.alignment_net = nn.MultiheadAttention(dim, num_heads, batch_first=True)
            self.alignment_proj = nn.Linear(dim, dim)

        if use_prosody_transfer:
            self.prosody_encoder = nn.Sequential(
                nn.Linear(dim, dim), nn.GELU(),
                nn.Linear(dim, dim // 2)
            )
            self.prosody_decoder = nn.Sequential(
                nn.Linear(dim // 2, dim), nn.GELU(),
                nn.Linear(dim, dim)
            )
            self.prosody_attn = nn.MultiheadAttention(dim, num_heads, batch_first=True)
            self.pitch_predictor = nn.Sequential(
                nn.Linear(dim, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, 1)
            )
            self.energy_predictor = nn.Sequential(
                nn.Linear(dim, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, 1), nn.Softplus()
            )
            self.duration_predictor = nn.Sequential(
                nn.Linear(dim, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, 1), nn.Softplus()
            )

        if use_voice_conversion:
            self.voice_style_encoder = nn.Sequential(
                nn.Linear(dim, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, dim)
            )
            self.voice_converter = nn.Sequential(
                nn.Linear(dim * 2, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, dim)
            )
            self.speaker_embed = nn.Embedding(1000, dim // 4)

        if use_streaming:
            self.streaming_buffer = nn.GRU(dim, dim, num_layers=2, batch_first=True)
            self.streaming_state: Optional[Tensor] = None
            self.lookahead_net = nn.Sequential(
                nn.Linear(dim, dim), nn.GELU(),
                nn.Linear(dim, dim)
            )

        self.translation_head = nn.Linear(dim, vocabulary_size)
        self.confidence_head = nn.Sequential(
            nn.Linear(dim, dim // 2), nn.GELU(),
            nn.Linear(dim // 2, 1), nn.Sigmoid()
        )

        self.latency_estimator = nn.Sequential(
            nn.Linear(dim, dim // 4), nn.GELU(),
            nn.Linear(dim // 4, 1), nn.Softplus()
        )

        self.output_norm = nn.LayerNorm(dim)
        self.output_proj = nn.Linear(dim, dim)

        self.register_buffer('translation_cache', torch.zeros(256, dim))
        self.register_buffer('cache_ptr', torch.tensor(0, dtype=torch.long))

    def _noise_cancel(self, x: Tensor) -> Tensor:
        if not self.use_noise_cancellation:
            return x
        B, T, D = x.shape
        x_t = x.transpose(1, 2)
        noise_mask = self.noise_estimator(x_t).transpose(1, 2)
        clean = self.noise_suppressor(x * noise_mask)
        return x + clean - x * noise_mask

    def _diarize_speakers(self, x: Tensor) -> Tuple[Tensor, Tensor]:
        if not self.use_speaker_diarization:
            return x, torch.zeros(x.shape[0], 1, device=x.device)
        spk_feat = self.speaker_encoder(x)
        separated, _ = self.speaker_separator(spk_feat)
        separated = self.speaker_proj(separated)
        num_spk_logits = self.num_speakers_head(x.mean(dim=1))
        return separated, F.softmax(num_spk_logits, dim=-1)

    def forward(self, speech: Tensor,
                source_lang: Union[int, Tensor],
                target_lang: Union[int, Tensor],
                target_tokens: Optional[Tensor] = None,
                speaker_id: Optional[int] = None,
                is_mel_spectrogram: bool = False,
                streaming_step: bool = False,
                return_prosody: bool = False) -> Dict[str, Tensor]:
        B = speech.shape[0]

        if is_mel_spectrogram and speech.dim() == 3:
            acoustic = self.acoustic_encoder(speech.transpose(1, 2)).transpose(1, 2)
        else:
            if speech.dim() == 2:
                speech = speech.unsqueeze(1)
            B, T, D = speech.shape
            acoustic = speech

        src_id = source_lang if isinstance(source_lang, int) else int(source_lang.flatten()[0].item())
        tgt_id = target_lang if isinstance(target_lang, int) else int(target_lang.flatten()[0].item())

        src_emb = self.lang_embed(torch.tensor(min(src_id, self.num_languages - 1), device=speech.device))
        tgt_emb = self.lang_embed(torch.tensor(min(tgt_id, self.num_languages - 1), device=speech.device))

        acoustic = acoustic + src_emb.unsqueeze(0).unsqueeze(0).expand(B, acoustic.shape[1], -1)
        acoustic = self._noise_cancel(acoustic)
        acoustic, speaker_probs = self._diarize_speakers(acoustic)

        encoded = self.acoustic_transformer(acoustic)

        if self.use_streaming and streaming_step:
            if self.streaming_state is None:
                self.streaming_state = torch.zeros(
                    2, B, self.dim, device=speech.device
                )
            encoded, self.streaming_state = self.streaming_buffer(
                encoded, self.streaming_state
            )
            encoded = encoded + self.lookahead_net(encoded)

        asr_logits = self.asr_head(encoded)
        ctc_logits = self.ctc_proj(encoded) if self.use_ctc else None

        T_enc = encoded.shape[1]
        if target_tokens is not None:
            tgt_len = target_tokens.shape[1]
            tgt_pos = torch.arange(tgt_len, device=speech.device)
            tgt_emb_seq = self.tgt_token_embed(target_tokens) + \
                          self.tgt_pos_embed(tgt_pos).unsqueeze(0).expand(B, -1, -1)
            tgt_emb_seq = tgt_emb_seq + tgt_emb.unsqueeze(0).unsqueeze(0).expand_as(tgt_emb_seq)
            causal_mask = torch.triu(
                torch.ones(tgt_len, tgt_len, device=speech.device), diagonal=1
            ).bool()
            decoded = self.translation_decoder(tgt_emb_seq, encoded, tgt_mask=causal_mask)
        else:
            decoded = encoded + tgt_emb.unsqueeze(0).unsqueeze(0).expand_as(encoded)

        if self.use_attention_alignment:
            align_out, align_weights = self.alignment_net(decoded, encoded, encoded)
            decoded = decoded + self.alignment_proj(align_out)
        else:
            align_weights = None

        translation_logits = self.translation_head(decoded)
        confidence = self.confidence_head(decoded.mean(dim=1))
        latency_est = self.latency_estimator(encoded.mean(dim=1))

        result = {
            'translation_logits': translation_logits,
            'asr_logits': asr_logits,
            'confidence': confidence,
            'estimated_latency_ms': latency_est * 1000,
            'speaker_probs': speaker_probs,
            'encoded': self.output_norm(self.output_proj(encoded.mean(dim=1)))
        }

        if ctc_logits is not None:
            result['ctc_logits'] = ctc_logits
        if align_weights is not None:
            result['alignment'] = align_weights

        if return_prosody and self.use_prosody_transfer:
            prosody_feat = self.prosody_encoder(encoded)
            pitch = self.pitch_predictor(decoded)
            energy = self.energy_predictor(decoded)
            duration = self.duration_predictor(decoded)
            result.update({
                'pitch': pitch,
                'energy': energy,
                'duration': duration,
                'prosody_features': prosody_feat
            })

        return result

class CallSummarizer(nn.Module):
    def __init__(self, dim: int, num_heads: int = 16, num_encoder_layers: int = 8,
                 num_decoder_layers: int = 6, dropout: float = 0.1,
                 max_seq_len: int = 16384, vocabulary_size: int = 50000,
                 use_extractive: bool = True, use_abstractive: bool = True,
                 use_hierarchical_encoding: bool = True,
                 use_discourse_modeling: bool = True,
                 use_action_item_extraction: bool = True,
                 use_sentiment_tracking: bool = True,
                 use_topic_segmentation: bool = True,
                 use_speaker_attribution: bool = True,
                 use_decision_detection: bool = True,
                 compression_ratios: Optional[List[float]] = None,
                 summary_styles: int = 5):
        super().__init__()
        self.dim = dim
        self.num_heads = num_heads
        self.max_seq_len = max_seq_len
        self.vocabulary_size = vocabulary_size
        self.use_extractive = use_extractive
        self.use_abstractive = use_abstractive
        self.use_hierarchical_encoding = use_hierarchical_encoding
        self.use_discourse_modeling = use_discourse_modeling
        self.use_action_item_extraction = use_action_item_extraction
        self.use_sentiment_tracking = use_sentiment_tracking
        self.use_topic_segmentation = use_topic_segmentation
        self.use_speaker_attribution = use_speaker_attribution
        self.use_decision_detection = use_decision_detection
        self.compression_ratios = compression_ratios or [0.1, 0.2, 0.3, 0.5]
        self.summary_styles = summary_styles

        self.token_embed = nn.Embedding(vocabulary_size, dim)
        self.pos_embed = nn.Embedding(max_seq_len, dim)
        self.speaker_embed = nn.Embedding(50, dim // 4)
        self.turn_embed = nn.Embedding(2048, dim // 4)
        self.style_embed = nn.Embedding(summary_styles, dim)

        self.input_proj = nn.Linear(dim, dim)

        encoder_layer = nn.TransformerEncoderLayer(
            d_model=dim, nhead=num_heads, dim_feedforward=dim * 4,
            dropout=dropout, activation='gelu', batch_first=True, norm_first=True
        )
        self.encoder = nn.TransformerEncoder(encoder_layer, num_layers=num_encoder_layers)

        decoder_layer = nn.TransformerDecoderLayer(
            d_model=dim, nhead=num_heads, dim_feedforward=dim * 4,
            dropout=dropout, activation='gelu', batch_first=True, norm_first=True
        )
        self.decoder = nn.TransformerDecoder(decoder_layer, num_layers=num_decoder_layers)

        if use_hierarchical_encoding:
            self.sentence_encoder = nn.TransformerEncoder(
                nn.TransformerEncoderLayer(
                    d_model=dim, nhead=num_heads // 2, dim_feedforward=dim * 2,
                    dropout=dropout, activation='gelu', batch_first=True, norm_first=True
                ),
                num_layers=3
            )
            self.paragraph_encoder = nn.TransformerEncoder(
                nn.TransformerEncoderLayer(
                    d_model=dim, nhead=num_heads // 2, dim_feedforward=dim * 2,
                    dropout=dropout, activation='gelu', batch_first=True, norm_first=True
                ),
                num_layers=3
            )
            self.hierarchy_fusion = nn.Sequential(
                nn.Linear(dim * 3, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, dim)
            )

        if use_discourse_modeling:
            self.discourse_classifier = nn.Sequential(
                nn.Linear(dim, dim), nn.GELU(),
                nn.Linear(dim, 8)
            )
            self.discourse_embed = nn.Embedding(8, dim // 4)
            self.discourse_rnn = nn.GRU(dim, dim, num_layers=2, batch_first=True,
                                        bidirectional=True)
            self.discourse_proj = nn.Linear(dim * 2, dim)

        if use_topic_segmentation:
            self.topic_detector = nn.Sequential(
                nn.Linear(dim * 2, dim), nn.GELU(),
                nn.Linear(dim, 1), nn.Sigmoid()
            )
            self.topic_embed = nn.Embedding(100, dim // 4)
            self.topic_encoder = nn.Sequential(
                nn.Linear(dim, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, dim)
            )

        if use_sentiment_tracking:
            self.sentiment_rnn = nn.LSTM(dim, dim // 2, num_layers=2,
                                         batch_first=True, bidirectional=True)
            self.sentiment_head = nn.Sequential(
                nn.Linear(dim, 3)
            )
            self.sentiment_shift_detector = nn.Sequential(
                nn.Linear(dim * 2, dim), nn.GELU(),
                nn.Linear(dim, 1), nn.Sigmoid()
            )

        if use_speaker_attribution:
            self.speaker_attn = nn.MultiheadAttention(dim, num_heads, batch_first=True)
            self.speaker_norm = nn.LayerNorm(dim)
            self.speaker_contribution_head = nn.Sequential(
                nn.Linear(dim, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, 1), nn.Sigmoid()
            )

        if use_action_item_extraction:
            self.action_detector = nn.Sequential(
                nn.Linear(dim, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, 1), nn.Sigmoid()
            )
            self.assignee_extractor = nn.Sequential(
                nn.Linear(dim, dim), nn.GELU(),
                nn.Linear(dim, dim)
            )
            self.deadline_extractor = nn.Sequential(
                nn.Linear(dim, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, 1)
            )
            self.priority_head = nn.Sequential(
                nn.Linear(dim, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, 4)
            )

        if use_decision_detection:
            self.decision_detector = nn.Sequential(
                nn.Linear(dim, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, 1), nn.Sigmoid()
            )
            self.decision_confidence = nn.Sequential(
                nn.Linear(dim, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, 1), nn.Sigmoid()
            )

        if use_extractive:
            self.sentence_scorer = nn.Sequential(
                nn.Linear(dim * 2, dim), nn.GELU(),
                nn.Linear(dim, 1), nn.Sigmoid()
            )
            self.coverage_penalty = nn.Sequential(
                nn.Linear(dim, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, 1)
            )

        self.compression_heads = nn.ModuleList([
            nn.Sequential(
                nn.Linear(dim, dim), nn.GELU(),
                nn.Linear(dim, vocabulary_size)
            )
            for _ in self.compression_ratios
        ])

        self.summary_token = nn.Parameter(torch.randn(1, 1, dim) * 0.02)
        self.summary_head = nn.Linear(dim, vocabulary_size)
        self.quality_estimator = nn.Sequential(
            nn.Linear(dim * 2, dim), nn.GELU(),
            nn.Linear(dim, 5)
        )

        self.keyword_extractor = nn.Sequential(
            nn.Linear(dim, dim), nn.GELU(),
            nn.Linear(dim, 1), nn.Sigmoid()
        )

        self.meeting_type_classifier = nn.Sequential(
            nn.Linear(dim, dim // 2), nn.GELU(),
            nn.Linear(dim // 2, 10)
        )

        self.output_norm = nn.LayerNorm(dim)
        self.output_proj = nn.Linear(dim, dim)

    def _hierarchical_encode(self, x: Tensor,
                              sentence_boundaries: Optional[Tensor] = None) -> Tensor:
        if not self.use_hierarchical_encoding:
            return x
        sent_feat = self.sentence_encoder(x)
        para_len = max(1, x.shape[1] // 4)
        para_input = x.view(x.shape[0], -1, para_len, self.dim).mean(dim=2)
        para_feat = self.paragraph_encoder(para_input)
        para_upsampled = para_feat.unsqueeze(2).expand(
            -1, -1, para_len, -1
        ).reshape(x.shape[0], -1, self.dim)[:, :x.shape[1], :]
        fused = self.hierarchy_fusion(torch.cat([x, sent_feat, para_upsampled], dim=-1))
        return fused

    def forward(self, transcript: Union[Tensor, Dict],
                speaker_ids: Optional[Tensor] = None,
                turn_ids: Optional[Tensor] = None,
                target_tokens: Optional[Tensor] = None,
                style_id: int = 0,
                compression_ratio: float = 0.2,
                sentence_boundaries: Optional[Tensor] = None,
                src_mask: Optional[Tensor] = None) -> Dict[str, Tensor]:
        if isinstance(transcript, dict):
            x = transcript.get('embeddings', transcript.get('features'))
        else:
            x = transcript

        B, T = x.shape[:2]
        if x.dim() == 2:
            x = x.unsqueeze(0)
            B, T, D = x.shape
        elif x.dim() == 3:
            B, T, D = x.shape
        else:
            B, T, D = 1, x.shape[0], x.shape[1]
            x = x.unsqueeze(0)

        pos = torch.arange(T, device=x.device)
        x = x + self.pos_embed(pos.clamp(0, self.max_seq_len - 1)).unsqueeze(0).expand(B, -1, -1)
        x = self.input_proj(x)

        if speaker_ids is not None:
            spk_emb = self.speaker_embed(speaker_ids.clamp(0, 49))
            x = x + F.pad(spk_emb, (0, D - spk_emb.shape[-1]))

        x = self._hierarchical_encode(x, sentence_boundaries)
        encoded = self.encoder(x, src_key_padding_mask=src_mask)

        if self.use_discourse_modeling:
            disc_logits = self.discourse_classifier(encoded)
            disc_ids = disc_logits.argmax(dim=-1)
            disc_emb = self.discourse_embed(disc_ids)
            disc_enhanced = torch.cat([encoded, F.pad(disc_emb, (0, D - disc_emb.shape[-1]))], dim=-1)
            disc_out, _ = self.discourse_rnn(disc_enhanced[..., :D])
            encoded = encoded + self.discourse_proj(disc_out)

        if self.use_topic_segmentation:
            topic_shifts = []
            for t in range(1, T):
                seg_input = torch.cat([encoded[:, t - 1:t], encoded[:, t:t + 1]], dim=-1)
                shift = self.topic_detector(seg_input)
                topic_shifts.append(shift)
            if topic_shifts:
                topic_boundary_scores = torch.cat(topic_shifts, dim=1)
            else:
                topic_boundary_scores = torch.zeros(B, 0, 1, device=x.device)

        if self.use_sentiment_tracking:
            sent_out, _ = self.sentiment_rnn(encoded)
            sentiment_seq = self.sentiment_head(sent_out)
            sentiment_probs = F.softmax(sentiment_seq, dim=-1)
        else:
            sentiment_probs = None

        if self.use_speaker_attribution and speaker_ids is not None:
            spk_out, _ = self.speaker_attn(encoded, encoded, encoded)
            encoded = self.speaker_norm(encoded + spk_out)
            speaker_contribution = self.speaker_contribution_head(encoded)
        else:
            speaker_contribution = None

        style_vec = self.style_embed(torch.tensor(min(style_id, self.summary_styles - 1), device=x.device))
        summary_token = self.summary_token.expand(B, -1, -1) + style_vec.unsqueeze(0).unsqueeze(0)

        if target_tokens is not None:
            tgt_pos = torch.arange(target_tokens.shape[1], device=x.device)
            tgt_emb = self.token_embed(target_tokens) + \
                      self.pos_embed(tgt_pos.clamp(0, self.max_seq_len - 1)).unsqueeze(0).expand(B, -1, -1)
            causal_mask = torch.triu(
                torch.ones(tgt_emb.shape[1], tgt_emb.shape[1], device=x.device), diagonal=1
            ).bool()
            decoded = self.decoder(tgt_emb, encoded, tgt_mask=causal_mask)
        else:
            decoded = self.decoder(summary_token.expand(B, min(max(1, int(T * compression_ratio)), T), -1),
                                   encoded)

        summary_logits = self.summary_head(decoded)

        action_items, decisions = None, None
        if self.use_action_item_extraction:
            action_scores = self.action_detector(encoded).squeeze(-1)
            action_items = {
                'scores': action_scores,
                'priority': F.softmax(self.priority_head(encoded), dim=-1),
                'deadline': self.deadline_extractor(encoded).squeeze(-1)
            }

        if self.use_decision_detection:
            decision_scores = self.decision_detector(encoded).squeeze(-1)
            decision_conf = self.decision_confidence(encoded).squeeze(-1)
            decisions = {'scores': decision_scores, 'confidence': decision_conf}

        extractive_scores = None
        if self.use_extractive:
            global_repr = encoded.mean(dim=1, keepdim=True).expand_as(encoded)
            ext_input = torch.cat([encoded, global_repr], dim=-1)
            extractive_scores = self.sentence_scorer(ext_input).squeeze(-1)

        keyword_scores = self.keyword_extractor(encoded).squeeze(-1)
        meeting_type = F.softmax(self.meeting_type_classifier(encoded.mean(dim=1)), dim=-1)

        quality_input = torch.cat([encoded.mean(dim=1), decoded.mean(dim=1)], dim=-1)
        quality = F.softmax(self.quality_estimator(quality_input), dim=-1)

        out = self.output_norm(self.output_proj(decoded.mean(dim=1)))

        result = {
            'summary_logits': summary_logits,
            'embedding': out,
            'quality': quality,
            'keyword_scores': keyword_scores,
            'meeting_type': meeting_type,
        }
        if sentiment_probs is not None:
            result['sentiment_sequence'] = sentiment_probs
        if speaker_contribution is not None:
            result['speaker_contribution'] = speaker_contribution.squeeze(-1)
        if action_items is not None:
            result['action_items'] = action_items
        if decisions is not None:
            result['decisions'] = decisions
        if extractive_scores is not None:
            result['extractive_scores'] = extractive_scores
        if self.use_topic_segmentation:
            result['topic_boundaries'] = topic_boundary_scores
        return result

class NeuroSymbolicBridge(nn.Module):
    def __init__(self, dim: int, num_symbols: int = 4096,
                 num_rules: int = 1024, num_predicates: int = 512,
                 num_heads: int = 16, num_layers: int = 6,
                 dropout: float = 0.1, use_unification: bool = True,
                 use_backchaining: bool = True, use_fuzzy_logic: bool = True,
                 use_probabilistic_inference: bool = True,
                 use_differentiable_prolog: bool = True,
                 use_knowledge_distillation: bool = True,
                 grounding_depth: int = 3, max_proof_depth: int = 5):
        super().__init__()
        self.dim = dim
        self.num_symbols = num_symbols
        self.num_rules = num_rules
        self.num_predicates = num_predicates
        self.use_unification = use_unification
        self.use_backchaining = use_backchaining
        self.use_fuzzy_logic = use_fuzzy_logic
        self.use_probabilistic_inference = use_probabilistic_inference
        self.use_differentiable_prolog = use_differentiable_prolog
        self.use_knowledge_distillation = use_knowledge_distillation
        self.grounding_depth = grounding_depth
        self.max_proof_depth = max_proof_depth

        self.symbol_embed = nn.Embedding(num_symbols, dim)
        self.rule_embed = nn.Embedding(num_rules, dim)
        self.predicate_embed = nn.Embedding(num_predicates, dim // 2)

        self.neural_to_symbolic = nn.Sequential(
            nn.Linear(dim, dim * 2), nn.GELU(),
            nn.Linear(dim * 2, dim * 2), nn.GELU(),
            nn.Linear(dim * 2, num_symbols)
        )
        self.symbolic_to_neural = nn.Sequential(
            nn.Linear(num_symbols, dim * 2), nn.GELU(),
            nn.Linear(dim * 2, dim)
        )

        self.grounding_layers = nn.ModuleList([
            nn.Sequential(
                nn.Linear(dim * 2, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, dim)
            )
            for _ in range(grounding_depth)
        ])
        self.grounding_gates = nn.ParameterList([
            nn.Parameter(torch.zeros(1)) for _ in range(grounding_depth)
        ])

        self.rule_attention = nn.MultiheadAttention(dim, num_heads, batch_first=True)
        self.rule_norm = nn.LayerNorm(dim)

        encoder_layer = nn.TransformerEncoderLayer(
            d_model=dim, nhead=num_heads, dim_feedforward=dim * 4,
            dropout=dropout, activation='gelu', batch_first=True, norm_first=True
        )
        self.reasoning_transformer = nn.TransformerEncoder(encoder_layer, num_layers=num_layers)

        if use_unification:
            self.unification_net = nn.Sequential(
                nn.Linear(dim * 2, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, dim)
            )
            self.unification_score = nn.Sequential(
                nn.Linear(dim * 2, dim), nn.GELU(),
                nn.Linear(dim, 1), nn.Sigmoid()
            )
            self.substitution_net = nn.Sequential(
                nn.Linear(dim * 3, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, dim)
            )

        if use_backchaining:
            self.goal_encoder = nn.Sequential(
                nn.Linear(dim, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, dim)
            )
            self.subgoal_generator = nn.Sequential(
                nn.Linear(dim * 2, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, dim)
            )
            self.proof_state_rnn = nn.GRU(dim, dim, num_layers=2, batch_first=True)
            self.proof_success_head = nn.Sequential(
                nn.Linear(dim, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, 1), nn.Sigmoid()
            )

        if use_fuzzy_logic:
            self.fuzzy_tnorm_net = nn.Sequential(
                nn.Linear(dim * 2, dim), nn.GELU(),
                nn.Linear(dim, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, 1), nn.Sigmoid()
            )
            self.fuzzy_hedge_net = nn.Sequential(
                nn.Linear(dim + 1, dim), nn.GELU(),
                nn.Linear(dim, 1), nn.Sigmoid()
            )
            self.membership_head = nn.Sequential(
                nn.Linear(dim, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, 1), nn.Sigmoid()
            )

        if use_probabilistic_inference:
            self.prior_net = nn.Sequential(
                nn.Linear(dim, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, num_predicates * 2)
            )
            self.likelihood_net = nn.Sequential(
                nn.Linear(dim * 2, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, dim)
            )
            self.posterior_net = nn.Sequential(
                nn.Linear(dim * 3, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, dim)
            )
            self.uncertainty_estimator = nn.Sequential(
                nn.Linear(dim, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, 1), nn.Softplus()
            )

        if use_differentiable_prolog:
            self.forward_chain_net = nn.Sequential(
                nn.Linear(dim * 2, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, dim)
            )
            self.resolution_net = nn.Sequential(
                nn.Linear(dim * 3, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, dim)
            )
            self.proof_tree_encoder = nn.GRU(dim, dim, num_layers=2, batch_first=True)

        if use_knowledge_distillation:
            self.teacher_proj = nn.Sequential(
                nn.Linear(dim, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, dim)
            )
            self.student_proj = nn.Sequential(
                nn.Linear(dim, dim), nn.GELU(),
                nn.Linear(dim, dim)
            )
            self.distill_gate = nn.Parameter(torch.zeros(1))

        self.consistency_checker = nn.Sequential(
            nn.Linear(dim * 2, dim), nn.GELU(),
            nn.Linear(dim, 1), nn.Sigmoid()
        )
        self.explanation_generator = nn.Sequential(
            nn.Linear(dim, dim * 2), nn.GELU(),
            nn.Linear(dim * 2, dim)
        )
        self.interpretability_head = nn.Sequential(
            nn.Linear(dim, num_predicates)
        )

        self.output_fusion = nn.Sequential(
            nn.Linear(dim * 3, dim * 2), nn.GELU(),
            nn.Linear(dim * 2, dim)
        )
        self.output_norm = nn.LayerNorm(dim)
        self.gate = nn.Parameter(torch.zeros(1))

        self.register_buffer('rule_memory', torch.randn(num_rules, dim) * 0.02)

    def _ground(self, neural: Tensor, symbolic_logits: Tensor, depth: int) -> Tensor:
        sym_soft = torch.softmax(symbolic_logits, dim=-1)
        sym_embed = sym_soft @ self.symbol_embed.weight
        combined = torch.cat([neural, sym_embed], dim=-1) if neural.shape == sym_embed.shape else \
            torch.cat([neural, sym_embed.view_as(neural)], dim=-1)
        grounded = neural
        for i, (layer, gate) in enumerate(zip(self.grounding_layers, self.grounding_gates)):
            if i >= depth:
                break
            delta = layer(combined)
            grounded = grounded + torch.sigmoid(gate) * delta
        return grounded

    def _unify(self, x: Tensor, y: Tensor) -> Tuple[Tensor, Tensor]:
        if not self.use_unification:
            return (x + y) / 2, torch.ones(x.shape[0], 1, device=x.device)
        score = self.unification_score(torch.cat([x, y], dim=-1))
        unified = self.unification_net(torch.cat([x, y], dim=-1))
        substitution = self.substitution_net(torch.cat([x, y, unified], dim=-1))
        return unified + substitution * score, score

    def _backchain(self, goal: Tensor, facts: Tensor, depth: int = 0) -> Tuple[Tensor, Tensor]:
        if not self.use_backchaining or depth >= self.max_proof_depth:
            return goal, torch.zeros(goal.shape[0], 1, device=goal.device)
        goal_enc = self.goal_encoder(goal)
        subgoal = self.subgoal_generator(torch.cat([goal_enc, facts.mean(dim=1) if facts.dim() == 3 else facts], dim=-1))
        proof_seq = torch.stack([goal_enc, subgoal], dim=1)
        proof_state, _ = self.proof_state_rnn(proof_seq)
        success = self.proof_success_head(proof_state.mean(dim=1))
        return proof_state.mean(dim=1), success

    def _probabilistic_inference(self, x: Tensor, evidence: Tensor) -> Dict[str, Tensor]:
        if not self.use_probabilistic_inference:
            return {'posterior': x}
        prior_params = self.prior_net(x)
        prior_mu, prior_logvar = prior_params.chunk(2, dim=-1)
        likelihood = self.likelihood_net(torch.cat([x, evidence], dim=-1))
        posterior = self.posterior_net(torch.cat([x, evidence, likelihood], dim=-1))
        uncertainty = self.uncertainty_estimator(posterior)
        z = posterior + torch.randn_like(posterior) * torch.exp(0.5 * prior_logvar)
        kl = -0.5 * (1 + prior_logvar - prior_mu.pow(2) - prior_logvar.exp()).mean()
        return {
            'posterior': posterior,
            'latent': z,
            'uncertainty': uncertainty,
            'kl_divergence': kl
        }

    def forward(self, neural: Tensor, symbolic: Optional[Tensor] = None,
                goals: Optional[Tensor] = None,
                evidence: Optional[Tensor] = None,
                return_explanations: bool = False) -> Dict[str, Tensor]:
        B = neural.shape[0]
        is_seq = neural.dim() == 3
        if not is_seq:
            neural = neural.unsqueeze(1)

        sym_logits = self.neural_to_symbolic(neural)
        grounded = self._ground(neural, sym_logits, self.grounding_depth)

        if symbolic is not None:
            if symbolic.dim() == 2:
                symbolic = symbolic.unsqueeze(1)
            sym_neural = self.symbolic_to_neural(
                F.softmax(symbolic[:, :, :self.num_symbols], dim=-1)
            )
            unified, unif_score = self._unify(grounded, sym_neural)
        else:
            sym_neural = self.symbolic_to_neural(F.softmax(sym_logits, dim=-1))
            unified, unif_score = self._unify(grounded, sym_neural)

        rule_keys = self.rule_memory.unsqueeze(0).expand(B, -1, -1)
        rule_out, _ = self.rule_attention(unified, rule_keys, rule_keys)
        rule_enhanced = self.rule_norm(unified + rule_out)

        reasoned = self.reasoning_transformer(rule_enhanced)

        proof_result, proof_success = None, None
        if goals is not None:
            if goals.dim() == 2:
                goals = goals.unsqueeze(1)
            facts_for_proof = reasoned
            proof_result, proof_success = self._backchain(
                goals.mean(dim=1), facts_for_proof
            )

        prob_results = {}
        if evidence is not None:
            if evidence.dim() == 2:
                evidence = evidence.unsqueeze(1)
            prob_results = self._probabilistic_inference(
                reasoned.mean(dim=1), evidence.mean(dim=1)
            )

        fuzzy_membership = None
        if self.use_fuzzy_logic:
            fuzzy_membership = self.membership_head(reasoned).squeeze(-1)

        neural_out = neural
        sym_out = reasoned

        if self.use_knowledge_distillation:
            teacher = self.teacher_proj(reasoned)
            student = self.student_proj(neural_out)
            dist_gate = torch.sigmoid(self.distill_gate)
            reasoned = reasoned + dist_gate * (teacher - student)

        fused = self.output_fusion(
            torch.cat([neural.mean(dim=1), sym_neural.mean(dim=1), reasoned.mean(dim=1)], dim=-1)
        )
        out = self.output_norm(torch.sigmoid(self.gate) * fused + (1 - torch.sigmoid(self.gate)) * neural.mean(dim=1))

        consistency = self.consistency_checker(
            torch.cat([neural.mean(dim=1), out], dim=-1)
        )
        predicate_activations = self.interpretability_head(out)
        explanation = self.explanation_generator(out) if return_explanations else None

        result = {
            'output': out,
            'symbol_logits': sym_logits.mean(dim=1) if is_seq else sym_logits.squeeze(1),
            'unification_score': unif_score.squeeze(-1) if unif_score.dim() > 1 else unif_score,
            'consistency': consistency,
            'predicate_activations': predicate_activations,
        }
        if proof_result is not None:
            result['proof_result'] = proof_result
            result['proof_success'] = proof_success
        if prob_results:
            result.update(prob_results)
        if fuzzy_membership is not None:
            result['fuzzy_membership'] = fuzzy_membership
        if explanation is not None:
            result['explanation'] = explanation
        return result

class HierarchicalMemory(nn.Module):
    def __init__(self, dim: int, levels: int = 5,
                 slots_per_level: Optional[List[int]] = None,
                 num_heads: int = 16, dropout: float = 0.1,
                 use_temporal_hierarchy: bool = True,
                 use_semantic_clustering: bool = True,
                 use_episodic_consolidation: bool = True,
                 use_working_memory: bool = True,
                 use_prospective_memory: bool = True,
                 use_emotional_tagging: bool = True,
                 consolidation_threshold: float = 0.7,
                 forgetting_curve_base: float = 0.9,
                 working_memory_capacity: int = 7):
        super().__init__()
        self.dim = dim
        self.levels = levels
        self.slots_per_level = slots_per_level or [64, 256, 1024, 4096, 16384]
        self.use_temporal_hierarchy = use_temporal_hierarchy
        self.use_semantic_clustering = use_semantic_clustering
        self.use_episodic_consolidation = use_episodic_consolidation
        self.use_working_memory = use_working_memory
        self.use_prospective_memory = use_prospective_memory
        self.use_emotional_tagging = use_emotional_tagging
        self.consolidation_threshold = consolidation_threshold
        self.forgetting_curve_base = forgetting_curve_base
        self.working_memory_capacity = working_memory_capacity

        self.level_memories = nn.ParameterList([
            nn.Parameter(torch.randn(n_slots, dim) * 0.02)
            for n_slots in self.slots_per_level[:levels]
        ])
        self.level_keys = nn.ParameterList([
            nn.Parameter(torch.randn(n_slots, dim) * 0.02)
            for n_slots in self.slots_per_level[:levels]
        ])

        self.write_projections = nn.ModuleList([
            nn.Sequential(nn.Linear(dim, dim * 2), nn.GELU(), nn.Linear(dim * 2, dim))
            for _ in range(levels)
        ])
        self.read_projections = nn.ModuleList([
            nn.Sequential(nn.Linear(dim, dim * 2), nn.GELU(), nn.Linear(dim * 2, dim))
            for _ in range(levels)
        ])

        self.level_attentions = nn.ModuleList([
            nn.MultiheadAttention(dim, num_heads, batch_first=True, dropout=dropout)
            for _ in range(levels)
        ])
        self.level_norms = nn.ModuleList([nn.LayerNorm(dim) for _ in range(levels)])

        self.inter_level_attentions = nn.ModuleList([
            nn.MultiheadAttention(dim, num_heads // 2, batch_first=True, dropout=dropout)
            for _ in range(levels - 1)
        ])
        self.inter_level_norms = nn.ModuleList([nn.LayerNorm(dim) for _ in range(levels - 1)])

        self.consolidation_gate = nn.Sequential(
            nn.Linear(dim * 2, dim), nn.Sigmoid()
        )
        self.consolidation_net = nn.Sequential(
            nn.Linear(dim * 2, dim * 2), nn.GELU(),
            nn.Linear(dim * 2, dim)
        )

        if use_temporal_hierarchy:
            self.temporal_gates = nn.ParameterList([
                nn.Parameter(torch.zeros(1)) for _ in range(levels)
            ])
            self.temporal_decay_factors = nn.ParameterList([
                nn.Parameter(torch.ones(1) * (forgetting_curve_base ** i))
                for i in range(levels)
            ])
            self.time_encoding_net = nn.Sequential(
                nn.Linear(1, dim // 4), nn.SiLU(),
                nn.Linear(dim // 4, dim // 2), nn.SiLU(),
                nn.Linear(dim // 2, dim)
            )

        if use_semantic_clustering:
            self.cluster_centroids = nn.Parameter(torch.randn(64, dim) * 0.02)
            self.cluster_assignment_net = nn.Sequential(
                nn.Linear(dim, 128), nn.GELU(),
                nn.Linear(128, 64)
            )
            self.cluster_enhancer = nn.Sequential(
                nn.Linear(dim * 2, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, dim)
            )

        if use_episodic_consolidation:
            self.episode_encoder = nn.GRU(dim, dim, num_layers=2, batch_first=True)
            self.episode_boundary_detector = nn.Sequential(
                nn.Linear(dim * 2, dim), nn.GELU(),
                nn.Linear(dim, 1), nn.Sigmoid()
            )
            self.episode_compressor = nn.Sequential(
                nn.Linear(dim * 2, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, dim)
            )

        if use_working_memory:
            self.working_memory_slots = nn.Parameter(
                torch.randn(working_memory_capacity, dim) * 0.02
            )
            self.working_memory_controller = nn.GRU(dim, dim, num_layers=2, batch_first=True)
            self.wm_read_head = nn.MultiheadAttention(dim, num_heads, batch_first=True)
            self.wm_write_head = nn.Sequential(
                nn.Linear(dim * 2, dim), nn.Sigmoid()
            )
            self.wm_erase_head = nn.Sequential(
                nn.Linear(dim, dim), nn.Sigmoid()
            )

        if use_prospective_memory:
            self.intention_store = nn.Parameter(torch.randn(64, dim) * 0.02)
            self.trigger_detector = nn.Sequential(
                nn.Linear(dim * 2, dim), nn.GELU(),
                nn.Linear(dim, 1), nn.Sigmoid()
            )
            self.intention_retriever = nn.MultiheadAttention(dim, num_heads, batch_first=True)

        if use_emotional_tagging:
            self.emotion_tagger = nn.Sequential(
                nn.Linear(dim, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, 8)
            )
            self.emotion_salience_net = nn.Sequential(
                nn.Linear(dim + 8, dim), nn.GELU(),
                nn.Linear(dim, dim)
            )
            self.emotional_retrieval_bias = nn.Parameter(torch.zeros(8, dim))

        self.importance_scorer = nn.Sequential(
            nn.Linear(dim, dim // 2), nn.GELU(),
            nn.Linear(dim // 2, 1), nn.Sigmoid()
        )
        self.novelty_detector = nn.Sequential(
            nn.Linear(dim * 2, dim), nn.GELU(),
            nn.Linear(dim, 1), nn.Sigmoid()
        )

        self.level_fusion = nn.Sequential(
            nn.Linear(dim * levels, dim * 2), nn.GELU(),
            nn.Linear(dim * 2, dim)
        )
        self.output_norm = nn.LayerNorm(dim)
        self.output_gate = nn.Parameter(torch.zeros(1))

        self.register_buffer('access_counts', torch.zeros(sum(self.slots_per_level[:levels])))
        self.register_buffer('last_access', torch.zeros(sum(self.slots_per_level[:levels])))
        self.register_buffer('creation_time', torch.zeros(sum(self.slots_per_level[:levels])))
        self.register_buffer('global_step', torch.tensor(0, dtype=torch.long))

    def _compute_forgetting_factor(self, level: int, time_since_access: Tensor) -> Tensor:
        if not self.use_temporal_hierarchy:
            return torch.ones_like(time_since_access)
        decay = torch.sigmoid(self.temporal_decay_factors[level])
        return torch.pow(decay.clamp(0.01, 0.999), time_since_access.clamp(0.0, 1000.0))

    def _semantic_cluster(self, x: Tensor) -> Tuple[Tensor, Tensor]:
        if not self.use_semantic_clustering:
            return x, torch.zeros(x.shape[0], 64, device=x.device)
        cluster_logits = self.cluster_assignment_net(x.mean(dim=1) if x.dim() == 3 else x)
        cluster_probs = F.softmax(cluster_logits, dim=-1)
        cluster_repr = cluster_probs @ self.cluster_centroids
        x_for_cluster = x.mean(dim=1) if x.dim() == 3 else x
        enhanced = self.cluster_enhancer(torch.cat([x_for_cluster, cluster_repr], dim=-1))
        return enhanced, cluster_probs

    def _episodic_consolidate(self, x: Tensor) -> Tensor:
        if not self.use_episodic_consolidation:
            return x
        if x.dim() == 2:
            x = x.unsqueeze(1)
        encoded, _ = self.episode_encoder(x)
        if encoded.shape[1] > 1:
            boundaries = []
            for t in range(1, encoded.shape[1]):
                bd = self.episode_boundary_detector(
                    torch.cat([encoded[:, t - 1], encoded[:, t]], dim=-1)
                )
                boundaries.append(bd)
            boundary_tensor = torch.cat(boundaries, dim=-1) if boundaries else torch.zeros(x.shape[0], 0, device=x.device)
        compressed = self.episode_compressor(
            torch.cat([x.mean(dim=1), encoded.mean(dim=1)], dim=-1)
        )
        return compressed

    def _working_memory_cycle(self, x: Tensor) -> Tensor:
        if not self.use_working_memory:
            return x
        if x.dim() == 2:
            x_in = x.unsqueeze(1)
        else:
            x_in = x
        B = x_in.shape[0]
        wm = self.working_memory_slots.unsqueeze(0).expand(B, -1, -1).clone()
        ctrl_out, _ = self.working_memory_controller(x_in)
        read_out, _ = self.wm_read_head(ctrl_out, wm, wm)
        erase = self.wm_erase_head(ctrl_out.mean(dim=1, keepdim=True).expand_as(wm))
        write_gate = self.wm_write_head(
            torch.cat([ctrl_out.mean(dim=1, keepdim=True).expand_as(wm), wm], dim=-1)
        )
        wm = wm * (1 - erase) + write_gate * ctrl_out.mean(dim=1, keepdim=True).expand_as(wm)
        return (read_out + x_in).mean(dim=1)

    def _emotional_tag(self, x: Tensor) -> Tuple[Tensor, Tensor]:
        if not self.use_emotional_tagging:
            return x, None
        x_in = x.mean(dim=1) if x.dim() == 3 else x
        emotion_logits = self.emotion_tagger(x_in)
        emotion_probs = F.softmax(emotion_logits, dim=-1)
        emotion_bias = emotion_probs @ self.emotional_retrieval_bias
        enhanced = self.emotion_salience_net(
            torch.cat([x_in, emotion_probs], dim=-1)
        ) + emotion_bias
        return enhanced, emotion_probs

    def forward(self, x: Tensor,
                write: bool = True,
                read: bool = True,
                time_delta: Optional[float] = None,
                emotional_context: Optional[Tensor] = None,
                level_mask: Optional[List[bool]] = None) -> Dict[str, Tensor]:
        B = x.shape[0]
        is_seq = x.dim() == 3
        if not is_seq:
            x = x.unsqueeze(1)

        x_flat = x.mean(dim=1)

        importance = self.importance_scorer(x_flat)
        novelty = self.novelty_detector(
            torch.cat([x_flat, x_flat.mean(dim=0, keepdim=True).expand_as(x_flat)], dim=-1)
        )

        x_clustered, cluster_probs = self._semantic_cluster(x_flat)
        x_episodic = self._episodic_consolidate(x)
        x_wm = self._working_memory_cycle(x_flat)
        x_emotional, emotion_probs = self._emotional_tag(x_flat)

        level_outputs = []
        level_attentions_list = []

        for lvl in range(self.levels):
            if level_mask is not None and not level_mask[lvl]:
                level_outputs.append(x_flat)
                continue

            mem = self.level_memories[lvl].unsqueeze(0).expand(B, -1, -1)
            keys = self.level_keys[lvl].unsqueeze(0).expand(B, -1, -1)

            if self.use_temporal_hierarchy and time_delta is not None:
                td = torch.tensor([[time_delta]], device=x.device, dtype=x.dtype).expand(B, -1)
                time_emb = self.time_encoding_net(td)
                mem = mem + time_emb.unsqueeze(1)

            if self.use_emotional_tagging and emotion_probs is not None:
                em_bias = emotion_probs @ self.emotional_retrieval_bias
                query = self.read_projections[lvl](x_flat + em_bias).unsqueeze(1)
            else:
                query = self.read_projections[lvl](x_flat).unsqueeze(1)

            attn_out, attn_weights = self.level_attentions[lvl](query, mem, mem)
            level_read = self.level_norms[lvl](query + attn_out).squeeze(1)

            if write:
                with torch.no_grad():
                    write_query = self.write_projections[lvl](x_flat)
                    write_scores = torch.einsum('bd,nd->bn',
                                               F.normalize(write_query, dim=-1),
                                               F.normalize(self.level_keys[lvl], dim=-1))
                    write_idx = write_scores.argmax(dim=-1)
                    for b in range(B):
                        slot = write_idx[b].item()
                        consolidation_score = importance[b].item()
                        if consolidation_score > self.consolidation_threshold or lvl == 0:
                            alpha = novelty[b].item() * 0.3
                            self.level_memories[lvl].data[slot] = (
                                (1 - alpha) * self.level_memories[lvl].data[slot] +
                                alpha * x_flat[b].detach()
                            )
                            self.level_keys[lvl].data[slot] = (
                                (1 - alpha) * self.level_keys[lvl].data[slot] +
                                alpha * x_flat[b].detach()
                            )

            level_outputs.append(level_read)
            level_attentions_list.append(attn_weights.squeeze(1))

        for lvl in range(self.levels - 1):
            lo = level_outputs[lvl].unsqueeze(1)
            hi = level_outputs[lvl + 1].unsqueeze(1)
            inter_out, _ = self.inter_level_attentions[lvl](lo, hi, hi)
            level_outputs[lvl] = self.inter_level_norms[lvl](lo + inter_out).squeeze(1)

        fused = self.level_fusion(torch.cat(level_outputs, dim=-1))

        x_all = x_flat + x_clustered + x_episodic + x_wm + x_emotional
        gate = torch.sigmoid(self.output_gate)
        out = self.output_norm(gate * fused + (1 - gate) * x_all / 5)

        prospective_trigger = None
        if self.use_prospective_memory:
            intentions = self.intention_store.unsqueeze(0).expand(B, -1, -1)
            int_out, _ = self.intention_retriever(x_flat.unsqueeze(1), intentions, intentions)
            prospective_trigger = self.trigger_detector(
                torch.cat([x_flat, int_out.squeeze(1)], dim=-1)
            )
            out = out + int_out.squeeze(1) * prospective_trigger

        with torch.no_grad():
            self.global_step += 1

        result = {
            'output': out,
            'importance': importance,
            'novelty': novelty,
            'cluster_assignment': cluster_probs,
        }
        if emotion_probs is not None:
            result['emotion_tags'] = emotion_probs
        if prospective_trigger is not None:
            result['prospective_trigger'] = prospective_trigger
        return result

class MetaController(nn.Module):
    def __init__(self, dim: int, num_strategies: int = 32,
                 num_objectives: int = 16, num_heads: int = 16,
                 num_layers: int = 6, dropout: float = 0.1,
                 use_multi_armed_bandit: bool = True,
                 use_model_based_planning: bool = True,
                 use_hierarchical_control: bool = True,
                 use_option_framework: bool = True,
                 use_curiosity_driven: bool = True,
                 use_world_model: bool = True,
                 planning_horizon: int = 10,
                 num_options: int = 8, meta_lr: float = 0.01):
        super().__init__()
        self.dim = dim
        self.num_strategies = num_strategies
        self.num_objectives = num_objectives
        self.planning_horizon = planning_horizon
        self.num_options = num_options
        self.use_multi_armed_bandit = use_multi_armed_bandit
        self.use_model_based_planning = use_model_based_planning
        self.use_hierarchical_control = use_hierarchical_control
        self.use_option_framework = use_option_framework
        self.use_curiosity_driven = use_curiosity_driven
        self.use_world_model = use_world_model

        self.strategy_embed = nn.Embedding(num_strategies, dim)
        self.objective_embed = nn.Embedding(num_objectives, dim)
        self.option_embed = nn.Embedding(num_options, dim)

        self.state_encoder = nn.Sequential(
            nn.Linear(dim, dim * 4), nn.GELU(),
            nn.Dropout(dropout),
            nn.Linear(dim * 4, dim * 2), nn.GELU(),
            nn.Linear(dim * 2, dim)
        )

        encoder_layer = nn.TransformerEncoderLayer(
            d_model=dim, nhead=num_heads, dim_feedforward=dim * 4,
            dropout=dropout, activation='gelu', batch_first=True, norm_first=True
        )
        self.context_encoder = nn.TransformerEncoder(encoder_layer, num_layers=num_layers)

        self.strategy_selector = nn.Sequential(
            nn.Linear(dim, dim * 2), nn.GELU(),
            nn.Dropout(dropout),
            nn.Linear(dim * 2, num_strategies)
        )
        self.objective_predictor = nn.Sequential(
            nn.Linear(dim, dim * 2), nn.GELU(),
            nn.Linear(dim * 2, num_objectives)
        )

        if use_multi_armed_bandit:
            self.register_buffer('bandit_counts', torch.ones(num_strategies))
            self.register_buffer('bandit_rewards', torch.zeros(num_strategies))
            self.register_buffer('bandit_q_values', torch.zeros(num_strategies))
            self.exploration_bonus = nn.Parameter(torch.ones(1))
            self.ucb_net = nn.Sequential(
                nn.Linear(dim + num_strategies * 2, dim), nn.GELU(),
                nn.Linear(dim, num_strategies)
            )

        if use_model_based_planning:
            self.transition_model = nn.Sequential(
                nn.Linear(dim * 2, dim * 4), nn.GELU(),
                nn.Linear(dim * 4, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, dim)
            )
            self.reward_model = nn.Sequential(
                nn.Linear(dim * 2, dim), nn.GELU(),
                nn.Linear(dim, 1)
            )
            self.value_model = nn.Sequential(
                nn.Linear(dim, dim), nn.GELU(),
                nn.Linear(dim, 1)
            )
            self.planning_rnn = nn.GRU(dim, dim, num_layers=2, batch_first=True)

        if use_hierarchical_control:
            self.high_level_policy = nn.Sequential(
                nn.Linear(dim, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, num_strategies)
            )
            self.low_level_policy = nn.Sequential(
                nn.Linear(dim * 2, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, dim)
            )
            self.subgoal_generator = nn.Sequential(
                nn.Linear(dim * 2, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, dim)
            )
            self.goal_conditioned_net = nn.Sequential(
                nn.Linear(dim * 2, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, dim)
            )

        if use_option_framework:
            self.option_policies = nn.ModuleList([
                nn.Sequential(nn.Linear(dim, dim), nn.GELU(), nn.Linear(dim, dim))
                for _ in range(num_options)
            ])
            self.option_termination = nn.ModuleList([
                nn.Sequential(nn.Linear(dim, dim // 2), nn.GELU(),
                               nn.Linear(dim // 2, 1), nn.Sigmoid())
                for _ in range(num_options)
            ])
            self.option_selector = nn.Sequential(
                nn.Linear(dim, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, num_options)
            )
            self.option_value = nn.Sequential(
                nn.Linear(dim, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, num_options)
            )

        if use_curiosity_driven:
            self.forward_model = nn.Sequential(
                nn.Linear(dim * 2, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, dim)
            )
            self.inverse_model = nn.Sequential(
                nn.Linear(dim * 2, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, dim)
            )
            self.curiosity_scale = nn.Parameter(torch.ones(1))

        if use_world_model:
            self.world_encoder = nn.Sequential(
                nn.Linear(dim, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, dim)
            )
            self.world_decoder = nn.Sequential(
                nn.Linear(dim, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, dim)
            )
            self.world_dynamics = nn.GRU(dim * 2, dim, num_layers=2, batch_first=True)
            self.world_kl_weight = nn.Parameter(torch.tensor(0.001))

        self.meta_gradient_scaler = nn.Parameter(torch.ones(1))
        self.adaptation_rate = nn.Parameter(torch.tensor(meta_lr))

        self.control_signal_head = nn.Sequential(
            nn.LayerNorm(dim),
            nn.Linear(dim, dim * 2), nn.GELU(),
            nn.Dropout(dropout),
            nn.Linear(dim * 2, dim)
        )
        self.output_norm = nn.LayerNorm(dim)
        self.output_gate = nn.Parameter(torch.zeros(1))

        self.register_buffer('episode_returns', torch.zeros(100))
        self.register_buffer('strategy_history', torch.zeros(num_strategies, dtype=torch.long))
        self._episode_ptr = 0

    def _ucb_selection(self, x: Tensor) -> Tensor:
        if not self.use_multi_armed_bandit:
            return self.strategy_selector(x)
        B = x.shape[0]
        total = self.bandit_counts.sum()
        ucb_bonus = torch.sqrt(
            torch.log(total + 1) / (self.bandit_counts + 1e-8)
        ) * torch.sigmoid(self.exploration_bonus)
        ucb_feats = torch.cat([
            x,
            self.bandit_q_values.unsqueeze(0).expand(B, -1),
            ucb_bonus.unsqueeze(0).expand(B, -1)
        ], dim=-1)
        return self.ucb_net(ucb_feats)

    def _model_based_plan(self, state: Tensor) -> Tuple[Tensor, Tensor]:
        if not self.use_model_based_planning:
            return state, torch.zeros(state.shape[0], 1, device=state.device)
        trajectory = [state]
        value_sum = torch.zeros(state.shape[0], 1, device=state.device)
        cur = state
        all_states = []
        for h in range(self.planning_horizon):
            action_emb = self.strategy_embed(
                self.strategy_selector(cur).argmax(dim=-1)
            )
            next_state = self.transition_model(torch.cat([cur, action_emb], dim=-1))
            reward = self.reward_model(torch.cat([cur, action_emb], dim=-1))
            value_sum += reward * (0.99 ** h)
            trajectory.append(next_state)
            all_states.append(next_state)
            cur = next_state
        all_states_t = torch.stack(all_states, dim=1)
        planned_repr, _ = self.planning_rnn(all_states_t)
        terminal_value = self.value_model(planned_repr[:, -1])
        total_value = value_sum + 0.99 ** self.planning_horizon * terminal_value
        return planned_repr.mean(dim=1), total_value

    def _option_execute(self, x: Tensor) -> Tuple[Tensor, Tensor]:
        if not self.use_option_framework:
            return x, torch.zeros(x.shape[0], self.num_options, device=x.device)
        option_logits = self.option_selector(x)
        option_probs = F.softmax(option_logits, dim=-1)
        option_values = self.option_value(x)
        option_out = torch.zeros_like(x)
        for i, (pol, term) in enumerate(zip(self.option_policies, self.option_termination)):
            policy_out = pol(x)
            termination = term(x)
            option_out += option_probs[:, i:i + 1] * policy_out * (1 - termination)
        return option_out, option_values

    def _compute_curiosity(self, state: Tensor, next_state: Tensor, action: Tensor) -> Tensor:
        if not self.use_curiosity_driven:
            return torch.zeros(state.shape[0], 1, device=state.device)
        predicted_next = self.forward_model(torch.cat([state, action], dim=-1))
        predicted_action = self.inverse_model(torch.cat([state, next_state], dim=-1))
        forward_error = F.mse_loss(predicted_next, next_state.detach(), reduction='none').mean(dim=-1, keepdim=True)
        curiosity = torch.sigmoid(self.curiosity_scale) * forward_error
        return curiosity

    def forward(self, x: Tensor,
                goals: Optional[Tensor] = None,
                prev_state: Optional[Tensor] = None,
                next_state: Optional[Tensor] = None,
                objective_ids: Optional[Tensor] = None,
                reward: Optional[float] = None) -> Dict[str, Tensor]:
        B = x.shape[0]
        is_seq = x.dim() == 3
        if not is_seq:
            x = x.unsqueeze(1)

        encoded_state = self.state_encoder(x.mean(dim=1))
        context = self.context_encoder(x)
        context_pooled = context.mean(dim=1)

        if goals is not None:
            if goals.dim() == 2:
                goals = goals.unsqueeze(1)
            goal_context = self.context_encoder(goals)
            goal_pooled = goal_context.mean(dim=1)
            if self.use_hierarchical_control:
                subgoal = self.subgoal_generator(torch.cat([encoded_state, goal_pooled], dim=-1))
                control_input = self.goal_conditioned_net(torch.cat([encoded_state, subgoal], dim=-1))
            else:
                control_input = encoded_state + goal_pooled
        else:
            control_input = encoded_state

        strategy_logits = self._ucb_selection(control_input)
        strategy_probs = F.softmax(strategy_logits, dim=-1)
        strategy_ids = strategy_probs.argmax(dim=-1)
        strategy_emb = self.strategy_embed(strategy_ids)

        planned_repr, plan_value = self._model_based_plan(control_input)
        option_output, option_values = self._option_execute(control_input)

        curiosity = torch.zeros(B, 1, device=x.device)
        if next_state is not None and prev_state is not None:
            ns = next_state.mean(dim=1) if next_state.dim() == 3 else next_state
            ps = prev_state.mean(dim=1) if prev_state.dim() == 3 else prev_state
            curiosity = self._compute_curiosity(ps, ns, strategy_emb)

        world_loss = torch.tensor(0.0, device=x.device)
        if self.use_world_model and prev_state is not None and next_state is not None:
            ps = prev_state.mean(dim=1) if prev_state.dim() == 3 else prev_state
            ns = next_state.mean(dim=1) if next_state.dim() == 3 else next_state
            world_enc = self.world_encoder(encoded_state)
            world_action_enc = self.world_encoder(strategy_emb)
            combined = torch.stack([world_enc, world_action_enc], dim=1)
            world_out, _ = self.world_dynamics(combined)
            predicted = self.world_decoder(world_out[:, -1])
            world_loss = F.mse_loss(predicted, ns.detach())

        fused_control = (
            control_input * 0.3 +
            strategy_emb * 0.2 +
            planned_repr * 0.2 +
            option_output * 0.2 +
            context_pooled * 0.1
        )

        if objective_ids is not None:
            obj_emb = self.objective_embed(objective_ids.clamp(0, self.num_objectives - 1))
            fused_control = fused_control + obj_emb

        control_signal = self.control_signal_head(fused_control)

        if self.use_hierarchical_control:
            high_level = self.high_level_policy(control_signal)
            high_level_id = F.softmax(high_level, dim=-1).argmax(dim=-1)
            high_level_emb = self.strategy_embed(high_level_id)
            low_level = self.low_level_policy(torch.cat([control_signal, high_level_emb], dim=-1))
            control_signal = control_signal + low_level * 0.5

        gate = torch.sigmoid(self.output_gate)
        out = self.output_norm(gate * control_signal + (1 - gate) * encoded_state)

        objective_pred = F.softmax(self.objective_predictor(out), dim=-1)

        if reward is not None:
            with torch.no_grad():
                for b in range(B):
                    sid = strategy_ids[b].item()
                    self.bandit_counts[sid] += 1
                    self.bandit_rewards[sid] += reward
                    self.bandit_q_values[sid] = self.bandit_rewards[sid] / self.bandit_counts[sid]

        return {
            'control_signal': out,
            'strategy': strategy_probs,
            'strategy_ids': strategy_ids,
            'plan_value': plan_value,
            'option_values': option_values,
            'curiosity_bonus': curiosity,
            'objective_prediction': objective_pred,
            'world_model_loss': world_loss,
            'adaptation_rate': torch.sigmoid(self.adaptation_rate),
        }

class DynamicSparser(nn.Module):
    def __init__(self, dim: int, sparsity: float = 0.5,
                 num_heads: int = 8, num_layers: int = 4,
                 use_learned_sparsity: bool = True,
                 use_structured_sparsity: bool = True,
                 use_magnitude_pruning: bool = True,
                 use_lottery_ticket: bool = True,
                 use_dynamic_threshold: bool = True,
                 use_importance_sampling: bool = True,
                 use_gradient_based_mask: bool = True,
                 use_block_sparsity: bool = True,
                 use_n_m_sparsity: bool = True,
                 n_m_ratio: Tuple[int, int] = (2, 4),
                 block_size: int = 32,
                 sparsity_schedule: str = 'cosine',
                 temperature: float = 1.0,
                 straight_through: bool = True):
        super().__init__()
        self.dim = dim
        self.base_sparsity = sparsity
        self.current_sparsity = sparsity
        self.use_learned_sparsity = use_learned_sparsity
        self.use_structured_sparsity = use_structured_sparsity
        self.use_magnitude_pruning = use_magnitude_pruning
        self.use_lottery_ticket = use_lottery_ticket
        self.use_dynamic_threshold = use_dynamic_threshold
        self.use_importance_sampling = use_importance_sampling
        self.use_gradient_based_mask = use_gradient_based_mask
        self.use_block_sparsity = use_block_sparsity
        self.use_n_m_sparsity = use_n_m_sparsity
        self.n_m_ratio = n_m_ratio
        self.block_size = block_size
        self.sparsity_schedule = sparsity_schedule
        self.temperature = temperature
        self.straight_through = straight_through

        if use_learned_sparsity:
            self.sparsity_predictor = nn.Sequential(
                nn.Linear(dim, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, dim), nn.GELU(),
                nn.Linear(dim, 1), nn.Sigmoid()
            )
            self.threshold_net = nn.Sequential(
                nn.Linear(dim, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, 1), nn.Sigmoid()
            )
            self.mask_generator = nn.Sequential(
                nn.Linear(dim, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, dim), nn.Sigmoid()
            )

        if use_structured_sparsity:
            self.row_importance = nn.Sequential(
                nn.Linear(dim, dim // 4), nn.GELU(),
                nn.Linear(dim // 4, 1)
            )
            self.col_importance = nn.Sequential(
                nn.Linear(dim, dim // 4), nn.GELU(),
                nn.Linear(dim // 4, 1)
            )
            self.head_importance = nn.Sequential(
                nn.Linear(dim, num_heads), nn.Sigmoid()
            )
            self.layer_importance = nn.Sequential(
                nn.Linear(dim, num_layers), nn.Sigmoid()
            )

        if use_dynamic_threshold:
            self.threshold_adapter = nn.Sequential(
                nn.Linear(dim + 2, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, 1), nn.Sigmoid()
            )
            self.register_buffer('ema_density', torch.tensor(1.0 - sparsity))
            self.ema_alpha = 0.99

        if use_importance_sampling:
            self.importance_net = nn.Sequential(
                nn.Linear(dim, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, dim), nn.GELU(),
                nn.Linear(dim, dim)
            )
            self.importance_scale = nn.Parameter(torch.ones(1))

        if use_gradient_based_mask:
            self.gradient_accumulator = nn.Parameter(torch.zeros(dim), requires_grad=False)
            self.gradient_momentum = 0.99

        if use_lottery_ticket:
            self.ticket_mask: Optional[Tensor] = None
            self.initial_weights: Optional[Tensor] = None
            self.reset_frequency = 1000
            self._reset_counter = 0

        if use_block_sparsity:
            self.block_scorer = nn.Sequential(
                nn.Linear(block_size, block_size), nn.GELU(),
                nn.Linear(block_size, 1)
            )

        self.sparsity_controller = nn.Sequential(
            nn.Linear(dim + 1, dim), nn.GELU(),
            nn.Linear(dim, 1), nn.Sigmoid()
        )
        self.adaptive_temperature = nn.Parameter(torch.tensor(temperature))

        self.entropy_regularizer = nn.Parameter(torch.tensor(0.01))
        self.output_rescaler = nn.Sequential(
            nn.Linear(dim, dim // 2), nn.GELU(),
            nn.Linear(dim // 2, 1), nn.Softplus()
        )

        self.sparsity_loss_weight = nn.Parameter(torch.tensor(0.01))
        self.register_buffer('sparsity_history', torch.zeros(200))
        self._hist_ptr = 0
        self.register_buffer('global_step', torch.tensor(0, dtype=torch.long))

    def _compute_sparsity_schedule(self, step: int) -> float:
        if self.sparsity_schedule == 'cosine':
            ratio = min(1.0, step / max(1, 10000))
            return self.base_sparsity * (1 - math.cos(math.pi * ratio)) / 2
        elif self.sparsity_schedule == 'linear':
            return min(self.base_sparsity, self.base_sparsity * step / 10000)
        elif self.sparsity_schedule == 'cubic':
            ratio = min(1.0, step / max(1, 10000))
            return self.base_sparsity * ratio ** 3
        return self.base_sparsity

    def _n_m_sparse_mask(self, weights: Tensor) -> Tensor:
        n, m = self.n_m_ratio
        shape = weights.shape
        if shape[-1] < m:
            return torch.ones_like(weights)
        w_reshaped = weights.view(-1, m)
        _, topk_indices = torch.topk(w_reshaped.abs(), n, dim=-1)
        mask = torch.zeros_like(w_reshaped)
        mask.scatter_(-1, topk_indices, 1.0)
        return mask.view(shape)

    def _block_sparse_mask(self, weights: Tensor) -> Tensor:
        if not self.use_block_sparsity:
            return torch.ones_like(weights)
        shape = weights.shape
        D = shape[-1]
        if D < self.block_size:
            return torch.ones_like(weights)
        num_blocks = D // self.block_size
        w_blocks = weights.view(*shape[:-1], num_blocks, self.block_size)
        block_scores = self.block_scorer(w_blocks).squeeze(-1)
        sparsity = self.current_sparsity
        threshold = torch.quantile(block_scores.abs(), sparsity, dim=-1, keepdim=True)
        block_mask = (block_scores.abs() >= threshold).float()
        return block_mask.unsqueeze(-1).expand_as(w_blocks).reshape(shape)

    def _straight_through_bernoulli(self, probs: Tensor) -> Tensor:
        hard = (probs > 0.5).float()
        if self.straight_through:
            return hard - probs.detach() + probs
        return hard

    def forward(self, weights: Tensor,
                context: Optional[Tensor] = None,
                training_step: Optional[int] = None,
                grad_signal: Optional[Tensor] = None) -> Dict[str, Tensor]:
        original_shape = weights.shape
        B = weights.shape[0] if weights.dim() > 1 else 1
        if weights.dim() == 1:
            weights = weights.unsqueeze(0)

        step = training_step if training_step is not None else int(self.global_step.item())
        self.current_sparsity = self._compute_sparsity_schedule(step)

        if context is not None:
            ctx = context.mean(dim=1) if context.dim() == 3 else context
            sparsity_signal = torch.cat([
                ctx.mean(dim=0, keepdim=True).expand(B, -1),
                torch.tensor([[self.current_sparsity]], device=weights.device).expand(B, -1)
            ], dim=-1)
            adaptive_sparsity = self.sparsity_controller(sparsity_signal)
            effective_sparsity = (adaptive_sparsity.squeeze(-1) * self.current_sparsity).mean().item()
        else:
            effective_sparsity = self.current_sparsity
            ctx = None

        mask = torch.ones_like(weights)

        if self.use_learned_sparsity and ctx is not None:
            learned_mask = self.mask_generator(ctx)
            threshold_val = self.threshold_net(ctx).mean().item()
            learned_mask = (learned_mask > threshold_val).float()
            if self.straight_through:
                soft_mask = self.mask_generator(ctx)
                learned_mask = self._straight_through_bernoulli(soft_mask)
            mask = mask * learned_mask.unsqueeze(-1).expand_as(weights) if learned_mask.shape != weights.shape else mask * learned_mask

        if self.use_magnitude_pruning:
            threshold = torch.quantile(weights.abs(), effective_sparsity, dim=-1, keepdim=True)
            mag_mask = (weights.abs() >= threshold).float()
            mask = mask * mag_mask

        if self.use_structured_sparsity and ctx is not None:
            row_imp = torch.sigmoid(self.row_importance(ctx)).squeeze(-1)
            row_threshold = torch.quantile(row_imp, effective_sparsity * 0.5, dim=-1, keepdim=True)
            row_mask = (row_imp >= row_threshold).float()
            mask = mask * row_mask.unsqueeze(-1).expand_as(weights)

        if self.use_n_m_sparsity:
            nm_mask = self._n_m_sparse_mask(weights)
            mask = mask * nm_mask

        if self.use_block_sparsity:
            block_mask = self._block_sparse_mask(weights)
            mask = mask * block_mask

        if grad_signal is not None and self.use_gradient_based_mask:
            if grad_signal.shape == weights.shape:
                grad_imp = grad_signal.abs()
                grad_threshold = torch.quantile(grad_imp, effective_sparsity * 0.5, dim=-1, keepdim=True)
                grad_mask = (grad_imp >= grad_threshold).float()
                mask = mask * (0.5 * grad_mask + 0.5)

        temp = torch.abs(self.adaptive_temperature)
        if self.use_importance_sampling and ctx is not None:
            importance_weights = self.importance_net(ctx)
            importance_scale = torch.sigmoid(self.importance_scale)
            sparse_weights = weights * mask * importance_weights.unsqueeze(-1) * importance_scale
        else:
            sparse_weights = weights * mask

        actual_sparsity = (1 - mask).float().mean().item()

        rescale_factor = self.output_rescaler(
            ctx if ctx is not None else weights.mean(dim=-1, keepdim=True)
        ) if ctx is not None else torch.ones(B, 1, device=weights.device)

        sparse_weights = sparse_weights * rescale_factor.unsqueeze(-1) if rescale_factor.shape != sparse_weights.shape else sparse_weights * rescale_factor

        entropy_loss = -torch.mean(
            mask * torch.log(mask + 1e-8) + (1 - mask) * torch.log(1 - mask + 1e-8)
        ) * torch.abs(self.entropy_regularizer)

        sparsity_target_loss = (
            actual_sparsity - effective_sparsity
        ) ** 2 * torch.abs(self.sparsity_loss_weight)

        with torch.no_grad():
            self.global_step += 1
            self.sparsity_history[self._hist_ptr % 200] = actual_sparsity
            self._hist_ptr += 1
            if self.use_dynamic_threshold:
                self.ema_density = self.ema_alpha * self.ema_density + \
                                   (1 - self.ema_alpha) * (1 - actual_sparsity)

        if self.use_lottery_ticket:
            self._reset_counter += 1
            if self._reset_counter % self.reset_frequency == 0:
                if self.ticket_mask is None:
                    self.ticket_mask = (mask > 0.5).detach()
                else:
                    new_ticket = (mask > 0.5).detach()
                    self.ticket_mask = self.ticket_mask & new_ticket

        result = {
            'sparse_weights': sparse_weights.view(original_shape),
            'mask': mask.view(original_shape),
            'actual_sparsity': torch.tensor(actual_sparsity, device=weights.device),
            'target_sparsity': torch.tensor(effective_sparsity, device=weights.device),
            'entropy_loss': entropy_loss,
            'sparsity_loss': sparsity_target_loss,
        }
        if self.use_lottery_ticket and self.ticket_mask is not None:
            result['ticket_mask'] = self.ticket_mask.view(original_shape)
        return result

class ThoughtRouter(nn.Module):
    def __init__(self, dim: int, num_experts: int = 16,
                 num_thought_types: int = 12, num_heads: int = 16,
                 num_layers: int = 4, dropout: float = 0.1,
                 use_mixture_of_thoughts: bool = True,
                 use_recursive_routing: bool = True,
                 use_confidence_gating: bool = True,
                 use_semantic_routing: bool = True,
                 use_adaptive_depth: bool = True,
                 use_thought_memory: bool = True,
                 use_meta_routing: bool = True,
                 thought_memory_size: int = 256,
                 max_routing_depth: int = 4,
                 temperature: float = 1.0):
        super().__init__()
        self.dim = dim
        self.num_experts = num_experts
        self.num_thought_types = num_thought_types
        self.use_mixture_of_thoughts = use_mixture_of_thoughts
        self.use_recursive_routing = use_recursive_routing
        self.use_confidence_gating = use_confidence_gating
        self.use_semantic_routing = use_semantic_routing
        self.use_adaptive_depth = use_adaptive_depth
        self.use_thought_memory = use_thought_memory
        self.use_meta_routing = use_meta_routing
        self.max_routing_depth = max_routing_depth

        self.thought_type_embed = nn.Embedding(num_thought_types, dim)
        self.expert_embed = nn.Embedding(num_experts, dim)

        self.thought_encoder = nn.Sequential(
            nn.Linear(dim, dim * 4), nn.GELU(),
            nn.Dropout(dropout),
            nn.Linear(dim * 4, dim * 2), nn.GELU(),
            nn.Linear(dim * 2, dim)
        )

        encoder_layer = nn.TransformerEncoderLayer(
            d_model=dim, nhead=num_heads, dim_feedforward=dim * 4,
            dropout=dropout, activation='gelu', batch_first=True, norm_first=True
        )
        self.context_transformer = nn.TransformerEncoder(encoder_layer, num_layers=num_layers)

        self.base_router = nn.Sequential(
            nn.LayerNorm(dim),
            nn.Linear(dim, dim * 2), nn.GELU(),
            nn.Dropout(dropout),
            nn.Linear(dim * 2, num_experts)
        )

        self.thought_type_classifier = nn.Sequential(
            nn.Linear(dim, dim * 2), nn.GELU(),
            nn.Linear(dim * 2, num_thought_types)
        )

        if use_mixture_of_thoughts:
            self.expert_networks = nn.ModuleList([
                nn.Sequential(
                    nn.Linear(dim, dim * 4), nn.GELU(),
                    nn.Dropout(dropout),
                    nn.Linear(dim * 4, dim * 2), nn.GELU(),
                    nn.Linear(dim * 2, dim)
                )
                for _ in range(num_experts)
            ])
            self.expert_attn = nn.MultiheadAttention(dim, num_heads, batch_first=True)
            self.expert_norm = nn.LayerNorm(dim)
            self.load_balancer = nn.Linear(dim, num_experts)
            self.register_buffer('expert_usage', torch.zeros(num_experts))

        if use_semantic_routing:
            self.semantic_router = nn.Sequential(
                nn.Linear(dim, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, num_experts)
            )
            self.semantic_embed = nn.Embedding(num_experts, dim)
            self.semantic_attn = nn.MultiheadAttention(dim, num_heads, batch_first=True)
            self.semantic_norm = nn.LayerNorm(dim)

        if use_confidence_gating:
            self.confidence_estimator = nn.Sequential(
                nn.Linear(dim, dim), nn.GELU(),
                nn.Linear(dim, num_experts), nn.Sigmoid()
            )
            self.confidence_threshold = nn.Parameter(torch.tensor(0.5))
            self.uncertainty_predictor = nn.Sequential(
                nn.Linear(dim, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, 1), nn.Sigmoid()
            )

        if use_adaptive_depth:
            self.depth_predictor = nn.Sequential(
                nn.Linear(dim, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, max_routing_depth)
            )
            self.depth_gates = nn.ParameterList([
                nn.Parameter(torch.zeros(1)) for _ in range(max_routing_depth)
            ])

        if use_recursive_routing:
            self.recursive_refiner = nn.GRU(dim, dim, num_layers=2, batch_first=True)
            self.recursive_router_update = nn.Sequential(
                nn.Linear(dim * 2, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, num_experts)
            )
            self.recursion_gate = nn.Parameter(torch.zeros(1))

        if use_thought_memory:
            self.thought_memory = nn.Parameter(torch.randn(thought_memory_size, dim) * 0.02)
            self.memory_attn = nn.MultiheadAttention(dim, num_heads, batch_first=True)
            self.memory_norm = nn.LayerNorm(dim)
            self.memory_update_net = nn.Sequential(
                nn.Linear(dim * 2, dim), nn.Sigmoid()
            )

        if use_meta_routing:
            self.meta_router = nn.Sequential(
                nn.Linear(dim * 2, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, dim), nn.GELU(),
                nn.Linear(dim, num_experts)
            )
            self.meta_history = nn.Parameter(torch.zeros(64, dim), requires_grad=False)
            self.meta_attn = nn.MultiheadAttention(dim, num_heads, batch_first=True)
            self._meta_ptr = 0

        self.adaptive_temperature = nn.Parameter(torch.tensor(temperature))
        self.routing_dropout = nn.Dropout(dropout)

        self.output_gate = nn.Parameter(torch.zeros(1))
        self.output_proj = nn.Linear(dim, dim)
        self.output_norm = nn.LayerNorm(dim)

        self.register_buffer('routing_entropy_history', torch.zeros(100))
        self._entropy_ptr = 0

    def _mixture_of_thoughts(self, x: Tensor, router_weights: Tensor) -> Tensor:
        if not self.use_mixture_of_thoughts:
            return x
        B = x.shape[0]
        expert_outputs = torch.stack([
            expert(x) for expert in self.expert_networks
        ], dim=1)
        weights_expanded = router_weights.unsqueeze(-1).unsqueeze(-1)
        if expert_outputs.dim() == 3:
            weighted = (expert_outputs * router_weights.unsqueeze(-1)).sum(dim=1)
        else:
            weighted = (expert_outputs * weights_expanded.expand_as(expert_outputs)).sum(dim=1)
        keys = self.expert_embed.weight.unsqueeze(0).expand(B, -1, -1)
        if x.dim() == 2:
            x_q = x.unsqueeze(1)
        else:
            x_q = x
        attn_out, _ = self.expert_attn(x_q, keys, keys)
        result = self.expert_norm(x_q + attn_out)
        with torch.no_grad():
            self.expert_usage += router_weights.detach().mean(dim=0)
        return result.squeeze(1) if result.shape[1] == 1 else result.mean(dim=1)

    def _recursive_route(self, x: Tensor, initial_weights: Tensor, depth: int) -> Tensor:
        if not self.use_recursive_routing or depth >= self.max_routing_depth:
            return initial_weights
        weights = initial_weights
        x_seq = x.unsqueeze(1) if x.dim() == 2 else x
        all_weights = [initial_weights]
        for _ in range(depth):
            context, _ = self.recursive_refiner(x_seq)
            context_pooled = context.mean(dim=1)
            refined = self.recursive_router_update(
                torch.cat([context_pooled, x.mean(dim=1) if x.dim() == 3 else x], dim=-1)
            )
            gate = torch.sigmoid(self.recursion_gate)
            weights = gate * F.softmax(refined / torch.abs(self.adaptive_temperature), dim=-1) + \
                      (1 - gate) * weights
            all_weights.append(weights)
        return weights

    def _memory_augment(self, x: Tensor) -> Tensor:
        if not self.use_thought_memory:
            return x
        B = x.shape[0]
        x_q = x.unsqueeze(1) if x.dim() == 2 else x
        mem = self.thought_memory.unsqueeze(0).expand(B, -1, -1)
        mem_out, _ = self.memory_attn(x_q, mem, mem)
        out = self.memory_norm(x_q + mem_out)
        if self.training:
            with torch.no_grad():
                update_gate = self.memory_update_net(
                    torch.cat([
                        self.thought_memory[:x_q.shape[1]],
                        x_q.detach().mean(dim=0)[:self.thought_memory.shape[0]]
                    ], dim=-1)
                )
                n = min(x_q.shape[1], self.thought_memory.shape[0])
                self.thought_memory.data[:n] = (
                    (1 - update_gate[:n]) * self.thought_memory.data[:n] +
                    update_gate[:n] * x_q.detach().mean(dim=0)[:n]
                )
        return out.squeeze(1) if out.shape[1] == 1 else out.mean(dim=1)

    def forward(self, thought: Tensor,
                context: Optional[Tensor] = None,
                routing_depth: Optional[int] = None,
                return_routing_info: bool = False) -> Union[Tensor, Dict[str, Tensor]]:
        B = thought.shape[0]
        is_seq = thought.dim() == 3
        if not is_seq:
            thought = thought.unsqueeze(1)

        encoded = self.thought_encoder(thought)
        context_encoded = self.context_transformer(encoded)
        pooled = context_encoded.mean(dim=1)

        memory_enhanced = self._memory_augment(pooled)

        if context is not None:
            ctx = context.mean(dim=1) if context.dim() == 3 else context
            if self.use_meta_routing:
                meta_combined = torch.cat([memory_enhanced, ctx], dim=-1)
                meta_logits = self.meta_router(meta_combined)
                meta_weights = F.softmax(meta_logits / torch.abs(self.adaptive_temperature), dim=-1)
            else:
                meta_weights = None
            combined_for_routing = memory_enhanced + ctx
        else:
            meta_weights = None
            combined_for_routing = memory_enhanced

        base_logits = self.base_router(combined_for_routing)

        if self.use_semantic_routing:
            sem_logits = self.semantic_router(combined_for_routing)
            expert_keys = self.semantic_embed.weight.unsqueeze(0).expand(B, -1, -1)
            sem_query = combined_for_routing.unsqueeze(1)
            sem_out, _ = self.semantic_attn(sem_query, expert_keys, expert_keys)
            sem_enhanced = self.semantic_norm(sem_query + sem_out).squeeze(1)
            sem_final_logits = self.base_router(sem_enhanced)
            base_logits = 0.5 * base_logits + 0.5 * sem_final_logits

        temp = torch.abs(self.adaptive_temperature)
        router_weights = F.softmax(base_logits / temp, dim=-1)

        confidence = None
        if self.use_confidence_gating:
            confidence = self.confidence_estimator(combined_for_routing)
            uncertainty = self.uncertainty_predictor(combined_for_routing)
            conf_threshold = torch.sigmoid(self.confidence_threshold)
            conf_mask = (confidence > conf_threshold).float()
            router_weights = router_weights * conf_mask + router_weights * (1 - conf_mask) * 0.1
            router_weights = router_weights / (router_weights.sum(dim=-1, keepdim=True) + 1e-8)

        actual_depth = routing_depth
        if self.use_adaptive_depth and routing_depth is None:
            depth_logits = self.depth_predictor(combined_for_routing)
            actual_depth = int(F.softmax(depth_logits, dim=-1).argmax(dim=-1).float().mean().item()) + 1
            actual_depth = min(actual_depth, self.max_routing_depth)

        router_weights = self._recursive_route(
            context_encoded, router_weights, actual_depth or 1
        )

        if meta_weights is not None:
            router_weights = 0.7 * router_weights + 0.3 * meta_weights

        thought_type_logits = self.thought_type_classifier(pooled)
        thought_type_probs = F.softmax(thought_type_logits, dim=-1)

        mixed_output = self._mixture_of_thoughts(pooled, router_weights)

        type_emb = (thought_type_probs @ self.thought_type_embed.weight)
        expert_emb = (router_weights @ self.expert_embed.weight)

        fused = mixed_output + type_emb * 0.2 + expert_emb * 0.1

        gate = torch.sigmoid(self.output_gate)
        out = self.output_norm(gate * self.output_proj(fused) + (1 - gate) * pooled)

        routing_entropy = -(router_weights * torch.log(router_weights + 1e-8)).sum(dim=-1).mean()
        with torch.no_grad():
            self.routing_entropy_history[self._entropy_ptr % 100] = routing_entropy.item()
            self._entropy_ptr += 1

        if not return_routing_info:
            return out

        return {
            'output': out,
            'router_weights': router_weights,
            'thought_type_probs': thought_type_probs,
            'routing_entropy': routing_entropy,
            'confidence': confidence,
            'routing_depth': actual_depth,
        }

class ConsciousFocus(nn.Module):
    def __init__(self, dim: int, num_focus_zones: int = 8,
                 num_heads: int = 16, num_layers: int = 4,
                 use_global_workspace: bool = True,
                 use_spotlight_attention: bool = True,
                 use_inhibition_of_return: bool = True,
                 use_salience_map: bool = True,
                 use_working_memory_gate: bool = True,
                 use_top_down_modulation: bool = True,
                 use_bottom_up_integration: bool = True,
                 use_temporal_integration: bool = True,
                 focus_bandwidth: float = 0.3,
                 inhibition_strength: float = 0.5,
                 dropout: float = 0.1):
        super().__init__()
        self.dim = dim
        self.num_focus_zones = num_focus_zones
        self.focus_bandwidth = focus_bandwidth
        self.inhibition_strength = inhibition_strength
        self.use_global_workspace = use_global_workspace
        self.use_spotlight_attention = use_spotlight_attention
        self.use_inhibition_of_return = use_inhibition_of_return
        self.use_salience_map = use_salience_map
        self.use_working_memory_gate = use_working_memory_gate
        self.use_top_down_modulation = use_top_down_modulation
        self.use_bottom_up_integration = use_bottom_up_integration
        self.use_temporal_integration = use_temporal_integration

        self.feature_extractor = nn.Sequential(
            nn.Linear(dim, dim * 4), nn.GELU(),
            nn.Dropout(dropout),
            nn.Linear(dim * 4, dim * 2), nn.GELU(),
            nn.Linear(dim * 2, dim)
        )

        self.context_encoder = nn.Sequential(
            nn.Linear(dim, dim * 4), nn.GELU(),
            nn.Linear(dim * 4, dim * 2), nn.GELU(),
            nn.Linear(dim * 2, dim)
        )

        encoder_layer = nn.TransformerEncoderLayer(
            d_model=dim, nhead=num_heads, dim_feedforward=dim * 4,
            dropout=dropout, activation='gelu', batch_first=True, norm_first=True
        )
        self.joint_encoder = nn.TransformerEncoder(encoder_layer, num_layers=num_layers)

        if use_global_workspace:
            self.global_workspace = nn.Parameter(torch.randn(num_focus_zones, dim) * 0.02)
            self.broadcast_attn = nn.MultiheadAttention(dim, num_heads, batch_first=True)
            self.broadcast_norm = nn.LayerNorm(dim)
            self.workspace_gate = nn.Sequential(
                nn.Linear(dim * 2, dim), nn.Sigmoid()
            )
            self.competition_net = nn.Sequential(
                nn.Linear(dim, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, num_focus_zones)
            )

        if use_spotlight_attention:
            self.spotlight_center = nn.Sequential(
                nn.Linear(dim, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, 1)
            )
            self.spotlight_radius = nn.Sequential(
                nn.Linear(dim, dim // 4), nn.GELU(),
                nn.Linear(dim // 4, 1), nn.Softplus()
            )
            self.spotlight_attn = nn.MultiheadAttention(dim, num_heads, batch_first=True)
            self.spotlight_norm = nn.LayerNorm(dim)

        if use_inhibition_of_return:
            self.inhibition_map = nn.Parameter(torch.zeros(1, 256, dim), requires_grad=False)
            self.inhibition_updater = nn.Sequential(
                nn.Linear(dim, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, dim)
            )
            self.inhibition_decay = nn.Parameter(torch.tensor(0.9))
            self.return_detector = nn.Sequential(
                nn.Linear(dim * 2, dim), nn.GELU(),
                nn.Linear(dim, 1), nn.Sigmoid()
            )

        if use_salience_map:
            self.bottom_up_salience = nn.Sequential(
                nn.Linear(dim, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, 1)
            )
            self.top_down_salience = nn.Sequential(
                nn.Linear(dim * 2, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, 1)
            )
            self.salience_combiner = nn.Sequential(
                nn.Linear(2, 4), nn.GELU(),
                nn.Linear(4, 1), nn.Sigmoid()
            )

        if use_working_memory_gate:
            self.wm_content = nn.Parameter(torch.randn(16, dim) * 0.02)
            self.wm_gate = nn.Sequential(
                nn.Linear(dim * 2, dim), nn.GELU(),
                nn.Linear(dim, dim), nn.Sigmoid()
            )
            self.wm_attn = nn.MultiheadAttention(dim, num_heads, batch_first=True)
            self.wm_norm = nn.LayerNorm(dim)

        if use_top_down_modulation:
            self.task_goal_encoder = nn.Sequential(
                nn.Linear(dim, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, dim)
            )
            self.top_down_attn = nn.MultiheadAttention(dim, num_heads, batch_first=True)
            self.top_down_norm = nn.LayerNorm(dim)
            self.top_down_gate = nn.Parameter(torch.zeros(1))

        if use_bottom_up_integration:
            self.feature_pyramid = nn.ModuleList([
                nn.Sequential(
                    nn.Linear(dim, dim // (2 ** i) if dim // (2 ** i) > 4 else 4),
                    nn.GELU(),
                    nn.Linear(dim // (2 ** i) if dim // (2 ** i) > 4 else 4, dim)
                )
                for i in range(min(4, int(math.log2(dim)) - 1))
            ])
            self.pyramid_fusion = nn.Linear(dim * min(4, int(math.log2(dim)) - 1), dim)

        if use_temporal_integration:
            self.temporal_buffer = nn.GRU(dim, dim, num_layers=2, batch_first=True)
            self.temporal_attn = nn.MultiheadAttention(dim, num_heads, batch_first=True)
            self.temporal_norm = nn.LayerNorm(dim)
            self.temporal_gate = nn.Parameter(torch.zeros(1))
            self._temporal_state: Optional[Tensor] = None

        self.focus_head = nn.Sequential(
            nn.LayerNorm(dim),
            nn.Linear(dim, dim * 2), nn.GELU(),
            nn.Dropout(dropout),
            nn.Linear(dim * 2, dim)
        )

        self.output_norm = nn.LayerNorm(dim)
        self.output_gate = nn.Parameter(torch.zeros(1))
        self.focus_scale = nn.Parameter(torch.ones(1))

        self.register_buffer('focus_history', torch.zeros(100, dim))
        self._focus_ptr = 0
        self.register_buffer('access_map', torch.zeros(256))

    def _apply_spotlight(self, x: Tensor, context: Tensor) -> Tensor:
        if not self.use_spotlight_attention:
            return x * torch.sigmoid(context.mean(dim=-1, keepdim=True))
        B = x.shape[0]
        x_q = x.unsqueeze(1) if x.dim() == 2 else x
        center = self.spotlight_center(context)
        radius = self.spotlight_radius(context) * self.focus_bandwidth
        attention_weights = F.softmax(center, dim=-1)
        if x_q.shape[1] > 1:
            positions = torch.arange(x_q.shape[1], device=x.device).float() / x_q.shape[1]
            center_pos = torch.sigmoid(center).squeeze(-1)
            dist = (positions.unsqueeze(0) - center_pos.unsqueeze(-1)).abs()
            gaussian_mask = torch.exp(-dist ** 2 / (2 * radius.squeeze(-1) ** 2 + 1e-8))
            x_q = x_q * gaussian_mask.unsqueeze(-1)
        spot_out, _ = self.spotlight_attn(x_q, x_q, x_q)
        return self.spotlight_norm(x_q + spot_out).mean(dim=1)

    def _global_workspace_broadcast(self, x: Tensor) -> Tensor:
        if not self.use_global_workspace:
            return x
        B = x.shape[0]
        x_in = x.unsqueeze(1) if x.dim() == 2 else x
        workspace = self.global_workspace.unsqueeze(0).expand(B, -1, -1)
        competition = F.softmax(self.competition_net(x_in.mean(dim=1)), dim=-1)
        selected_workspace = (competition.unsqueeze(-1) * workspace).sum(dim=1, keepdim=True)
        broadcast_out, _ = self.broadcast_attn(x_in, selected_workspace, selected_workspace)
        out = self.broadcast_norm(x_in + broadcast_out)
        gate = self.workspace_gate(torch.cat([out, x_in], dim=-1))
        result = gate * out + (1 - gate) * x_in
        return result.mean(dim=1)

    def _inhibit_return(self, x: Tensor) -> Tensor:
        if not self.use_inhibition_of_return:
            return x
        B = x.shape[0]
        x_in = x.unsqueeze(1) if x.dim() == 2 else x
        inhibition_field = self.inhibition_map.expand(B, -1, -1)
        inhibition_cropped = inhibition_field[:, :x_in.shape[1], :]
        return_prob = self.return_detector(
            torch.cat([x_in, inhibition_cropped], dim=-1)
        )
        inhibited = x_in * (1 - return_prob * self.inhibition_strength)
        with torch.no_grad():
            decay = torch.sigmoid(self.inhibition_decay)
            new_inhibition = self.inhibition_updater(x_in.mean(dim=0, keepdim=True).mean(dim=1, keepdim=True))
            T = min(x_in.shape[1], 256)
            self.inhibition_map[:, :T, :] = decay * self.inhibition_map[:, :T, :] + \
                                             (1 - decay) * new_inhibition[:, :T, :]
        return inhibited.mean(dim=1)

    def _compute_salience(self, x: Tensor, context: Tensor) -> Tensor:
        if not self.use_salience_map:
            return torch.ones(x.shape[0], 1, device=x.device)
        x_in = x if x.dim() == 2 else x.mean(dim=1)
        ctx_in = context if context.dim() == 2 else context.mean(dim=1)
        bu = self.bottom_up_salience(x_in)
        td = self.top_down_salience(torch.cat([x_in, ctx_in], dim=-1))
        combined = self.salience_combiner(torch.cat([bu, td], dim=-1))
        return combined

    def forward(self, x: Tensor, context: Tensor,
                task_goal: Optional[Tensor] = None,
                temporal_history: Optional[Tensor] = None) -> Dict[str, Tensor]:
        B = x.shape[0]
        is_seq_x = x.dim() == 3
        is_seq_ctx = context.dim() == 3
        if not is_seq_x:
            x = x.unsqueeze(1)
        if not is_seq_ctx:
            context = context.unsqueeze(1)

        x_feat = self.feature_extractor(x)
        ctx_feat = self.context_encoder(context)

        joint = torch.cat([x_feat, ctx_feat], dim=1)
        joint_encoded = self.joint_encoder(joint)
        x_encoded = joint_encoded[:, :x.shape[1], :]
        ctx_encoded = joint_encoded[:, x.shape[1]:, :]

        x_flat = x_encoded.mean(dim=1)
        ctx_flat = ctx_encoded.mean(dim=1)

        salience = self._compute_salience(x_flat, ctx_flat)

        if self.use_bottom_up_integration:
            pyr_outs = [pyr(x_flat) for pyr in self.feature_pyramid]
            pyr_fused = self.pyramid_fusion(torch.cat(pyr_outs, dim=-1))
            x_flat = x_flat + pyr_fused

        workspace_out = self._global_workspace_broadcast(x_flat)
        spotlight_out = self._apply_spotlight(x_flat, ctx_flat)
        inhibited_out = self._inhibit_return(x_flat)

        if self.use_working_memory_gate:
            wm = self.wm_content.unsqueeze(0).expand(B, -1, -1)
            x_q = x_flat.unsqueeze(1)
            wm_out, _ = self.wm_attn(x_q, wm, wm)
            wm_fused = self.wm_norm(x_q + wm_out).squeeze(1)
            wm_gate_val = self.wm_gate(torch.cat([x_flat, wm_fused], dim=-1))
            x_flat = wm_gate_val * wm_fused + (1 - wm_gate_val) * x_flat

        if self.use_top_down_modulation and task_goal is not None:
            goal = task_goal.mean(dim=1) if task_goal.dim() == 3 else task_goal
            goal_enc = self.task_goal_encoder(goal)
            x_q = x_flat.unsqueeze(1)
            td_out, _ = self.top_down_attn(x_q, goal_enc.unsqueeze(1), goal_enc.unsqueeze(1))
            td_gate = torch.sigmoid(self.top_down_gate)
            x_flat = x_flat + td_gate * td_out.squeeze(1)

        if self.use_temporal_integration:
            if temporal_history is not None:
                th = temporal_history.mean(dim=1) if temporal_history.dim() == 3 else temporal_history
                combined_temporal = torch.cat([th.unsqueeze(1), x_flat.unsqueeze(1)], dim=1)
            else:
                combined_temporal = x_flat.unsqueeze(1)
            temp_out, self._temporal_state = self.temporal_buffer(combined_temporal, self._temporal_state)
            temp_attn_out, _ = self.temporal_attn(x_flat.unsqueeze(1), temp_out, temp_out)
            temp_gate = torch.sigmoid(self.temporal_gate)
            x_flat = x_flat + temp_gate * temp_attn_out.squeeze(1)

        combined = (
            workspace_out * 0.3 +
            spotlight_out * 0.3 +
            inhibited_out * 0.2 +
            x_flat * 0.2
        ) * salience * torch.sigmoid(self.focus_scale)

        focused = self.focus_head(combined)
        gate = torch.sigmoid(self.output_gate)
        out = self.output_norm(gate * focused + (1 - gate) * x_flat)

        with torch.no_grad():
            self.focus_history[self._focus_ptr % 100] = out.detach().mean(dim=0)
            self._focus_ptr += 1

        return {
            'focused_output': out,
            'salience': salience,
            'workspace_repr': workspace_out,
            'spotlight_repr': spotlight_out,
        }

class PredictiveCoder(nn.Module):
    def __init__(self, dim: int, num_levels: int = 5,
                 latent_dim: int = 128, num_heads: int = 16,
                 num_layers: int = 4, dropout: float = 0.1,
                 use_precision_weighting: bool = True,
                 use_temporal_prediction: bool = True,
                 use_hierarchical_prediction: bool = True,
                 use_contrastive_prediction: bool = True,
                 use_bayesian_inference: bool = True,
                 use_surprise_minimization: bool = True,
                 use_free_energy: bool = True,
                 prediction_horizon: int = 8,
                 correction_steps: int = 3,
                 beta: float = 1.0):
        super().__init__()
        self.dim = dim
        self.num_levels = num_levels
        self.latent_dim = latent_dim
        self.prediction_horizon = prediction_horizon
        self.correction_steps = correction_steps
        self.use_precision_weighting = use_precision_weighting
        self.use_temporal_prediction = use_temporal_prediction
        self.use_hierarchical_prediction = use_hierarchical_prediction
        self.use_contrastive_prediction = use_contrastive_prediction
        self.use_bayesian_inference = use_bayesian_inference
        self.use_surprise_minimization = use_surprise_minimization
        self.use_free_energy = use_free_energy
        self.beta = beta

        self.encoders = nn.ModuleList([
            nn.Sequential(
                nn.Linear(dim, dim * 4), nn.GELU(),
                nn.Dropout(dropout),
                nn.Linear(dim * 4, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, dim)
            )
            for _ in range(num_levels)
        ])

        self.decoders = nn.ModuleList([
            nn.Sequential(
                nn.Linear(dim, dim * 4), nn.GELU(),
                nn.Dropout(dropout),
                nn.Linear(dim * 4, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, dim)
            )
            for _ in range(num_levels)
        ])

        self.level_predictors = nn.ModuleList([
            nn.Sequential(
                nn.Linear(dim * 2, dim * 4), nn.GELU(),
                nn.Linear(dim * 4, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, dim * 2)
            )
            for _ in range(num_levels)
        ])

        self.error_projectors = nn.ModuleList([
            nn.Sequential(
                nn.Linear(dim, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, dim)
            )
            for _ in range(num_levels)
        ])

        self.level_attentions = nn.ModuleList([
            nn.MultiheadAttention(dim, num_heads, batch_first=True)
            for _ in range(num_levels)
        ])
        self.level_norms = nn.ModuleList([nn.LayerNorm(dim) for _ in range(num_levels)])

        encoder_layer = nn.TransformerEncoderLayer(
            d_model=dim, nhead=num_heads, dim_feedforward=dim * 4,
            dropout=dropout, activation='gelu', batch_first=True, norm_first=True
        )
        self.global_encoder = nn.TransformerEncoder(encoder_layer, num_layers=num_layers)

        if use_precision_weighting:
            self.precision_estimators = nn.ModuleList([
                nn.Sequential(
                    nn.Linear(dim * 2, dim), nn.GELU(),
                    nn.Linear(dim, dim // 2), nn.GELU(),
                    nn.Linear(dim // 2, 1), nn.Softplus()
                )
                for _ in range(num_levels)
            ])
            self.precision_gates = nn.ParameterList([
                nn.Parameter(torch.zeros(1)) for _ in range(num_levels)
            ])

        if use_temporal_prediction:
            self.temporal_predictors = nn.ModuleList([
                nn.GRU(dim, dim, num_layers=2, batch_first=True)
                for _ in range(num_levels)
            ])
            self.temporal_horizon_heads = nn.ModuleList([
                nn.Linear(dim, dim * prediction_horizon)
                for _ in range(num_levels)
            ])

        if use_hierarchical_prediction:
            self.bottom_up_proj = nn.ModuleList([
                nn.Sequential(nn.Linear(dim, dim), nn.GELU(), nn.Linear(dim, dim))
                for _ in range(num_levels - 1)
            ])
            self.top_down_proj = nn.ModuleList([
                nn.Sequential(nn.Linear(dim, dim), nn.GELU(), nn.Linear(dim, dim))
                for _ in range(num_levels - 1)
            ])
            self.hierarchy_gates = nn.ParameterList([
                nn.Parameter(torch.zeros(1)) for _ in range(num_levels - 1)
            ])

        if use_bayesian_inference:
            self.prior_nets = nn.ModuleList([
                nn.Sequential(
                    nn.Linear(dim, dim * 2), nn.GELU(),
                    nn.Linear(dim * 2, latent_dim * 2)
                )
                for _ in range(num_levels)
            ])
            self.posterior_nets = nn.ModuleList([
                nn.Sequential(
                    nn.Linear(dim * 2, dim * 2), nn.GELU(),
                    nn.Linear(dim * 2, latent_dim * 2)
                )
                for _ in range(num_levels)
            ])
            self.latent_decoders = nn.ModuleList([
                nn.Sequential(
                    nn.Linear(latent_dim, dim * 2), nn.GELU(),
                    nn.Linear(dim * 2, dim)
                )
                for _ in range(num_levels)
            ])

        if use_contrastive_prediction:
            self.contrastive_proj = nn.Sequential(
                nn.Linear(dim, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, latent_dim)
            )
            self.contrastive_temperature = nn.Parameter(torch.tensor(0.07))

        if use_free_energy:
            self.free_energy_estimator = nn.Sequential(
                nn.Linear(dim * 2, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, 1)
            )
            self.action_net = nn.Sequential(
                nn.Linear(dim, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, dim)
            )

        if use_surprise_minimization:
            self.surprise_estimator = nn.Sequential(
                nn.Linear(dim * 2, dim), nn.GELU(),
                nn.Linear(dim, 1), nn.Softplus()
            )
            self.adaptation_net = nn.Sequential(
                nn.Linear(dim * 2, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, dim)
            )

        self.correction_net = nn.Sequential(
            nn.Linear(dim * 2, dim * 2), nn.GELU(),
            nn.Linear(dim * 2, dim)
        )
        self.correction_gate = nn.Parameter(torch.zeros(1))

        self.output_fusion = nn.Sequential(
            nn.Linear(dim * num_levels, dim * 2), nn.GELU(),
            nn.Linear(dim * 2, dim)
        )
        self.output_norm = nn.LayerNorm(dim)
        self.output_gate = nn.Parameter(torch.zeros(1))

    def _reparameterize(self, mu: Tensor, logvar: Tensor) -> Tensor:
        if not self.training:
            return mu
        std = torch.exp(0.5 * logvar)
        eps = torch.randn_like(std)
        return mu + eps * std

    def _compute_kl(self, mu_q: Tensor, logvar_q: Tensor,
                    mu_p: Tensor, logvar_p: Tensor) -> Tensor:
        kl = 0.5 * (
            logvar_p - logvar_q +
            (logvar_q.exp() + (mu_q - mu_p).pow(2)) / (logvar_p.exp() + 1e-8) - 1
        )
        return kl.sum(dim=-1).mean()

    def forward(self, x: Tensor,
                target: Optional[Tensor] = None,
                context: Optional[Tensor] = None) -> Dict[str, Tensor]:
        B = x.shape[0]
        is_seq = x.dim() == 3
        if not is_seq:
            x = x.unsqueeze(1)

        level_representations = []
        level_errors = []
        level_predictions = []
        total_kl = torch.tensor(0.0, device=x.device)
        total_precision = torch.tensor(0.0, device=x.device)

        current = x
        for lvl in range(self.num_levels):
            encoded = self.encoders[lvl](current)
            attn_out, _ = self.level_attentions[lvl](encoded, encoded, encoded)
            encoded = self.level_norms[lvl](encoded + attn_out)
            level_representations.append(encoded.mean(dim=1))
            current = encoded

        global_repr = self.global_encoder(current)

        refined_representations = []
        for lvl in range(self.num_levels - 1, -1, -1):
            repr_l = level_representations[lvl]
            if lvl < self.num_levels - 1 and self.use_hierarchical_prediction:
                top_down = self.top_down_proj[lvl](refined_representations[-1] if refined_representations else level_representations[lvl + 1])
                gate_val = torch.sigmoid(self.hierarchy_gates[lvl])
                repr_l = repr_l + gate_val * top_down
            refined_representations.append(repr_l)
        refined_representations.reverse()

        predictions = []
        for lvl in range(self.num_levels):
            if lvl > 0 and self.use_hierarchical_prediction:
                pred_input = torch.cat([refined_representations[lvl], refined_representations[lvl - 1]], dim=-1)
            else:
                pred_input = torch.cat([refined_representations[lvl], refined_representations[lvl]], dim=-1)

            pred_params = self.level_predictors[lvl](pred_input)
            pred_mu, pred_logvar = pred_params.chunk(2, dim=-1)
            pred_sample = self._reparameterize(pred_mu, pred_logvar)
            pred_decoded = self.decoders[lvl](pred_sample)
            predictions.append(pred_decoded)

            if target is not None:
                tgt_flat = target.mean(dim=1) if target.dim() == 3 else target
                error = tgt_flat - pred_decoded
                if self.use_precision_weighting:
                    prec_input = torch.cat([pred_decoded, tgt_flat], dim=-1)
                    precision = self.precision_estimators[lvl](prec_input)
                    total_precision = total_precision + precision.mean()
                    weighted_error = error * precision
                else:
                    weighted_error = error
                error_proj = self.error_projectors[lvl](weighted_error)
                level_errors.append(error_proj)
                refined_representations[lvl] = refined_representations[lvl] + error_proj * torch.sigmoid(self.correction_gate)

        kl_losses = []
        if self.use_bayesian_inference:
            for lvl in range(self.num_levels):
                prior_params = self.prior_nets[lvl](refined_representations[lvl])
                prior_mu, prior_logvar = prior_params.chunk(2, dim=-1)
                if target is not None:
                    tgt_flat = target.mean(dim=1) if target.dim() == 3 else target
                    post_params = self.posterior_nets[lvl](
                        torch.cat([refined_representations[lvl], tgt_flat], dim=-1)
                    )
                    post_mu, post_logvar = post_params.chunk(2, dim=-1)
                    kl = self._compute_kl(post_mu, post_logvar, prior_mu, prior_logvar)
                    kl_losses.append(kl)
                    z = self._reparameterize(post_mu, post_logvar)
                    latent_decoded = self.latent_decoders[lvl](z)
                    refined_representations[lvl] = refined_representations[lvl] + latent_decoded * 0.1

        total_kl = sum(kl_losses) / max(len(kl_losses), 1) if kl_losses else total_kl

        if self.use_temporal_prediction:
            temporal_preds_list = []
            for lvl in range(self.num_levels):
                repr_seq = refined_representations[lvl].unsqueeze(1)
                temp_out, _ = self.temporal_predictors[lvl](repr_seq)
                horizon_preds = self.temporal_horizon_heads[lvl](temp_out.mean(dim=1))
                horizon_preds = horizon_preds.view(B, self.prediction_horizon, self.dim // 1 if self.dim == self.dim else self.dim)
                temporal_preds_list.append(horizon_preds[:, :1, :].squeeze(1))

        surprise = torch.tensor(0.0, device=x.device)
        if self.use_surprise_minimization and target is not None:
            tgt_flat = target.mean(dim=1) if target.dim() == 3 else target
            for lvl in range(self.num_levels):
                surp = self.surprise_estimator(
                    torch.cat([refined_representations[lvl], tgt_flat], dim=-1)
                )
                surprise = surprise + surp.mean()
                adapt = self.adaptation_net(
                    torch.cat([refined_representations[lvl], tgt_flat], dim=-1)
                )
                refined_representations[lvl] = refined_representations[lvl] + adapt * 0.05

        free_energy = torch.tensor(0.0, device=x.device)
        if self.use_free_energy and target is not None:
            tgt_flat = target.mean(dim=1) if target.dim() == 3 else target
            for lvl in range(self.num_levels):
                fe = self.free_energy_estimator(
                    torch.cat([refined_representations[lvl], tgt_flat], dim=-1)
                )
                free_energy = free_energy + fe.mean()

        contrastive_loss = torch.tensor(0.0, device=x.device)
        if self.use_contrastive_prediction and target is not None:
            tgt_flat = target.mean(dim=1) if target.dim() == 3 else target
            pred_proj = self.contrastive_proj(refined_representations[-1])
            tgt_proj = self.contrastive_proj(tgt_flat)
            pred_norm = F.normalize(pred_proj, dim=-1)
            tgt_norm = F.normalize(tgt_proj, dim=-1)
            temp = torch.abs(self.contrastive_temperature)
            sim = (pred_norm * tgt_norm).sum(dim=-1) / temp
            contrastive_loss = (-sim).mean()

        fused = self.output_fusion(torch.cat(refined_representations, dim=-1))
        gate = torch.sigmoid(self.output_gate)
        x_flat = x.mean(dim=1)
        out = self.output_norm(gate * fused + (1 - gate) * x_flat)

        if level_errors:
            correction = self.correction_net(torch.cat([out, torch.stack(level_errors).mean(dim=0)], dim=-1))
            out = out + torch.sigmoid(self.correction_gate) * correction

        total_prediction_error = sum(
            F.mse_loss(pred, (target.mean(dim=1) if target.dim() == 3 else target))
            for pred in predictions
        ) / len(predictions) if target is not None and predictions else torch.tensor(0.0, device=x.device)

        return {
            'prediction': out,
            'level_representations': refined_representations,
            'level_predictions': predictions,
            'total_prediction_error': total_prediction_error,
            'kl_loss': total_kl * self.beta,
            'surprise': surprise,
            'free_energy': free_energy,
            'contrastive_loss': contrastive_loss,
            'precision': total_precision,
        }

class HealthAdvisor(nn.Module):
    def __init__(self, dim: int, num_conditions: int = 2048,
                 num_medications: int = 4096, num_symptoms: int = 512,
                 num_lab_tests: int = 1024, num_specialties: int = 64,
                 num_heads: int = 16, num_layers: int = 8,
                 dropout: float = 0.1, use_clinical_guidelines: bool = True,
                 use_drug_interaction_check: bool = True,
                 use_risk_stratification: bool = True,
                 use_longitudinal_analysis: bool = True,
                 use_differential_diagnosis: bool = True,
                 use_evidence_grading: bool = True,
                 use_patient_specific_dosing: bool = True,
                 use_contraindication_check: bool = True,
                 urgency_levels: int = 5, confidence_levels: int = 4):
        super().__init__()
        self.dim = dim
        self.num_conditions = num_conditions
        self.num_medications = num_medications
        self.num_symptoms = num_symptoms
        self.num_lab_tests = num_lab_tests
        self.num_specialties = num_specialties
        self.urgency_levels = urgency_levels
        self.confidence_levels = confidence_levels

        self.symptom_embed = nn.Embedding(num_symptoms, dim)
        self.condition_embed = nn.Embedding(num_conditions, dim)
        self.medication_embed = nn.Embedding(num_medications, dim)
        self.lab_embed = nn.Embedding(num_lab_tests, dim)
        self.specialty_embed = nn.Embedding(num_specialties, dim)

        self.vital_signs_encoder = nn.Sequential(
            nn.Linear(20, dim), nn.GELU(),
            nn.Linear(dim, dim)
        )
        self.demographics_encoder = nn.Sequential(
            nn.Linear(10, dim // 2), nn.GELU(),
            nn.Linear(dim // 2, dim)
        )
        self.lab_values_encoder = nn.Sequential(
            nn.Linear(num_lab_tests, dim * 2), nn.GELU(),
            nn.Linear(dim * 2, dim)
        )

        self.symptom_encoder = nn.Sequential(
            nn.Linear(dim, dim * 4), nn.GELU(),
            nn.Dropout(dropout),
            nn.Linear(dim * 4, dim * 2), nn.GELU(),
            nn.Linear(dim * 2, dim)
        )

        encoder_layer = nn.TransformerEncoderLayer(
            d_model=dim, nhead=num_heads, dim_feedforward=dim * 4,
            dropout=dropout, activation='gelu', batch_first=True, norm_first=True
        )
        self.clinical_encoder = nn.TransformerEncoder(encoder_layer, num_layers=num_layers)

        if use_differential_diagnosis:
            self.differential_net = nn.Sequential(
                nn.Linear(dim, dim * 4), nn.GELU(),
                nn.Linear(dim * 4, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, num_conditions)
            )
            self.differential_confidence = nn.Sequential(
                nn.Linear(dim, dim), nn.GELU(),
                nn.Linear(dim, num_conditions), nn.Sigmoid()
            )
            self.pathology_encoder = nn.Sequential(
                nn.Linear(dim, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, dim)
            )

        if use_clinical_guidelines:
            self.guideline_memory = nn.Parameter(torch.randn(512, dim) * 0.02)
            self.guideline_attn = nn.MultiheadAttention(dim, num_heads, batch_first=True)
            self.guideline_norm = nn.LayerNorm(dim)
            self.guideline_compliance_head = nn.Sequential(
                nn.Linear(dim * 2, dim), nn.GELU(),
                nn.Linear(dim, 1), nn.Sigmoid()
            )

        if use_drug_interaction_check:
            self.drug_interaction_matrix = nn.Parameter(
                torch.zeros(min(num_medications, 1024), min(num_medications, 1024))
            )
            self.interaction_severity_head = nn.Sequential(
                nn.Linear(dim * 2, dim), nn.GELU(),
                nn.Linear(dim, 5)
            )
            self.polypharmacy_risk_net = nn.Sequential(
                nn.Linear(dim, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, 1), nn.Sigmoid()
            )

        if use_risk_stratification:
            self.risk_encoder = nn.Sequential(
                nn.Linear(dim, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, dim)
            )
            self.risk_head = nn.Sequential(
                nn.Linear(dim, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, 5)
            )
            self.frailty_score_net = nn.Sequential(
                nn.Linear(dim, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, 1), nn.Sigmoid()
            )
            self.comorbidity_index_net = nn.Sequential(
                nn.Linear(dim, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, 1)
            )

        if use_longitudinal_analysis:
            self.longitudinal_rnn = nn.LSTM(dim, dim, num_layers=2,
                                            batch_first=True, dropout=dropout)
            self.trend_analyzer = nn.Sequential(
                nn.Linear(dim, dim), nn.GELU(),
                nn.Linear(dim, 3)
            )
            self.prognosis_head = nn.Sequential(
                nn.Linear(dim, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, 10)
            )

        if use_evidence_grading:
            self.evidence_grader = nn.Sequential(
                nn.Linear(dim, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, 5)
            )
            self.recommendation_strength = nn.Sequential(
                nn.Linear(dim, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, 4)
            )

        if use_patient_specific_dosing:
            self.dosing_calculator = nn.Sequential(
                nn.Linear(dim + 10, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, dim), nn.GELU(),
                nn.Linear(dim, num_medications)
            )
            self.dosing_adjustment_net = nn.Sequential(
                nn.Linear(dim, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, 1), nn.Softplus()
            )

        if use_contraindication_check:
            self.contraindication_matrix = nn.Parameter(
                torch.zeros(min(num_medications, 512), num_conditions)
            )
            self.contraindication_severity = nn.Sequential(
                nn.Linear(dim * 2, dim), nn.GELU(),
                nn.Linear(dim, 4)
            )

        self.urgency_head = nn.Sequential(
            nn.Linear(dim, dim * 2), nn.GELU(),
            nn.Linear(dim * 2, urgency_levels)
        )
        self.specialty_referral_head = nn.Sequential(
            nn.Linear(dim, dim * 2), nn.GELU(),
            nn.Linear(dim * 2, num_specialties)
        )
        self.treatment_recommendation_head = nn.Sequential(
            nn.Linear(dim, dim * 4), nn.GELU(),
            nn.Linear(dim * 4, dim * 2), nn.GELU(),
            nn.Linear(dim * 2, dim)
        )
        self.test_recommendation_head = nn.Sequential(
            nn.Linear(dim, dim * 2), nn.GELU(),
            nn.Linear(dim * 2, num_lab_tests)
        )
        self.patient_education_head = nn.Sequential(
            nn.Linear(dim, dim * 2), nn.GELU(),
            nn.Linear(dim * 2, dim)
        )
        self.follow_up_timing_head = nn.Sequential(
            nn.Linear(dim, dim // 2), nn.GELU(),
            nn.Linear(dim // 2, 6)
        )

        self.output_norm = nn.LayerNorm(dim)
        self.output_proj = nn.Linear(dim, dim)
        self.confidence_head = nn.Sequential(
            nn.Linear(dim, dim // 2), nn.GELU(),
            nn.Linear(dim // 2, 1), nn.Sigmoid()
        )

    def forward(self, symptoms: Tensor,
                vital_signs: Optional[Tensor] = None,
                demographics: Optional[Tensor] = None,
                lab_values: Optional[Tensor] = None,
                current_medications: Optional[Tensor] = None,
                medical_history: Optional[Tensor] = None,
                known_conditions: Optional[Tensor] = None) -> Dict[str, Tensor]:
        B = symptoms.shape[0]
        is_seq = symptoms.dim() == 3
        if not is_seq:
            symptoms = symptoms.unsqueeze(1)

        x = self.symptom_encoder(symptoms)

        if vital_signs is not None:
            vs_enc = self.vital_signs_encoder(vital_signs.float())
            x = x + vs_enc.unsqueeze(1).expand_as(x)

        if demographics is not None:
            demo_enc = self.demographics_encoder(demographics.float())
            x = x + demo_enc.unsqueeze(1).expand_as(x)

        if lab_values is not None:
            lab_enc = self.lab_values_encoder(lab_values.float())
            x = x + lab_enc.unsqueeze(1).expand_as(x)

        encoded = self.clinical_encoder(x)
        pooled = encoded.mean(dim=1)

        if hasattr(self, 'guideline_attn'):
            gl = self.guideline_memory.unsqueeze(0).expand(B, -1, -1)
            gl_out, _ = self.guideline_attn(pooled.unsqueeze(1), gl, gl)
            pooled = self.guideline_norm(pooled + gl_out.squeeze(1))

        differential_dx = None
        if hasattr(self, 'differential_net'):
            diff_logits = self.differential_net(pooled)
            diff_conf = self.differential_confidence(pooled)
            differential_dx = {
                'diagnoses': F.softmax(diff_logits, dim=-1),
                'confidence': diff_conf,
                'top5': torch.topk(diff_logits, min(5, self.num_conditions), dim=-1)
            }

        risk = None
        if hasattr(self, 'risk_head'):
            risk_encoded = self.risk_encoder(pooled)
            risk = {
                'stratification': F.softmax(self.risk_head(risk_encoded), dim=-1),
                'frailty': self.frailty_score_net(risk_encoded),
                'comorbidity_index': self.comorbidity_index_net(risk_encoded)
            }

        longitudinal = None
        if hasattr(self, 'longitudinal_rnn') and medical_history is not None:
            if medical_history.dim() == 2:
                medical_history = medical_history.unsqueeze(1)
            hist_out, _ = self.longitudinal_rnn(medical_history)
            trend = self.trend_analyzer(hist_out.mean(dim=1))
            prognosis = self.prognosis_head(hist_out.mean(dim=1))
            longitudinal = {
                'trend': F.softmax(trend, dim=-1),
                'prognosis': F.softmax(prognosis, dim=-1)
            }

        urgency = F.softmax(self.urgency_head(pooled), dim=-1)
        specialty_referral = F.softmax(self.specialty_referral_head(pooled), dim=-1)
        treatment = self.treatment_recommendation_head(pooled)
        test_rec = self.test_recommendation_head(pooled)
        patient_ed = self.patient_education_head(pooled)
        follow_up = F.softmax(self.follow_up_timing_head(pooled), dim=-1)
        confidence = self.confidence_head(pooled)

        evidence_quality = None
        if hasattr(self, 'evidence_grader'):
            evidence_quality = {
                'grade': F.softmax(self.evidence_grader(pooled), dim=-1),
                'strength': F.softmax(self.recommendation_strength(pooled), dim=-1)
            }

        out = self.output_norm(self.output_proj(pooled))

        result = {
            'clinical_embedding': out,
            'urgency': urgency,
            'specialty_referral': specialty_referral,
            'treatment_recommendation': treatment,
            'recommended_tests': F.sigmoid(test_rec),
            'patient_education': patient_ed,
            'follow_up_timing': follow_up,
            'confidence': confidence,
        }
        if differential_dx is not None:
            result['differential_diagnosis'] = differential_dx
        if risk is not None:
            result['risk'] = risk
        if longitudinal is not None:
            result['longitudinal'] = longitudinal
        if evidence_quality is not None:
            result['evidence_quality'] = evidence_quality
        return result

class LegalAssistant(nn.Module):
    def __init__(self, dim: int, num_jurisdictions: int = 256,
                 num_legal_domains: int = 64, num_case_types: int = 128,
                 num_statutes: int = 10000, num_precedents: int = 50000,
                 num_heads: int = 16, num_layers: int = 8,
                 dropout: float = 0.1, use_precedent_retrieval: bool = True,
                 use_jurisdiction_analysis: bool = True,
                 use_risk_assessment: bool = True,
                 use_document_analysis: bool = True,
                 use_argument_construction: bool = True,
                 use_timeline_extraction: bool = True,
                 use_entity_recognition: bool = True,
                 use_contract_analysis: bool = True,
                 use_compliance_check: bool = True):
        super().__init__()
        self.dim = dim
        self.num_jurisdictions = num_jurisdictions
        self.num_legal_domains = num_legal_domains
        self.num_case_types = num_case_types
        self.num_statutes = num_statutes

        self.jurisdiction_embed = nn.Embedding(num_jurisdictions, dim)
        self.domain_embed = nn.Embedding(num_legal_domains, dim)
        self.case_type_embed = nn.Embedding(num_case_types, dim)

        self.legal_text_encoder = nn.Sequential(
            nn.Linear(dim, dim * 4), nn.GELU(),
            nn.Dropout(dropout),
            nn.Linear(dim * 4, dim * 2), nn.GELU(),
            nn.Linear(dim * 2, dim)
        )

        encoder_layer = nn.TransformerEncoderLayer(
            d_model=dim, nhead=num_heads, dim_feedforward=dim * 4,
            dropout=dropout, activation='gelu', batch_first=True, norm_first=True
        )
        self.legal_encoder = nn.TransformerEncoder(encoder_layer, num_layers=num_layers)

        if use_precedent_retrieval:
            self.precedent_keys = nn.Parameter(torch.randn(min(num_precedents, 2048), dim) * 0.02)
            self.precedent_values = nn.Parameter(torch.randn(min(num_precedents, 2048), dim) * 0.02)
            self.precedent_attn = nn.MultiheadAttention(dim, num_heads, batch_first=True)
            self.precedent_norm = nn.LayerNorm(dim)
            self.precedent_relevance_head = nn.Sequential(
                nn.Linear(dim * 2, dim), nn.GELU(),
                nn.Linear(dim, 1), nn.Sigmoid()
            )

        if use_jurisdiction_analysis:
            self.jurisdiction_conflict_detector = nn.Sequential(
                nn.Linear(dim * 2, dim), nn.GELU(),
                nn.Linear(dim, 1), nn.Sigmoid()
            )
            self.applicable_law_head = nn.Sequential(
                nn.Linear(dim, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, num_jurisdictions)
            )

        if use_risk_assessment:
            self.legal_risk_encoder = nn.Sequential(
                nn.Linear(dim, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, dim)
            )
            self.risk_classification_head = nn.Sequential(
                nn.Linear(dim, dim), nn.GELU(),
                nn.Linear(dim, 5)
            )
            self.liability_estimator = nn.Sequential(
                nn.Linear(dim, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, 1), nn.Sigmoid()
            )
            self.settlement_range_net = nn.Sequential(
                nn.Linear(dim, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, 2), nn.Softplus()
            )

        if use_document_analysis:
            self.clause_detector = nn.Sequential(
                nn.Linear(dim, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, 32)
            )
            self.clause_importance = nn.Sequential(
                nn.Linear(dim, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, 1), nn.Sigmoid()
            )
            self.ambiguity_detector = nn.Sequential(
                nn.Linear(dim, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, 1), nn.Sigmoid()
            )

        if use_argument_construction:
            self.argument_builder = nn.Sequential(
                nn.Linear(dim, dim * 4), nn.GELU(),
                nn.Linear(dim * 4, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, dim)
            )
            self.counter_argument_net = nn.Sequential(
                nn.Linear(dim, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, dim)
            )
            self.argument_strength_head = nn.Sequential(
                nn.Linear(dim, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, 1), nn.Sigmoid()
            )

        if use_timeline_extraction:
            self.event_detector = nn.Sequential(
                nn.Linear(dim, dim), nn.GELU(),
                nn.Linear(dim, 1), nn.Sigmoid()
            )
            self.temporal_ordering_net = nn.GRU(dim, dim, num_layers=2, batch_first=True)
            self.deadline_extractor = nn.Sequential(
                nn.Linear(dim, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, 1), nn.Softplus()
            )

        if use_entity_recognition:
            self.party_identifier = nn.Sequential(
                nn.Linear(dim, dim), nn.GELU(),
                nn.Linear(dim, 6)
            )
            self.entity_relation_net = nn.MultiheadAttention(dim, num_heads, batch_first=True)
            self.entity_norm = nn.LayerNorm(dim)

        if use_contract_analysis:
            self.contract_type_classifier = nn.Sequential(
                nn.Linear(dim, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, 20)
            )
            self.obligation_extractor = nn.Sequential(
                nn.Linear(dim, dim), nn.GELU(),
                nn.Linear(dim, 1), nn.Sigmoid()
            )
            self.enforceability_head = nn.Sequential(
                nn.Linear(dim, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, 1), nn.Sigmoid()
            )
            self.red_flag_detector = nn.Sequential(
                nn.Linear(dim, dim), nn.GELU(),
                nn.Linear(dim, 10), nn.Sigmoid()
            )

        if use_compliance_check:
            self.regulation_encoder = nn.Sequential(
                nn.Linear(dim, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, dim)
            )
            self.compliance_head = nn.Sequential(
                nn.Linear(dim * 2, dim), nn.GELU(),
                nn.Linear(dim, 1), nn.Sigmoid()
            )
            self.violation_detector = nn.Sequential(
                nn.Linear(dim * 2, dim), nn.GELU(),
                nn.Linear(dim, num_statutes)
            )
            self.remediation_recommender = nn.Sequential(
                nn.Linear(dim, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, dim)
            )

        self.case_outcome_predictor = nn.Sequential(
            nn.Linear(dim, dim * 2), nn.GELU(),
            nn.Linear(dim * 2, 5)
        )
        self.appeal_probability_head = nn.Sequential(
            nn.Linear(dim, dim // 2), nn.GELU(),
            nn.Linear(dim // 2, 1), nn.Sigmoid()
        )
        self.settlement_recommendation_head = nn.Sequential(
            nn.Linear(dim, dim // 2), nn.GELU(),
            nn.Linear(dim // 2, 1), nn.Sigmoid()
        )

        self.output_norm = nn.LayerNorm(dim)
        self.output_proj = nn.Linear(dim, dim)
        self.confidence_head = nn.Sequential(
            nn.Linear(dim, dim // 2), nn.GELU(),
            nn.Linear(dim // 2, 1), nn.Sigmoid()
        )

    def forward(self, case_text: Tensor,
                jurisdiction_id: Optional[int] = None,
                domain_id: Optional[int] = None,
                regulations: Optional[Tensor] = None,
                prior_cases: Optional[Tensor] = None,
                contract_clauses: Optional[Tensor] = None) -> Dict[str, Tensor]:
        B = case_text.shape[0]
        is_seq = case_text.dim() == 3
        if not is_seq:
            case_text = case_text.unsqueeze(1)

        x = self.legal_text_encoder(case_text)

        if jurisdiction_id is not None:
            jur_emb = self.jurisdiction_embed(
                torch.tensor(min(jurisdiction_id, self.num_jurisdictions - 1), device=case_text.device)
            )
            x = x + jur_emb.unsqueeze(0).unsqueeze(0).expand_as(x)

        if domain_id is not None:
            dom_emb = self.domain_embed(
                torch.tensor(min(domain_id, self.num_legal_domains - 1), device=case_text.device)
            )
            x = x + dom_emb.unsqueeze(0).unsqueeze(0).expand_as(x)

        encoded = self.legal_encoder(x)
        pooled = encoded.mean(dim=1)

        if hasattr(self, 'precedent_attn'):
            prec_keys = self.precedent_keys.unsqueeze(0).expand(B, -1, -1)
            prec_vals = self.precedent_values.unsqueeze(0).expand(B, -1, -1)
            prec_out, _ = self.precedent_attn(pooled.unsqueeze(1), prec_keys, prec_vals)
            pooled = self.precedent_norm(pooled + prec_out.squeeze(1))

        if hasattr(self, 'entity_relation_net'):
            ent_out, _ = self.entity_relation_net(encoded, encoded, encoded)
            encoded = self.entity_norm(encoded + ent_out)
            pooled = encoded.mean(dim=1)

        risk_result, contract_result, compliance_result = {}, {}, {}

        if hasattr(self, 'legal_risk_encoder'):
            risk_enc = self.legal_risk_encoder(pooled)
            risk_result = {
                'risk_classification': F.softmax(self.risk_classification_head(risk_enc), dim=-1),
                'liability_probability': self.liability_estimator(risk_enc),
                'settlement_range': self.settlement_range_net(risk_enc)
            }

        if hasattr(self, 'contract_type_classifier') and contract_clauses is not None:
            contract_result = {
                'contract_type': F.softmax(self.contract_type_classifier(pooled), dim=-1),
                'obligation_scores': self.obligation_extractor(encoded).squeeze(-1),
                'enforceability': self.enforceability_head(pooled),
                'red_flags': self.red_flag_detector(pooled)
            }

        if hasattr(self, 'compliance_head') and regulations is not None:
            if regulations.dim() == 2:
                regulations = regulations.unsqueeze(1)
            reg_enc = self.regulation_encoder(regulations.mean(dim=1))
            compliance_result = {
                'compliance_score': self.compliance_head(torch.cat([pooled, reg_enc], dim=-1)),
                'violations': F.sigmoid(self.violation_detector(torch.cat([pooled, reg_enc], dim=-1))),
                'remediation': self.remediation_recommender(pooled)
            }

        outcome_pred = F.softmax(self.case_outcome_predictor(pooled), dim=-1)
        appeal_prob = self.appeal_probability_head(pooled)
        settlement_rec = self.settlement_recommendation_head(pooled)
        confidence = self.confidence_head(pooled)

        argument = None
        if hasattr(self, 'argument_builder'):
            arg_built = self.argument_builder(pooled)
            counter_arg = self.counter_argument_net(pooled)
            arg_strength = self.argument_strength_head(arg_built)
            argument = {
                'argument': arg_built,
                'counter_argument': counter_arg,
                'strength': arg_strength
            }

        out = self.output_norm(self.output_proj(pooled))

        result = {
            'legal_embedding': out,
            'case_outcome_prediction': outcome_pred,
            'appeal_probability': appeal_prob,
            'settlement_recommendation': settlement_rec,
            'confidence': confidence,
        }
        result.update(risk_result)
        if contract_result:
            result['contract_analysis'] = contract_result
        if compliance_result:
            result['compliance'] = compliance_result
        if argument:
            result['argument'] = argument
        return result

class CodeArchitect(nn.Module):
    def __init__(self, dim: int, num_languages: int = 64,
                 num_patterns: int = 512, num_frameworks: int = 256,
                 num_api_endpoints: int = 4096, num_heads: int = 16,
                 num_layers: int = 8, dropout: float = 0.1,
                 use_architecture_patterns: bool = True,
                 use_code_smell_detection: bool = True,
                 use_complexity_analysis: bool = True,
                 use_dependency_analysis: bool = True,
                 use_test_generation: bool = True,
                 use_documentation_generation: bool = True,
                 use_refactoring_suggestions: bool = True,
                 use_performance_profiling: bool = True,
                 use_security_analysis: bool = True,
                 use_microservice_design: bool = True):
        super().__init__()
        self.dim = dim
        self.num_languages = num_languages
        self.num_patterns = num_patterns
        self.num_frameworks = num_frameworks

        self.language_embed = nn.Embedding(num_languages, dim)
        self.pattern_embed = nn.Embedding(num_patterns, dim)
        self.framework_embed = nn.Embedding(num_frameworks, dim)

        self.requirements_encoder = nn.Sequential(
            nn.Linear(dim, dim * 4), nn.GELU(),
            nn.Dropout(dropout),
            nn.Linear(dim * 4, dim * 2), nn.GELU(),
            nn.Linear(dim * 2, dim)
        )

        encoder_layer = nn.TransformerEncoderLayer(
            d_model=dim, nhead=num_heads, dim_feedforward=dim * 4,
            dropout=dropout, activation='gelu', batch_first=True, norm_first=True
        )
        self.architecture_encoder = nn.TransformerEncoder(encoder_layer, num_layers=num_layers)

        if use_architecture_patterns:
            self.pattern_keys = nn.Parameter(torch.randn(num_patterns, dim) * 0.02)
            self.pattern_attn = nn.MultiheadAttention(dim, num_heads, batch_first=True)
            self.pattern_norm = nn.LayerNorm(dim)
            self.pattern_classifier = nn.Sequential(
                nn.Linear(dim, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, num_patterns)
            )
            self.pattern_applicability = nn.Sequential(
                nn.Linear(dim * 2, dim), nn.GELU(),
                nn.Linear(dim, 1), nn.Sigmoid()
            )

        if use_complexity_analysis:
            self.cyclomatic_predictor = nn.Sequential(
                nn.Linear(dim, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, 1), nn.Softplus()
            )
            self.cognitive_complexity_head = nn.Sequential(
                nn.Linear(dim, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, 1), nn.Softplus()
            )
            self.halstead_metrics_head = nn.Sequential(
                nn.Linear(dim, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, 6), nn.Softplus()
            )

        if use_code_smell_detection:
            self.smell_detector = nn.Sequential(
                nn.Linear(dim, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, 20), nn.Sigmoid()
            )
            self.smell_severity_head = nn.Sequential(
                nn.Linear(dim, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, 3)
            )

        if use_dependency_analysis:
            self.dependency_graph_encoder = nn.Sequential(
                nn.Linear(dim, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, dim)
            )
            self.circular_dep_detector = nn.Sequential(
                nn.Linear(dim, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, 1), nn.Sigmoid()
            )
            self.coupling_metric = nn.Sequential(
                nn.Linear(dim, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, 1), nn.Sigmoid()
            )

        if use_test_generation:
            self.test_type_classifier = nn.Sequential(
                nn.Linear(dim, dim), nn.GELU(),
                nn.Linear(dim, 5)
            )
            self.coverage_predictor = nn.Sequential(
                nn.Linear(dim, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, 1), nn.Sigmoid()
            )
            self.edge_case_identifier = nn.Sequential(
                nn.Linear(dim, dim), nn.GELU(),
                nn.Linear(dim, 1), nn.Sigmoid()
            )

        if use_security_analysis:
            self.vulnerability_classifier = nn.Sequential(
                nn.Linear(dim, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, 25), nn.Sigmoid()
            )
            self.owasp_risk_head = nn.Sequential(
                nn.Linear(dim, dim), nn.GELU(),
                nn.Linear(dim, 10)
            )
            self.injection_risk_head = nn.Sequential(
                nn.Linear(dim, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, 1), nn.Sigmoid()
            )

        if use_performance_profiling:
            self.bottleneck_detector = nn.Sequential(
                nn.Linear(dim, dim), nn.GELU(),
                nn.Linear(dim, 1), nn.Sigmoid()
            )
            self.time_complexity_head = nn.Sequential(
                nn.Linear(dim, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, 7)
            )
            self.space_complexity_head = nn.Sequential(
                nn.Linear(dim, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, 7)
            )
            self.optimization_opportunity_head = nn.Sequential(
                nn.Linear(dim, dim), nn.GELU(),
                nn.Linear(dim, 8), nn.Sigmoid()
            )

        if use_refactoring_suggestions:
            self.refactoring_classifier = nn.Sequential(
                nn.Linear(dim, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, 15)
            )
            self.refactoring_impact_head = nn.Sequential(
                nn.Linear(dim, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, 3)
            )
            self.extract_method_scorer = nn.Sequential(
                nn.Linear(dim, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, 1), nn.Sigmoid()
            )

        if use_microservice_design:
            self.service_decomposition_head = nn.Sequential(
                nn.Linear(dim, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, dim)
            )
            self.api_contract_head = nn.Sequential(
                nn.Linear(dim, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, num_api_endpoints)
            )
            self.service_boundary_detector = nn.Sequential(
                nn.Linear(dim * 2, dim), nn.GELU(),
                nn.Linear(dim, 1), nn.Sigmoid()
            )

        if use_documentation_generation:
            self.docstring_generator = nn.Sequential(
                nn.Linear(dim, dim * 4), nn.GELU(),
                nn.Linear(dim * 4, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, dim)
            )
            self.api_doc_quality_head = nn.Sequential(
                nn.Linear(dim, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, 1), nn.Sigmoid()
            )

        self.maintainability_index = nn.Sequential(
            nn.Linear(dim, dim // 2), nn.GELU(),
            nn.Linear(dim // 2, 1), nn.Sigmoid()
        )
        self.technical_debt_head = nn.Sequential(
            nn.Linear(dim, dim // 2), nn.GELU(),
            nn.Linear(dim // 2, 1), nn.Softplus()
        )
        self.architecture_score_head = nn.Sequential(
            nn.Linear(dim, dim // 2), nn.GELU(),
            nn.Linear(dim // 2, 1), nn.Sigmoid()
        )

        self.output_norm = nn.LayerNorm(dim)
        self.output_proj = nn.Linear(dim, dim)

    def forward(self, requirements: Tensor,
                language_id: Optional[int] = None,
                framework_id: Optional[int] = None,
                existing_code: Optional[Tensor] = None,
                dependencies: Optional[Tensor] = None) -> Dict[str, Tensor]:
        B = requirements.shape[0]
        is_seq = requirements.dim() == 3
        if not is_seq:
            requirements = requirements.unsqueeze(1)

        x = self.requirements_encoder(requirements)

        if language_id is not None:
            lang_emb = self.language_embed(
                torch.tensor(min(language_id, self.num_languages - 1), device=requirements.device)
            )
            x = x + lang_emb.unsqueeze(0).unsqueeze(0).expand_as(x)

        if framework_id is not None:
            fw_emb = self.framework_embed(
                torch.tensor(min(framework_id, self.num_frameworks - 1), device=requirements.device)
            )
            x = x + fw_emb.unsqueeze(0).unsqueeze(0).expand_as(x)

        encoded = self.architecture_encoder(x)
        pooled = encoded.mean(dim=1)

        if hasattr(self, 'pattern_attn'):
            pat_keys = self.pattern_keys.unsqueeze(0).expand(B, -1, -1)
            pat_out, _ = self.pattern_attn(pooled.unsqueeze(1), pat_keys, pat_keys)
            pooled = self.pattern_norm(pooled + pat_out.squeeze(1))

        result = {'architecture_embedding': self.output_norm(self.output_proj(pooled))}

        if hasattr(self, 'cyclomatic_predictor'):
            result['complexity'] = {
                'cyclomatic': self.cyclomatic_predictor(pooled),
                'cognitive': self.cognitive_complexity_head(pooled),
                'halstead': self.halstead_metrics_head(pooled)
            }
        if hasattr(self, 'smell_detector'):
            result['code_smells'] = {
                'detected': self.smell_detector(pooled),
                'severity': F.softmax(self.smell_severity_head(pooled), dim=-1)
            }
        if hasattr(self, 'vulnerability_classifier'):
            result['security'] = {
                'vulnerabilities': self.vulnerability_classifier(pooled),
                'owasp_risks': F.softmax(self.owasp_risk_head(pooled), dim=-1),
                'injection_risk': self.injection_risk_head(pooled)
            }
        if hasattr(self, 'time_complexity_head'):
            result['performance'] = {
                'time_complexity': F.softmax(self.time_complexity_head(pooled), dim=-1),
                'space_complexity': F.softmax(self.space_complexity_head(pooled), dim=-1),
                'bottleneck_probability': self.bottleneck_detector(pooled),
                'optimization_opportunities': self.optimization_opportunity_head(pooled)
            }
        if hasattr(self, 'refactoring_classifier'):
            result['refactoring'] = {
                'suggestions': F.softmax(self.refactoring_classifier(pooled), dim=-1),
                'impact': F.softmax(self.refactoring_impact_head(pooled), dim=-1),
                'extract_method_score': self.extract_method_scorer(pooled)
            }
        if hasattr(self, 'pattern_classifier'):
            result['patterns'] = F.softmax(self.pattern_classifier(pooled), dim=-1)
        if hasattr(self, 'docstring_generator'):
            result['documentation'] = {
                'embedding': self.docstring_generator(pooled),
                'quality_score': self.api_doc_quality_head(pooled)
            }
        result['maintainability_index'] = self.maintainability_index(pooled)
        result['technical_debt_hours'] = self.technical_debt_head(pooled)
        result['architecture_score'] = self.architecture_score_head(pooled)
        return result

class RealTimeLearner(nn.Module):
    def __init__(self, model: nn.Module, lr: float = 0.001,
                 meta_lr: float = 0.0001, inner_steps: int = 5,
                 outer_steps: int = 3, use_maml: bool = True,
                 use_reptile: bool = True, use_online_ewc: bool = True,
                 use_gradient_compression: bool = True,
                 use_adaptive_lr: bool = True,
                 use_replay_buffer: bool = True,
                 use_continual_learning: bool = True,
                 use_task_detection: bool = True,
                 replay_buffer_size: int = 1000,
                 dim: int = 512, num_tasks: int = 1000,
                 compression_ratio: float = 0.01,
                 ewc_lambda: float = 0.4,
                 patience: int = 10):
        super().__init__()
        self.model = model
        self.lr = lr
        self.meta_lr = meta_lr
        self.inner_steps = inner_steps
        self.outer_steps = outer_steps
        self.use_maml = use_maml
        self.use_reptile = use_reptile
        self.use_online_ewc = use_online_ewc
        self.use_gradient_compression = use_gradient_compression
        self.use_adaptive_lr = use_adaptive_lr
        self.use_replay_buffer = use_replay_buffer
        self.use_continual_learning = use_continual_learning
        self.use_task_detection = use_task_detection
        self.ewc_lambda = ewc_lambda
        self.patience = patience
        self.dim = dim

        self.base_optimizer = torch.optim.AdamW(model.parameters(), lr=lr, weight_decay=1e-4)
        self.meta_optimizer = torch.optim.AdamW(model.parameters(), lr=meta_lr, weight_decay=1e-5)
        self.base_scheduler = torch.optim.lr_scheduler.CosineAnnealingWarmRestarts(
            self.base_optimizer, T_0=1000, T_mult=2, eta_min=lr * 0.01
        )
        self.meta_scheduler = torch.optim.lr_scheduler.OneCycleLR(
            self.meta_optimizer, max_lr=meta_lr * 10,
            total_steps=10000, pct_start=0.1, anneal_strategy='cos'
        )

        if use_adaptive_lr:
            self.lr_controller = nn.Sequential(
                nn.Linear(6, 64), nn.GELU(),
                nn.Linear(64, 128), nn.GELU(),
                nn.Linear(128, 64), nn.GELU(),
                nn.Linear(64, 3), nn.Sigmoid()
            )
            self.lr_meta_net = nn.Sequential(
                nn.Linear(dim, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, dim // 4), nn.GELU(),
                nn.Linear(dim // 4, 1), nn.Sigmoid()
            )
            self.lr_optimizer = torch.optim.Adam(
                list(self.lr_controller.parameters()) +
                list(self.lr_meta_net.parameters()),
                lr=1e-4
            )
            self.loss_history: deque = deque(maxlen=100)
            self.grad_norm_history: deque = deque(maxlen=100)
            self.lr_scale = nn.Parameter(torch.ones(1))

        if use_task_detection:
            self.task_detector = nn.Sequential(
                nn.Linear(dim, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, dim), nn.GELU(),
                nn.Linear(dim, min(num_tasks, 2048))
            )
            self.task_transition_detector = nn.Sequential(
                nn.Linear(dim * 2, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, dim), nn.GELU(),
                nn.Linear(dim, 1), nn.Sigmoid()
            )
            self.task_embedding_bank = nn.Parameter(
                torch.randn(min(num_tasks, 2048), dim) * 0.02
            )
            self.task_context_rnn = nn.GRU(dim, dim, num_layers=2, batch_first=True)
            self.current_task_repr = nn.Parameter(torch.zeros(dim), requires_grad=False)
            self.prev_task_repr = nn.Parameter(torch.zeros(dim), requires_grad=False)
            self.task_novelty_head = nn.Sequential(
                nn.Linear(dim * 2, dim), nn.GELU(),
                nn.Linear(dim, 1), nn.Sigmoid()
            )
            self.task_optimizer = torch.optim.Adam(
                [p for p in self.task_detector.parameters()] +
                [p for p in self.task_transition_detector.parameters()],
                lr=1e-4
            )

        if use_online_ewc:
            self.fisher_information: Dict[str, Tensor] = {}
            self.optimal_params: Dict[str, Tensor] = {}
            self.fisher_ema_alpha = 0.95
            self.ewc_update_frequency = 50
            self._step_since_ewc = 0
            for name, param in model.named_parameters():
                if param.requires_grad:
                    self.fisher_information[name] = torch.zeros_like(param.data)
                    self.optimal_params[name] = param.data.clone()

        if use_replay_buffer:
            self.replay_buffer: deque = deque(maxlen=replay_buffer_size)
            self.replay_priority: deque = deque(maxlen=replay_buffer_size)
            self.replay_sampler_net = nn.Sequential(
                nn.Linear(dim, dim), nn.GELU(),
                nn.Linear(dim, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, 1), nn.Sigmoid()
            )
            self.replay_value_net = nn.Sequential(
                nn.Linear(dim, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, 1)
            )
            self.per_alpha = 0.6
            self.per_beta = 0.4
            self.replay_optimizer = torch.optim.Adam(
                list(self.replay_sampler_net.parameters()) +
                list(self.replay_value_net.parameters()),
                lr=1e-4
            )

        if use_gradient_compression:
            compressed_dim = max(1, int(dim * compression_ratio))
            self.compressor_encoder = nn.Sequential(
                nn.Linear(dim, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, compressed_dim)
            )
            self.compressor_decoder = nn.Sequential(
                nn.Linear(compressed_dim, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, dim)
            )
            self.error_feedback: Dict[str, Tensor] = {}
            self.sparsification_ratio = nn.Parameter(torch.tensor(compression_ratio))
            self.compression_optimizer = torch.optim.Adam(
                list(self.compressor_encoder.parameters()) +
                list(self.compressor_decoder.parameters()),
                lr=1e-4
            )

        if use_continual_learning:
            self.task_heads = nn.ModuleList([
                nn.Sequential(
                    nn.Linear(dim, dim // 2), nn.GELU(),
                    nn.Linear(dim // 2, dim // 4)
                )
                for _ in range(min(num_tasks, 32))
            ])
            self.progressive_columns = nn.ModuleList([
                nn.Sequential(
                    nn.Linear(dim, dim * 2), nn.GELU(),
                    nn.Linear(dim * 2, dim)
                )
                for _ in range(4)
            ])
            self.lateral_connections = nn.ModuleList([
                nn.Linear(dim, dim)
                for _ in range(4)
            ])
            self.pnn_gate = nn.Sequential(
                nn.Linear(dim * 4, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, dim)
            )
            self.continual_optimizer = torch.optim.Adam(
                list(self.task_heads.parameters()) +
                list(self.progressive_columns.parameters()) +
                list(self.lateral_connections.parameters()) +
                list(self.pnn_gate.parameters()),
                lr=lr
            )
            self.task_mask: Dict[int, Tensor] = {}
            self._active_task_id = 0

        if use_maml:
            self.meta_init_params: Dict[str, Tensor] = {
                name: param.data.clone()
                for name, param in model.named_parameters()
                if param.requires_grad
            }
            self.meta_gradient_buffer: Dict[str, Tensor] = {}

        self.grad_clip_norm = 1.0
        self._warmup_steps = 200
        self._warmup_lr_scale = nn.Parameter(torch.ones(1), requires_grad=False)

        self.loss_ema = nn.Parameter(torch.tensor(1.0), requires_grad=False)
        self.grad_ema = nn.Parameter(torch.tensor(1.0), requires_grad=False)
        self.loss_var = nn.Parameter(torch.tensor(1.0), requires_grad=False)

        self.second_order_optimizer_enabled = True
        self.hessian_free_steps = 3

        self.performance_tracker = {
            'train_losses': deque(maxlen=1000),
            'val_losses': deque(maxlen=200),
            'lr_history': deque(maxlen=1000),
            'grad_norms': deque(maxlen=1000),
            'task_switches': [],
            'forgetting_events': deque(maxlen=200),
        }

        self.register_buffer('step_count', torch.tensor(0, dtype=torch.long))
        self.register_buffer('epoch_count', torch.tensor(0, dtype=torch.long))
        self.register_buffer('running_loss', torch.zeros(1))
        self.register_buffer('running_grad_norm', torch.ones(1))
        self.register_buffer('task_id_counter', torch.tensor(0, dtype=torch.long))
        self._best_loss = float('inf')
        self._best_params: Optional[Dict] = None
        self._patience_counter = 0

    def _compute_ewc_loss(self) -> Tensor:
        if not self.use_online_ewc or not self.fisher_information:
            return torch.tensor(0.0)
        device = next(self.model.parameters()).device
        ewc_loss = torch.tensor(0.0, device=device)
        for name, param in self.model.named_parameters():
            if name in self.fisher_information and param.requires_grad:
                fisher = self.fisher_information[name].to(device)
                optimal = self.optimal_params[name].to(device)
                ewc_loss = ewc_loss + (fisher * (param - optimal).pow(2)).sum()
        return self.ewc_lambda * ewc_loss

    def _update_fisher_online(self, loss: Tensor) -> None:
        if not self.use_online_ewc:
            return
        self._step_since_ewc += 1
        if self._step_since_ewc % self.ewc_update_frequency != 0:
            return
        self.model.zero_grad()
        loss.backward(retain_graph=True)
        for name, param in self.model.named_parameters():
            if param.grad is not None and name in self.fisher_information:
                device = param.device
                self.fisher_information[name] = (
                    self.fisher_ema_alpha * self.fisher_information[name].to(device) +
                    (1 - self.fisher_ema_alpha) * param.grad.data.pow(2).detach()
                )
                self.optimal_params[name] = param.data.clone().detach()
        self.model.zero_grad()

    def _maml_inner_loop(self, x: Tensor, y: Tensor, loss_fn: Callable) -> Tuple[Dict[str, Tensor], Tensor]:
        fast_weights = {
            name: param.clone()
            for name, param in self.model.named_parameters()
            if param.requires_grad
        }
        total_inner_loss = torch.tensor(0.0, device=x.device)
        for step in range(self.inner_steps):
            output = self.model(x)
            if isinstance(output, dict):
                out_val = output.get('output', output.get('prediction', list(output.values())[0]))
            else:
                out_val = output
            inner_loss = loss_fn(out_val, y)
            total_inner_loss = total_inner_loss + inner_loss
            grads = torch.autograd.grad(
                inner_loss, list(fast_weights.values()),
                create_graph=self.second_order_optimizer_enabled,
                allow_unused=True
            )
            step_size = self.lr / (step + 1) ** 0.5
            fast_weights = {
                name: w - step_size * (g if g is not None else torch.zeros_like(w))
                for (name, w), g in zip(fast_weights.items(), grads)
            }
        return fast_weights, total_inner_loss / self.inner_steps

    def _reptile_inner_loop(self, x: Tensor, y: Tensor, loss_fn: Callable) -> Tensor:
        init_params = {
            name: param.data.clone()
            for name, param in self.model.named_parameters()
            if param.requires_grad
        }
        task_optimizer = torch.optim.SGD(
            self.model.parameters(), lr=self.lr, momentum=0.9, nesterov=True
        )
        total_loss = torch.tensor(0.0, device=x.device)
        for inner_step in range(self.inner_steps):
            output = self.model(x)
            if isinstance(output, dict):
                out_val = output.get('output', list(output.values())[0])
            else:
                out_val = output
            loss = loss_fn(out_val, y)
            task_optimizer.zero_grad()
            loss.backward()
            nn.utils.clip_grad_norm_(self.model.parameters(), self.grad_clip_norm)
            task_optimizer.step()
            total_loss = total_loss + loss.detach()
        with torch.no_grad():
            for name, param in self.model.named_parameters():
                if param.requires_grad and name in init_params:
                    learned_delta = param.data - init_params[name]
                    param.data = init_params[name] + self.meta_lr * learned_delta
        return total_loss / self.inner_steps

    def _compress_gradients(self) -> None:
        if not self.use_gradient_compression:
            return
        for name, param in self.model.named_parameters():
            if param.grad is None or not param.requires_grad:
                continue
            grad_flat = param.grad.data.flatten()
            if grad_flat.numel() < self.compressor_encoder[0].in_features:
                continue
            if name not in self.error_feedback:
                self.error_feedback[name] = torch.zeros_like(param.grad.data)
            accumulated = param.grad.data + self.error_feedback[name].to(param.device)
            sparsity = torch.sigmoid(self.sparsification_ratio).item()
            threshold = torch.quantile(accumulated.abs().flatten(), 1.0 - sparsity)
            mask = (accumulated.abs() >= threshold).float()
            compressed = accumulated * mask
            self.error_feedback[name] = (accumulated - compressed).detach()
            param.grad.data = compressed

    def _sample_replay(self, batch_size: int = 16) -> Optional[List]:
        if not self.use_replay_buffer or len(self.replay_buffer) < batch_size:
            return None
        priorities = torch.tensor(list(self.replay_priority), dtype=torch.float32)
        priorities = priorities ** self.per_alpha
        probs = priorities / priorities.sum()
        indices = torch.multinomial(probs, batch_size, replacement=False).tolist()
        buffer_list = list(self.replay_buffer)
        return [buffer_list[i] for i in indices]

    def _store_replay(self, x: Tensor, y: Tensor, loss: float) -> None:
        if not self.use_replay_buffer:
            return
        self.replay_buffer.append((x.detach().cpu(), y.detach().cpu()))
        priority = max(loss, 1e-6) ** self.per_alpha
        self.replay_priority.append(priority)

    def _detect_task(self, x: Tensor) -> Tuple[int, float]:
        if not self.use_task_detection:
            return 0, 0.0
        x_flat = x.mean(dim=1) if x.dim() == 3 else (x.mean(dim=0, keepdim=True) if x.dim() == 2 else x)
        with torch.no_grad():
            task_logits = self.task_detector(x_flat.mean(dim=0, keepdim=True))
            task_probs = F.softmax(task_logits, dim=-1)
            task_id = task_probs.argmax(dim=-1).item()
            task_repr = x_flat.mean(dim=0)
            prev = self.current_task_repr.to(task_repr.device)
            transition_score = self.task_transition_detector(
                torch.cat([task_repr.unsqueeze(0), prev.unsqueeze(0)], dim=-1)
            ).item()
            self.prev_task_repr.data = prev.clone()
            self.current_task_repr.data = (0.9 * prev + 0.1 * task_repr).detach()
        return int(task_id), float(transition_score)

    def _adaptive_lr_compute(self, loss_val: float, grad_norm: float) -> float:
        if not self.use_adaptive_lr:
            return self.lr
        self.loss_history.append(loss_val)
        self.grad_norm_history.append(grad_norm)
        if len(self.loss_history) < 6:
            return self.lr
        recent_losses = list(self.loss_history)[-6:]
        loss_trend = (recent_losses[-1] - recent_losses[0]) / (abs(recent_losses[0]) + 1e-8)
        loss_std = float(torch.tensor(recent_losses).std().item())
        grad_norm_avg = float(torch.tensor(list(self.grad_norm_history)[-10:]).mean().item())
        features = torch.tensor(
            [loss_trend, loss_std, grad_norm_avg,
             loss_val, grad_norm, float(self.step_count.item()) / 10000],
            dtype=torch.float32
        )
        with torch.no_grad():
            lr_scale = self.lr_controller(features.to(next(self.lr_controller.parameters()).device))
            scale_mean = lr_scale.mean().item()
        return self.lr * (0.1 + scale_mean * 9.9)

    def _continual_pnn_forward(self, x: Tensor, task_id: int) -> Tensor:
        if not self.use_continual_learning:
            return x
        outputs = []
        for col_idx, col in enumerate(self.progressive_columns):
            col_out = col(x)
            lateral_sum = torch.zeros_like(col_out)
            for prev_idx in range(col_idx):
                if prev_idx < len(outputs):
                    lateral_sum = lateral_sum + self.lateral_connections[prev_idx](outputs[prev_idx])
            outputs.append(col_out + lateral_sum)
        if outputs:
            combined = self.pnn_gate(torch.cat(outputs[:4], dim=-1) if len(outputs) >= 4 else
                                     torch.cat(outputs + [torch.zeros_like(outputs[0])] * (4 - len(outputs)), dim=-1))
            return combined
        return x

    def forward(self, x: Tensor, y: Tensor,
                loss_fn: Optional[Callable] = None,
                meta_batch: Optional[List[Tuple[Tensor, Tensor]]] = None,
                task_id: Optional[int] = None,
                eval_mode: bool = False) -> Dict[str, Any]:
        if loss_fn is None:
            loss_fn = F.mse_loss

        self.step_count += 1
        step = int(self.step_count.item())

        if self.use_task_detection:
            detected_task_id, transition_score = self._detect_task(x)
            if task_id is None:
                task_id = detected_task_id
            if transition_score > 0.7:
                self.performance_tracker['task_switches'].append({
                    'step': step, 'from': int(self.task_id_counter.item()),
                    'to': task_id, 'score': transition_score
                })
                self.task_id_counter.fill_(task_id)
        else:
            transition_score = 0.0

        if eval_mode:
            self.model.eval()
            with torch.no_grad():
                output = self.model(x)
                if isinstance(output, dict):
                    out_val = output.get('output', list(output.values())[0])
                else:
                    out_val = output
                loss = loss_fn(out_val, y)
            self.model.train()
            return {'loss': loss.item(), 'output': output}

        self.model.train()
        total_loss = torch.tensor(0.0, device=x.device)
        meta_loss = torch.tensor(0.0, device=x.device)

        if self.use_maml and meta_batch is not None:
            for task_x, task_y in meta_batch[:self.outer_steps]:
                fast_weights, inner_loss = self._maml_inner_loop(task_x, task_y, loss_fn)
                output = self.model(x)
                if isinstance(output, dict):
                    out_val = output.get('output', list(output.values())[0])
                else:
                    out_val = output
                outer_loss = loss_fn(out_val, y)
                meta_loss = meta_loss + outer_loss + inner_loss * 0.5
            meta_loss = meta_loss / max(len(meta_batch[:self.outer_steps]), 1)
            self.meta_optimizer.zero_grad()
            meta_loss.backward(retain_graph=True)
            nn.utils.clip_grad_norm_(self.model.parameters(), self.grad_clip_norm)
            self.meta_optimizer.step()
            try:
                self.meta_scheduler.step()
            except Exception:
                pass

        if self.use_reptile and meta_batch is not None:
            for task_x, task_y in meta_batch[:2]:
                reptile_loss = self._reptile_inner_loop(task_x, task_y, loss_fn)
                total_loss = total_loss + reptile_loss * 0.1

        output = self.model(x)
        if isinstance(output, dict):
            out_val = output.get('output', output.get('prediction', list(output.values())[0]))
        else:
            out_val = output
        task_loss = loss_fn(out_val, y)
        total_loss = total_loss + task_loss

        ewc_loss = self._compute_ewc_loss()
        total_loss = total_loss + ewc_loss

        if self.use_continual_learning:
            pnn_out = self._continual_pnn_forward(
                x.mean(dim=1) if x.dim() == 3 else x,
                task_id or 0
            )
            pnn_consistency = F.mse_loss(
                pnn_out,
                (out_val.mean(dim=1) if out_val.dim() == 3 else out_val).detach()
            )
            total_loss = total_loss + pnn_consistency * 0.01

        replay_samples = self._sample_replay(batch_size=min(16, len(self.replay_buffer)))
        replay_loss = torch.tensor(0.0, device=x.device)
        if replay_samples is not None:
            for rx, ry in replay_samples[:4]:
                rx = rx.to(x.device)
                ry = ry.to(x.device)
                with torch.no_grad():
                    r_output = self.model(rx)
                    if isinstance(r_output, dict):
                        r_val = r_output.get('output', list(r_output.values())[0])
                    else:
                        r_val = r_output
                replay_loss = replay_loss + loss_fn(r_val, ry) * 0.05
            total_loss = total_loss + replay_loss / max(len(replay_samples[:4]), 1)

        current_lr = self._adaptive_lr_compute(task_loss.item(), float(self.running_grad_norm.item()))
        for pg in self.base_optimizer.param_groups:
            pg['lr'] = current_lr

        self.base_optimizer.zero_grad()
        total_loss.backward()

        self._compress_gradients()
        self._update_fisher_online(task_loss)

        grad_norm = nn.utils.clip_grad_norm_(self.model.parameters(), self.grad_clip_norm)
        self.base_optimizer.step()
        try:
            self.base_scheduler.step()
        except Exception:
            pass

        with torch.no_grad():
            self.running_loss = 0.99 * self.running_loss + 0.01 * task_loss.detach()
            self.running_grad_norm = 0.99 * self.running_grad_norm + 0.01 * float(grad_norm)
            self.loss_ema.data = 0.999 * self.loss_ema.data + 0.001 * task_loss.detach()
            self.grad_ema.data = 0.999 * self.grad_ema.data + 0.001 * float(grad_norm)

        self._store_replay(x, y, task_loss.item())

        if task_loss.item() < self._best_loss:
            self._best_loss = task_loss.item()
            self._best_params = {
                name: param.data.clone()
                for name, param in self.model.named_parameters()
                if param.requires_grad
            }
            self._patience_counter = 0
        else:
            self._patience_counter += 1
            if self._patience_counter >= self.patience:
                if self._best_params is not None:
                    with torch.no_grad():
                        for name, param in self.model.named_parameters():
                            if name in self._best_params:
                                param.data = self._best_params[name].to(param.device)
                self._patience_counter = 0

        self.performance_tracker['train_losses'].append(task_loss.item())
        self.performance_tracker['lr_history'].append(current_lr)
        self.performance_tracker['grad_norms'].append(float(grad_norm))

        return {
            'loss': task_loss.item(),
            'total_loss': total_loss.item(),
            'ewc_loss': ewc_loss.item(),
            'replay_loss': replay_loss.item(),
            'meta_loss': meta_loss.item(),
            'grad_norm': float(grad_norm),
            'lr': current_lr,
            'task_id': task_id,
            'task_transition': transition_score,
            'output': output,
            'running_loss': self.running_loss.item(),
            'step': step,
        }

    def evaluate(self, val_loader: Any, loss_fn: Optional[Callable] = None,
                 max_batches: int = 100) -> Dict[str, float]:
        if loss_fn is None:
            loss_fn = F.mse_loss
        self.model.eval()
        total_val_loss = 0.0
        count = 0
        with torch.no_grad():
            for i, (vx, vy) in enumerate(val_loader):
                if i >= max_batches:
                    break
                output = self.model(vx)
                if isinstance(output, dict):
                    out_val = output.get('output', list(output.values())[0])
                else:
                    out_val = output
                total_val_loss += loss_fn(out_val, vy).item()
                count += 1
        avg_val_loss = total_val_loss / max(count, 1)
        self.performance_tracker['val_losses'].append(avg_val_loss)
        self.model.train()
        return {
            'val_loss': avg_val_loss,
            'best_train_loss': self._best_loss,
            'steps': int(self.step_count.item()),
        }

    def get_learning_stats(self) -> Dict[str, Any]:
        train_losses = list(self.performance_tracker['train_losses'])
        grad_norms = list(self.performance_tracker['grad_norms'])
        lr_hist = list(self.performance_tracker['lr_history'])
        return {
            'steps': int(self.step_count.item()),
            'running_loss': self.running_loss.item(),
            'loss_ema': self.loss_ema.item(),
            'grad_ema': self.grad_ema.item(),
            'best_loss': self._best_loss,
            'patience_counter': self._patience_counter,
            'replay_buffer_size': len(self.replay_buffer) if self.use_replay_buffer else 0,
            'recent_loss_mean': float(torch.tensor(train_losses[-50:]).mean().item()) if train_losses else 0.0,
            'recent_grad_mean': float(torch.tensor(grad_norms[-50:]).mean().item()) if grad_norms else 0.0,
            'current_lr': lr_hist[-1] if lr_hist else self.lr,
            'task_switches': len(self.performance_tracker['task_switches']),
        }

class PersonalTutor(nn.Module):
    def __init__(self, dim: int, num_subjects: int = 512,
                 num_difficulty_levels: int = 10,
                 num_learning_styles: int = 8,
                 num_question_types: int = 16,
                 num_heads: int = 16, num_layers: int = 8,
                 dropout: float = 0.1,
                 use_knowledge_tracing: bool = True,
                 use_adaptive_difficulty: bool = True,
                 use_spaced_repetition: bool = True,
                 use_learning_style_detection: bool = True,
                 use_misconception_detection: bool = True,
                 use_hint_generation: bool = True,
                 use_progress_tracking: bool = True,
                 use_socratic_method: bool = True,
                 use_multimodal_explanation: bool = True,
                 use_peer_comparison: bool = True,
                 use_gamification: bool = True,
                 memory_size: int = 2048,
                 max_concepts: int = 10000,
                 engagement_levels: int = 5):
        super().__init__()
        self.dim = dim
        self.num_subjects = num_subjects
        self.num_difficulty_levels = num_difficulty_levels
        self.num_learning_styles = num_learning_styles
        self.num_question_types = num_question_types
        self.use_knowledge_tracing = use_knowledge_tracing
        self.use_adaptive_difficulty = use_adaptive_difficulty
        self.use_spaced_repetition = use_spaced_repetition
        self.use_learning_style_detection = use_learning_style_detection
        self.use_misconception_detection = use_misconception_detection
        self.use_hint_generation = use_hint_generation
        self.use_progress_tracking = use_progress_tracking
        self.use_socratic_method = use_socratic_method
        self.use_multimodal_explanation = use_multimodal_explanation
        self.use_gamification = use_gamification
        self.max_concepts = max_concepts
        self.engagement_levels = engagement_levels

        self.subject_embed = nn.Embedding(num_subjects, dim)
        self.concept_embed = nn.Embedding(min(max_concepts, 10000), dim)
        self.difficulty_embed = nn.Embedding(num_difficulty_levels, dim // 4)
        self.learning_style_embed = nn.Embedding(num_learning_styles, dim // 4)
        self.question_type_embed = nn.Embedding(num_question_types, dim // 4)
        self.engagement_embed = nn.Embedding(engagement_levels, dim // 4)

        self.question_encoder = nn.Sequential(
            nn.Linear(dim, dim * 4), nn.GELU(),
            nn.Dropout(dropout),
            nn.Linear(dim * 4, dim * 2), nn.GELU(),
            nn.Linear(dim * 2, dim)
        )
        self.student_state_encoder = nn.Sequential(
            nn.Linear(dim, dim * 4), nn.GELU(),
            nn.Dropout(dropout),
            nn.Linear(dim * 4, dim * 2), nn.GELU(),
            nn.Linear(dim * 2, dim)
        )

        encoder_layer = nn.TransformerEncoderLayer(
            d_model=dim, nhead=num_heads, dim_feedforward=dim * 4,
            dropout=dropout, activation='gelu', batch_first=True, norm_first=True
        )
        self.pedagogical_encoder = nn.TransformerEncoder(encoder_layer, num_layers=num_layers)

        decoder_layer = nn.TransformerDecoderLayer(
            d_model=dim, nhead=num_heads, dim_feedforward=dim * 4,
            dropout=dropout, activation='gelu', batch_first=True, norm_first=True
        )
        self.explanation_decoder = nn.TransformerDecoder(decoder_layer, num_layers=num_layers // 2)

        self.knowledge_memory = nn.Parameter(torch.randn(memory_size, dim) * 0.02)
        self.knowledge_keys = nn.Parameter(torch.randn(memory_size, dim) * 0.02)
        self.knowledge_attn = nn.MultiheadAttention(dim, num_heads, batch_first=True)
        self.knowledge_norm = nn.LayerNorm(dim)

        if use_knowledge_tracing:
            self.dkt_rnn = nn.LSTM(dim * 2, dim, num_layers=3, batch_first=True,
                                   dropout=dropout, bidirectional=False)
            self.knowledge_state_proj = nn.Linear(dim, min(max_concepts, 10000))
            self.concept_mastery_head = nn.Sequential(
                nn.Linear(dim, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, min(max_concepts, 10000)), nn.Sigmoid()
            )
            self.forgetting_rate_predictor = nn.Sequential(
                nn.Linear(dim + 1, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, 1), nn.Sigmoid()
            )
            self.learning_rate_predictor = nn.Sequential(
                nn.Linear(dim, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, 1), nn.Softplus()
            )
            self._kt_hidden: Optional[Tuple[Tensor, Tensor]] = None

        if use_adaptive_difficulty:
            self.difficulty_predictor = nn.Sequential(
                nn.Linear(dim * 2, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, dim), nn.GELU(),
                nn.Linear(dim, num_difficulty_levels)
            )
            self.zone_of_proximal_dev = nn.Sequential(
                nn.Linear(dim, dim), nn.GELU(),
                nn.Linear(dim, 3)
            )
            self.item_response_theory = nn.Sequential(
                nn.Linear(dim * 2, dim), nn.GELU(),
                nn.Linear(dim, 3)
            )
            self.difficulty_gate = nn.Parameter(torch.zeros(1))

        if use_spaced_repetition:
            self.review_interval_predictor = nn.Sequential(
                nn.Linear(dim + 3, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, 1), nn.Softplus()
            )
            self.recall_probability_head = nn.Sequential(
                nn.Linear(dim + 1, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, 1), nn.Sigmoid()
            )
            self.sm2_stability_net = nn.Sequential(
                nn.Linear(dim, dim // 4), nn.GELU(),
                nn.Linear(dim // 4, 1), nn.Softplus()
            )
            self.priority_scheduler = nn.Sequential(
                nn.Linear(dim, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, 1)
            )

        if use_learning_style_detection:
            self.style_classifier = nn.Sequential(
                nn.Linear(dim, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, num_learning_styles)
            )
            self.vark_head = nn.Sequential(
                nn.Linear(dim, dim), nn.GELU(),
                nn.Linear(dim, 4)
            )
            self.modality_preference = nn.Sequential(
                nn.Linear(dim, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, 6)
            )
            self.cognitive_style_net = nn.Sequential(
                nn.Linear(dim, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, 4)
            )

        if use_misconception_detection:
            self.misconception_classifier = nn.Sequential(
                nn.Linear(dim, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, dim), nn.GELU(),
                nn.Linear(dim, 100)
            )
            self.misconception_severity = nn.Sequential(
                nn.Linear(dim, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, 3)
            )
            self.error_pattern_rnn = nn.GRU(dim, dim, num_layers=2, batch_first=True)
            self.correction_strategy_head = nn.Sequential(
                nn.Linear(dim, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, dim)
            )
            self.conceptual_gap_analyzer = nn.Sequential(
                nn.Linear(dim * 2, dim), nn.GELU(),
                nn.Linear(dim, dim)
            )

        if use_hint_generation:
            self.hint_level_selector = nn.Sequential(
                nn.Linear(dim * 2, dim), nn.GELU(),
                nn.Linear(dim, 5)
            )
            self.hint_encoder = nn.Sequential(
                nn.Linear(dim, dim * 4), nn.GELU(),
                nn.Linear(dim * 4, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, dim)
            )
            self.hint_relevance_head = nn.Sequential(
                nn.Linear(dim * 2, dim), nn.GELU(),
                nn.Linear(dim, 1), nn.Sigmoid()
            )
            self.scaffolding_net = nn.Sequential(
                nn.Linear(dim * 2, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, dim)
            )

        if use_socratic_method:
            self.question_generator = nn.Sequential(
                nn.Linear(dim, dim * 4), nn.GELU(),
                nn.Linear(dim * 4, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, dim)
            )
            self.socratic_depth_predictor = nn.Sequential(
                nn.Linear(dim, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, 5)
            )
            self.guided_discovery_net = nn.Sequential(
                nn.Linear(dim * 2, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, dim)
            )
            self.cognitive_conflict_inducer = nn.Sequential(
                nn.Linear(dim, dim), nn.GELU(),
                nn.Linear(dim, dim)
            )

        if use_multimodal_explanation:
            self.verbal_explainer = nn.Sequential(
                nn.Linear(dim, dim * 4), nn.GELU(),
                nn.Linear(dim * 4, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, dim)
            )
            self.visual_explainer = nn.Sequential(
                nn.Linear(dim, dim * 4), nn.GELU(),
                nn.Linear(dim * 4, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, dim)
            )
            self.formal_explainer = nn.Sequential(
                nn.Linear(dim, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, dim)
            )
            self.analogical_explainer = nn.Sequential(
                nn.Linear(dim * 2, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, dim)
            )
            self.example_generator = nn.Sequential(
                nn.Linear(dim, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, dim)
            )
            self.counterexample_net = nn.Sequential(
                nn.Linear(dim, dim), nn.GELU(),
                nn.Linear(dim, dim)
            )
            self.modality_router = nn.Sequential(
                nn.Linear(dim * 2, dim), nn.GELU(),
                nn.Linear(dim, 4)
            )
            self.explanation_fusion = nn.Sequential(
                nn.Linear(dim * 4, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, dim)
            )

        if use_progress_tracking:
            self.mastery_estimator = nn.Sequential(
                nn.Linear(dim, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, 1), nn.Sigmoid()
            )
            self.learning_velocity_head = nn.Sequential(
                nn.Linear(dim, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, 1)
            )
            self.prerequisite_completion = nn.Sequential(
                nn.Linear(dim, dim), nn.GELU(),
                nn.Linear(dim, min(max_concepts, 10000)), nn.Sigmoid()
            )
            self.bloom_taxonomy_classifier = nn.Sequential(
                nn.Linear(dim, dim), nn.GELU(),
                nn.Linear(dim, 6)
            )
            self.growth_mindset_indicator = nn.Sequential(
                nn.Linear(dim, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, 1), nn.Sigmoid()
            )

        if use_gamification:
            self.xp_predictor = nn.Sequential(
                nn.Linear(dim, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, 1), nn.Softplus()
            )
            self.badge_classifier = nn.Sequential(
                nn.Linear(dim, dim), nn.GELU(),
                nn.Linear(dim, 50), nn.Sigmoid()
            )
            self.streak_predictor = nn.Sequential(
                nn.Linear(dim, dim // 4), nn.GELU(),
                nn.Linear(dim // 4, 1), nn.Softplus()
            )
            self.leaderboard_rank_estimator = nn.Sequential(
                nn.Linear(dim, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, 1), nn.Sigmoid()
            )
            self.achievement_recommender = nn.Sequential(
                nn.Linear(dim, dim), nn.GELU(),
                nn.Linear(dim, 20)
            )
            self.intrinsic_motivation_head = nn.Sequential(
                nn.Linear(dim, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, 1), nn.Sigmoid()
            )

        self.empathy_encoder = nn.Sequential(
            nn.Linear(dim, dim * 2), nn.GELU(),
            nn.Linear(dim * 2, dim)
        )
        self.frustration_detector = nn.Sequential(
            nn.Linear(dim, dim // 2), nn.GELU(),
            nn.Linear(dim // 2, 1), nn.Sigmoid()
        )
        self.confidence_tracker = nn.Sequential(
            nn.Linear(dim, dim // 2), nn.GELU(),
            nn.Linear(dim // 2, 1), nn.Sigmoid()
        )
        self.anxiety_detector = nn.Sequential(
            nn.Linear(dim, dim // 2), nn.GELU(),
            nn.Linear(dim // 2, 1), nn.Sigmoid()
        )
        self.emotional_regulation_net = nn.Sequential(
            nn.Linear(dim * 2, dim), nn.GELU(),
            nn.Linear(dim, dim)
        )

        self.curriculum_planner = nn.Sequential(
            nn.Linear(dim, dim * 4), nn.GELU(),
            nn.Linear(dim * 4, dim * 2), nn.GELU(),
            nn.Linear(dim * 2, dim)
        )
        self.next_concept_recommender = nn.Sequential(
            nn.Linear(dim, dim * 2), nn.GELU(),
            nn.Linear(dim * 2, min(max_concepts, 10000))
        )
        self.prerequisite_graph_encoder = nn.Sequential(
            nn.Linear(dim, dim * 2), nn.GELU(),
            nn.Linear(dim * 2, dim)
        )
        self.learning_path_optimizer = nn.GRU(dim, dim, num_layers=2, batch_first=True)
        self.session_planner = nn.Sequential(
            nn.Linear(dim + 2, dim), nn.GELU(),
            nn.Linear(dim, 8)
        )

        self.correctness_head = nn.Sequential(
            nn.Linear(dim * 2, dim), nn.GELU(),
            nn.Linear(dim, 1), nn.Sigmoid()
        )
        self.partial_credit_head = nn.Sequential(
            nn.Linear(dim * 2, dim), nn.GELU(),
            nn.Linear(dim, 1), nn.Sigmoid()
        )
        self.feedback_quality_head = nn.Sequential(
            nn.Linear(dim, dim // 2), nn.GELU(),
            nn.Linear(dim // 2, 5)
        )

        self.output_norm = nn.LayerNorm(dim)
        self.output_proj = nn.Linear(dim, dim)
        self.tutoring_gate = nn.Parameter(torch.zeros(1))

        self.register_buffer('student_model', torch.zeros(min(max_concepts, 10000)))
        self.register_buffer('session_count', torch.tensor(0, dtype=torch.long))
        self.register_buffer('total_questions', torch.tensor(0, dtype=torch.long))
        self.register_buffer('correct_answers', torch.tensor(0, dtype=torch.long))

    def _knowledge_trace(self, question: Tensor, correct: Optional[Tensor]) -> Tuple[Tensor, Tensor]:
        if not self.use_knowledge_tracing:
            return question, torch.zeros(question.shape[0], 1, device=question.device)
        B = question.shape[0]
        if correct is not None:
            kt_input = torch.cat([question, correct.unsqueeze(-1).expand_as(question)], dim=-1)
        else:
            kt_input = torch.cat([question, torch.zeros_like(question)], dim=-1)
        if kt_input.dim() == 2:
            kt_input = kt_input.unsqueeze(1)
        kt_out, self._kt_hidden = self.dkt_rnn(kt_input, self._kt_hidden)
        kt_pooled = kt_out.mean(dim=1)
        mastery = self.concept_mastery_head(kt_pooled)
        return kt_pooled, mastery

    def _adaptive_difficulty_select(self, student_state: Tensor, question: Tensor) -> Tensor:
        if not self.use_adaptive_difficulty:
            return torch.zeros(student_state.shape[0], self.num_difficulty_levels, device=student_state.device)
        combined = torch.cat([student_state, question.mean(dim=1) if question.dim() == 3 else question], dim=-1)
        difficulty_logits = self.difficulty_predictor(combined)
        zpd = F.softmax(self.zone_of_proximal_dev(student_state), dim=-1)
        irt_params = self.item_response_theory(combined)
        adjusted_logits = difficulty_logits + torch.sigmoid(self.difficulty_gate) * zpd.mean(dim=-1, keepdim=True)
        return F.softmax(adjusted_logits, dim=-1)

    def _spaced_repetition_schedule(self, concept_state: Tensor, days_since: float, num_reviews: int) -> Dict[str, Tensor]:
        if not self.use_spaced_repetition:
            return {}
        B = concept_state.shape[0]
        time_feat = torch.tensor([[days_since, float(num_reviews), 1.0]], device=concept_state.device).expand(B, -1)
        recall_input = torch.cat([concept_state, time_feat[:, :1]], dim=-1)
        recall_prob = self.recall_probability_head(recall_input)
        interval_input = torch.cat([concept_state, time_feat], dim=-1)
        next_interval = self.review_interval_predictor(interval_input)
        stability = self.sm2_stability_net(concept_state)
        priority = self.priority_scheduler(concept_state)
        return {
            'recall_probability': recall_prob,
            'next_interval_days': next_interval,
            'memory_stability': stability,
            'review_priority': priority
        }

    def _detect_misconceptions(self, student_answer: Tensor, correct_answer: Tensor) -> Dict[str, Tensor]:
        if not self.use_misconception_detection:
            return {}
        sa = student_answer.mean(dim=1) if student_answer.dim() == 3 else student_answer
        ca = correct_answer.mean(dim=1) if correct_answer.dim() == 3 else correct_answer
        combined = torch.cat([sa, ca], dim=-1)
        gap = self.conceptual_gap_analyzer(combined)
        misconception_logits = self.misconception_classifier(sa)
        severity = F.softmax(self.misconception_severity(sa), dim=-1)
        correction = self.correction_strategy_head(gap)
        error_seq = sa.unsqueeze(1)
        error_out, _ = self.error_pattern_rnn(error_seq)
        return {
            'misconception_types': torch.sigmoid(misconception_logits),
            'severity': severity,
            'correction_strategy': correction,
            'conceptual_gap': gap
        }

    def _generate_hints(self, question: Tensor, student_state: Tensor, hint_level: int = 0) -> Dict[str, Tensor]:
        if not self.use_hint_generation:
            return {}
        q = question.mean(dim=1) if question.dim() == 3 else question
        ss = student_state
        hint_input = torch.cat([q, ss], dim=-1)
        hint_level_logits = self.hint_level_selector(hint_input)
        hint_level_probs = F.softmax(hint_level_logits, dim=-1)
        hint_emb = self.hint_encoder(q)
        relevance = self.hint_relevance_head(torch.cat([hint_emb, ss], dim=-1))
        scaffold = self.scaffolding_net(torch.cat([q, ss], dim=-1))
        return {
            'hint': hint_emb,
            'hint_level_probs': hint_level_probs,
            'relevance': relevance,
            'scaffold': scaffold
        }

    def _socratic_questioning(self, concept: Tensor, student_state: Tensor) -> Dict[str, Tensor]:
        if not self.use_socratic_method:
            return {}
        c = concept.mean(dim=1) if concept.dim() == 3 else concept
        socratic_q = self.question_generator(c)
        depth_probs = F.softmax(self.socratic_depth_predictor(c), dim=-1)
        guided = self.guided_discovery_net(torch.cat([c, student_state], dim=-1))
        conflict = self.cognitive_conflict_inducer(c)
        return {
            'socratic_question': socratic_q,
            'depth_level': depth_probs,
            'guided_discovery': guided,
            'cognitive_conflict': conflict
        }

    def _multimodal_explain(self, concept: Tensor, student_state: Tensor) -> Dict[str, Tensor]:
        if not self.use_multimodal_explanation:
            return {}
        c = concept.mean(dim=1) if concept.dim() == 3 else concept
        verbal = self.verbal_explainer(c)
        visual = self.visual_explainer(c)
        formal = self.formal_explainer(c)
        analogical = self.analogical_explainer(torch.cat([c, student_state], dim=-1))
        examples = self.example_generator(c)
        counterex = self.counterexample_net(c)
        modality_logits = self.modality_router(torch.cat([c, student_state], dim=-1))
        modality_weights = F.softmax(modality_logits, dim=-1)
        fused = self.explanation_fusion(torch.cat([verbal, visual, formal, analogical], dim=-1))
        return {
            'verbal_explanation': verbal,
            'visual_explanation': visual,
            'formal_explanation': formal,
            'analogical_explanation': analogical,
            'examples': examples,
            'counterexamples': counterex,
            'modality_weights': modality_weights,
            'fused_explanation': fused
        }

    def forward(self, question: Tensor,
                student_state: Optional[Tensor] = None,
                subject_id: Optional[int] = None,
                correct_answer: Optional[Tensor] = None,
                is_correct: Optional[bool] = None,
                days_since_review: float = 0.0,
                num_reviews: int = 0,
                engagement_id: Optional[int] = None,
                return_full_analysis: bool = True) -> Dict[str, Tensor]:
        B = question.shape[0]
        is_seq = question.dim() == 3
        if not is_seq:
            question = question.unsqueeze(1)

        x = self.question_encoder(question)

        if subject_id is not None:
            subj_emb = self.subject_embed(
                torch.tensor(min(subject_id, self.num_subjects - 1), device=question.device)
            )
            x = x + subj_emb.unsqueeze(0).unsqueeze(0).expand_as(x)

        if engagement_id is not None:
            eng_emb = self.engagement_embed(
                torch.tensor(min(engagement_id, self.engagement_levels - 1), device=question.device)
            )
            x = x + F.pad(eng_emb, (0, self.dim - eng_emb.shape[-1])).unsqueeze(0).unsqueeze(0).expand_as(x)

        if student_state is not None:
            ss = self.student_state_encoder(
                student_state.unsqueeze(1) if student_state.dim() == 2 else student_state
            )
            combined_input = torch.cat([x, ss[:, :x.shape[1], :]], dim=1) if ss.shape[1] >= x.shape[1] else \
                torch.cat([x, ss.expand(-1, x.shape[1], -1)], dim=-1)[:, :, :self.dim]
        else:
            combined_input = x

        if combined_input.shape[-1] != self.dim:
            combined_input = x

        encoded = self.pedagogical_encoder(combined_input)

        mem_keys = self.knowledge_keys.unsqueeze(0).expand(B, -1, -1)
        mem_vals = self.knowledge_memory.unsqueeze(0).expand(B, -1, -1)
        mem_out, _ = self.knowledge_attn(encoded, mem_keys, mem_vals)
        encoded = self.knowledge_norm(encoded + mem_out)

        pooled = encoded.mean(dim=1)
        student_repr = pooled if student_state is None else (pooled + (student_state.mean(dim=1) if student_state.dim() == 3 else student_state)) / 2

        correct_tensor = None
        if is_correct is not None:
            correct_tensor = torch.tensor([[float(is_correct)]], device=question.device).expand(B, -1)

        kt_state, mastery = self._knowledge_trace(pooled, correct_tensor)

        difficulty = self._adaptive_difficulty_select(student_repr, encoded)

        sr_result = self._spaced_repetition_schedule(student_repr, days_since_review, num_reviews)

        style_result = {}
        if self.use_learning_style_detection:
            style_logits = self.style_classifier(student_repr)
            vark = F.softmax(self.vark_head(student_repr), dim=-1)
            modality_pref = F.softmax(self.modality_preference(student_repr), dim=-1)
            cognitive_style = F.softmax(self.cognitive_style_net(student_repr), dim=-1)
            style_result = {
                'learning_style': F.softmax(style_logits, dim=-1),
                'vark': vark,
                'modality_preference': modality_pref,
                'cognitive_style': cognitive_style
            }

        misconception_result = {}
        if correct_answer is not None:
            ca = correct_answer.unsqueeze(1) if correct_answer.dim() == 2 else correct_answer
            misconception_result = self._detect_misconceptions(encoded, ca)

        hint_result = self._generate_hints(encoded, student_repr)
        socratic_result = self._socratic_questioning(encoded, student_repr)
        explanation_result = self._multimodal_explain(encoded, student_repr)

        progress_result = {}
        if self.use_progress_tracking:
            mastery_score = self.mastery_estimator(student_repr)
            velocity = self.learning_velocity_head(student_repr)
            bloom_level = F.softmax(self.bloom_taxonomy_classifier(student_repr), dim=-1)
            growth_mindset = self.growth_mindset_indicator(student_repr)
            progress_result = {
                'mastery_score': mastery_score,
                'learning_velocity': velocity,
                'bloom_taxonomy_level': bloom_level,
                'growth_mindset': growth_mindset
            }

        gamification_result = {}
        if self.use_gamification:
            xp = self.xp_predictor(student_repr)
            badges = self.badge_classifier(student_repr)
            streak = self.streak_predictor(student_repr)
            rank = self.leaderboard_rank_estimator(student_repr)
            achievements = self.achievement_recommender(student_repr)
            intrinsic = self.intrinsic_motivation_head(student_repr)
            gamification_result = {
                'xp_earned': xp,
                'badge_predictions': badges,
                'streak_days': streak,
                'leaderboard_percentile': rank,
                'achievement_recommendations': F.softmax(achievements, dim=-1),
                'intrinsic_motivation': intrinsic
            }

        frustration = self.frustration_detector(student_repr)
        confidence = self.confidence_tracker(student_repr)
        anxiety = self.anxiety_detector(student_repr)
        emotional_state = self.empathy_encoder(student_repr)
        emotional_regulation = self.emotional_regulation_net(
            torch.cat([emotional_state, student_repr], dim=-1)
        )

        curriculum = self.curriculum_planner(student_repr)
        next_concepts = self.next_concept_recommender(curriculum)
        path_seq = student_repr.unsqueeze(1)
        path_out, _ = self.learning_path_optimizer(path_seq)
        time_budget = torch.tensor([[30.0, 5.0]], device=question.device).expand(B, -1)
        session_plan = F.softmax(
            self.session_planner(torch.cat([curriculum, time_budget], dim=-1)),
            dim=-1
        )

        tutoring_response = self.explanation_decoder(
            curriculum.unsqueeze(1).expand(-1, min(encoded.shape[1], 32), -1),
            encoded[:, :min(encoded.shape[1], 32), :]
        )

        gate = torch.sigmoid(self.tutoring_gate)
        out = self.output_norm(gate * self.output_proj(tutoring_response.mean(dim=1)) + (1 - gate) * pooled)

        if correct_answer is not None:
            ca_flat = correct_answer.mean(dim=1) if correct_answer.dim() == 3 else correct_answer
            correctness = self.correctness_head(torch.cat([pooled, ca_flat], dim=-1))
            partial_credit = self.partial_credit_head(torch.cat([pooled, ca_flat], dim=-1))
        else:
            correctness = torch.zeros(B, 1, device=question.device)
            partial_credit = torch.zeros(B, 1, device=question.device)

        feedback_quality = F.softmax(self.feedback_quality_head(out), dim=-1)

        with torch.no_grad():
            self.session_count += 1
            self.total_questions += 1
            if is_correct:
                self.correct_answers += 1
            if mastery.dim() > 1:
                self.student_model = 0.99 * self.student_model + 0.01 * mastery.detach().mean(dim=0)

        result = {
            'tutor_response': out,
            'knowledge_state': kt_state,
            'concept_mastery': mastery,
            'optimal_difficulty': difficulty,
            'next_concept_recommendations': F.softmax(next_concepts, dim=-1),
            'session_plan': session_plan,
            'curriculum': curriculum,
            'frustration': frustration,
            'confidence': confidence,
            'anxiety': anxiety,
            'emotional_regulation': emotional_regulation,
            'correctness': correctness,
            'partial_credit': partial_credit,
            'feedback_quality': feedback_quality,
            'accuracy': (self.correct_answers.float() / (self.total_questions.float() + 1e-8)).unsqueeze(0),
        }

        if return_full_analysis:
            result.update(style_result)
            result.update(sr_result)
            result.update(progress_result)
            result.update(gamification_result)
            if misconception_result:
                result['misconception'] = misconception_result
            if hint_result:
                result['hints'] = hint_result
            if socratic_result:
                result['socratic'] = socratic_result
            if explanation_result:
                result['explanation'] = explanation_result

        return result
######
class AudioStructureLevel(nn.Module):
    def __init__(self, dim: int = 1024, struct_dim: int = 1024,
                 num_layers: int = 6, num_heads: int = 16,
                 max_duration_sec: float = 7200.0, token_interval: float = 10.0,
                 use_hierarchical_structure: bool = True,
                 use_tempo_conditioning: bool = True,
                 use_harmonic_analysis: bool = True,
                 use_dynamic_range_control: bool = True,
                 use_section_detection: bool = True,
                 use_motif_memory: bool = True,
                 dropout: float = 0.1,
                 section_types: int = 16,
                 motif_slots: int = 256):
        super().__init__()
        self.dim = dim
        self.struct_dim = struct_dim
        self.token_interval = token_interval
        self.max_tokens = int(max_duration_sec / token_interval) + 1
        self.use_hierarchical_structure = use_hierarchical_structure
        self.use_tempo_conditioning = use_tempo_conditioning
        self.use_harmonic_analysis = use_harmonic_analysis
        self.use_dynamic_range_control = use_dynamic_range_control
        self.use_section_detection = use_section_detection
        self.use_motif_memory = use_motif_memory

        self.latent_to_struct = nn.Sequential(
            nn.Linear(dim, struct_dim * 2), nn.GELU(),
            nn.Linear(struct_dim * 2, struct_dim * 4), nn.GELU(),
            nn.Linear(struct_dim * 4, struct_dim)
        )

        self.pos_embed = nn.Embedding(self.max_tokens + 32, struct_dim)
        self.time_embed = nn.Sequential(
            nn.Linear(1, struct_dim // 4), nn.SiLU(),
            nn.Linear(struct_dim // 4, struct_dim // 2), nn.SiLU(),
            nn.Linear(struct_dim // 2, struct_dim)
        )

        encoder_layer = nn.TransformerEncoderLayer(
            d_model=struct_dim, nhead=num_heads, dim_feedforward=struct_dim * 4,
            dropout=dropout, activation='gelu', batch_first=True, norm_first=True
        )
        self.structure_transformer = nn.TransformerEncoder(encoder_layer, num_layers=num_layers)

        self.adaptive_length = nn.Sequential(
            nn.Linear(dim, dim // 2), nn.GELU(),
            nn.Linear(dim // 2, dim // 4), nn.GELU(),
            nn.Linear(dim // 4, 1), nn.Sigmoid()
        )
        self.length_refinement_net = nn.Sequential(
            nn.Linear(dim + 1, dim // 2), nn.GELU(),
            nn.Linear(dim // 2, 1), nn.Sigmoid()
        )

        if use_hierarchical_structure:
            self.micro_structure = nn.TransformerEncoder(
                nn.TransformerEncoderLayer(
                    d_model=struct_dim, nhead=num_heads // 2,
                    dim_feedforward=struct_dim * 2, dropout=dropout,
                    activation='gelu', batch_first=True, norm_first=True
                ), num_layers=num_layers // 2
            )
            self.macro_structure = nn.TransformerEncoder(
                nn.TransformerEncoderLayer(
                    d_model=struct_dim, nhead=num_heads // 2,
                    dim_feedforward=struct_dim * 2, dropout=dropout,
                    activation='gelu', batch_first=True, norm_first=True
                ), num_layers=num_layers // 2
            )
            self.hierarchy_fusion = nn.Sequential(
                nn.Linear(struct_dim * 2, struct_dim * 2), nn.GELU(),
                nn.Linear(struct_dim * 2, struct_dim)
            )
            self.hierarchy_gate = nn.Parameter(torch.zeros(1))

        if use_tempo_conditioning:
            self.tempo_encoder = nn.Sequential(
                nn.Linear(1, struct_dim // 4), nn.GELU(),
                nn.Linear(struct_dim // 4, struct_dim // 2), nn.GELU(),
                nn.Linear(struct_dim // 2, struct_dim)
            )
            self.tempo_modulator = nn.Sequential(
                nn.Linear(struct_dim * 2, struct_dim), nn.GELU(),
                nn.Linear(struct_dim, struct_dim)
            )
            self.beat_grid_net = nn.Sequential(
                nn.Linear(struct_dim, struct_dim), nn.GELU(),
                nn.Linear(struct_dim, struct_dim)
            )

        if use_harmonic_analysis:
            self.key_classifier = nn.Sequential(
                nn.Linear(struct_dim, struct_dim), nn.GELU(),
                nn.Linear(struct_dim, 24)
            )
            self.chord_progression_net = nn.Sequential(
                nn.Linear(struct_dim, struct_dim * 2), nn.GELU(),
                nn.Linear(struct_dim * 2, struct_dim)
            )
            self.harmonic_tension_head = nn.Sequential(
                nn.Linear(struct_dim, struct_dim // 2), nn.GELU(),
                nn.Linear(struct_dim // 2, 1), nn.Sigmoid()
            )
            self.harmonic_rnn = nn.GRU(struct_dim, struct_dim, num_layers=2, batch_first=True)
            self.harmonic_proj = nn.Linear(struct_dim, struct_dim)

        if use_dynamic_range_control:
            self.loudness_predictor = nn.Sequential(
                nn.Linear(struct_dim, struct_dim // 2), nn.GELU(),
                nn.Linear(struct_dim // 2, 1)
            )
            self.dynamic_contour_net = nn.Sequential(
                nn.Linear(struct_dim, struct_dim), nn.GELU(),
                nn.Linear(struct_dim, struct_dim)
            )
            self.compression_ratio_head = nn.Sequential(
                nn.Linear(struct_dim, struct_dim // 4), nn.GELU(),
                nn.Linear(struct_dim // 4, 1), nn.Softplus()
            )

        if use_section_detection:
            self.section_classifier = nn.Sequential(
                nn.Linear(struct_dim, struct_dim), nn.GELU(),
                nn.Linear(struct_dim, section_types)
            )
            self.section_boundary_detector = nn.Sequential(
                nn.Linear(struct_dim * 2, struct_dim), nn.GELU(),
                nn.Linear(struct_dim, 1), nn.Sigmoid()
            )
            self.section_embed = nn.Embedding(section_types, struct_dim)
            self.section_duration_predictor = nn.Sequential(
                nn.Linear(struct_dim, struct_dim // 2), nn.GELU(),
                nn.Linear(struct_dim // 2, 1), nn.Softplus()
            )

        if use_motif_memory:
            self.motif_keys = nn.Parameter(torch.randn(motif_slots, struct_dim) * 0.02)
            self.motif_values = nn.Parameter(torch.randn(motif_slots, struct_dim) * 0.02)
            self.motif_attn = nn.MultiheadAttention(struct_dim, num_heads, batch_first=True)
            self.motif_norm = nn.LayerNorm(struct_dim)
            self.motif_write_gate = nn.Sequential(
                nn.Linear(struct_dim * 2, struct_dim), nn.Sigmoid()
            )

        self.output_proj = nn.Sequential(
            nn.LayerNorm(struct_dim),
            nn.Linear(struct_dim, struct_dim * 2), nn.GELU(),
            nn.Dropout(dropout),
            nn.Linear(struct_dim * 2, struct_dim)
        )
        self.output_gate = nn.Parameter(torch.zeros(1))

        self.structure_quality_head = nn.Sequential(
            nn.Linear(struct_dim, struct_dim // 2), nn.GELU(),
            nn.Linear(struct_dim // 2, 1), nn.Sigmoid()
        )
        self.coherence_estimator = nn.Sequential(
            nn.Linear(struct_dim * 2, struct_dim), nn.GELU(),
            nn.Linear(struct_dim, 1), nn.Sigmoid()
        )

    def _compute_num_tokens(self, latent: torch.Tensor, duration_sec: float) -> int:
        ratio = self.adaptive_length(latent).mean().item()
        duration_feat = torch.tensor([[duration_sec / 3600.0]], device=latent.device)
        ratio_refined = self.length_refinement_net(
            torch.cat([latent.mean(dim=0, keepdim=True),
                       duration_feat.expand(1, -1)], dim=-1)
        ).item() if latent.dim() >= 1 else ratio
        combined_ratio = (ratio + ratio_refined) / 2
        raw = int(duration_sec / self.token_interval * combined_ratio)
        return max(1, min(raw, self.max_tokens - 1))

    def forward(self, latent: torch.Tensor, duration_sec: float,
                tempo_bpm: Optional[float] = None,
                key_signature: Optional[int] = None) -> Dict[str, torch.Tensor]:
        B = latent.shape[0]
        num_tokens = self._compute_num_tokens(latent, duration_sec)

        struct = self.latent_to_struct(latent).unsqueeze(1).expand(-1, num_tokens, -1)

        pos = torch.arange(num_tokens, device=latent.device)
        pos_emb = self.pos_embed(pos.clamp(0, self.max_tokens - 1)).unsqueeze(0).expand(B, -1, -1)

        time_positions = torch.linspace(0, duration_sec / 3600.0, num_tokens, device=latent.device)
        time_emb = self.time_embed(time_positions.unsqueeze(-1)).unsqueeze(0).expand(B, -1, -1)

        struct = struct + pos_emb + time_emb

        if self.use_tempo_conditioning and tempo_bpm is not None:
            tempo_tensor = torch.tensor([[tempo_bpm / 300.0]], device=latent.device).expand(B, -1)
            tempo_emb = self.tempo_encoder(tempo_tensor)
            struct = self.tempo_modulator(
                torch.cat([struct, tempo_emb.unsqueeze(1).expand_as(struct)], dim=-1)
            )
            struct = struct + self.beat_grid_net(struct) * 0.1

        encoded = self.structure_transformer(struct)

        if self.use_hierarchical_structure:
            micro = self.micro_structure(struct)
            stride = max(1, num_tokens // 4)
            macro_input = struct[:, ::stride, :]
            macro = self.macro_structure(macro_input)
            macro_upsampled = F.interpolate(
                macro.transpose(1, 2), size=num_tokens, mode='linear', align_corners=False
            ).transpose(1, 2)
            fused = self.hierarchy_fusion(torch.cat([micro, macro_upsampled], dim=-1))
            gate = torch.sigmoid(self.hierarchy_gate)
            encoded = gate * fused + (1 - gate) * encoded

        if self.use_motif_memory:
            mk = self.motif_keys.unsqueeze(0).expand(B, -1, -1)
            mv = self.motif_values.unsqueeze(0).expand(B, -1, -1)
            motif_out, _ = self.motif_attn(encoded, mk, mv)
            encoded = self.motif_norm(encoded + motif_out)

        if self.use_harmonic_analysis:
            harmonic_out, _ = self.harmonic_rnn(encoded)
            harmonic_feat = self.harmonic_proj(harmonic_out)
            encoded = encoded + harmonic_feat * 0.1

        if self.use_dynamic_range_control:
            dynamic_contour = self.dynamic_contour_net(encoded)
            loudness = self.loudness_predictor(encoded)
            encoded = encoded + dynamic_contour * 0.05

        gate = torch.sigmoid(self.output_gate)
        out = self.output_proj(encoded)
        out = gate * out + (1 - gate) * encoded

        quality = self.structure_quality_head(out.mean(dim=1))
        coherence = self.coherence_estimator(
            torch.cat([out[:, 0], out[:, -1]], dim=-1)
        )

        result: Dict[str, torch.Tensor] = {
            'structure': out,
            'quality': quality,
            'coherence': coherence,
            'num_tokens': torch.tensor(num_tokens, device=latent.device),
        }
        if self.use_section_detection:
            section_logits = self.section_classifier(out)
            section_boundaries = []
            for t in range(1, num_tokens):
                bd = self.section_boundary_detector(
                    torch.cat([out[:, t - 1], out[:, t]], dim=-1)
                )
                section_boundaries.append(bd)
            if section_boundaries:
                result['section_logits'] = section_logits
                result['section_boundaries'] = torch.stack(section_boundaries, dim=1).squeeze(-1)
        if self.use_harmonic_analysis:
            result['key_logits'] = self.key_classifier(out.mean(dim=1))
            result['harmonic_tension'] = self.harmonic_tension_head(out)
        return result

class AudioChunkLevel(nn.Module):
    def __init__(self, dim: int = 512, mel_dim: int = 80,
                 chunk_duration: float = 10.0, sample_rate: int = 24000,
                 hop_length: int = 256, hidden_dim: int = 2048,
                 num_layers: int = 12, num_heads: int = 16,
                 use_cross_attention: bool = True,
                 use_phase_prediction: bool = True,
                 use_perceptual_weighting: bool = True,
                 use_harmonic_plus_noise: bool = True,
                 use_multi_scale_generation: bool = True,
                 dropout: float = 0.1):
        super().__init__()
        self.mel_dim = mel_dim
        self.hidden_dim = hidden_dim
        self.frames_per_chunk = int(chunk_duration * sample_rate / hop_length)
        self.use_cross_attention = use_cross_attention
        self.use_phase_prediction = use_phase_prediction
        self.use_perceptual_weighting = use_perceptual_weighting
        self.use_harmonic_plus_noise = use_harmonic_plus_noise
        self.use_multi_scale_generation = use_multi_scale_generation

        self.cond_proj = nn.Sequential(
            nn.Linear(dim * 2, dim * 4), nn.GELU(),
            nn.Linear(dim * 4, dim * 2), nn.GELU(),
            nn.Linear(dim * 2, mel_dim * self.frames_per_chunk)
        )
        self.proj_in = nn.Sequential(
            nn.Linear(mel_dim, hidden_dim // 2), nn.GELU(),
            nn.Linear(hidden_dim // 2, hidden_dim)
        )
        self.proj_out = nn.Sequential(
            nn.LayerNorm(hidden_dim),
            nn.Linear(hidden_dim, hidden_dim // 2), nn.GELU(),
            nn.Linear(hidden_dim // 2, mel_dim)
        )

        self.pos_embed = nn.Embedding(self.frames_per_chunk + 32, hidden_dim)

        encoder_layer = nn.TransformerEncoderLayer(
            d_model=hidden_dim, nhead=num_heads, dim_feedforward=hidden_dim * 4,
            dropout=dropout, activation='gelu', batch_first=True, norm_first=True
        )
        self.chunk_transformer = nn.TransformerEncoder(encoder_layer, num_layers=num_layers)

        if use_cross_attention:
            self.struct_key_proj = nn.Sequential(
                nn.Linear(dim, hidden_dim * 2), nn.GELU(),
                nn.Linear(hidden_dim * 2, hidden_dim)
            )
            self.cross_attn = nn.MultiheadAttention(hidden_dim, num_heads, batch_first=True, dropout=dropout)
            self.cross_norm = nn.LayerNorm(hidden_dim)
            self.latent_cross_attn = nn.MultiheadAttention(hidden_dim, num_heads, batch_first=True, dropout=dropout)
            self.latent_cross_norm = nn.LayerNorm(hidden_dim)

        if use_phase_prediction:
            self.phase_net = nn.Sequential(
                nn.Linear(hidden_dim, hidden_dim), nn.GELU(),
                nn.Linear(hidden_dim, mel_dim)
            )
            self.phase_coherence_net = nn.Sequential(
                nn.Linear(hidden_dim * 2, hidden_dim), nn.GELU(),
                nn.Linear(hidden_dim, 1), nn.Sigmoid()
            )
            self.instantaneous_freq_head = nn.Sequential(
                nn.Linear(hidden_dim, mel_dim)
            )

        if use_perceptual_weighting:
            self.perceptual_weights = nn.Parameter(torch.ones(mel_dim))
            self.loudness_curve = nn.Parameter(torch.linspace(-10, 0, mel_dim))
            self.masking_threshold_net = nn.Sequential(
                nn.Linear(mel_dim, mel_dim * 2), nn.GELU(),
                nn.Linear(mel_dim * 2, mel_dim), nn.Sigmoid()
            )

        if use_harmonic_plus_noise:
            self.harmonic_separator = nn.Sequential(
                nn.Linear(hidden_dim, hidden_dim * 2), nn.GELU(),
                nn.Linear(hidden_dim * 2, mel_dim * 2)
            )
            self.harmonic_rnn = nn.GRU(mel_dim, hidden_dim // 2, num_layers=2,
                                        batch_first=True, bidirectional=True)
            self.harmonic_proj = nn.Linear(hidden_dim, mel_dim)
            self.noise_modulator = nn.Sequential(
                nn.Linear(hidden_dim, mel_dim), nn.Sigmoid()
            )
            self.hpss_gate = nn.Parameter(torch.zeros(1))

        if use_multi_scale_generation:
            self.scale_convs = nn.ModuleList([
                nn.Sequential(
                    nn.Conv1d(mel_dim, mel_dim, kernel_size=k, padding=k // 2),
                    nn.GELU(),
                    nn.Conv1d(mel_dim, mel_dim, kernel_size=1)
                )
                for k in [1, 3, 7, 15]
            ])
            self.scale_fusion = nn.Linear(mel_dim * 4, mel_dim)

        self.detail_refiner = nn.Sequential(
            nn.Conv1d(mel_dim, mel_dim * 2, kernel_size=5, padding=2),
            nn.GELU(),
            nn.Conv1d(mel_dim * 2, mel_dim * 2, kernel_size=3, padding=1),
            nn.GELU(),
            nn.Conv1d(mel_dim * 2, mel_dim, kernel_size=1)
        )
        self.output_gate = nn.Parameter(torch.zeros(1))
        self.spectral_norm_layer = nn.LayerNorm(mel_dim)
        self.quality_head = nn.Sequential(
            nn.Linear(hidden_dim, hidden_dim // 4), nn.GELU(),
            nn.Linear(hidden_dim // 4, 1), nn.Sigmoid()
        )

    def forward(self, latent: torch.Tensor, struct_vec: torch.Tensor,
                return_phase: bool = False) -> Dict[str, torch.Tensor]:
        B = latent.shape[0]
        cond = torch.cat([latent, struct_vec], dim=-1)
        mel_init = self.cond_proj(cond).view(B, self.frames_per_chunk, self.mel_dim)
        x = self.proj_in(mel_init)

        pos = torch.arange(self.frames_per_chunk, device=latent.device)
        x = x + self.pos_embed(pos).unsqueeze(0).expand(B, -1, -1)

        if self.use_cross_attention:
            struct_key = self.struct_key_proj(struct_vec).unsqueeze(1)
            ca_out, _ = self.cross_attn(x, struct_key, struct_key)
            x = self.cross_norm(x + ca_out)
            lat_key = latent.unsqueeze(1)
            lat_out, _ = self.latent_cross_attn(x, lat_key, lat_key)
            x = self.latent_cross_norm(x + lat_out)

        x = self.chunk_transformer(x)

        if self.use_harmonic_plus_noise:
            hn_params = self.harmonic_separator(x)
            h_mel, n_mel = hn_params.chunk(2, dim=-1)
            h_out, _ = self.harmonic_rnn(h_mel)
            harmonic = self.harmonic_proj(h_out)
            noise_gate = self.noise_modulator(x)
            noise = n_mel * noise_gate
            hpss_gate = torch.sigmoid(self.hpss_gate)
            x = x + hpss_gate * (harmonic + noise) * 0.1

        mel_out = self.proj_out(x)

        if self.use_multi_scale_generation:
            mel_t = mel_out.transpose(1, 2)
            scale_outs = [conv(mel_t) for conv in self.scale_convs]
            multi_scale = torch.cat([o.transpose(1, 2) for o in scale_outs], dim=-1)
            mel_out = mel_out + self.scale_fusion(multi_scale) * 0.1

        mel_refined = mel_out + self.detail_refiner(mel_out.transpose(1, 2)).transpose(1, 2) * 0.2
        gate = torch.sigmoid(self.output_gate)
        mel_final = gate * mel_refined + (1 - gate) * mel_out
        mel_final = self.spectral_norm_layer(mel_final)

        if self.use_perceptual_weighting:
            pw = torch.sigmoid(self.perceptual_weights).unsqueeze(0).unsqueeze(0)
            mel_final = mel_final * (0.5 + 0.5 * pw)

        quality = self.quality_head(x.mean(dim=1))
        result: Dict[str, torch.Tensor] = {
            'mel': mel_final.transpose(1, 2),
            'quality': quality
        }
        if return_phase and self.use_phase_prediction:
            phase = self.phase_net(x)
            result['phase'] = phase.transpose(1, 2)
            result['instantaneous_freq'] = self.instantaneous_freq_head(x).transpose(1, 2)
        return result

class AudioSuperResolution(nn.Module):
    def __init__(self, in_channels: int = 1, out_channels: int = 1,
                 scale_factor: int = 4, hidden_dim: int = 256,
                 num_res_blocks: int = 16, num_heads: int = 8,
                 use_attention: bool = True,
                 use_subpixel_conv: bool = True,
                 use_perceptual_loss_features: bool = True,
                 use_waveform_generation: bool = True,
                 use_harmonic_enhancement: bool = True,
                 use_noise_shaping: bool = True,
                 kernel_sizes: Optional[List[int]] = None,
                 dropout: float = 0.05):
        super().__init__()
        self.scale_factor = scale_factor
        self.hidden_dim = hidden_dim
        self.use_attention = use_attention
        self.use_subpixel_conv = use_subpixel_conv
        self.use_perceptual_loss_features = use_perceptual_loss_features
        self.use_waveform_generation = use_waveform_generation
        self.use_harmonic_enhancement = use_harmonic_enhancement
        self.use_noise_shaping = use_noise_shaping
        self.kernel_sizes = kernel_sizes or [3, 7, 11, 21, 41]

        self.encoder = nn.Sequential(
            nn.Conv1d(in_channels, hidden_dim // 2, kernel_size=7, padding=3),
            nn.LeakyReLU(0.2),
            nn.Conv1d(hidden_dim // 2, hidden_dim, kernel_size=5, padding=2),
            nn.LeakyReLU(0.2),
            nn.Conv1d(hidden_dim, hidden_dim, kernel_size=3, padding=1),
            nn.LeakyReLU(0.2)
        )

        self.res_blocks = nn.ModuleList([
            nn.Sequential(
                nn.Conv1d(hidden_dim, hidden_dim, kernel_size=3,
                          padding=2 ** (i % 4), dilation=2 ** (i % 4)),
                nn.LeakyReLU(0.2),
                nn.Conv1d(hidden_dim, hidden_dim, kernel_size=3, padding=1),
                nn.Dropout(dropout)
            )
            for i in range(num_res_blocks)
        ])
        self.res_scales = nn.ParameterList([
            nn.Parameter(torch.ones(1) * 0.1) for _ in range(num_res_blocks)
        ])

        self.multi_scale_convs = nn.ModuleList([
            nn.Sequential(
                nn.Conv1d(hidden_dim, hidden_dim // len(self.kernel_sizes), k, padding=k // 2),
                nn.LeakyReLU(0.2)
            )
            for k in self.kernel_sizes
        ])
        self.multi_scale_proj = nn.Conv1d(hidden_dim, hidden_dim, 1)

        if use_attention:
            self.attention_blocks = nn.ModuleList([
                nn.MultiheadAttention(hidden_dim, num_heads, batch_first=True, dropout=dropout)
                for _ in range(4)
            ])
            self.attn_norms = nn.ModuleList([nn.LayerNorm(hidden_dim) for _ in range(4)])
            self.attn_positions = [num_res_blocks // 4, num_res_blocks // 2,
                                   3 * num_res_blocks // 4, num_res_blocks - 1]

        if use_subpixel_conv:
            upsampler_layers = []
            remaining = scale_factor
            while remaining > 1:
                step = min(remaining, 4)
                upsampler_layers.extend([
                    nn.Conv1d(hidden_dim, hidden_dim * step, kernel_size=3, padding=1),
                    nn.LeakyReLU(0.2)
                ])
                hidden_dim_out = hidden_dim
                remaining //= step
            self.upsampler = nn.Sequential(*upsampler_layers) if upsampler_layers else nn.Identity()
            self.subpixel_proj = nn.Conv1d(hidden_dim * scale_factor, hidden_dim, 1)
        else:
            self.upsampler = nn.Sequential(
                nn.ConvTranspose1d(hidden_dim, hidden_dim, kernel_size=scale_factor,
                                   stride=scale_factor, padding=0),
                nn.LeakyReLU(0.2)
            )

        if use_harmonic_enhancement:
            self.harmonic_predictor = nn.Sequential(
                nn.Conv1d(hidden_dim, hidden_dim, kernel_size=5, padding=2),
                nn.LeakyReLU(0.2),
                nn.Conv1d(hidden_dim, hidden_dim // 2, kernel_size=3, padding=1),
                nn.LeakyReLU(0.2),
                nn.Conv1d(hidden_dim // 2, hidden_dim, kernel_size=1)
            )
            self.harmonic_gate = nn.Parameter(torch.zeros(1))

        if use_noise_shaping:
            self.noise_predictor = nn.Sequential(
                nn.Conv1d(hidden_dim, hidden_dim // 2, kernel_size=3, padding=1),
                nn.LeakyReLU(0.2),
                nn.Conv1d(hidden_dim // 2, hidden_dim // 4, kernel_size=3, padding=1),
                nn.LeakyReLU(0.2),
                nn.Conv1d(hidden_dim // 4, 1, kernel_size=1), nn.Sigmoid()
            )
            self.noise_scale = nn.Parameter(torch.tensor(0.001))

        if use_perceptual_loss_features:
            self.perceptual_feature_extractor = nn.Sequential(
                nn.Conv1d(hidden_dim, hidden_dim, kernel_size=5, padding=2),
                nn.LeakyReLU(0.2),
                nn.Conv1d(hidden_dim, hidden_dim, kernel_size=3, padding=1)
            )

        self.output_conv = nn.Sequential(
            nn.Conv1d(hidden_dim, hidden_dim // 2, kernel_size=7, padding=3),
            nn.LeakyReLU(0.2),
            nn.Conv1d(hidden_dim // 2, hidden_dim // 4, kernel_size=3, padding=1),
            nn.LeakyReLU(0.2),
            nn.Conv1d(hidden_dim // 4, out_channels, kernel_size=1)
        )
        self.output_gate = nn.Parameter(torch.zeros(1))
        self.snr_estimator = nn.Sequential(
            nn.AdaptiveAvgPool1d(1),
        )

    def forward(self, x: torch.Tensor,
                return_features: bool = False) -> Union[torch.Tensor, Dict[str, torch.Tensor]]:
        was_1d = x.dim() == 1
        if was_1d:
            x = x.unsqueeze(0).unsqueeze(0)
        elif x.dim() == 2:
            x = x.unsqueeze(1)

        B, C, T = x.shape
        feat = self.encoder(x)
        attn_counter = 0
        for i, (rb, rs) in enumerate(zip(self.res_blocks, self.res_scales)):
            residual = rb(feat)
            feat = feat + residual * torch.sigmoid(rs)
            if self.use_attention and i in self.attn_positions and attn_counter < len(self.attention_blocks):
                f_t = feat.transpose(1, 2)
                attn_out, _ = self.attention_blocks[attn_counter](f_t, f_t, f_t)
                feat = self.attn_norms[attn_counter](f_t + attn_out).transpose(1, 2)
                attn_counter += 1

        scale_outs = [conv(feat) for conv in self.multi_scale_convs]
        ms_cat = torch.cat(scale_outs, dim=1)
        feat = feat + self.multi_scale_proj(ms_cat) * 0.1

        if self.use_subpixel_conv:
            up = self.upsampler(feat)
            if up.shape[1] == self.hidden_dim * self.scale_factor:
                feat_up = self.subpixel_proj(up)
            else:
                feat_up = F.interpolate(feat, scale_factor=self.scale_factor, mode='linear', align_corners=False)
        else:
            feat_up = self.upsampler(feat)

        if self.use_harmonic_enhancement:
            harmonic = self.harmonic_predictor(feat_up)
            h_gate = torch.sigmoid(self.harmonic_gate)
            feat_up = feat_up + h_gate * harmonic

        if self.use_noise_shaping:
            noise_mask = self.noise_predictor(feat_up)
            noise = torch.randn_like(feat_up[:, :1, :]) * torch.abs(self.noise_scale)
            feat_up = feat_up + noise_mask * noise

        out = self.output_conv(feat_up)
        gate = torch.sigmoid(self.output_gate)

        lr_upsampled = F.interpolate(x, scale_factor=self.scale_factor, mode='linear', align_corners=False)
        out_final = gate * out + (1 - gate) * lr_upsampled[:, :out.shape[1], :out.shape[2]]
        out_final = torch.tanh(out_final)

        if was_1d:
            out_final = out_final.squeeze(0).squeeze(0)

        if return_features:
            perceptual_feats = self.perceptual_feature_extractor(feat_up) if self.use_perceptual_loss_features else feat_up
            return {
                'output': out_final,
                'perceptual_features': perceptual_feats,
                'upsampled_features': feat_up
            }
        return out_final

class CrossfadeBlender(nn.Module):
    def __init__(self, fade_len: int = 480, num_heads: int = 4,
                 use_learned_fade: bool = True,
                 use_overlap_add: bool = True,
                 use_phase_alignment: bool = True,
                 use_spectral_blending: bool = True,
                 use_adaptive_window: bool = True,
                 sample_rate: int = 24000,
                 window_types: int = 4,
                 dropout: float = 0.0):
        super().__init__()
        self.fade_len = fade_len
        self.use_learned_fade = use_learned_fade
        self.use_overlap_add = use_overlap_add
        self.use_phase_alignment = use_phase_alignment
        self.use_spectral_blending = use_spectral_blending
        self.use_adaptive_window = use_adaptive_window
        self.sample_rate = sample_rate

        if use_learned_fade:
            self.fade_in_net = nn.Sequential(
                nn.Linear(fade_len, fade_len * 2), nn.GELU(),
                nn.Linear(fade_len * 2, fade_len), nn.Sigmoid()
            )
            self.fade_out_net = nn.Sequential(
                nn.Linear(fade_len, fade_len * 2), nn.GELU(),
                nn.Linear(fade_len * 2, fade_len), nn.Sigmoid()
            )
            self.fade_context_encoder = nn.Sequential(
                nn.Linear(fade_len * 2, fade_len), nn.GELU(),
                nn.Linear(fade_len, fade_len // 2)
            )
        else:
            fi = torch.linspace(0, 1, fade_len)
            fo = torch.linspace(1, 0, fade_len)
            self.register_buffer('default_fade_in', fi)
            self.register_buffer('default_fade_out', fo)

        if use_adaptive_window:
            self.window_selector = nn.Sequential(
                nn.Linear(fade_len * 2, fade_len), nn.GELU(),
                nn.Linear(fade_len, window_types)
            )
            self.window_types_count = window_types

        if use_spectral_blending:
            self.spectral_fade_net = nn.Sequential(
                nn.Linear(fade_len // 2 + 1, fade_len), nn.GELU(),
                nn.Linear(fade_len, fade_len // 2 + 1), nn.Sigmoid()
            )

        self.blend_quality_estimator = nn.Sequential(
            nn.Linear(fade_len * 2, fade_len), nn.GELU(),
            nn.Linear(fade_len, 1), nn.Sigmoid()
        )
        self.artifact_detector = nn.Sequential(
            nn.Linear(fade_len, fade_len // 2), nn.GELU(),
            nn.Linear(fade_len // 2, 1), nn.Sigmoid()
        )
        self.output_smoother = nn.Sequential(
            nn.Conv1d(1, 8, kernel_size=5, padding=2),
            nn.GELU(),
            nn.Conv1d(8, 1, kernel_size=3, padding=1)
        )
        self.output_gate = nn.Parameter(torch.zeros(1))

    def _get_window(self, length: int, window_type: str = 'hann',
                    device: Optional[torch.device] = None) -> torch.Tensor:
        t = torch.linspace(0, 1, length, device=device)
        if window_type == 'hann':
            return 0.5 * (1 - torch.cos(2 * math.pi * t))
        elif window_type == 'bartlett':
            return 1 - (2 * t - 1).abs()
        elif window_type == 'linear_in':
            return t
        elif window_type == 'linear_out':
            return 1 - t
        elif window_type == 'cosine':
            return torch.sin(math.pi * t / 2)
        return t

    def _phase_align(self, a: torch.Tensor, b: torch.Tensor) -> Tuple[torch.Tensor, torch.Tensor]:
        if not self.use_phase_alignment or a.shape[-1] < 4:
            return a, b
        fa = torch.fft.rfft(a.float())
        fb = torch.fft.rfft(b.float())
        phase_a = torch.angle(fa)
        phase_b = torch.angle(fb)
        phase_diff = phase_b - phase_a
        correction = torch.exp(1j * phase_diff * 0.5)
        fa_aligned = fa * correction
        a_aligned = torch.fft.irfft(fa_aligned, n=a.shape[-1]).to(a.dtype)
        return a_aligned, b

    def forward(self, chunks: torch.Tensor,
                return_quality: bool = False) -> Union[torch.Tensor, Dict[str, torch.Tensor]]:
        if chunks.dim() == 1:
            chunks = chunks.unsqueeze(0)
        B, T = chunks.shape
        fl = min(self.fade_len, T // 4)
        if fl <= 0:
            return {'blended': chunks, 'quality': torch.ones(B, 1, device=chunks.device)} if return_quality else chunks

        region_start = chunks[:, :fl].clone()
        region_end = chunks[:, -fl:].clone()

        if self.use_learned_fade:
            fi = self.fade_in_net(region_start)
            fo = self.fade_out_net(region_end)
        else:
            fi = self.default_fade_in[:fl].unsqueeze(0).expand(B, -1)
            fo = self.default_fade_out[:fl].unsqueeze(0).expand(B, -1)

        if self.use_phase_alignment:
            region_start_aligned, _ = self._phase_align(region_start, region_end)
        else:
            region_start_aligned = region_start

        blended = chunks.clone()
        blended[:, :fl] = blended[:, :fl] * fi
        blended[:, -fl:] = blended[:, -fl:] * fo

        if self.use_spectral_blending and fl >= 4:
            transition = chunks[:, fl:fl * 2] if T > fl * 2 else chunks[:, fl:]
            try:
                spec = torch.fft.rfft(transition.float(), n=fl * 2)
                mag = spec.abs()
                sf = self.spectral_fade_net(mag[:, :fl // 2 + 1].clamp(0, 1000))
                spec_masked = spec[:, :fl // 2 + 1] * sf
                transition_refined = torch.fft.irfft(spec_masked, n=fl * 2).to(chunks.dtype)
                tl = min(transition_refined.shape[-1], T - fl)
                blended[:, fl:fl + tl] = blended[:, fl:fl + tl] + transition_refined[:, :tl] * 0.05
            except Exception:
                pass

        blended_s = self.output_smoother(blended.unsqueeze(1)).squeeze(1)
        gate = torch.sigmoid(self.output_gate)
        final = gate * blended_s + (1 - gate) * blended

        if return_quality:
            ctx = torch.cat([region_start, region_end], dim=-1)
            quality = self.blend_quality_estimator(ctx)
            artifact = self.artifact_detector(blended[:, :fl])
            return {
                'blended': final,
                'quality': quality,
                'artifact_probability': artifact
            }
        return final

class ResBlock1d(nn.Module):
    def __init__(self, channels: int, dilation: int = 1,
                 use_skip_scale: bool = True,
                 use_gated_activation: bool = True,
                 use_weight_norm: bool = True,
                 use_instance_norm: bool = False,
                 use_film_conditioning: bool = False,
                 cond_dim: int = 0,
                 kernel_size: int = 3,
                 dropout: float = 0.0,
                 activation: str = 'leaky_relu',
                 use_se_attention: bool = True,
                 se_ratio: int = 4):
        super().__init__()
        self.channels = channels
        self.use_gated_activation = use_gated_activation
        self.use_film_conditioning = use_film_conditioning
        self.use_se_attention = use_se_attention

        pad = dilation * (kernel_size - 1) // 2

        conv1 = nn.Conv1d(channels, channels * 2 if use_gated_activation else channels,
                          kernel_size=kernel_size, dilation=dilation, padding=pad)
        conv2 = nn.Conv1d(channels, channels, kernel_size=1)

        if use_weight_norm:
            conv1 = nn.utils.weight_norm(conv1)
            conv2 = nn.utils.weight_norm(conv2)

        self.conv1 = conv1
        self.conv2 = conv2

        if activation == 'leaky_relu':
            self.act = nn.LeakyReLU(0.2)
        elif activation == 'gelu':
            self.act = nn.GELU()
        elif activation == 'silu':
            self.act = nn.SiLU()
        else:
            self.act = nn.LeakyReLU(0.2)

        self.dropout = nn.Dropout(dropout) if dropout > 0 else nn.Identity()

        if use_instance_norm:
            self.norm1 = nn.InstanceNorm1d(channels, affine=True)
            self.norm2 = nn.InstanceNorm1d(channels, affine=True)
        else:
            self.norm1 = nn.Identity()
            self.norm2 = nn.Identity()

        if use_se_attention:
            se_hidden = max(1, channels // se_ratio)
            self.se = nn.Sequential(
                nn.AdaptiveAvgPool1d(1),
                nn.Flatten(),
                nn.Linear(channels, se_hidden), nn.ReLU(),
                nn.Linear(se_hidden, channels), nn.Sigmoid()
            )

        if use_film_conditioning and cond_dim > 0:
            self.film_gamma = nn.Linear(cond_dim, channels)
            self.film_beta = nn.Linear(cond_dim, channels)

        self.use_skip_scale = use_skip_scale
        if use_skip_scale:
            self.skip_scale = nn.Parameter(torch.ones(1) * 0.1)

        self.dilation_conv_large = nn.Sequential(
            nn.Conv1d(channels, channels, kernel_size=kernel_size,
                      dilation=dilation * 2, padding=dilation * 2 * (kernel_size - 1) // 2),
            nn.LeakyReLU(0.2)
        )
        self.branch_fusion = nn.Conv1d(channels * 2, channels, kernel_size=1)

    def forward(self, x: torch.Tensor,
                cond: Optional[torch.Tensor] = None) -> torch.Tensor:
        residual = x
        h = self.conv1(x)

        if self.use_gated_activation:
            h_tanh, h_sig = h.chunk(2, dim=1)
            h = torch.tanh(h_tanh) * torch.sigmoid(h_sig)
        else:
            h = self.act(h)

        h = self.norm1(h)
        h = self.dropout(h)
        h = self.conv2(h)
        h = self.norm2(h)

        if self.use_se_attention:
            se_weight = self.se(h).unsqueeze(-1)
            h = h * se_weight

        if self.use_film_conditioning and cond is not None and hasattr(self, 'film_gamma'):
            gamma = self.film_gamma(cond).unsqueeze(-1)
            beta = self.film_beta(cond).unsqueeze(-1)
            h = h * (1 + gamma) + beta

        h_large = self.dilation_conv_large(x)
        h_fused = self.branch_fusion(torch.cat([h, h_large], dim=1))

        scale = torch.sigmoid(self.skip_scale) if self.use_skip_scale else 1.0
        return residual + h_fused * scale

class RLHFEngine:
    def __init__(self, model: nn.Module, ref_model: Optional[nn.Module] = None,
                 lr: float = 1e-6, clip_eps: float = 0.2,
                 kl_coef: float = 0.1, vf_coef: float = 0.1,
                 entropy_coef: float = 0.01, gamma: float = 0.99,
                 lam: float = 0.95, ppo_epochs: int = 4,
                 mini_batch: int = 4, reward_scaling: float = 1.0,
                 use_reward_normalization: bool = True,
                 use_value_clipping: bool = True,
                 use_dual_clip: bool = True,
                 dual_clip_c: float = 3.0,
                 use_gae_lambda: bool = True,
                 use_advantage_normalization: bool = True,
                 use_reward_shaping: bool = True,
                 use_curiosity_bonus: bool = False,
                 use_constitutional_ai: bool = True,
                 use_dpo: bool = True,
                 dpo_beta: float = 0.1,
                 max_grad_norm: float = 1.0,
                 warmup_steps: int = 100):
        self.model = model
        self.ref_model = ref_model
        self.clip_eps = clip_eps
        self.kl_coef = kl_coef
        self.vf_coef = vf_coef
        self.entropy_coef = entropy_coef
        self.gamma = gamma
        self.lam = lam
        self.ppo_epochs = ppo_epochs
        self.mini_batch = mini_batch
        self.reward_scaling = reward_scaling
        self.use_reward_normalization = use_reward_normalization
        self.use_value_clipping = use_value_clipping
        self.use_dual_clip = use_dual_clip
        self.dual_clip_c = dual_clip_c
        self.use_gae_lambda = use_gae_lambda
        self.use_advantage_normalization = use_advantage_normalization
        self.use_reward_shaping = use_reward_shaping
        self.use_curiosity_bonus = use_curiosity_bonus
        self.use_constitutional_ai = use_constitutional_ai
        self.use_dpo = use_dpo
        self.dpo_beta = dpo_beta
        self.max_grad_norm = max_grad_norm

        self.optimizer = torch.optim.AdamW(
            model.parameters(), lr=lr, weight_decay=1e-4, eps=1e-8
        )
        self.scheduler = torch.optim.lr_scheduler.LinearLR(
            self.optimizer, start_factor=0.1, end_factor=1.0, total_iters=warmup_steps
        )

        self._step = 0
        self._reward_history: List[float] = []
        self._kl_history: List[float] = []
        self._loss_history: List[float] = []
        self._reward_running_mean = 0.0
        self._reward_running_var = 1.0
        self._reward_ema_alpha = 0.99

        if ref_model is not None:
            for p in ref_model.parameters():
                p.requires_grad_(False)
            ref_model.eval()

        if use_curiosity_bonus:
            param_count = sum(p.numel() for p in model.parameters() if p.requires_grad)
            hidden = min(512, max(64, param_count // 1000))
            self.forward_model_curiosity = nn.Sequential(
                nn.Linear(hidden, hidden * 2), nn.GELU(),
                nn.Linear(hidden * 2, hidden)
            )
            self.inverse_model_curiosity = nn.Sequential(
                nn.Linear(hidden * 2, hidden * 2), nn.GELU(),
                nn.Linear(hidden * 2, hidden)
            )
            self.curiosity_optimizer = torch.optim.Adam(
                list(self.forward_model_curiosity.parameters()) +
                list(self.inverse_model_curiosity.parameters()),
                lr=lr * 10
            )
            self.curiosity_scale = 0.01

    def _normalize_rewards(self, rewards: torch.Tensor) -> torch.Tensor:
        if not self.use_reward_normalization:
            return rewards * self.reward_scaling
        batch_mean = rewards.mean().item()
        batch_var = rewards.var().item() + 1e-8
        self._reward_running_mean = (
            self._reward_ema_alpha * self._reward_running_mean +
            (1 - self._reward_ema_alpha) * batch_mean
        )
        self._reward_running_var = (
            self._reward_ema_alpha * self._reward_running_var +
            (1 - self._reward_ema_alpha) * batch_var
        )
        normalized = (rewards - self._reward_running_mean) / (self._reward_running_var ** 0.5 + 1e-8)
        return normalized * self.reward_scaling

    def compute_advantages_gae(self, rewards: torch.Tensor, values: torch.Tensor,
                                dones: torch.Tensor,
                                next_values: Optional[torch.Tensor] = None) -> Tuple[torch.Tensor, torch.Tensor]:
        rewards = self._normalize_rewards(rewards)
        T = len(rewards)
        advantages = torch.zeros_like(rewards)
        returns = torch.zeros_like(rewards)
        gae = 0.0
        next_val = next_values[-1].item() if next_values is not None else 0.0

        for t in reversed(range(T)):
            mask = 1.0 - dones[t].item()
            delta = rewards[t].item() + self.gamma * next_val * mask - values[t].item()
            gae = delta + self.gamma * self.lam * mask * gae
            advantages[t] = gae
            returns[t] = gae + values[t]
            next_val = values[t].item()

        if self.use_advantage_normalization:
            adv_mean = advantages.mean()
            adv_std = advantages.std() + 1e-8
            advantages = (advantages - adv_mean) / adv_std

        return advantages, returns

    def ppo_clip_loss(self, log_probs_new: torch.Tensor,
                      log_probs_old: torch.Tensor,
                      advantages: torch.Tensor) -> torch.Tensor:
        ratio = torch.exp(log_probs_new - log_probs_old.detach())
        surr1 = ratio * advantages
        surr2 = torch.clamp(ratio, 1.0 - self.clip_eps, 1.0 + self.clip_eps) * advantages

        if self.use_dual_clip:
            surr3 = self.dual_clip_c * advantages
            policy_loss = -torch.mean(
                torch.max(torch.min(surr1, surr2), surr3)
            )
        else:
            policy_loss = -torch.min(surr1, surr2).mean()

        return policy_loss

    def value_loss(self, values_new: torch.Tensor, values_old: torch.Tensor,
                   returns: torch.Tensor) -> torch.Tensor:
        if self.use_value_clipping:
            values_clipped = values_old + torch.clamp(
                values_new - values_old, -self.clip_eps, self.clip_eps
            )
            vf_loss1 = F.mse_loss(values_new, returns)
            vf_loss2 = F.mse_loss(values_clipped, returns)
            return torch.max(vf_loss1, vf_loss2)
        return F.mse_loss(values_new, returns)

    def compute_kl_from_ref(self, log_probs_new: torch.Tensor) -> torch.Tensor:
        if self.ref_model is None:
            return torch.tensor(0.0, device=log_probs_new.device)
        with torch.no_grad():
            ref_log_probs = log_probs_new.detach()
        kl = (torch.exp(ref_log_probs) * (ref_log_probs - log_probs_new)).sum(dim=-1).mean()
        return kl.clamp(min=0.0)

    def dpo_loss(self, policy_chosen_logps: torch.Tensor,
                 policy_rejected_logps: torch.Tensor,
                 ref_chosen_logps: torch.Tensor,
                 ref_rejected_logps: torch.Tensor) -> torch.Tensor:
        if not self.use_dpo:
            return torch.tensor(0.0, device=policy_chosen_logps.device)
        chosen_ratio = policy_chosen_logps - ref_chosen_logps
        rejected_ratio = policy_rejected_logps - ref_rejected_logps
        loss = -F.logsigmoid(self.dpo_beta * (chosen_ratio - rejected_ratio)).mean()
        return loss

    def apply_feedback(self, rollout: Dict[str, Any],
                       preferred_sequences: Optional[Dict] = None) -> Dict[str, float]:
        if not rollout:
            return {}

        rewards = torch.as_tensor(rollout.get('rewards', [0.0]), dtype=torch.float32)
        values = torch.as_tensor(rollout.get('values', [0.0]), dtype=torch.float32)
        dones = torch.as_tensor(rollout.get('dones', [1.0]), dtype=torch.float32)
        log_probs_old = torch.as_tensor(rollout.get('log_probs', [0.0]), dtype=torch.float32)
        entropy = torch.as_tensor(rollout.get('entropy', [0.0]), dtype=torch.float32)
        next_values = torch.as_tensor(rollout.get('next_values', values), dtype=torch.float32)

        advantages, returns = self.compute_advantages_gae(rewards, values, dones, next_values)
        self._reward_history.append(rewards.mean().item())

        total_policy_loss = 0.0
        total_value_loss = 0.0
        total_kl = 0.0
        total_entropy = 0.0

        batch_size = len(log_probs_old)
        mb_size = max(1, min(self.mini_batch, batch_size))

        for epoch in range(self.ppo_epochs):
            indices = torch.randperm(batch_size)
            for start in range(0, batch_size, mb_size):
                idx = indices[start:start + mb_size]
                if len(idx) == 0:
                    continue
                mb_log_probs = log_probs_old[idx]
                mb_advantages = advantages[idx]
                mb_returns = returns[idx]
                mb_values_old = values[idx]
                mb_entropy = entropy[idx]

                p_loss = self.ppo_clip_loss(mb_log_probs, mb_log_probs, mb_advantages)
                v_loss = self.value_loss(mb_values_old, mb_values_old, mb_returns)
                ent_loss = -mb_entropy.mean()
                kl_pen = self.compute_kl_from_ref(mb_log_probs.unsqueeze(-1))

                loss = (p_loss + self.vf_coef * v_loss +
                        self.entropy_coef * ent_loss + self.kl_coef * kl_pen)

                if preferred_sequences and self.use_dpo:
                    pc_lp = torch.as_tensor(preferred_sequences.get('chosen_logps', [0.0]), dtype=torch.float32)
                    pr_lp = torch.as_tensor(preferred_sequences.get('rejected_logps', [0.0]), dtype=torch.float32)
                    ref_c = torch.as_tensor(preferred_sequences.get('ref_chosen_logps', [0.0]), dtype=torch.float32)
                    ref_r = torch.as_tensor(preferred_sequences.get('ref_rejected_logps', [0.0]), dtype=torch.float32)
                    dpo_l = self.dpo_loss(pc_lp, pr_lp, ref_c, ref_r)
                    loss = loss + dpo_l * 0.5

                self.optimizer.zero_grad()
                loss.backward()
                nn.utils.clip_grad_norm_(self.model.parameters(), self.max_grad_norm)
                self.optimizer.step()
                self.scheduler.step()

                total_policy_loss += p_loss.item()
                total_value_loss += v_loss.item()
                total_kl += kl_pen.item()
                total_entropy += ent_loss.item()

        self._step += 1
        n = self.ppo_epochs * max(1, batch_size // mb_size)
        self._loss_history.append(total_policy_loss / n)
        self._kl_history.append(total_kl / n)

        return {
            'policy_loss': total_policy_loss / n,
            'value_loss': total_value_loss / n,
            'kl': total_kl / n,
            'entropy': total_entropy / n,
            'mean_reward': rewards.mean().item(),
            'mean_advantage': advantages.mean().item(),
            'reward_std': rewards.std().item(),
            'step': self._step,
            'lr': self.optimizer.param_groups[0]['lr'],
        }

    def get_stats(self) -> Dict[str, float]:
        if not self._reward_history:
            return {}
        rewards = self._reward_history[-100:]
        losses = self._loss_history[-100:]
        return {
            'mean_reward_100': float(sum(rewards) / len(rewards)),
            'max_reward': float(max(self._reward_history)),
            'mean_policy_loss': float(sum(losses) / len(losses)) if losses else 0.0,
            'total_steps': self._step,
            'reward_running_mean': self._reward_running_mean,
            'reward_running_std': self._reward_running_var ** 0.5,
        }

class StudioOrchestrator(nn.Module):
    def __init__(self, dim: int = 512, num_heads: int = 8,
                 num_stages: int = 16, num_modalities: int = 8,
                 use_dependency_graph: bool = True,
                 use_resource_scheduling: bool = True,
                 use_quality_control: bool = True,
                 use_parallel_execution: bool = True,
                 use_adaptive_routing: bool = True,
                 use_version_control: bool = True,
                 dropout: float = 0.1,
                 max_pipeline_depth: int = 32):
        super().__init__()
        self.dim = dim
        self.num_stages = num_stages
        self.num_modalities = num_modalities
        self.use_dependency_graph = use_dependency_graph
        self.use_resource_scheduling = use_resource_scheduling
        self.use_quality_control = use_quality_control
        self.use_parallel_execution = use_parallel_execution
        self.use_adaptive_routing = use_adaptive_routing
        self.use_version_control = use_version_control
        self.max_pipeline_depth = max_pipeline_depth

        self.task_encoder = nn.Sequential(
            nn.Linear(dim, dim * 4), nn.GELU(),
            nn.Dropout(dropout),
            nn.Linear(dim * 4, dim * 2), nn.GELU(),
            nn.Linear(dim * 2, dim)
        )
        self.task_router = nn.Sequential(
            nn.LayerNorm(dim),
            nn.Linear(dim, dim * 2), nn.GELU(),
            nn.Dropout(dropout),
            nn.Linear(dim * 2, num_stages)
        )
        self.modality_embed = nn.Embedding(num_modalities, dim)
        self.stage_embed = nn.Embedding(num_stages, dim)

        encoder_layer = nn.TransformerEncoderLayer(
            d_model=dim, nhead=num_heads, dim_feedforward=dim * 4,
            dropout=dropout, activation='gelu', batch_first=True, norm_first=True
        )
        self.orchestration_transformer = nn.TransformerEncoder(encoder_layer, num_layers=4)

        if use_dependency_graph:
            self.dependency_encoder = nn.Sequential(
                nn.Linear(dim * 2, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, dim)
            )
            self.dependency_attn = nn.MultiheadAttention(dim, num_heads, batch_first=True)
            self.dependency_norm = nn.LayerNorm(dim)
            self.critical_path_detector = nn.Sequential(
                nn.Linear(dim, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, 1), nn.Sigmoid()
            )

        if use_resource_scheduling:
            self.resource_estimator = nn.Sequential(
                nn.Linear(dim, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, 4)
            )
            self.priority_scorer = nn.Sequential(
                nn.Linear(dim, dim // 2), nn.GELU(),
                nn.Linear(dim // 2, 1)
            )
            self.parallelism_predictor = nn.Sequential(
                nn.Linear(dim, dim // 4), nn.GELU(),
                nn.Linear(dim // 4, 1), nn.Sigmoid()
            )

        if use_quality_control:
            self.quality_gate = nn.Sequential(
                nn.Linear(dim * 2, dim), nn.GELU(),
                nn.Linear(dim, 1), nn.Sigmoid()
            )
            self.output_validator = nn.Sequential(
                nn.Linear(dim, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, 5)
            )
            self.consistency_checker = nn.Sequential(
                nn.Linear(dim * 2, dim), nn.GELU(),
                nn.Linear(dim, 1), nn.Sigmoid()
            )

        if use_adaptive_routing:
            self.routing_history = nn.Parameter(torch.zeros(num_stages, dim), requires_grad=False)
            self.adaptive_router = nn.Sequential(
                nn.Linear(dim + num_stages, dim * 2), nn.GELU(),
                nn.Linear(dim * 2, num_stages)
            )
            self.routing_temperature = nn.Parameter(torch.ones(1))

        self.merge_attention = nn.MultiheadAttention(dim, num_heads, batch_first=True)
        self.merge_norm = nn.LayerNorm(dim)
        self.merge_proj = nn.Sequential(
            nn.Linear(dim * num_stages, dim * 4), nn.GELU(),
            nn.Dropout(dropout),
            nn.Linear(dim * 4, dim)
        )

        self.output_proj = nn.Linear(dim, dim)
        self.output_norm = nn.LayerNorm(dim)

        self._pipeline: List[Callable] = []
        self._results: Dict[str, Any] = {}
        self._stage_metrics: Dict[str, float] = {}
        self._version_log: List[Dict] = []
        self._execution_lock = threading.Lock()

    def register_stage(self, fn: Callable, name: Optional[str] = None) -> str:
        stage_id = name or f'stage_{len(self._pipeline)}'
        self._pipeline.append({'fn': fn, 'name': stage_id, 'calls': 0, 'total_time': 0.0})
        return stage_id

    def orchestrate(self, tasks: List[Dict[str, Any]],
                    timeout_per_task: float = 30.0) -> Dict[str, Any]:
        results: Dict[str, Any] = {}
        execution_order = self._resolve_dependencies(tasks)

        for task in execution_order:
            name = task.get('name', f'task_{len(results)}')
            stage_fn = task.get('fn')
            args = task.get('args', {})
            dependencies = task.get('depends_on', [])
            dep_results = {d: results.get(d) for d in dependencies if d in results}
            if dep_results:
                args = {**args, '_dependencies': dep_results}
            start_t = time.time()
            try:
                if stage_fn is not None:
                    out = stage_fn(**{k: v for k, v in args.items() if k != '_dependencies'})
                else:
                    out = args
                elapsed = time.time() - start_t
                results[name] = {'status': 'ok', 'result': out, 'elapsed': elapsed}
                self._stage_metrics[name] = elapsed
            except Exception as e:
                results[name] = {'status': 'failed', 'error': str(e), 'elapsed': time.time() - start_t}

        if self.use_version_control:
            self._version_log.append({
                'timestamp': time.time(),
                'tasks': [t.get('name') for t in tasks],
                'n_success': sum(1 for r in results.values() if r.get('status') == 'ok'),
                'n_failed': sum(1 for r in results.values() if r.get('status') == 'failed'),
            })

        self._results = results
        return results

    def _resolve_dependencies(self, tasks: List[Dict]) -> List[Dict]:
        resolved: List[Dict] = []
        visited: set = set()
        def visit(task: Dict) -> None:
            name = task.get('name', '')
            if name in visited:
                return
            for dep in task.get('depends_on', []):
                dep_task = next((t for t in tasks if t.get('name') == dep), None)
                if dep_task:
                    visit(dep_task)
            visited.add(name)
            resolved.append(task)
        for t in tasks:
            visit(t)
        return resolved

    def forward(self, x: torch.Tensor,
                modality_ids: Optional[torch.Tensor] = None) -> Dict[str, torch.Tensor]:
        B = x.shape[0]
        is_seq = x.dim() == 3
        if not is_seq:
            x = x.unsqueeze(1)

        task_feat = self.task_encoder(x)
        encoded = self.orchestration_transformer(task_feat)
        pooled = encoded.mean(dim=1)

        if modality_ids is not None:
            mod_emb = self.modality_embed(modality_ids.clamp(0, self.num_modalities - 1))
            pooled = pooled + mod_emb

        route_logits = self.task_router(pooled)
        if self.use_adaptive_routing:
            routing_hist = self.routing_history.unsqueeze(0).expand(B, -1, -1).mean(dim=1)
            adaptive_input = torch.cat([pooled, F.softmax(route_logits, dim=-1)], dim=-1)
            route_logits = route_logits + self.adaptive_router(adaptive_input) * 0.3

        temp = torch.abs(self.routing_temperature) if self.use_adaptive_routing else torch.ones(1, device=x.device)
        stage_weights = F.softmax(route_logits / temp, dim=-1)
        stage_embeds = self.stage_embed.weight.unsqueeze(0).expand(B, -1, -1)
        merged_vec = (stage_weights.unsqueeze(-1) * stage_embeds).sum(dim=1)

        merge_out, _ = self.merge_attention(
            merged_vec.unsqueeze(1),
            stage_embeds,
            stage_embeds
        )
        merged_vec = self.merge_norm(merged_vec + merge_out.squeeze(1))

        out = self.output_norm(self.output_proj(merged_vec))

        result: Dict[str, torch.Tensor] = {
            'output': out,
            'stage_weights': stage_weights,
            'task_embedding': pooled,
        }
        if self.use_resource_scheduling:
            result['resource_estimate'] = torch.relu(self.resource_estimator(pooled))
            result['priority_score'] = self.priority_scorer(pooled)
        if self.use_quality_control:
            qc_input = torch.cat([out, pooled], dim=-1)
            result['quality_gate'] = self.quality_gate(qc_input)
            result['output_validity'] = F.softmax(self.output_validator(out), dim=-1)
        return result

class TaskScheduler:
    def __init__(self, max_workers: int = 8, max_retries: int = 3,
                 use_priority_queue: bool = True,
                 use_dependency_resolution: bool = True,
                 use_deadline_scheduling: bool = True,
                 use_resource_aware: bool = True,
                 use_preemption: bool = False,
                 use_work_stealing: bool = True,
                 use_circuit_breaker: bool = True,
                 circuit_breaker_threshold: int = 5,
                 default_timeout: float = 60.0):
        self.max_workers = max_workers
        self.max_retries = max_retries
        self.use_priority_queue = use_priority_queue
        self.use_dependency_resolution = use_dependency_resolution
        self.use_deadline_scheduling = use_deadline_scheduling
        self.use_resource_aware = use_resource_aware
        self.use_preemption = use_preemption
        self.use_work_stealing = use_work_stealing
        self.use_circuit_breaker = use_circuit_breaker
        self.circuit_breaker_threshold = circuit_breaker_threshold
        self.default_timeout = default_timeout

        self._queue: queue.PriorityQueue = queue.PriorityQueue()
        self._results: Dict[str, Any] = {}
        self._pending: Dict[str, Dict] = {}
        self._running: Dict[str, Any] = {}
        self._failed_counts: Dict[str, int] = defaultdict(int)
        self._lock = threading.RLock()
        self._counter = 0
        self._worker_pool: Optional[Any] = None
        self._circuit_open: set = set()
        self._metrics: Dict[str, float] = {
            'total_scheduled': 0.0, 'total_completed': 0.0,
            'total_failed': 0.0, 'avg_latency': 0.0
        }
        self._latency_history: deque = deque(maxlen=1000)
        self._start_time = time.time()

    def schedule(self, fn: Callable, args: tuple = (),
                 kwargs: Optional[Dict] = None, priority: int = 5,
                 task_id: Optional[str] = None,
                 depends_on: Optional[List[str]] = None,
                 deadline: Optional[float] = None,
                 timeout: Optional[float] = None,
                 resource_units: float = 1.0,
                 tags: Optional[List[str]] = None) -> str:
        if kwargs is None:
            kwargs = {}
        task_id = task_id or secrets.token_hex(8)
        with self._lock:
            effective_priority = priority
            if self.use_deadline_scheduling and deadline is not None:
                time_to_deadline = max(0.0, deadline - time.time())
                effective_priority = max(0, priority - int(10 / (time_to_deadline + 0.1)))
            entry: Dict[str, Any] = {
                'id': task_id, 'fn': fn, 'args': args, 'kwargs': kwargs,
                'retries': 0, 'max_retries': self.max_retries,
                'depends_on': depends_on or [],
                'deadline': deadline,
                'timeout': timeout or self.default_timeout,
                'resource_units': resource_units,
                'tags': tags or [],
                'scheduled_at': time.time(),
                'priority': effective_priority,
            }
            self._pending[task_id] = entry
            self._queue.put((effective_priority, self._counter, entry))
            self._counter += 1
            self._metrics['total_scheduled'] += 1
        return task_id

    def _can_run(self, task: Dict) -> bool:
        if not self.use_dependency_resolution:
            return True
        return all(
            dep in self._results and self._results[dep].get('status') == 'ok'
            for dep in task.get('depends_on', [])
        )

    def _is_circuit_open(self, fn_name: str) -> bool:
        if not self.use_circuit_breaker:
            return False
        return fn_name in self._circuit_open

    def _execute_task(self, task: Dict) -> None:
        fn_name = getattr(task['fn'], '__name__', str(task['fn']))
        if self._is_circuit_open(fn_name):
            with self._lock:
                self._results[task['id']] = {
                    'status': 'circuit_open', 'error': f'Circuit breaker open for {fn_name}'
                }
            return

        start_t = time.time()
        try:
            result = task['fn'](*task['args'], **task['kwargs'])
            elapsed = time.time() - start_t
            with self._lock:
                self._results[task['id']] = {
                    'status': 'ok', 'result': result,
                    'elapsed': elapsed, 'completed_at': time.time()
                }
                self._failed_counts[fn_name] = 0
                self._metrics['total_completed'] += 1
                self._latency_history.append(elapsed)
                if self._latency_history:
                    self._metrics['avg_latency'] = sum(self._latency_history) / len(self._latency_history)
        except Exception as e:
            elapsed = time.time() - start_t
            with self._lock:
                task['retries'] += 1
                self._failed_counts[fn_name] += 1
                if self._failed_counts[fn_name] >= self.circuit_breaker_threshold:
                    self._circuit_open.add(fn_name)
                if task['retries'] < task['max_retries']:
                    backoff = min(2 ** task['retries'], 30)
                    time.sleep(backoff * 0.01)
                    self._queue.put((task['priority'], self._counter, task))
                    self._counter += 1
                else:
                    self._results[task['id']] = {
                        'status': 'failed', 'error': str(e), 'elapsed': elapsed,
                        'retries': task['retries']
                    }
                    self._metrics['total_failed'] += 1

    def run_all(self, timeout: Optional[float] = None,
                max_concurrent: Optional[int] = None) -> Dict[str, Any]:
        timeout = timeout or self.default_timeout
        max_c = max_concurrent or self.max_workers
        deadline = time.time() + timeout
        pending_tasks: List[Dict] = []

        with self._lock:
            while not self._queue.empty():
                try:
                    _, _, task = self._queue.get_nowait()
                    pending_tasks.append(task)
                except queue.Empty:
                    break

        with concurrent.futures.ThreadPoolExecutor(max_workers=max_c) as executor:
            futures: Dict[Any, str] = {}
            processed: set = set()
            while (pending_tasks or futures) and time.time() < deadline:
                ready = [t for t in pending_tasks
                         if t['id'] not in processed and self._can_run(t)]
                for task in ready:
                    if task['id'] not in processed:
                        processed.add(task['id'])
                        pending_tasks.remove(task)
                        fut = executor.submit(self._execute_task, task)
                        futures[fut] = task['id']
                done_futures = [f for f in list(futures.keys()) if f.done()]
                for f in done_futures:
                    del futures[f]
                if not ready and not done_futures:
                    time.sleep(0.005)
            for fut in concurrent.futures.as_completed(futures.keys(), timeout=max(0.1, deadline - time.time())):
                pass

        return self._results

    def get_result(self, task_id: str,
                   wait: bool = False, timeout: float = 10.0) -> Optional[Any]:
        if wait:
            deadline = time.time() + timeout
            while time.time() < deadline:
                with self._lock:
                    if task_id in self._results:
                        return self._results[task_id]
                time.sleep(0.01)
            return None
        with self._lock:
            return self._results.get(task_id)

    def cancel(self, task_id: str) -> bool:
        with self._lock:
            if task_id in self._pending and task_id not in self._results:
                self._results[task_id] = {'status': 'cancelled'}
                return True
        return False

    def get_metrics(self) -> Dict[str, Any]:
        with self._lock:
            return {
                **self._metrics,
                'uptime_sec': time.time() - self._start_time,
                'pending_count': self._queue.qsize(),
                'result_count': len(self._results),
                'circuit_breakers_open': list(self._circuit_open),
            }

    def reset_circuit_breaker(self, fn_name: str) -> None:
        with self._lock:
            self._circuit_open.discard(fn_name)
            self._failed_counts[fn_name] = 0

class SelfBootstrapper:
    def __init__(self, use_health_monitoring: bool = True,
                 use_dependency_validation: bool = True,
                 use_config_validation: bool = True,
                 use_auto_repair: bool = True,
                 use_graceful_degradation: bool = True,
                 use_telemetry: bool = True,
                 retry_on_failure: int = 3,
                 startup_timeout: float = 60.0):
        self.use_health_monitoring = use_health_monitoring
        self.use_dependency_validation = use_dependency_validation
        self.use_config_validation = use_config_validation
        self.use_auto_repair = use_auto_repair
        self.use_graceful_degradation = use_graceful_degradation
        self.use_telemetry = use_telemetry
        self.retry_on_failure = retry_on_failure
        self.startup_timeout = startup_timeout

        self._checks: List[Dict[str, Any]] = []
        self._repair_handlers: Dict[str, Callable] = {}
        self._config: Dict[str, Any] = {}
        self._component_status: Dict[str, str] = {}
        self._errors: List[Dict] = []
        self._warnings: List[str] = []
        self._startup_time: Optional[float] = None
        self._telemetry_data: Dict[str, Any] = {}
        self._initialized_components: List[str] = []

    def add_check(self, name: str, fn: Callable[[], bool],
                  critical: bool = True,
                  repair_fn: Optional[Callable] = None,
                  timeout: float = 10.0) -> None:
        self._checks.append({
            'name': name, 'fn': fn, 'critical': critical,
            'timeout': timeout, 'repair_fn': repair_fn
        })
        if repair_fn is not None:
            self._repair_handlers[name] = repair_fn

    def _check_environment(self) -> Dict[str, Any]:
        env_status: Dict[str, Any] = {}
        env_status['python_version'] = f'{sys.version_info.major}.{sys.version_info.minor}.{sys.version_info.micro}'
        env_status['python_ok'] = sys.version_info >= (3, 9)
        env_status['cuda_available'] = torch.cuda.is_available()
        env_status['cuda_device_count'] = torch.cuda.device_count() if torch.cuda.is_available() else 0
        env_status['torch_version'] = torch.__version__
        env_status['cpu_count'] = os.cpu_count() or 1
        env_status['platform'] = sys.platform

        try:
            import psutil
            env_status['ram_gb'] = round(psutil.virtual_memory().total / 1e9, 2)
            env_status['ram_available_gb'] = round(psutil.virtual_memory().available / 1e9, 2)
            env_status['disk_free_gb'] = round(psutil.disk_usage('/').free / 1e9, 2)
        except ImportError:
            env_status['ram_gb'] = 'unknown'

        if torch.cuda.is_available():
            try:
                for i in range(torch.cuda.device_count()):
                    props = torch.cuda.get_device_properties(i)
                    env_status[f'gpu_{i}_name'] = props.name
                    env_status[f'gpu_{i}_vram_gb'] = round(props.total_memory / 1e9, 2)
            except Exception as e:
                env_status['gpu_error'] = str(e)
        return env_status

    def _validate_config(self, config: Dict) -> Tuple[bool, List[str]]:
        if not self.use_config_validation:
            return True, []
        errors: List[str] = []
        required_types = {
            str: ['model_name', 'output_dir'],
            int: ['batch_size', 'num_workers'],
            float: ['learning_rate'],
        }
        for expected_type, keys in required_types.items():
            for key in keys:
                if key in config and not isinstance(config[key], expected_type):
                    errors.append(f"Config key '{key}' should be {expected_type.__name__}, got {type(config[key]).__name__}")
        for k, v in config.items():
            if isinstance(v, float) and (math.isnan(v) or math.isinf(v)):
                errors.append(f"Config key '{k}' has invalid value: {v}")
        return len(errors) == 0, errors

    def _run_check_with_retry(self, check: Dict) -> Tuple[bool, Optional[str]]:
        for attempt in range(self.retry_on_failure + 1):
            try:
                result = check['fn']()
                if result:
                    return True, None
                if attempt < self.retry_on_failure and self.use_auto_repair:
                    repair_fn = check.get('repair_fn') or self._repair_handlers.get(check['name'])
                    if repair_fn is not None:
                        try:
                            repair_fn()
                        except Exception as re:
                            pass
            except Exception as e:
                if attempt == self.retry_on_failure:
                    return False, str(e)
                time.sleep(0.1 * (attempt + 1))
        return False, f"Check '{check['name']}' failed after {self.retry_on_failure} retries"

    def bootstrap(self, config_path: Optional[str] = None,
                  config_dict: Optional[Dict] = None,
                  skip_non_critical: bool = False) -> Dict[str, Any]:
        self._startup_time = time.time()
        report: Dict[str, Any] = {
            'status': 'ok',
            'checks': {},
            'errors': [],
            'warnings': [],
            'components': {},
            'env': {},
        }

        report['env'] = self._check_environment()

        if config_path is not None and os.path.exists(config_path):
            try:
                ext = os.path.splitext(config_path)[1].lower()
                if ext in ('.yaml', '.yml'):
                    try:
                        import yaml
                        with open(config_path, 'r', encoding='utf-8') as f:
                            self._config = yaml.safe_load(f) or {}
                    except ImportError:
                        import json
                        with open(config_path, 'r', encoding='utf-8') as f:
                            self._config = json.load(f)
                elif ext == '.json':
                    import json
                    with open(config_path, 'r', encoding='utf-8') as f:
                        self._config = json.load(f)
                else:
                    with open(config_path, 'r', encoding='utf-8') as f:
                        import json
                        self._config = json.load(f)
                report['config_loaded'] = True
                if self.use_config_validation:
                    valid, config_errors = self._validate_config(self._config)
                    if not valid:
                        report['warnings'].extend(config_errors)
            except Exception as e:
                report['errors'].append({'component': 'config', 'error': str(e), 'critical': False})
                report['warnings'].append(f'Config load failed: {e}')
        elif config_dict is not None:
            self._config = config_dict
            report['config_loaded'] = True

        has_critical_failure = False
        for check in self._checks:
            name = check['name']
            if skip_non_critical and not check.get('critical', True):
                report['checks'][name] = 'skipped'
                continue
            ok, err = self._run_check_with_retry(check)
            report['checks'][name] = 'ok' if ok else 'failed'
            self._component_status[name] = 'ok' if ok else 'failed'
            if not ok:
                error_entry = {
                    'component': name, 'error': err or 'Unknown',
                    'critical': check.get('critical', True)
                }
                report['errors'].append(error_entry)
                if check.get('critical', True):
                    has_critical_failure = True
                else:
                    report['warnings'].append(f'Non-critical check failed: {name}')

        if has_critical_failure:
            if self.use_graceful_degradation:
                report['status'] = 'degraded'
            else:
                report['status'] = 'failed'
        elif report['errors']:
            report['status'] = 'degraded'

        report['startup_time_sec'] = round(time.time() - self._startup_time, 3)
        report['components'] = self._component_status.copy()

        if self.use_telemetry:
            self._telemetry_data = {
                'bootstrap_status': report['status'],
                'startup_time': report['startup_time_sec'],
                'checks_passed': sum(1 for v in report['checks'].values() if v == 'ok'),
                'checks_failed': sum(1 for v in report['checks'].values() if v == 'failed'),
                'timestamp': time.time(),
            }
            report['telemetry'] = self._telemetry_data

        self._errors = report['errors']
        self._warnings = report['warnings']
        return report

    def get_component_status(self) -> Dict[str, str]:
        return self._component_status.copy()

    def get_config(self, key: str, default: Any = None) -> Any:
        return self._config.get(key, default)

    def is_healthy(self) -> bool:
        return all(v == 'ok' for v in self._component_status.values())

    def get_telemetry(self) -> Dict[str, Any]:
        return self._telemetry_data.copy()

class SelfHealingArchitecture:
    def __init__(self, model: Optional[nn.Module] = None,
                 use_anomaly_detection: bool = True,
                 use_automatic_rollback: bool = True,
                 use_redundant_components: bool = True,
                 use_health_checks: bool = True,
                 use_watchdog: bool = True,
                 use_adaptive_healing: bool = True,
                 use_predictive_maintenance: bool = True,
                 health_check_interval: float = 30.0,
                 max_heal_attempts: int = 3,
                 checkpoint_frequency: int = 100,
                 anomaly_threshold: float = 3.0,
                 recovery_strategies: Optional[List[str]] = None):
        self.model = model
        self.use_anomaly_detection = use_anomaly_detection
        self.use_automatic_rollback = use_automatic_rollback
        self.use_redundant_components = use_redundant_components
        self.use_health_checks = use_health_checks
        self.use_watchdog = use_watchdog
        self.use_adaptive_healing = use_adaptive_healing
        self.use_predictive_maintenance = use_predictive_maintenance
        self.health_check_interval = health_check_interval
        self.max_heal_attempts = max_heal_attempts
        self.checkpoint_frequency = checkpoint_frequency
        self.anomaly_threshold = anomaly_threshold
        self.recovery_strategies = recovery_strategies or [
            'restart', 'rollback', 'reinitialize', 'fallback', 'reduce_load'
        ]

        self._checkpoints: deque = deque(maxlen=5)
        self._health_history: deque = deque(maxlen=500)
        self._anomaly_scores: deque = deque(maxlen=200)
        self._heal_attempts: Dict[str, int] = defaultdict(int)
        self._component_registry: Dict[str, Any] = {}
        self._fallback_registry: Dict[str, Any] = {}
        self._health_hooks: List[Callable] = []
        self._recovery_hooks: Dict[str, Callable] = {}
        self._step_count = 0
        self._last_health_check = time.time()
        self._is_degraded = False
        self._degradation_reason: Optional[str] = None
        self._lock = threading.RLock()

        if use_anomaly_detection:
            self._metric_history: Dict[str, deque] = defaultdict(lambda: deque(maxlen=100))
            self._anomaly_baselines: Dict[str, Tuple[float, float]] = {}

        if use_predictive_maintenance:
            self._failure_predictions: Dict[str, float] = {}
            self._maintenance_schedule: List[Dict] = []

    def register_component(self, name: str, component: Any,
                           fallback: Optional[Any] = None) -> None:
        with self._lock:
            self._component_registry[name] = component
            if fallback is not None:
                self._fallback_registry[name] = fallback

    def add_health_hook(self, fn: Callable[[], Dict[str, float]]) -> None:
        self._health_hooks.append(fn)

    def add_recovery_hook(self, strategy: str, fn: Callable) -> None:
        self._recovery_hooks[strategy] = fn

    def checkpoint(self, metadata: Optional[Dict] = None) -> str:
        checkpoint_id = secrets.token_hex(8)
        with self._lock:
            ckpt: Dict[str, Any] = {
                'id': checkpoint_id,
                'timestamp': time.time(),
                'step': self._step_count,
                'metadata': metadata or {},
            }
            if self.model is not None:
                ckpt['model_state'] = {
                    k: v.cpu().clone()
                    for k, v in self.model.state_dict().items()
                }
            self._checkpoints.append(ckpt)
        return checkpoint_id

    def rollback(self, checkpoint_id: Optional[str] = None) -> bool:
        if not self.use_automatic_rollback:
            return False
        with self._lock:
            if not self._checkpoints:
                return False
            if checkpoint_id is not None:
                target = next((c for c in self._checkpoints if c['id'] == checkpoint_id), None)
            else:
                target = list(self._checkpoints)[-1]
            if target is None or self.model is None:
                return False
            try:
                if 'model_state' in target:
                    device = next(self.model.parameters()).device
                    state = {k: v.to(device) for k, v in target['model_state'].items()}
                    self.model.load_state_dict(state, strict=False)
                return True
            except Exception:
                return False

    def _detect_anomalies(self, metrics: Dict[str, float]) -> Dict[str, float]:
        if not self.use_anomaly_detection:
            return {}
        anomaly_scores: Dict[str, float] = {}
        for name, value in metrics.items():
            if not math.isfinite(value):
                anomaly_scores[name] = float('inf')
                continue
            hist = self._metric_history[name]
            hist.append(value)
            if len(hist) >= 10:
                vals = list(hist)
                mu = sum(vals) / len(vals)
                sigma = (sum((v - mu) ** 2 for v in vals) / len(vals)) ** 0.5 + 1e-8
                z_score = abs(value - mu) / sigma
                anomaly_scores[name] = z_score
                self._anomaly_baselines[name] = (mu, sigma)
            else:
                anomaly_scores[name] = 0.0
        return anomaly_scores

    def health_check(self, metrics: Optional[Dict[str, float]] = None) -> Dict[str, Any]:
        if not self.use_health_checks:
            return {'status': 'ok'}

        current_time = time.time()
        health: Dict[str, Any] = {
            'timestamp': current_time,
            'status': 'ok',
            'components': {},
            'anomalies': {},
            'metrics': metrics or {},
        }

        for hook in self._health_hooks:
            try:
                hook_metrics = hook()
                if metrics is None:
                    metrics = {}
                metrics.update(hook_metrics)
            except Exception as e:
                health['warnings'] = health.get('warnings', []) + [f'Health hook error: {e}']

        if metrics:
            anomaly_scores = self._detect_anomalies(metrics)
            health['anomalies'] = anomaly_scores
            critical_anomalies = {
                k: v for k, v in anomaly_scores.items()
                if v > self.anomaly_threshold and math.isfinite(v)
            }
            if critical_anomalies:
                health['status'] = 'degraded'
                health['critical_anomalies'] = critical_anomalies

        if self.model is not None:
            try:
                has_nan = any(
                    torch.isnan(p.data).any().item() or torch.isinf(p.data).any().item()
                    for p in self.model.parameters()
                )
                health['components']['model_weights'] = 'corrupted' if has_nan else 'ok'
                if has_nan:
                    health['status'] = 'critical'
            except Exception as e:
                health['components']['model_weights'] = f'error: {e}'

        with self._lock:
            self._health_history.append(health.copy())
            self._is_degraded = health['status'] != 'ok'
            if self._is_degraded:
                self._degradation_reason = str(health.get('critical_anomalies', health.get('components', 'unknown')))
            self._last_health_check = current_time

        return health

    def heal(self, issue: Optional[str] = None,
             strategy: Optional[str] = None) -> Dict[str, Any]:
        issue_key = issue or 'general'
        with self._lock:
            self._heal_attempts[issue_key] += 1
            attempt = self._heal_attempts[issue_key]

        if attempt > self.max_heal_attempts:
            return {
                'success': False,
                'reason': f'Exceeded max heal attempts ({self.max_heal_attempts}) for {issue_key}',
                'attempts': attempt
            }

        chosen_strategy = strategy
        if chosen_strategy is None:
            if self.use_adaptive_healing:
                strategy_idx = min(attempt - 1, len(self.recovery_strategies) - 1)
                chosen_strategy = self.recovery_strategies[strategy_idx]
            else:
                chosen_strategy = self.recovery_strategies[0]

        if chosen_strategy in self._recovery_hooks:
            try:
                self._recovery_hooks[chosen_strategy]()
                self._heal_attempts[issue_key] = 0
                return {'success': True, 'strategy': chosen_strategy, 'attempts': attempt}
            except Exception as e:
                return {'success': False, 'strategy': chosen_strategy, 'error': str(e), 'attempts': attempt}

        if chosen_strategy == 'rollback':
            success = self.rollback()
            if success:
                self._heal_attempts[issue_key] = 0
            return {'success': success, 'strategy': 'rollback', 'attempts': attempt}

        elif chosen_strategy == 'reinitialize' and self.model is not None:
            try:
                with self._lock:
                    for module in self.model.modules():
                        if hasattr(module, 'reset_parameters'):
                            module.reset_parameters()
                    self._heal_attempts[issue_key] = 0
                return {'success': True, 'strategy': 'reinitialize', 'attempts': attempt}
            except Exception as e:
                return {'success': False, 'strategy': 'reinitialize', 'error': str(e), 'attempts': attempt}

        elif chosen_strategy == 'fallback':
            with self._lock:
                for name, fallback in self._fallback_registry.items():
                    self._component_registry[name] = fallback
            self._heal_attempts[issue_key] = 0
            return {'success': True, 'strategy': 'fallback', 'attempts': attempt}

        return {'success': False, 'strategy': chosen_strategy, 'reason': 'No handler found', 'attempts': attempt}

    def step(self, metrics: Optional[Dict[str, float]] = None) -> Optional[Dict]:
        self._step_count += 1
        if self._step_count % self.checkpoint_frequency == 0:
            self.checkpoint({'step': self._step_count, 'metrics': metrics})

        if time.time() - self._last_health_check > self.health_check_interval:
            health = self.health_check(metrics)
            if health['status'] in ('degraded', 'critical'):
                return self.heal()
        return None

    def get_status(self) -> Dict[str, Any]:
        with self._lock:
            return {
                'is_degraded': self._is_degraded,
                'degradation_reason': self._degradation_reason,
                'step_count': self._step_count,
                'checkpoints_stored': len(self._checkpoints),
                'heal_attempts': dict(self._heal_attempts),
                'components': list(self._component_registry.keys()),
                'fallbacks': list(self._fallback_registry.keys()),
                'last_health_check': self._last_health_check,
            }

class TechnicalAnalyzer:
    def __init__(self, use_ichimoku: bool = True,
                 use_fibonacci: bool = True,
                 use_volume_profile: bool = True,
                 use_elliott_wave: bool = True,
                 use_harmonic_patterns: bool = True,
                 use_market_microstructure: bool = True,
                 use_order_flow_analysis: bool = True,
                 use_sentiment_indicators: bool = True,
                 use_volatility_regime: bool = True,
                 default_periods: Optional[Dict[str, int]] = None):
        self.use_ichimoku = use_ichimoku
        self.use_fibonacci = use_fibonacci
        self.use_volume_profile = use_volume_profile
        self.use_elliott_wave = use_elliott_wave
        self.use_harmonic_patterns = use_harmonic_patterns
        self.use_market_microstructure = use_market_microstructure
        self.use_order_flow_analysis = use_order_flow_analysis
        self.use_sentiment_indicators = use_sentiment_indicators
        self.use_volatility_regime = use_volatility_regime
        self.periods = default_periods or {
            'sma_fast': 20, 'sma_slow': 50, 'sma_200': 200,
            'ema_fast': 12, 'ema_slow': 26, 'rsi': 14,
            'macd_signal': 9, 'bb': 20, 'atr': 14,
            'stoch': 14, 'williams': 14, 'cci': 20,
            'adx': 14, 'obv_smooth': 5
        }

    @staticmethod
    def _ema(arr: np.ndarray, period: int) -> np.ndarray:
        if len(arr) == 0:
            return arr
        k = 2.0 / (period + 1)
        out = np.empty_like(arr, dtype=float)
        out[0] = arr[0]
        for i in range(1, len(arr)):
            out[i] = float(arr[i]) * k + out[i - 1] * (1 - k)
        return out

    @staticmethod
    def _sma(arr: np.ndarray, period: int) -> np.ndarray:
        return np.convolve(arr, np.ones(period) / period, mode='valid')

    @staticmethod
    def _true_range(high: np.ndarray, low: np.ndarray, close: np.ndarray) -> np.ndarray:
        tr1 = high[1:] - low[1:]
        tr2 = np.abs(high[1:] - close[:-1])
        tr3 = np.abs(low[1:] - close[:-1])
        return np.maximum(tr1, np.maximum(tr2, tr3))

    def _rsi(self, prices: np.ndarray, period: int = 14) -> float:
        if len(prices) < period + 1:
            return 50.0
        deltas = np.diff(prices[-(period * 2):])
        gains = np.where(deltas > 0, deltas, 0.0)
        losses = np.where(deltas < 0, -deltas, 0.0)
        avg_gain = float(np.mean(gains[-period:]) + 1e-9)
        avg_loss = float(np.mean(losses[-period:]) + 1e-9)
        return float(100.0 - 100.0 / (1.0 + avg_gain / avg_loss))

    def _stochastic(self, close: np.ndarray, high: np.ndarray,
                    low: np.ndarray, period: int = 14) -> Tuple[float, float]:
        if len(close) < period:
            return 50.0, 50.0
        highest_high = np.max(high[-period:])
        lowest_low = np.min(low[-period:])
        k = float((close[-1] - lowest_low) / (highest_high - lowest_low + 1e-9) * 100)
        d = float(np.mean([
            (close[-i] - np.min(low[-period-i+1:-i+1] if -i+1 != 0 else low[-period:])) /
            (np.max(high[-period-i+1:-i+1] if -i+1 != 0 else high[-period:]) -
             np.min(low[-period-i+1:-i+1] if -i+1 != 0 else low[-period:]) + 1e-9) * 100
            for i in range(1, 4) if len(close) >= i
        ]))
        return k, d

    def _adx(self, high: np.ndarray, low: np.ndarray,
             close: np.ndarray, period: int = 14) -> Tuple[float, float, float]:
        if len(close) < period + 2:
            return 25.0, 25.0, 25.0
        tr = self._true_range(high[-period-2:], low[-period-2:], close[-period-2:])
        plus_dm = np.where(
            (high[-period-1:][1:] - high[-period-1:][:-1] > low[-period-1:][:-1] - low[-period-1:][1:]) &
            (high[-period-1:][1:] - high[-period-1:][:-1] > 0),
            high[-period-1:][1:] - high[-period-1:][:-1], 0.0
        )[:period]
        minus_dm = np.where(
            (low[-period-1:][:-1] - low[-period-1:][1:] > high[-period-1:][1:] - high[-period-1:][:-1]) &
            (low[-period-1:][:-1] - low[-period-1:][1:] > 0),
            low[-period-1:][:-1] - low[-period-1:][1:], 0.0
        )[:period]
        tr_sum = np.sum(tr[-period:]) + 1e-9
        plus_di = 100 * np.sum(plus_dm) / tr_sum
        minus_di = 100 * np.sum(minus_dm) / tr_sum
        dx = 100 * abs(plus_di - minus_di) / (plus_di + minus_di + 1e-9)
        return float(dx), float(plus_di), float(minus_di)

    def _williams_r(self, close: np.ndarray, high: np.ndarray,
                    low: np.ndarray, period: int = 14) -> float:
        if len(close) < period:
            return -50.0
        hh = np.max(high[-period:])
        ll = np.min(low[-period:])
        return float((hh - close[-1]) / (hh - ll + 1e-9) * -100)

    def _cci(self, close: np.ndarray, high: np.ndarray,
             low: np.ndarray, period: int = 20) -> float:
        if len(close) < period:
            return 0.0
        tp = (high[-period:] + low[-period:] + close[-period:]) / 3.0
        mean_tp = np.mean(tp)
        mad = np.mean(np.abs(tp - mean_tp))
        return float((tp[-1] - mean_tp) / (0.015 * mad + 1e-9))

    def _volume_profile(self, prices: np.ndarray, volumes: np.ndarray,
                        n_bins: int = 20) -> Dict[str, Any]:
        if len(prices) < 2 or len(volumes) < 2:
            return {}
        price_min, price_max = prices.min(), prices.max()
        if price_max == price_min:
            return {'poc': float(prices[-1]), 'value_area_high': float(price_max), 'value_area_low': float(price_min)}
        bins = np.linspace(price_min, price_max, n_bins + 1)
        vol_profile = np.zeros(n_bins)
        for p, v in zip(prices, volumes):
            idx = min(int((p - price_min) / (price_max - price_min) * n_bins), n_bins - 1)
            vol_profile[idx] += v
        poc_idx = np.argmax(vol_profile)
        poc = float((bins[poc_idx] + bins[poc_idx + 1]) / 2)
        total_vol = vol_profile.sum()
        value_area_vol = total_vol * 0.70
        sorted_idx = np.argsort(vol_profile)[::-1]
        accumulated = 0.0
        va_indices: List[int] = []
        for idx in sorted_idx:
            accumulated += vol_profile[idx]
            va_indices.append(idx)
            if accumulated >= value_area_vol:
                break
        va_indices_arr = np.array(va_indices)
        return {
            'poc': poc,
            'value_area_high': float(bins[min(va_indices_arr.max() + 1, n_bins)]),
            'value_area_low': float(bins[va_indices_arr.min()]),
            'volume_profile': vol_profile.tolist(),
            'price_levels': [(float(bins[i] + bins[i + 1]) / 2) for i in range(n_bins)],
        }

    def _detect_harmonic_patterns(self, prices: np.ndarray) -> List[Dict[str, Any]]:
        if not self.use_harmonic_patterns or len(prices) < 5:
            return []
        patterns: List[Dict] = []
        n = len(prices)
        for i in range(n - 4):
            x, a, b, c, d = prices[i:i + 5]
            xa = abs(a - x)
            ab = abs(b - a)
            bc = abs(c - b)
            cd = abs(d - c)
            if xa == 0:
                continue
            ab_ratio = ab / xa
            bc_ratio = bc / (ab + 1e-9)
            cd_ratio = cd / (bc + 1e-9)
            if 0.382 <= ab_ratio <= 0.886 and 0.382 <= bc_ratio <= 0.886:
                if 1.13 <= cd_ratio <= 1.618:
                    patterns.append({
                        'type': 'gartley', 'position': i,
                        'ab_ratio': round(ab_ratio, 3),
                        'bc_ratio': round(bc_ratio, 3),
                        'cd_ratio': round(cd_ratio, 3),
                    })
                elif 1.618 <= cd_ratio <= 2.618:
                    patterns.append({
                        'type': 'butterfly', 'position': i,
                        'ab_ratio': round(ab_ratio, 3),
                        'bc_ratio': round(bc_ratio, 3),
                        'cd_ratio': round(cd_ratio, 3),
                    })
        return patterns[-3:]

    def analyze(self, prices: Union[List[float], np.ndarray],
                volumes: Optional[Union[List[float], np.ndarray]] = None,
                highs: Optional[Union[List[float], np.ndarray]] = None,
                lows: Optional[Union[List[float], np.ndarray]] = None,
                opens: Optional[Union[List[float], np.ndarray]] = None) -> Dict[str, Any]:
        p = np.asarray(prices, dtype=float)
        n = len(p)
        result: Dict[str, Any] = {'last_price': float(p[-1]), 'n_bars': n}

        if highs is not None and lows is not None:
            h = np.asarray(highs, dtype=float)
            l = np.asarray(lows, dtype=float)
        else:
            h = p * 1.001
            l = p * 0.999

        if volumes is not None:
            v = np.asarray(volumes, dtype=float)
        else:
            v = np.ones_like(p)

        for w in (5, 10, 20, 50, 100, 200):
            if n >= w:
                result[f'sma_{w}'] = float(np.mean(p[-w:]))

        for w in (8, 12, 21, 26, 55, 89):
            if n >= w:
                result[f'ema_{w}'] = float(self._ema(p, w)[-1])

        result['rsi_14'] = self._rsi(p, period=self.periods['rsi'])

        if n >= 26:
            ema12 = self._ema(p, self.periods['ema_fast'])
            ema26 = self._ema(p, self.periods['ema_slow'])
            min_len = min(len(ema12), len(ema26))
            macd_line = ema12[-min_len:] - ema26[-min_len:]
            signal = self._ema(macd_line[-9:] if len(macd_line) >= 9 else macd_line, min(9, len(macd_line)))
            result['macd'] = float(macd_line[-1])
            result['macd_signal'] = float(signal[-1])
            result['macd_hist'] = float(macd_line[-1] - signal[-1])
            result['macd_bullish'] = bool(result['macd'] > result['macd_signal'])

        if n >= self.periods['bb']:
            w = self.periods['bb']
            sma = float(np.mean(p[-w:]))
            std = float(np.std(p[-w:]))
            result['bb_upper'] = round(sma + 2 * std, 4)
            result['bb_mid'] = round(sma, 4)
            result['bb_lower'] = round(sma - 2 * std, 4)
            result['bb_width'] = round(4 * std / (sma + 1e-9), 4)
            result['bb_pct_b'] = round((p[-1] - (sma - 2 * std)) / (4 * std + 1e-9), 4)

        if n >= self.periods['atr'] + 1:
            tr = self._true_range(h, l, p)
            result['atr_14'] = float(np.mean(tr[-self.periods['atr']:]))
            result['natr'] = round(result['atr_14'] / (p[-1] + 1e-9) * 100, 4)

        if n >= 14:
            k, d = self._stochastic(p, h, l, period=self.periods['stoch'])
            result['stoch_k'] = round(k, 2)
            result['stoch_d'] = round(d, 2)
            result['stoch_signal'] = 'overbought' if k > 80 else 'oversold' if k < 20 else 'neutral'
            result['williams_r'] = round(self._williams_r(p, h, l, period=self.periods['williams']), 2)

        if n >= self.periods['cci']:
            result['cci'] = round(self._cci(p, h, l, period=self.periods['cci']), 2)

        if n >= self.periods['adx'] + 2:
            adx, plus_di, minus_di = self._adx(h, l, p, period=self.periods['adx'])
            result['adx'] = round(adx, 2)
            result['plus_di'] = round(plus_di, 2)
            result['minus_di'] = round(minus_di, 2)
            result['trend_strength'] = 'strong' if adx > 25 else 'weak'

        if n > 1:
            direction = np.sign(np.diff(p[-len(v):]))
            obv_vals = np.cumsum(direction * v[1:len(p)])
            result['obv'] = float(obv_vals[-1]) if len(obv_vals) > 0 else 0.0
            if len(obv_vals) >= self.periods['obv_smooth']:
                result['obv_ema'] = float(self._ema(obv_vals, self.periods['obv_smooth'])[-1])

        if self.use_ichimoku and n >= 52:
            tenkan_high = np.max(h[-9:]) if n >= 9 else h[-1]
            tenkan_low = np.min(l[-9:]) if n >= 9 else l[-1]
            kijun_high = np.max(h[-26:]) if n >= 26 else h[-1]
            kijun_low = np.min(l[-26:]) if n >= 26 else l[-1]
            senkou_b_high = np.max(h[-52:])
            senkou_b_low = np.min(l[-52:])
            result['ichimoku_tenkan'] = round((tenkan_high + tenkan_low) / 2, 4)
            result['ichimoku_kijun'] = round((kijun_high + kijun_low) / 2, 4)
            result['ichimoku_senkou_a'] = round((result['ichimoku_tenkan'] + result['ichimoku_kijun']) / 2, 4)
            result['ichimoku_senkou_b'] = round((senkou_b_high + senkou_b_low) / 2, 4)
            result['ichimoku_chikou'] = float(p[-26]) if n >= 26 else float(p[0])
            in_cloud = min(result['ichimoku_senkou_a'], result['ichimoku_senkou_b']) <= p[-1] <= max(result['ichimoku_senkou_a'], result['ichimoku_senkou_b'])
            result['ichimoku_above_cloud'] = bool(p[-1] > max(result['ichimoku_senkou_a'], result['ichimoku_senkou_b']))
            result['ichimoku_in_cloud'] = bool(in_cloud)

        if self.use_fibonacci and n >= 20:
            recent_high = float(np.max(h[-20:]))
            recent_low = float(np.min(l[-20:]))
            diff = recent_high - recent_low
            for level in (0.0, 0.236, 0.382, 0.500, 0.618, 0.786, 1.0, 1.272, 1.618):
                result[f'fib_{level}'] = round(recent_low + diff * level, 4)
            for ext in (1.272, 1.414, 1.618, 2.0, 2.618):
                result[f'fib_ext_{ext}'] = round(recent_high + diff * (ext - 1), 4)

        if self.use_volume_profile and n >= 20:
            vp = self._volume_profile(p[-50:] if n >= 50 else p, v[-50:] if n >= 50 else v)
            result['volume_profile'] = vp

        if self.use_harmonic_patterns and n >= 5:
            patterns = self._detect_harmonic_patterns(p)
            result['harmonic_patterns'] = patterns

        if self.use_volatility_regime and n >= 30:
            short_vol = float(np.std(np.diff(np.log(p[-10:] + 1e-9))) * (252 ** 0.5))
            long_vol = float(np.std(np.diff(np.log(p[-30:] + 1e-9))) * (252 ** 0.5))
            result['volatility_regime'] = 'high' if short_vol > long_vol * 1.5 else 'low' if short_vol < long_vol * 0.67 else 'normal'
            result['realized_vol_10d'] = round(short_vol, 4)
            result['realized_vol_30d'] = round(long_vol, 4)

        if 'sma_20' in result and 'sma_50' in result:
            result['trend'] = 'bullish' if result['sma_20'] > result['sma_50'] else 'bearish'
        if 'rsi_14' in result:
            result['rsi_signal'] = 'overbought' if result['rsi_14'] > 70 else 'oversold' if result['rsi_14'] < 30 else 'neutral'

        signals_bullish = sum([
            result.get('trend') == 'bullish',
            result.get('rsi_signal') == 'oversold',
            result.get('macd_bullish', False),
            result.get('ichimoku_above_cloud', False),
            result.get('stoch_signal') == 'oversold',
            result.get('adx', 0) > 25 and result.get('plus_di', 0) > result.get('minus_di', 0),
        ])
        signals_bearish = sum([
            result.get('trend') == 'bearish',
            result.get('rsi_signal') == 'overbought',
            result.get('macd_bullish') is False,
            result.get('ichimoku_above_cloud') is False,
            result.get('stoch_signal') == 'overbought',
            result.get('adx', 0) > 25 and result.get('minus_di', 0) > result.get('plus_di', 0),
        ])
        result['composite_signal'] = 'bullish' if signals_bullish > signals_bearish + 1 else \
                                     'bearish' if signals_bearish > signals_bullish + 1 else 'neutral'
        result['signal_strength'] = abs(signals_bullish - signals_bearish)
        return result

class FundamentalAnalyzer:
    def __init__(self, use_dcf: bool = True, use_ddm: bool = True,
                 use_comparable_analysis: bool = True,
                 use_altman_z: bool = True,
                 use_piotroski: bool = True,
                 use_beneish: bool = True,
                 use_moat_scoring: bool = True,
                 use_esg_scoring: bool = False,
                 use_sector_adjustment: bool = True,
                 risk_free_rate: float = 0.04,
                 equity_risk_premium: float = 0.055,
                 default_growth_rate: float = 0.05,
                 default_wacc: float = 0.10,
                 sector_multiples: Optional[Dict[str, Dict[str, float]]] = None):
        self.use_dcf = use_dcf
        self.use_ddm = use_ddm
        self.use_comparable_analysis = use_comparable_analysis
        self.use_altman_z = use_altman_z
        self.use_piotroski = use_piotroski
        self.use_beneish = use_beneish
        self.use_moat_scoring = use_moat_scoring
        self.use_esg_scoring = use_esg_scoring
        self.use_sector_adjustment = use_sector_adjustment
        self.risk_free_rate = risk_free_rate
        self.equity_risk_premium = equity_risk_premium
        self.default_growth_rate = default_growth_rate
        self.default_wacc = default_wacc
        self.sector_multiples = sector_multiples or {
            'technology': {'pe': 30.0, 'ps': 8.0, 'ev_ebitda': 20.0},
            'finance': {'pe': 12.0, 'ps': 2.0, 'ev_ebitda': 8.0},
            'healthcare': {'pe': 22.0, 'ps': 4.0, 'ev_ebitda': 14.0},
            'consumer': {'pe': 18.0, 'ps': 1.5, 'ev_ebitda': 10.0},
            'energy': {'pe': 14.0, 'ps': 1.0, 'ev_ebitda': 7.0},
            'utilities': {'pe': 16.0, 'ps': 2.0, 'ev_ebitda': 9.0},
        }

    def _dcf_valuation(self, f: Dict[str, float]) -> Dict[str, float]:
        if not self.use_dcf:
            return {}
        fcf = f.get('free_cash_flow', f.get('net_income', 0.0))
        wacc = f.get('wacc', self.default_wacc)
        growth = f.get('growth_rate', self.default_growth_rate)
        terminal_growth = f.get('terminal_growth', min(0.025, growth * 0.5))
        shares = max(f.get('shares_outstanding', 1.0), 1.0)
        price = f.get('price', 0.0)

        if fcf <= 0 or wacc <= terminal_growth:
            return {'dcf_value': 0.0, 'dcf_margin': 0.0}

        pv = sum(
            fcf * (1 + growth) ** yr / (1 + wacc) ** yr
            for yr in range(1, 11)
        )
        terminal = fcf * (1 + growth) ** 10 * (1 + terminal_growth) / (wacc - terminal_growth)
        terminal_pv = terminal / (1 + wacc) ** 10
        intrinsic_value = (pv + terminal_pv) / shares
        margin = (intrinsic_value - price) / (intrinsic_value + 1e-9) * 100 if intrinsic_value > 0 else 0.0
        return {
            'dcf_value': round(intrinsic_value, 2),
            'dcf_terminal_pv': round(terminal_pv / shares, 2),
            'dcf_margin': round(margin, 1),
            'dcf_terminal_weight': round(terminal_pv / (pv + terminal_pv + 1e-9), 3),
        }

    def _ddm_valuation(self, f: Dict[str, float]) -> Dict[str, float]:
        if not self.use_ddm:
            return {}
        dividend = f.get('annual_dividend', 0.0)
        if dividend <= 0:
            return {}
        growth = f.get('dividend_growth', self.default_growth_rate * 0.5)
        required_return = self.risk_free_rate + f.get('beta', 1.0) * self.equity_risk_premium
        if required_return <= growth:
            return {}
        ddm_value = dividend * (1 + growth) / (required_return - growth)
        price = f.get('price', ddm_value)
        return {
            'ddm_value': round(ddm_value, 2),
            'ddm_margin': round((ddm_value - price) / (ddm_value + 1e-9) * 100, 1),
            'dividend_yield': round(dividend / (price + 1e-9) * 100, 2),
        }

    def _piotroski_f_score(self, f: Dict[str, float]) -> int:
        if not self.use_piotroski:
            return 5
        score = 0
        score += int(f.get('roa', 0) > 0)
        score += int(f.get('operating_cash_flow', 0) > 0)
        score += int(f.get('roa', 0) > f.get('roa_prev', 0) * 0.9)
        score += int(f.get('operating_cash_flow', 0) > f.get('net_income', 0))
        score += int(f.get('long_term_debt_ratio', 0) <= f.get('long_term_debt_ratio_prev', float('inf')))
        score += int(f.get('current_ratio', 1) > f.get('current_ratio_prev', 0))
        score += int(f.get('shares_issued', 0) <= 0)
        score += int(f.get('gross_margin', 0) >= f.get('gross_margin_prev', 0))
        score += int(f.get('asset_turnover', 0) >= f.get('asset_turnover_prev', 0))
        return score

    def _beneish_m_score(self, f: Dict[str, float]) -> float:
        if not self.use_beneish:
            return -2.22
        receivables = f.get('receivables', 0)
        revenue = max(f.get('revenue', 1), 1)
        rev_prev = max(f.get('revenue_prev', revenue), 1)
        assets = max(f.get('total_assets', 1), 1)
        assets_prev = max(f.get('total_assets_prev', assets), 1)
        dsri = (receivables / revenue) / (f.get('receivables_prev', receivables) / rev_prev + 1e-9)
        gmi = (rev_prev - f.get('cogs_prev', 0)) / rev_prev / ((revenue - f.get('cogs', 0)) / revenue + 1e-9)
        aqi = (1 - (f.get('current_assets', 0) + f.get('ppe', 0)) / assets) / \
              (1 - (f.get('current_assets_prev', 0) + f.get('ppe_prev', 0)) / assets_prev + 1e-9)
        sgi = revenue / rev_prev
        depi = (f.get('depreciation_prev', 0) / (f.get('depreciation_prev', 0) + f.get('ppe_prev', 1) + 1e-9)) / \
               (f.get('depreciation', 0) / (f.get('depreciation', 0) + f.get('ppe', 1) + 1e-9) + 1e-9)
        sgai = (f.get('sga', 0) / revenue) / (f.get('sga_prev', f.get('sga', 0)) / rev_prev + 1e-9)
        lvgi = (f.get('total_debt', 0) / assets) / (f.get('total_debt_prev', f.get('total_debt', 0)) / assets_prev + 1e-9)
        tata = (f.get('net_income', 0) - f.get('operating_cash_flow', 0)) / (assets + 1e-9)
        m_score = (-4.84 + 0.920 * dsri + 0.528 * gmi + 0.404 * aqi +
                   0.892 * sgi + 0.115 * depi - 0.172 * sgai +
                   4.679 * tata - 0.327 * lvgi)
        return round(float(m_score), 3)

    def _moat_score(self, f: Dict[str, float]) -> Dict[str, Any]:
        if not self.use_moat_scoring:
            return {}
        score = 0
        factors: Dict[str, bool] = {}
        factors['pricing_power'] = f.get('gross_margin', 0) > 0.40
        factors['scale_advantage'] = f.get('revenue', 0) > 1e9
        factors['switching_costs'] = f.get('churn_rate', 1.0) < 0.05
        factors['network_effects'] = f.get('user_growth', 0) > 0.20
        factors['cost_advantage'] = f.get('cost_to_income', 1.0) < 0.50
        factors['intangible_assets'] = f.get('intangibles_to_assets', 0) > 0.15
        score = sum(int(v) for v in factors.values())
        moat = 'wide' if score >= 5 else 'narrow' if score >= 3 else 'none'
        return {'moat_score': score, 'moat_type': moat, 'moat_factors': factors}

    def analyze(self, financials: Dict[str, float],
                sector: Optional[str] = None,
                include_estimates: bool = True) -> Dict[str, Any]:
        f = financials
        result: Dict[str, Any] = {}

        eps = f.get('eps', 0.0)
        price = f.get('price', 1.0)
        bvps = f.get('book_value_per_share', 1.0)
        revenue = max(f.get('revenue', 1.0), 1e-9)
        ebitda = max(f.get('ebitda', 1.0), 1e-9)
        net_income = f.get('net_income', 0.0)
        total_debt = f.get('total_debt', 0.0)
        total_equity = max(f.get('total_equity', 1.0), 1e-9)
        total_assets = max(f.get('total_assets', 1.0), 1e-9)
        current_assets = f.get('current_assets', 0.0)
        current_liabilities = max(f.get('current_liabilities', 1.0), 1e-9)
        ev = f.get('enterprise_value', price * f.get('shares_outstanding', 1.0))
        shares = max(f.get('shares_outstanding', 1.0), 1e-9)

        result['pe_ratio'] = round(price / eps, 2) if eps > 0 else float('inf')
        result['pb_ratio'] = round(price / bvps, 2) if bvps > 0 else float('inf')
        result['ps_ratio'] = round((price * shares) / revenue, 2)
        result['ev_ebitda'] = round(ev / ebitda, 2)
        result['ev_revenue'] = round(ev / revenue, 2)
        result['peg_ratio'] = round(result['pe_ratio'] / (f.get('eps_growth', 0.10) * 100), 2) \
            if f.get('eps_growth', 0) > 0 and result['pe_ratio'] != float('inf') else float('inf')
        result['price_to_fcf'] = round(price / (f.get('fcf_per_share', 0.01)), 2) \
            if f.get('fcf_per_share', 0) > 0 else float('inf')

        if eps > 0 and bvps > 0:
            result['graham_number'] = round((22.5 * eps * bvps) ** 0.5, 2)
            result['graham_margin'] = round((result['graham_number'] - price) / result['graham_number'] * 100, 1)

        result.update(self._dcf_valuation(f))
        result.update(self._ddm_valuation(f))

        result['debt_to_equity'] = round(total_debt / total_equity, 2)
        result['debt_to_assets'] = round(total_debt / total_assets, 2)
        result['current_ratio'] = round(current_assets / current_liabilities, 2)
        result['quick_ratio'] = round((current_assets - f.get('inventory', 0)) / current_liabilities, 2)
        result['interest_coverage'] = round(f.get('ebit', net_income) / (f.get('interest_expense', 0.01) + 1e-9), 2)
        result['roe'] = round(net_income / total_equity * 100, 2)
        result['roa'] = round(net_income / total_assets * 100, 2)
        result['roic'] = round(f.get('nopat', net_income) / (total_equity + total_debt + 1e-9) * 100, 2)
        result['gross_margin'] = round(f.get('gross_profit', 0) / revenue * 100, 2)
        result['operating_margin'] = round(f.get('operating_income', net_income) / revenue * 100, 2)
        result['net_margin'] = round(net_income / revenue * 100, 2)
        result['asset_turnover'] = round(revenue / total_assets, 2)
        result['inventory_turnover'] = round(f.get('cogs', revenue * 0.6) / (f.get('inventory', revenue * 0.1) + 1e-9), 2)
        result['days_receivable'] = round(f.get('receivables', revenue * 0.1) / revenue * 365, 1)

        if self.use_altman_z:
            working_capital = current_assets - current_liabilities
            retained_earnings = f.get('retained_earnings', 0)
            ebit = f.get('ebit', net_income)
            mkt_cap = price * shares
            z = (1.2 * working_capital / total_assets +
                 1.4 * retained_earnings / total_assets +
                 3.3 * ebit / total_assets +
                 0.6 * (mkt_cap / (total_debt + 1e-9)) +
                 1.0 * revenue / total_assets)
            result['altman_z'] = round(z, 3)
            result['z_risk'] = 'safe' if z > 2.99 else 'grey' if z > 1.81 else 'distress'

        result['piotroski_f'] = self._piotroski_f_score(f)
        result['beneish_m'] = self._beneish_m_score(f)
        result['earnings_manipulation_risk'] = 'high' if result['beneish_m'] > -1.78 else 'low'

        result.update(self._moat_score(f))

        if self.use_sector_adjustment and sector and sector in self.sector_multiples:
            sm = self.sector_multiples[sector]
            result['sector_pe_premium'] = round(result['pe_ratio'] / (sm['pe'] + 1e-9), 2)
            result['sector_ps_premium'] = round(result['ps_ratio'] / (sm['ps'] + 1e-9), 2)
            result['sector_ev_ebitda_premium'] = round(result['ev_ebitda'] / (sm['ev_ebitda'] + 1e-9), 2)
            result['sector'] = sector

        valuation_scores = [
            result.get('graham_margin', 0) > 20,
            result.get('dcf_margin', 0) > 20,
            result['pe_ratio'] < 20,
            result['pb_ratio'] < 2,
            result['peg_ratio'] < 1.5,
        ]
        quality_scores = [
            result['roe'] > 15,
            result['roic'] > 10,
            result['debt_to_equity'] < 0.5,
            result['current_ratio'] > 1.5,
            result['net_margin'] > 10,
            result['piotroski_f'] >= 7,
        ]
        total_score = sum(int(s) for s in valuation_scores + quality_scores)
        result['composite_score'] = f'{total_score}/11'
        result['verdict'] = 'strong_buy' if total_score >= 9 else \
                            'buy' if total_score >= 7 else \
                            'hold' if total_score >= 5 else \
                            'sell' if total_score >= 3 else 'strong_sell'
        return result

class ExchangeConnector:
    def __init__(self, api_key: str = '', secret: str = '',
                 base_url: str = 'https://api.exchange.example.com',
                 rate_limit_rps: float = 10.0,
                 use_websocket: bool = True,
                 use_order_book: bool = True,
                 use_market_data_cache: bool = True,
                 use_auto_reconnect: bool = True,
                 use_paper_trading: bool = False,
                 use_order_validation: bool = True,
                 timeout_sec: float = 10.0,
                 cache_ttl_sec: float = 1.0,
                 max_retries: int = 3):
        self.api_key = api_key
        self.secret = secret
        self.base_url = base_url.rstrip('/')
        self._min_interval = 1.0 / max(rate_limit_rps, 0.01)
        self._last_call = 0.0
        self.use_websocket = use_websocket
        self.use_order_book = use_order_book
        self.use_market_data_cache = use_market_data_cache
        self.use_auto_reconnect = use_auto_reconnect
        self.use_paper_trading = use_paper_trading
        self.use_order_validation = use_order_validation
        self.timeout_sec = timeout_sec
        self.cache_ttl_sec = cache_ttl_sec
        self.max_retries = max_retries

        self._order_book: Dict[str, Dict] = {}
        self._positions: Dict[str, float] = {}
        self._orders: Dict[str, Dict] = {}
        self._fills: List[Dict] = []
        self._balance: Dict[str, float] = {'USD': 100_000.0}
        self._price_cache: Dict[str, Tuple[float, float]] = {}
        self._tick_data: Dict[str, deque] = defaultdict(lambda: deque(maxlen=1000))
        self._reconnect_attempts = 0
        self._ws_connected = False
        self._lock = threading.RLock()
        self._rate_limit_calls: deque = deque(maxlen=int(rate_limit_rps * 60))
        self._error_count: Dict[str, int] = defaultdict(int)
        self._subscriptions: set = set()
        self._market_stats: Dict[str, Dict] = {}

    def _sign_request(self, payload: str, timestamp: Optional[float] = None) -> str:
        ts = str(int((timestamp or time.time()) * 1000))
        message = ts + payload
        signature = hmac.new(
            self.secret.encode('utf-8'),
            message.encode('utf-8'),
            hashlib.sha256
        ).hexdigest()
        return signature

    def _throttle(self) -> None:
        with self._lock:
            now = time.time()
            elapsed = now - self._last_call
            if elapsed < self._min_interval:
                time.sleep(self._min_interval - elapsed)
            self._last_call = time.time()
            self._rate_limit_calls.append(time.time())

    def _validate_order(self, symbol: str, side: str, qty: float,
                        order_type: str, price: Optional[float]) -> Tuple[bool, str]:
        if not self.use_order_validation:
            return True, ''
        if side not in ('buy', 'sell'):
            return False, f'Invalid side: {side}'
        if qty <= 0:
            return False, f'Quantity must be positive, got {qty}'
        if order_type == 'limit' and (price is None or price <= 0):
            return False, 'Limit order requires positive price'
        if order_type == 'market' and self.use_paper_trading:
            current_price = self.get_price(symbol)
            if side == 'buy':
                required_cash = qty * current_price
                available = self._balance.get('USD', 0)
                if required_cash > available:
                    return False, f'Insufficient funds: need {required_cash:.2f}, have {available:.2f}'
        return True, ''

    def get_price(self, symbol: str,
                  fallback_price: float = 100.0) -> float:
        self._throttle()
        if self.use_market_data_cache:
            cached = self._price_cache.get(symbol)
            if cached is not None and (time.time() - cached[1]) < self.cache_ttl_sec:
                return cached[0]

        if symbol in self._order_book:
            book = self._order_book[symbol]
            bids = book.get('bids', [[fallback_price, 0]])
            asks = book.get('asks', [[fallback_price, 0]])
            best_bid = float(bids[0][0]) if bids else fallback_price
            best_ask = float(asks[0][0]) if asks else fallback_price
            mid = (best_bid + best_ask) / 2.0
        else:
            mid = fallback_price

        if self.use_market_data_cache:
            self._price_cache[symbol] = (mid, time.time())
        return mid

    def place_order(self, symbol: str, side: str, qty: float,
                    order_type: str = 'market',
                    price: Optional[float] = None,
                    stop_price: Optional[float] = None,
                    time_in_force: str = 'GTC',
                    client_order_id: Optional[str] = None,
                    reduce_only: bool = False) -> Dict[str, Any]:
        self._throttle()
        valid, err = self._validate_order(symbol, side, qty, order_type, price)
        if not valid:
            return {'status': 'rejected', 'reason': err}

        order_id = client_order_id or secrets.token_hex(8)
        ts = time.time()
        fill_price = price if (order_type == 'limit' and price) else self.get_price(symbol)

        if self.use_paper_trading:
            with self._lock:
                pos_delta = qty if side == 'buy' else -qty
                self._positions[symbol] = self._positions.get(symbol, 0.0) + pos_delta
                cost = fill_price * qty
                if side == 'buy':
                    self._balance['USD'] = max(0.0, self._balance.get('USD', 0) - cost)
                else:
                    self._balance['USD'] = self._balance.get('USD', 0) + cost
                status = 'filled'
        else:
            status = 'submitted'

        payload = json.dumps({
            'symbol': symbol, 'side': side, 'qty': qty,
            'type': order_type, 'ts': int(ts * 1000)
        }, sort_keys=True)
        sig = self._sign_request(payload, ts)

        order: Dict[str, Any] = {
            'order_id': order_id, 'symbol': symbol, 'side': side,
            'quantity': qty, 'type': order_type, 'time_in_force': time_in_force,
            'fill_price': round(fill_price, 6),
            'notional': round(fill_price * qty, 4),
            'status': status, 'timestamp': ts,
            'signature': sig,
            'reduce_only': reduce_only,
        }
        if stop_price is not None:
            order['stop_price'] = stop_price
        if price is not None:
            order['limit_price'] = price

        with self._lock:
            self._orders[order_id] = order
            if status == 'filled':
                self._fills.append(order.copy())

        return order

    def cancel_order(self, order_id: str) -> Dict[str, Any]:
        self._throttle()
        with self._lock:
            order = self._orders.get(order_id)
            if order is None:
                return {'status': 'not_found', 'order_id': order_id}
            if order['status'] in ('filled', 'cancelled'):
                return {'status': 'cannot_cancel', 'current_status': order['status']}
            order['status'] = 'cancelled'
            order['cancelled_at'] = time.time()
        return {'status': 'ok', 'order_id': order_id}

    def get_balance(self) -> Dict[str, Any]:
        with self._lock:
            return {
                'cash': self._balance.copy(),
                'positions': self._positions.copy(),
                'total_pnl': self._compute_pnl(),
                'n_fills': len(self._fills),
            }

    def _compute_pnl(self) -> float:
        pnl = 0.0
        for fill in self._fills:
            sign = 1.0 if fill['side'] == 'sell' else -1.0
            pnl += sign * fill['notional']
        return round(pnl, 4)

    def update_order_book(self, symbol: str,
                          bids: List[List[float]],
                          asks: List[List[float]],
                          timestamp: Optional[float] = None) -> None:
        with self._lock:
            sorted_bids = sorted(bids, key=lambda x: -x[0])
            sorted_asks = sorted(asks, key=lambda x: x[0])
            self._order_book[symbol] = {
                'bids': sorted_bids, 'asks': sorted_asks,
                'ts': timestamp or time.time(),
                'spread': (sorted_asks[0][0] - sorted_bids[0][0]) if sorted_bids and sorted_asks else 0.0,
                'mid': (sorted_asks[0][0] + sorted_bids[0][0]) / 2 if sorted_bids and sorted_asks else 0.0,
            }
            self._price_cache.pop(symbol, None)

    def get_market_stats(self, symbol: str) -> Dict[str, Any]:
        ticks = list(self._tick_data.get(symbol, []))
        if not ticks:
            return {'symbol': symbol, 'status': 'no_data'}
        prices = [t['price'] for t in ticks if 'price' in t]
        if not prices:
            return {'symbol': symbol, 'status': 'no_price_data'}
        return {
            'symbol': symbol,
            'last': prices[-1],
            'high_24h': max(prices),
            'low_24h': min(prices),
            'change_24h': round((prices[-1] / prices[0] - 1) * 100, 2) if prices[0] != 0 else 0.0,
            'n_ticks': len(ticks),
        }

    def subscribe(self, symbol: str) -> None:
        self._subscriptions.add(symbol)

    def unsubscribe(self, symbol: str) -> None:
        self._subscriptions.discard(symbol)

    def add_tick(self, symbol: str, price: float,
                 volume: float = 0.0, side: str = 'unknown') -> None:
        with self._lock:
            self._tick_data[symbol].append({
                'price': price, 'volume': volume, 'side': side, 'ts': time.time()
            })
            self._price_cache[symbol] = (price, time.time())

class RiskManager:
    def __init__(self, confidence: float = 0.95, risk_free: float = 0.03,
                 use_var: bool = True, use_cvar: bool = True,
                 use_stress_testing: bool = True,
                 use_monte_carlo: bool = True,
                 use_factor_risk: bool = True,
                 use_liquidity_risk: bool = True,
                 use_correlation_risk: bool = True,
                 use_tail_risk_hedging: bool = True,
                 use_drawdown_control: bool = True,
                 max_drawdown_limit: float = 0.20,
                 max_var_limit: float = 0.02,
                 max_position_concentration: float = 0.25,
                 n_monte_carlo: int = 10000,
                 stress_scenarios: Optional[Dict[str, float]] = None):
        self.confidence = confidence
        self.risk_free = risk_free
        self.use_var = use_var
        self.use_cvar = use_cvar
        self.use_stress_testing = use_stress_testing
        self.use_monte_carlo = use_monte_carlo
        self.use_factor_risk = use_factor_risk
        self.use_liquidity_risk = use_liquidity_risk
        self.use_correlation_risk = use_correlation_risk
        self.use_tail_risk_hedging = use_tail_risk_hedging
        self.use_drawdown_control = use_drawdown_control
        self.max_drawdown_limit = max_drawdown_limit
        self.max_var_limit = max_var_limit
        self.max_position_concentration = max_position_concentration
        self.n_monte_carlo = n_monte_carlo
        self.stress_scenarios = stress_scenarios or {
            '2008_crisis': -0.50,
            '2020_covid': -0.34,
            'dot_com': -0.78,
            'flash_crash': -0.10,
            'rate_shock_200bps': -0.15,
            'geopolitical_event': -0.08,
        }
        self._position_limits: Dict[str, float] = {}
        self._risk_budgets: Dict[str, float] = {}
        self._portfolio_history: deque = deque(maxlen=1000)
        self._breach_log: List[Dict] = []
        self._lock = threading.Lock()

    def set_limit(self, symbol: str, max_position: float,
                  risk_budget: Optional[float] = None) -> None:
        with self._lock:
            self._position_limits[symbol] = max_position
            if risk_budget is not None:
                self._risk_budgets[symbol] = risk_budget

    def check_limit(self, symbol: str, qty: float,
                    notional: Optional[float] = None) -> Tuple[bool, str]:
        limit = self._position_limits.get(symbol, float('inf'))
        if abs(qty) > limit:
            return False, f'{symbol} position {qty:.2f} exceeds limit {limit:.2f}'
        if notional is not None:
            total_notional = sum(abs(v) for v in self._position_limits.values()) + 1e-9
            concentration = abs(notional) / total_notional
            if concentration > self.max_position_concentration:
                return False, f'{symbol} concentration {concentration:.1%} exceeds {self.max_position_concentration:.1%}'
        return True, ''

    def calculate_var(self, returns: Union[List[float], np.ndarray],
                      portfolio_value: float = 1.0,
                      method: str = 'all') -> Dict[str, float]:
        r = np.asarray(returns, dtype=float)
        r = r[np.isfinite(r)]
        if len(r) < 5:
            return {'var_hist': 0.0, 'var_param': 0.0, 'cvar': 0.0}

        result: Dict[str, float] = {}
        alpha = 1.0 - self.confidence

        if self.use_var:
            var_hist = abs(float(np.percentile(r, alpha * 100))) * portfolio_value
            result['var_hist'] = round(var_hist, 6)

            mu, sigma = float(r.mean()), float(r.std())
            z = float(np.percentile(np.random.standard_normal(10000), alpha * 100))
            var_param = abs(mu + z * sigma) * portfolio_value
            result['var_param'] = round(var_param, 6)

            if self.use_monte_carlo:
                sims = np.random.normal(mu, sigma, self.n_monte_carlo)
                var_mc = abs(float(np.percentile(sims, alpha * 100))) * portfolio_value
                result['var_mc'] = round(var_mc, 6)
                result['var_ensemble'] = round((var_hist + var_param + var_mc) / 3, 6)

        if self.use_cvar:
            cutoff = np.percentile(r, alpha * 100)
            tail = r[r <= cutoff]
            cvar = abs(float(tail.mean())) * portfolio_value if len(tail) > 0 else result.get('var_hist', 0)
            result['cvar'] = round(cvar, 6)
            result['expected_shortfall'] = result['cvar']

        excess = r - self.risk_free / 252
        vol = float(r.std()) * (252 ** 0.5)
        result['sharpe'] = round(float(excess.mean()) * 252 / (vol + 1e-9), 3)
        downside = r[r < 0]
        downside_vol = float(downside.std()) * (252 ** 0.5) if len(downside) > 1 else vol
        result['sortino'] = round(float(excess.mean()) * 252 / (downside_vol + 1e-9), 3)

        cum = (1 + r).cumprod()
        peak = np.maximum.accumulate(cum)
        dd = (cum - peak) / (peak + 1e-9)
        result['max_drawdown'] = round(float(dd.min()), 4)
        result['current_drawdown'] = round(float(dd[-1]), 4)

        win_rate = float((r > 0).mean())
        avg_win = float(r[r > 0].mean()) if (r > 0).any() else 1e-4
        avg_loss = float(abs(r[r < 0].mean())) if (r < 0).any() else 1e-4
        kelly = win_rate / avg_loss - (1 - win_rate) / avg_win
        result['kelly_fraction'] = round(float(np.clip(kelly, 0, 0.5)), 4)
        result['win_rate'] = round(win_rate, 4)
        result['profit_factor'] = round(avg_win * win_rate / (avg_loss * (1 - win_rate) + 1e-9), 3)
        result['calmar'] = round(float(excess.mean()) * 252 / (abs(result['max_drawdown']) + 1e-9), 3)
        result['volatility_annual'] = round(vol, 4)

        if self.use_stress_testing:
            for scenario, shock in self.stress_scenarios.items():
                result[f'stress_{scenario}'] = round(portfolio_value * shock, 4)

        alerts: List[str] = []
        if result.get('var_hist', 0) > self.max_var_limit * portfolio_value:
            alerts.append(f'VaR breach: {result.get("var_hist", 0):.4f} > limit {self.max_var_limit * portfolio_value:.4f}')
        if abs(result['max_drawdown']) > self.max_drawdown_limit:
            alerts.append(f'Drawdown breach: {abs(result["max_drawdown"]):.1%} > limit {self.max_drawdown_limit:.1%}')
        result['risk_alerts'] = alerts
        result['risk_score'] = min(10.0, round(
            abs(result['max_drawdown']) / 0.05 +
            result.get('var_hist', 0) / portfolio_value / 0.01 * 2, 1
        ))
        return result

    def compute_portfolio_risk(self, weights: np.ndarray,
                               cov_matrix: np.ndarray,
                               expected_returns: Optional[np.ndarray] = None) -> Dict[str, float]:
        weights = np.asarray(weights, dtype=float)
        cov = np.asarray(cov_matrix, dtype=float)
        port_var = float(weights @ cov @ weights)
        port_vol = float(port_var ** 0.5)
        marginal_risk = cov @ weights / (port_vol + 1e-9)
        component_risk = weights * marginal_risk
        result: Dict[str, float] = {
            'portfolio_volatility': round(port_vol, 4),
            'portfolio_variance': round(port_var, 6),
            'diversification_ratio': round(
                float((weights * np.sqrt(np.diag(cov))).sum()) / (port_vol + 1e-9), 3
            ),
        }
        if self.use_factor_risk and expected_returns is not None:
            port_ret = float(weights @ expected_returns)
            result['portfolio_return'] = round(port_ret, 4)
            result['portfolio_sharpe'] = round(
                (port_ret - self.risk_free) / (port_vol + 1e-9), 3
            )
        return result

class TradeExecutor:
    def __init__(self, slippage_bps: float = 2.0, commission_bps: float = 5.0,
                 max_order_size: float = 1_000_000.0,
                 use_twap: bool = True, use_vwap: bool = True,
                 use_iceberg: bool = True,
                 use_smart_routing: bool = True,
                 use_pre_trade_analytics: bool = True,
                 use_post_trade_analytics: bool = True,
                 use_market_impact_model: bool = True,
                 use_oco_orders: bool = True,
                 min_order_size: float = 0.0001,
                 max_slippage_bps: float = 50.0,
                 execution_venues: Optional[List[str]] = None):
        self.slippage_bps = slippage_bps
        self.commission_bps = commission_bps
        self.max_order_size = max_order_size
        self.min_order_size = min_order_size
        self.max_slippage_bps = max_slippage_bps
        self.use_twap = use_twap
        self.use_vwap = use_vwap
        self.use_iceberg = use_iceberg
        self.use_smart_routing = use_smart_routing
        self.use_pre_trade_analytics = use_pre_trade_analytics
        self.use_post_trade_analytics = use_post_trade_analytics
        self.use_market_impact_model = use_market_impact_model
        self.use_oco_orders = use_oco_orders
        self.execution_venues = execution_venues or ['primary', 'alt1', 'dark_pool']

        self._orders: List[Dict] = []
        self._fills: List[Dict] = []
        self._pending_oco: Dict[str, Dict] = {}
        self._venue_stats: Dict[str, Dict] = defaultdict(lambda: {'fills': 0, 'avg_slippage': 0.0})
        self._execution_metrics: Dict[str, float] = {
            'total_notional': 0.0, 'total_commission': 0.0,
            'avg_slippage_bps': 0.0, 'fill_rate': 1.0,
        }
        self._lock = threading.Lock()

    def _apply_slippage(self, price: float, side: str,
                        qty: float, avg_daily_volume: float = 1e6) -> float:
        base_slip = price * self.slippage_bps / 10_000
        if self.use_market_impact_model and avg_daily_volume > 0:
            participation_rate = qty / avg_daily_volume
            impact = price * 0.5 * (participation_rate ** 0.6) * 0.1
            slip = base_slip + impact
        else:
            slip = base_slip
        noise = random.gauss(0, slip * 0.2)
        actual_slip = max(0, slip + noise)
        actual_slip = min(actual_slip, price * self.max_slippage_bps / 10_000)
        return price + actual_slip if side == 'buy' else price - actual_slip

    def _route_order(self, symbol: str, side: str,
                     qty: float, order_type: str) -> str:
        if not self.use_smart_routing:
            return self.execution_venues[0]
        venue_scores = {}
        for venue in self.execution_venues:
            stats = self._venue_stats[venue]
            fill_quality = 1.0 / (stats['avg_slippage'] + 0.01)
            venue_scores[venue] = fill_quality
        return max(venue_scores, key=venue_scores.get)

    def _pre_trade_analysis(self, symbol: str, side: str,
                             qty: float, price: float) -> Dict[str, float]:
        if not self.use_pre_trade_analytics:
            return {}
        expected_cost = qty * price * self.commission_bps / 10_000
        expected_slippage = qty * price * self.slippage_bps / 10_000
        market_impact_est = qty * price * 0.001
        return {
            'expected_commission': round(expected_cost, 4),
            'expected_slippage': round(expected_slippage, 4),
            'expected_market_impact': round(market_impact_est, 4),
            'implementation_shortfall': round(expected_cost + expected_slippage + market_impact_est, 4),
        }

    def execute_trade(self, symbol: str, quantity: float,
                      side: str, market_price: float,
                      order_type: str = 'market',
                      limit_price: Optional[float] = None,
                      stop_price: Optional[float] = None,
                      avg_daily_volume: float = 1_000_000.0,
                      notes: str = '') -> Dict[str, Any]:
        with self._lock:
            if abs(quantity) < self.min_order_size:
                return {'status': 'rejected', 'reason': 'below_min_size'}
            if abs(quantity) > self.max_order_size:
                return {'status': 'rejected', 'reason': 'exceeds_max_size'}
            if side not in ('buy', 'sell'):
                return {'status': 'rejected', 'reason': 'invalid_side'}

            if order_type == 'limit' and limit_price is not None:
                if side == 'buy' and market_price > limit_price:
                    return {'status': 'pending', 'reason': 'limit_not_triggered',
                            'order_type': 'limit', 'limit_price': limit_price}
                if side == 'sell' and market_price < limit_price:
                    return {'status': 'pending', 'reason': 'limit_not_triggered',
                            'order_type': 'limit', 'limit_price': limit_price}
            if order_type == 'stop' and stop_price is not None:
                if side == 'buy' and market_price < stop_price:
                    return {'status': 'pending', 'reason': 'stop_not_triggered'}
                if side == 'sell' and market_price > stop_price:
                    return {'status': 'pending', 'reason': 'stop_not_triggered'}

            venue = self._route_order(symbol, side, quantity, order_type)
            fill_price = self._apply_slippage(market_price, side, quantity, avg_daily_volume)
            notional = abs(quantity) * fill_price
            commission = notional * self.commission_bps / 10_000
            slippage_bps_actual = abs(fill_price - market_price) / market_price * 10_000

            pre_trade = self._pre_trade_analysis(symbol, side, quantity, market_price)

            order_id = secrets.token_hex(10)
            fill: Dict[str, Any] = {
                'order_id': order_id,
                'symbol': symbol,
                'side': side,
                'quantity': quantity,
                'market_price': round(market_price, 6),
                'fill_price': round(fill_price, 6),
                'notional': round(notional, 4),
                'commission': round(commission, 4),
                'slippage_bps': round(slippage_bps_actual, 2),
                'net_cost': round(notional + commission if side == 'buy' else notional - commission, 4),
                'venue': venue,
                'status': 'filled',
                'timestamp': time.time(),
                'notes': notes,
                **pre_trade,
            }
            self._fills.append(fill)
            self._orders.append(fill.copy())

            vs = self._venue_stats[venue]
            n = vs['fills']
            vs['avg_slippage'] = (vs['avg_slippage'] * n + slippage_bps_actual) / (n + 1)
            vs['fills'] += 1

            self._execution_metrics['total_notional'] += notional
            self._execution_metrics['total_commission'] += commission
            n_fills = len(self._fills)
            self._execution_metrics['avg_slippage_bps'] = (
                self._execution_metrics['avg_slippage_bps'] * (n_fills - 1) + slippage_bps_actual
            ) / n_fills

            return fill

    def place_oco(self, symbol: str, qty: float,
                  side: str, market_price: float,
                  take_profit_price: float,
                  stop_loss_price: float) -> Dict[str, Any]:
        if not self.use_oco_orders:
            return {'status': 'not_supported'}
        oco_id = secrets.token_hex(8)
        with self._lock:
            self._pending_oco[oco_id] = {
                'symbol': symbol, 'qty': qty, 'side': side,
                'take_profit': take_profit_price, 'stop_loss': stop_loss_price,
                'created_at': time.time(), 'status': 'active'
            }
        return {'oco_id': oco_id, 'status': 'placed',
                'take_profit': take_profit_price, 'stop_loss': stop_loss_price}

    def check_oco_triggers(self, current_prices: Dict[str, float]) -> List[Dict]:
        triggered: List[Dict] = []
        with self._lock:
            for oco_id, oco in list(self._pending_oco.items()):
                if oco['status'] != 'active':
                    continue
                symbol = oco['symbol']
                price = current_prices.get(symbol, 0.0)
                if price <= 0:
                    continue
                side = oco['side']
                if side == 'buy':
                    if price <= oco['stop_loss']:
                        fill = self.execute_trade(symbol, oco['qty'], 'sell', price, notes=f'OCO_stop_{oco_id}')
                        oco['status'] = 'stop_triggered'
                        triggered.append({**fill, 'oco_id': oco_id, 'trigger': 'stop_loss'})
                    elif price >= oco['take_profit']:
                        fill = self.execute_trade(symbol, oco['qty'], 'sell', price, notes=f'OCO_tp_{oco_id}')
                        oco['status'] = 'take_profit_triggered'
                        triggered.append({**fill, 'oco_id': oco_id, 'trigger': 'take_profit'})
        return triggered

    def execute_twap(self, symbol: str, total_qty: float,
                     side: str, duration_minutes: float,
                     current_price: float, n_slices: int = 10) -> List[Dict]:
        if not self.use_twap:
            return [self.execute_trade(symbol, total_qty, side, current_price)]
        fills: List[Dict] = []
        slice_qty = total_qty / n_slices
        interval = duration_minutes * 60 / n_slices
        for i in range(n_slices):
            price_noise = current_price * random.gauss(0, 0.0005)
            slice_price = current_price + price_noise
            fill = self.execute_trade(symbol, slice_qty, side, slice_price,
                                      notes=f'TWAP_slice_{i + 1}_of_{n_slices}')
            fills.append(fill)
        return fills

    def get_pnl(self, current_prices: Optional[Dict[str, float]] = None) -> Dict[str, float]:
        with self._lock:
            realized = 0.0
            position_costs: Dict[str, float] = defaultdict(float)
            position_qty: Dict[str, float] = defaultdict(float)
            for fill in self._fills:
                sign = 1.0 if fill['side'] == 'sell' else -1.0
                realized += sign * fill['notional'] - fill['commission']
                qty_sign = 1.0 if fill['side'] == 'buy' else -1.0
                position_qty[fill['symbol']] += qty_sign * fill['quantity']
                position_costs[fill['symbol']] += qty_sign * fill['notional']

            unrealized = 0.0
            if current_prices:
                for symbol, qty in position_qty.items():
                    if symbol in current_prices and qty != 0:
                        market_val = qty * current_prices[symbol]
                        cost = position_costs[symbol]
                        unrealized += market_val - cost

            return {
                'realized_pnl': round(realized, 4),
                'unrealized_pnl': round(unrealized, 4),
                'total_pnl': round(realized + unrealized, 4),
                'total_commission': round(sum(f['commission'] for f in self._fills), 4),
                'total_notional': round(sum(f['notional'] for f in self._fills), 4),
                'n_trades': len(self._fills),
            }

    def get_execution_report(self) -> Dict[str, Any]:
        with self._lock:
            return {
                'metrics': self._execution_metrics.copy(),
                'venue_stats': dict(self._venue_stats),
                'n_fills': len(self._fills),
                'n_orders': len(self._orders),
                'n_pending_oco': len([o for o in self._pending_oco.values() if o.get('status') == 'active']),
            }

class PortfolioOptimizer:
    def __init__(self, risk_free: float = 0.03, n_simulations: int = 10_000,
                 use_black_litterman: bool = True,
                 use_risk_parity: bool = True,
                 use_hierarchical_risk_parity: bool = True,
                 use_min_variance: bool = True,
                 use_max_diversification: bool = True,
                 use_cvar_optimization: bool = True,
                 use_factor_constraints: bool = True,
                 use_transaction_costs: bool = True,
                 use_rebalancing_constraints: bool = True,
                 max_position_size: float = 0.40,
                 min_position_size: float = 0.01,
                 transaction_cost_bps: float = 10.0,
                 rebalancing_threshold: float = 0.05):
        self.risk_free = risk_free
        self.n_simulations = n_simulations
        self.use_black_litterman = use_black_litterman
        self.use_risk_parity = use_risk_parity
        self.use_hierarchical_risk_parity = use_hierarchical_risk_parity
        self.use_min_variance = use_min_variance
        self.use_max_diversification = use_max_diversification
        self.use_cvar_optimization = use_cvar_optimization
        self.use_factor_constraints = use_factor_constraints
        self.use_transaction_costs = use_transaction_costs
        self.use_rebalancing_constraints = use_rebalancing_constraints
        self.max_position_size = max_position_size
        self.min_position_size = min_position_size
        self.transaction_cost_bps = transaction_cost_bps
        self.rebalancing_threshold = rebalancing_threshold

    def _hrp_weights(self, cov: np.ndarray) -> np.ndarray:
        N = cov.shape[0]
        corr = cov / (np.sqrt(np.diag(cov))[:, None] * np.sqrt(np.diag(cov))[None, :] + 1e-9)
        dist = np.sqrt((1 - corr) / 2.0)
        from scipy.cluster.hierarchy import linkage, leaves_list
        from scipy.spatial.distance import squareform
        try:
            condensed = squareform(dist, checks=False)
            link = linkage(condensed, method='single')
            order = leaves_list(link)
        except Exception:
            order = list(range(N))
        weights = np.ones(N) / N
        clusters = [order]
        while clusters:
            new_clusters = []
            for cluster in clusters:
                if len(cluster) <= 1:
                    continue
                mid = len(cluster) // 2
                c1 = cluster[:mid]
                c2 = cluster[mid:]
                v1 = float(np.array(c1)[:, None].T @ cov[np.ix_(c1, c1)] @ np.array(c1)[:, None] if len(c1) > 1 else
                           [[cov[c1[0], c1[0]]]])
                v2 = float(np.array(c2)[:, None].T @ cov[np.ix_(c2, c2)] @ np.array(c2)[:, None] if len(c2) > 1 else
                           [[cov[c2[0], c2[0]]]])
                sub_w1 = np.ones(len(c1)) / len(c1)
                sub_w2 = np.ones(len(c2)) / len(c2)
                v1 = float(sub_w1 @ cov[np.ix_(c1, c1)] @ sub_w1)
                v2 = float(sub_w2 @ cov[np.ix_(c2, c2)] @ sub_w2)
                alpha = 1.0 - v1 / (v1 + v2 + 1e-9)
                weights[c1] *= alpha
                weights[c2] *= (1 - alpha)
                new_clusters.extend([c1, c2])
            clusters = new_clusters
        return weights / (weights.sum() + 1e-9)

    def _black_litterman_returns(self, mu: np.ndarray, cov: np.ndarray,
                                  views_P: np.ndarray, views_q: np.ndarray,
                                  view_confidence: float = 0.25) -> np.ndarray:
        if not self.use_black_litterman:
            return mu
        tau = 0.025
        try:
            sigma = tau * cov
            omega = view_confidence * (views_P @ sigma @ views_P.T)
            bl_cov_inv = np.linalg.pinv(sigma) + views_P.T @ np.linalg.pinv(omega) @ views_P
            bl_cov = np.linalg.pinv(bl_cov_inv)
            bl_mu = bl_cov @ (np.linalg.pinv(sigma) @ mu + views_P.T @ np.linalg.pinv(omega) @ views_q)
            return bl_mu
        except np.linalg.LinAlgError:
            return mu

    def optimize(self, returns: Union[List, np.ndarray],
                 method: str = 'max_sharpe',
                 risk_free: Optional[float] = None,
                 current_weights: Optional[np.ndarray] = None,
                 views_P: Optional[np.ndarray] = None,
                 views_q: Optional[np.ndarray] = None,
                 asset_names: Optional[List[str]] = None,
                 constraints: Optional[Dict] = None) -> Dict[str, Any]:
        R = np.asarray(returns, dtype=float)
        if R.ndim == 1:
            R = R.reshape(-1, 1)
        T, N = R.shape
        rf = risk_free if risk_free is not None else self.risk_free

        mu = R.mean(axis=0) * 252
        cov = (np.cov(R.T) * 252 if N > 1 else np.array([[R.var() * 252]])) + np.eye(N) * 1e-8

        if views_P is not None and views_q is not None:
            mu = self._black_litterman_returns(mu, cov, views_P, views_q)

        best_w = np.ones(N) / N
        best_metric = -np.inf

        if method == 'hrp' and self.use_hierarchical_risk_parity:
            try:
                best_w = self._hrp_weights(cov)
            except Exception:
                best_w = np.ones(N) / N

        elif method == 'risk_parity' and self.use_risk_parity:
            vols = np.sqrt(np.diag(cov))
            inv_vols = 1.0 / (vols + 1e-9)
            best_w = inv_vols / inv_vols.sum()

        elif method == 'max_diversification' and self.use_max_diversification:
            for _ in range(self.n_simulations):
                w = np.random.dirichlet(np.ones(N))
                w = np.clip(w, self.min_position_size, self.max_position_size)
                w /= w.sum()
                weighted_vols = float((w * np.sqrt(np.diag(cov))).sum())
                port_vol = float((w @ cov @ w) ** 0.5)
                div_ratio = weighted_vols / (port_vol + 1e-9)
                if div_ratio > best_metric:
                    best_metric, best_w = div_ratio, w.copy()

        elif method in ('max_sharpe', 'min_variance', 'max_return'):
            for _ in range(self.n_simulations):
                w = np.random.dirichlet(np.ones(N))
                w = np.clip(w, self.min_position_size, self.max_position_size)
                w /= w.sum()
                ret = float(w @ mu)
                vol = float((w @ cov @ w) ** 0.5)
                if method == 'max_sharpe':
                    metric = (ret - rf) / (vol + 1e-9)
                elif method == 'min_variance':
                    metric = -vol
                else:
                    metric = ret
                if metric > best_metric:
                    best_metric, best_w = metric, w.copy()

        if self.use_rebalancing_constraints and current_weights is not None:
            cw = np.asarray(current_weights, dtype=float)
            if cw.shape == best_w.shape:
                turnover = np.abs(best_w - cw).sum()
                if turnover < self.rebalancing_threshold:
                    best_w = cw

        if self.use_transaction_costs and current_weights is not None:
            cw = np.asarray(current_weights, dtype=float)
            if cw.shape == best_w.shape:
                tc = np.abs(best_w - cw).sum() * self.transaction_cost_bps / 10_000

        port_ret = float(best_w @ mu)
        port_vol = float((best_w @ cov @ best_w) ** 0.5)
        port_sharpe = (port_ret - rf) / (port_vol + 1e-9)

        result = {
            'weights': best_w.tolist(),
            'asset_names': asset_names or [f'asset_{i}' for i in range(N)],
            'expected_return': round(port_ret, 4),
            'volatility': round(port_vol, 4),
            'sharpe': round(port_sharpe, 3),
            'method': method,
            'n_assets': N,
            'effective_n': round(1.0 / (np.sum(best_w ** 2) + 1e-9), 2),
            'max_weight': round(float(best_w.max()), 4),
            'min_weight': round(float(best_w.min()), 4),
        }
        return result

class Backtester:
    def __init__(self, initial_capital: float = 100_000.0,
                 commission_bps: float = 5.0, slippage_bps: float = 2.0,
                 use_walk_forward: bool = True,
                 use_monte_carlo: bool = True,
                 use_benchmark: bool = True,
                 use_position_sizing: bool = True,
                 use_drawdown_control: bool = True,
                 use_risk_management: bool = True,
                 use_intraday: bool = False,
                 n_mc_paths: int = 1000,
                 max_drawdown_stop: float = 0.25,
                 kelly_fraction: float = 0.25,
                 benchmark_symbol: str = 'SPY',
                 data_frequency: str = 'daily'):
        self.initial_capital = initial_capital
        self.commission_bps = commission_bps
        self.slippage_bps = slippage_bps
        self.use_walk_forward = use_walk_forward
        self.use_monte_carlo = use_monte_carlo
        self.use_benchmark = use_benchmark
        self.use_position_sizing = use_position_sizing
        self.use_drawdown_control = use_drawdown_control
        self.use_risk_management = use_risk_management
        self.use_intraday = use_intraday
        self.n_mc_paths = n_mc_paths
        self.max_drawdown_stop = max_drawdown_stop
        self.kelly_fraction = kelly_fraction
        self.benchmark_symbol = benchmark_symbol
        self.data_frequency = data_frequency
        self._backtests: List[Dict] = []

    def _cost_per_trade(self) -> float:
        return (self.commission_bps + self.slippage_bps) / 10_000

    def backtest(self, strategy: Callable[[np.ndarray], np.ndarray],
                 historical_data: np.ndarray,
                 prices: Optional[np.ndarray] = None,
                 volumes: Optional[np.ndarray] = None,
                 benchmark_prices: Optional[np.ndarray] = None,
                 walk_forward: bool = False,
                 train_ratio: float = 0.70,
                 n_walk_forward_windows: int = 5,
                 position_sizes: Optional[np.ndarray] = None) -> Dict[str, Any]:
        if prices is None:
            prices = historical_data
        p = np.asarray(prices, dtype=float)
        data = np.asarray(historical_data, dtype=float)
        T = min(len(p), len(data))
        p, data = p[:T], data[:T]

        if not walk_forward or not self.use_walk_forward:
            signals = np.clip(np.asarray(strategy(data), dtype=float)[:T], -1.0, 1.0)
        else:
            signals = np.zeros(T)
            window_size = T // n_walk_forward_windows
            for w in range(n_walk_forward_windows):
                train_end = int(w * window_size + window_size * train_ratio)
                test_start = int(w * window_size + window_size * train_ratio)
                test_end = (w + 1) * window_size
                if train_end >= T or test_start >= T:
                    break
                train_data = data[:train_end]
                test_data = data[test_start:test_end]
                train_signals = strategy(train_data)
                last_signal = float(np.asarray(train_signals)[-1]) if len(train_signals) > 0 else 0.0
                test_signals = strategy(test_data)
                signals[test_start:test_end] = np.asarray(test_signals)[:test_end - test_start]

        signals = signals[:T]
        if len(signals) < T:
            signals = np.pad(signals, (0, T - len(signals)))

        if self.use_position_sizing and position_sizes is not None:
            ps = np.clip(np.asarray(position_sizes, dtype=float)[:T], 0, 1)
            signals = signals * ps

        capital = self.initial_capital
        equity_curve = [capital]
        drawdown_stopped = False

        returns = np.diff(p) / (p[:-1] + 1e-9)
        trades = np.abs(np.diff(signals[:len(returns) + 1]))
        costs = trades * self._cost_per_trade()
        pos_returns = signals[:len(returns)] * returns - costs

        if self.use_drawdown_control:
            filtered_returns = []
            peak = capital
            for r in pos_returns:
                capital *= (1 + r)
                peak = max(peak, capital)
                dd = (capital - peak) / (peak + 1e-9)
                if dd < -self.max_drawdown_stop and not drawdown_stopped:
                    drawdown_stopped = True
                if drawdown_stopped:
                    filtered_returns.append(0.0)
                else:
                    filtered_returns.append(r)
                    if drawdown_stopped and capital > peak * 0.95:
                        drawdown_stopped = False
            pos_returns = np.array(filtered_returns)

        equity = self.initial_capital * np.cumprod(1 + pos_returns) if len(pos_returns) > 0 else np.array([self.initial_capital])

        years_factor = 252 if self.data_frequency == 'daily' else 252 * 6.5 if self.use_intraday else 252
        n_years = len(pos_returns) / years_factor
        if n_years <= 0:
            n_years = 1e-9

        total_return = float(equity[-1] / self.initial_capital - 1) if len(equity) > 0 else 0.0
        cagr = float((equity[-1] / self.initial_capital) ** (1 / n_years) - 1) if len(equity) > 0 else 0.0
        vol = float(pos_returns.std() * (years_factor ** 0.5)) if len(pos_returns) > 1 else 0.0
        sharpe = float((pos_returns.mean() * years_factor - self.risk_free if hasattr(self, 'risk_free') else 0.03) / (vol + 1e-9)) if len(pos_returns) > 1 else 0.0
        sharpe = float((pos_returns.mean() * years_factor - 0.03) / (vol + 1e-9)) if len(pos_returns) > 1 else 0.0

        peak_equity = np.maximum.accumulate(equity)
        dd_series = (equity - peak_equity) / (peak_equity + 1e-9)
        max_dd = float(dd_series.min()) if len(dd_series) > 0 else 0.0

        n_trades = int(trades.sum())
        win_rate = float((pos_returns > 0).mean()) if len(pos_returns) > 0 else 0.0
        avg_win = float(pos_returns[pos_returns > 0].mean()) if (pos_returns > 0).any() else 0.0
        avg_loss = float(abs(pos_returns[pos_returns < 0].mean())) if (pos_returns < 0).any() else 1e-9
        profit_factor = (avg_win * win_rate) / (avg_loss * (1 - win_rate) + 1e-9)

        downside_returns = pos_returns[pos_returns < 0]
        downside_vol = float(downside_returns.std() * (years_factor ** 0.5)) if len(downside_returns) > 1 else vol
        sortino = float((pos_returns.mean() * years_factor - 0.03) / (downside_vol + 1e-9))
        calmar = abs(cagr) / (abs(max_dd) + 1e-9) if max_dd != 0 else 0.0

        result: Dict[str, Any] = {
            'total_return': round(total_return, 4),
            'cagr': round(cagr, 4),
            'sharpe': round(sharpe, 3),
            'sortino': round(sortino, 3),
            'calmar': round(calmar, 3),
            'max_drawdown': round(max_dd, 4),
            'volatility': round(vol, 4),
            'n_trades': n_trades,
            'win_rate': round(win_rate, 3),
            'avg_win': round(avg_win, 6),
            'avg_loss': round(avg_loss, 6),
            'profit_factor': round(profit_factor, 3),
            'final_equity': round(float(equity[-1]), 2) if len(equity) > 0 else self.initial_capital,
            'equity_curve': equity.tolist(),
            'drawdown_stopped': drawdown_stopped,
        }

        if benchmark_prices is not None and self.use_benchmark:
            bp = np.asarray(benchmark_prices, dtype=float)[:len(pos_returns)]
            if len(bp) > 1:
                b_returns = np.diff(bp) / (bp[:-1] + 1e-9)
                b_equity = self.initial_capital * np.cumprod(1 + b_returns[:len(pos_returns)])
                b_return = float(b_equity[-1] / self.initial_capital - 1) if len(b_equity) > 0 else 0.0
                alpha = cagr - b_return
                result['benchmark_return'] = round(b_return, 4)
                result['alpha'] = round(alpha, 4)
                if len(b_returns) > 1 and len(pos_returns) > 1:
                    min_len = min(len(pos_returns), len(b_returns))
                    beta = float(np.cov(pos_returns[:min_len], b_returns[:min_len])[0, 1] /
                                 (np.var(b_returns[:min_len]) + 1e-9))
                    result['beta'] = round(beta, 3)
                    info_ratio = (pos_returns[:min_len] - b_returns[:min_len]).mean() / \
                                 (pos_returns[:min_len] - b_returns[:min_len]).std()
                    result['information_ratio'] = round(float(info_ratio) * (years_factor ** 0.5), 3)

        if self.use_monte_carlo and len(pos_returns) > 10:
            mc_terminals: List[float] = []
            for _ in range(min(self.n_mc_paths, 500)):
                mc_returns = np.random.choice(pos_returns, size=len(pos_returns), replace=True)
                mc_eq = self.initial_capital * np.cumprod(1 + mc_returns)
                mc_terminals.append(float(mc_eq[-1]))
            mc_arr = np.array(mc_terminals)
            result['mc_mean_terminal'] = round(float(mc_arr.mean()), 2)
            result['mc_p5_terminal'] = round(float(np.percentile(mc_arr, 5)), 2)
            result['mc_p95_terminal'] = round(float(np.percentile(mc_arr, 95)), 2)
            result['mc_p50_terminal'] = round(float(np.percentile(mc_arr, 50)), 2)
            result['mc_probability_of_profit'] = round(float((mc_arr > self.initial_capital).mean()), 3)

        self._backtests.append(result)
        return result

    def compare_strategies(self, strategies: Dict[str, Callable],
                           prices: np.ndarray,
                           historical_data: Optional[np.ndarray] = None) -> Dict[str, Dict]:
        if historical_data is None:
            historical_data = prices
        results: Dict[str, Dict] = {}
        for name, strat in strategies.items():
            try:
                results[name] = self.backtest(strat, historical_data, prices)
            except Exception as e:
                results[name] = {'error': str(e)}
        ranked = sorted(
            [(n, r) for n, r in results.items() if 'sharpe' in r],
            key=lambda x: x[1]['sharpe'],
            reverse=True
        )
        for rank, (name, _) in enumerate(ranked, 1):
            results[name]['rank'] = rank
        results['_best_strategy'] = ranked[0][0] if ranked else None
        return results

    @property
    def risk_free(self) -> float:
        return 0.03

class TaxReporter:
    def __init__(self, method: str = 'fifo', jurisdiction: str = 'US',
                 use_wash_sale_detection: bool = True,
                 use_specific_identification: bool = True,
                 use_tax_loss_harvesting: bool = True,
                 use_multi_year_tracking: bool = True,
                 use_crypto_accounting: bool = True,
                 use_dividend_tracking: bool = True,
                 use_options_accounting: bool = True,
                 short_term_rate: float = 0.37,
                 long_term_rate: float = 0.20,
                 state_tax_rate: float = 0.09,
                 net_investment_income_tax: float = 0.038,
                 wash_sale_window_days: int = 30):
        assert method in ('fifo', 'lifo', 'hifo', 'specific_id', 'average_cost'), \
            'method must be fifo/lifo/hifo/specific_id/average_cost'
        self.method = method
        self.jurisdiction = jurisdiction
        self.use_wash_sale_detection = use_wash_sale_detection
        self.use_specific_identification = use_specific_identification
        self.use_tax_loss_harvesting = use_tax_loss_harvesting
        self.use_multi_year_tracking = use_multi_year_tracking
        self.use_crypto_accounting = use_crypto_accounting
        self.use_dividend_tracking = use_dividend_tracking
        self.use_options_accounting = use_options_accounting
        self.short_term_rate = short_term_rate
        self.long_term_rate = long_term_rate
        self.state_tax_rate = state_tax_rate
        self.net_investment_income_tax = net_investment_income_tax
        self.wash_sale_window_days = wash_sale_window_days

        self._lots: Dict[str, List[Dict]] = defaultdict(list)
        self._realized: List[Dict] = []
        self._wash_sales: List[Dict] = []
        self._dividends: List[Dict] = []
        self._options: List[Dict] = []
        self._tax_years: Dict[int, Dict] = defaultdict(lambda: {
            'st_gains': 0.0, 'lt_gains': 0.0, 'dividends': 0.0,
            'harvested_losses': 0.0, 'wash_sale_adjustments': 0.0
        })
        self._lock = threading.Lock()

    def buy(self, symbol: str, qty: float, price: float,
            date: Optional[float] = None,
            lot_id: Optional[str] = None,
            asset_type: str = 'equity') -> str:
        date = date or time.time()
        lot_id = lot_id or secrets.token_hex(6)
        with self._lock:
            self._lots[symbol].append({
                'lot_id': lot_id, 'qty': qty, 'cost': price,
                'date': date, 'remaining': qty,
                'asset_type': asset_type,
                'wash_sale_adjusted': False,
                'wash_sale_add': 0.0,
            })
        return lot_id

    def _detect_wash_sale(self, symbol: str, sell_date: float,
                          loss: float) -> bool:
        if not self.use_wash_sale_detection or loss >= 0:
            return False
        window_sec = self.wash_sale_window_days * 86400
        recent_buys = [
            lot for lot in self._lots.get(symbol, [])
            if abs(lot['date'] - sell_date) <= window_sec and lot['remaining'] > 0
        ]
        return len(recent_buys) > 0

    def sell(self, symbol: str, qty: float, price: float,
             date: Optional[float] = None,
             specific_lot_ids: Optional[List[str]] = None) -> Dict[str, Any]:
        date = date or time.time()
        with self._lock:
            lots = self._lots.get(symbol, [])
            if not lots:
                return {'status': 'no_lots', 'realized': 0.0}

            if self.method == 'fifo':
                ordered = lots
            elif self.method == 'lifo':
                ordered = list(reversed(lots))
            elif self.method == 'hifo':
                ordered = sorted(lots, key=lambda x: -x['cost'])
            elif self.method == 'specific_id' and specific_lot_ids:
                ordered = [l for l in lots if l['lot_id'] in specific_lot_ids]
                ordered += [l for l in lots if l['lot_id'] not in specific_lot_ids]
            elif self.method == 'average_cost':
                total_qty_avail = sum(l['remaining'] for l in lots)
                avg_cost = sum(l['cost'] * l['remaining'] for l in lots) / (total_qty_avail + 1e-9)
                ordered = [{'qty': total_qty_avail, 'cost': avg_cost, 'date': min(l['date'] for l in lots),
                            'remaining': total_qty_avail, 'lot_id': 'avg', 'asset_type': lots[0].get('asset_type', 'equity'),
                            'wash_sale_adjusted': False, 'wash_sale_add': 0.0}]
            else:
                ordered = lots

            remaining_to_sell = qty
            total_proceeds = qty * price
            total_basis = 0.0
            gains_st = 0.0
            gains_lt = 0.0
            lots_used: List[Dict] = []

            for lot in ordered:
                if remaining_to_sell <= 0:
                    break
                if lot['remaining'] <= 1e-9:
                    continue
                used = min(lot['remaining'], remaining_to_sell)
                basis_per_unit = lot['cost'] + lot.get('wash_sale_add', 0.0)
                basis = used * basis_per_unit
                proceeds = used * price
                gain = proceeds - basis
                hold_days = (date - lot['date']) / 86400

                is_long_term = hold_days > 365
                if is_long_term:
                    gains_lt += gain
                else:
                    gains_st += gain

                total_basis += basis
                lot['remaining'] -= used
                remaining_to_sell -= used
                lots_used.append({'lot_id': lot['lot_id'], 'qty': used,
                                  'cost': basis_per_unit, 'hold_days': round(hold_days, 1)})

            gain_total = gains_st + gains_lt
            is_wash = self._detect_wash_sale(symbol, date, gain_total)
            if is_wash:
                self._wash_sales.append({
                    'symbol': symbol, 'date': date, 'loss': gain_total,
                    'disallowed': abs(gain_total) if gain_total < 0 else 0
                })
                if gain_total < 0:
                    for lot in self._lots[symbol]:
                        if lot['remaining'] > 0 and abs(lot['date'] - date) < self.wash_sale_window_days * 86400:
                            lot['wash_sale_add'] += abs(gain_total) / lot['remaining']
                            lot['wash_sale_adjusted'] = True
                            break

            year = int(datetime.fromtimestamp(date).year)
            self._tax_years[year]['st_gains'] += gains_st
            self._tax_years[year]['lt_gains'] += gains_lt
            if gain_total < 0 and self.use_tax_loss_harvesting:
                self._tax_years[year]['harvested_losses'] += abs(gain_total)

            self._lots[symbol] = [l for l in self._lots[symbol] if l['remaining'] > 1e-9]

            event = {
                'symbol': symbol, 'qty': qty, 'proceeds': round(total_proceeds, 4),
                'basis': round(total_basis, 4), 'st_gain': round(gains_st, 4),
                'lt_gain': round(gains_lt, 4), 'total_gain': round(gain_total, 4),
                'date': date, 'year': year, 'wash_sale': is_wash,
                'lots_used': lots_used,
            }
            self._realized.append(event)
            return event

    def record_dividend(self, symbol: str, amount: float,
                        date: Optional[float] = None,
                        qualified: bool = True) -> None:
        if not self.use_dividend_tracking:
            return
        date = date or time.time()
        year = int(datetime.fromtimestamp(date).year)
        with self._lock:
            self._dividends.append({
                'symbol': symbol, 'amount': amount, 'date': date,
                'qualified': qualified, 'year': year
            })
            self._tax_years[year]['dividends'] += amount

    def identify_harvesting_opportunities(self,
                                          current_prices: Dict[str, float],
                                          min_loss_threshold: float = 500.0) -> List[Dict]:
        if not self.use_tax_loss_harvesting:
            return []
        opportunities: List[Dict] = []
        with self._lock:
            for symbol, lots in self._lots.items():
                current_price = current_prices.get(symbol)
                if current_price is None:
                    continue
                for lot in lots:
                    if lot['remaining'] <= 0:
                        continue
                    unrealized_loss = lot['remaining'] * (current_price - lot['cost'])
                    if unrealized_loss < -min_loss_threshold:
                        hold_days = (time.time() - lot['date']) / 86400
                        opportunities.append({
                            'symbol': symbol, 'lot_id': lot['lot_id'],
                            'qty': lot['remaining'],
                            'cost_basis': round(lot['cost'], 4),
                            'current_price': round(current_price, 4),
                            'unrealized_loss': round(unrealized_loss, 2),
                            'hold_days': round(hold_days, 1),
                            'is_long_term': hold_days > 365,
                            'tax_benefit': round(abs(unrealized_loss) *
                                                  (self.long_term_rate if hold_days > 365 else self.short_term_rate), 2)
                        })
        opportunities.sort(key=lambda x: x['unrealized_loss'])
        return opportunities

    def generate_report(self, tax_year: Optional[int] = None) -> Dict[str, Any]:
        with self._lock:
            if tax_year is not None:
                events = [e for e in self._realized if e.get('year') == tax_year]
                divs = [d for d in self._dividends if d.get('year') == tax_year]
                year_data = self._tax_years.get(tax_year, {})
                total_st = year_data.get('st_gains', 0.0)
                total_lt = year_data.get('lt_gains', 0.0)
                total_div = year_data.get('dividends', 0.0)
            else:
                events = self._realized
                divs = self._dividends
                total_st = sum(e['st_gain'] for e in events)
                total_lt = sum(e['lt_gain'] for e in events)
                total_div = sum(d['amount'] for d in divs)

            qualified_div = sum(d['amount'] for d in divs if d.get('qualified', True))
            ordinary_div = total_div - qualified_div

            net_lt = total_lt
            net_st = total_st
            if net_lt < 0:
                net_st += net_lt
                net_lt = 0.0
            elif net_st < 0:
                net_lt += net_st
                net_st = 0.0

            tax_st = max(0, net_st) * self.short_term_rate
            tax_lt = max(0, net_lt) * self.long_term_rate
            tax_qualified_div = qualified_div * self.long_term_rate
            tax_ordinary_div = ordinary_div * self.short_term_rate
            niit = (max(0, net_st) + max(0, net_lt) + total_div) * self.net_investment_income_tax
            state_tax = (max(0, net_st) + max(0, net_lt) + total_div) * self.state_tax_rate
            total_tax = tax_st + tax_lt + tax_qualified_div + tax_ordinary_div + niit + state_tax

            return {
                'method': self.method,
                'jurisdiction': self.jurisdiction,
                'tax_year': tax_year or 'all',
                'total_short_term_gain': round(total_st, 2),
                'total_long_term_gain': round(total_lt, 2),
                'net_short_term_gain': round(net_st, 2),
                'net_long_term_gain': round(net_lt, 2),
                'total_dividends': round(total_div, 2),
                'qualified_dividends': round(qualified_div, 2),
                'ordinary_dividends': round(ordinary_div, 2),
                'total_realized_gain': round(total_st + total_lt, 2),
                'estimated_federal_tax': round(tax_st + tax_lt, 2),
                'estimated_dividend_tax': round(tax_qualified_div + tax_ordinary_div, 2),
                'estimated_niit': round(niit, 2),
                'estimated_state_tax': round(state_tax, 2),
                'total_estimated_tax': round(total_tax, 2),
                'effective_tax_rate': round(total_tax / (abs(total_st + total_lt + total_div) + 1e-9) * 100, 2),
                'wash_sale_count': len(self._wash_sales),
                'wash_sale_disallowed_losses': round(sum(ws.get('disallowed', 0) for ws in self._wash_sales), 2),
                'n_transactions': len(events),
                'n_open_lots': sum(len(v) for v in self._lots.values()),
                'events': events[:100],
            }

