class SpectralNormGuard(ModuleUtilsMixin, nn.Module):
    """
    (11) Online spectral-norm monitoring and clamping for stability.

    Training instability in deep transformers is frequently traceable to a few
    layers whose weight spectral norm blows up. This guard estimates the largest
    singular value of registered weights via power iteration (cheap, one vector
    per step) and, when a weight exceeds ``max_sigma``, rescales it back down in
    place. It turns "the loss went to NaN at step 4000" into a bounded,
    observable quantity.
    """

    def __init__(self, max_sigma: float = 4.0, n_power_iter: int = 1):
        super().__init__()
        self.max_sigma = max_sigma
        self.n_power_iter = n_power_iter
        self._u: Dict[str, Tensor] = {}
        self._tracked: List[Tuple[str, nn.Parameter]] = []

    def track(self, name: str, weight: nn.Parameter):
        """Register a 2-D weight for monitoring."""
        if weight.dim() != 2:
            return
        self._tracked.append((name, weight))
        self._u[name] = F.normalize(torch.randn(weight.size(0), device=weight.device), dim=0)

    @classmethod
    def from_args(cls, args, **overrides):
        kwargs = dict(max_sigma=float(getattr(args, "max_grad_norm", 4.0) or 4.0))
        kwargs.update(overrides)
        return cls(**kwargs)

    @torch.no_grad()
    def _sigma(self, name: str, w: Tensor) -> float:
        u = self._u[name].to(w.device)
        for _ in range(self.n_power_iter):
            v = F.normalize(w.t() @ u, dim=0)
            u = F.normalize(w @ v, dim=0)
        self._u[name] = u
        return float(u @ w @ v)

    @torch.no_grad()
    def enforce(self) -> Dict[str, float]:
        """Clamp any tracked weight whose spectral norm exceeds the ceiling."""
        report = {}
        for name, w in self._tracked:
            sigma = self._sigma(name, w.data)
            report[name] = sigma
            if sigma > self.max_sigma:
                w.data.mul_(self.max_sigma / (sigma + 1e-8))
        return report

    def forward(self):
        return self.enforce()


class GradientConflictResolver(ModuleUtilsMixin, nn.Module):
    """
    (12) Multi-task gradient surgery (PCGrad-style).

    When a model is trained on several objectives, their gradients can point in
    conflicting directions, so one task's update undoes another's. This resolver
    detects conflicting gradient pairs (negative cosine) and projects each out of
    the other's conflicting component before summing, so every task makes
    non-destructive progress. Operates on a list of per-task gradient vectors.
    """

    def __init__(self):
        super().__init__()

    @classmethod
    def from_args(cls, args, **overrides):
        return cls()

    @torch.no_grad()
    def resolve(self, task_grads: List[Tensor]) -> Tensor:
        """Project away pairwise conflicts, then sum. Inputs are flat grad vectors."""
        if not task_grads:
            raise ValueError("GradientConflictResolver: empty gradient list")
        resolved = [g.clone() for g in task_grads]
        n = len(resolved)
        for i in range(n):
            for j in range(n):
                if i == j:
                    continue
                gi, gj = resolved[i], task_grads[j]
                dot = torch.dot(gi, gj)
                if dot < 0:                                   # conflict
                    resolved[i] = gi - (dot / (gj.dot(gj) + 1e-12)) * gj
        return torch.stack(resolved).sum(dim=0)

    def forward(self, task_grads: List[Tensor]) -> Tensor:
        return self.resolve(task_grads)


class AdaptiveGradientClipper(ModuleUtilsMixin, nn.Module):
    """
    (13) Percentile-adaptive gradient clipping (AGC-flavoured).

    A fixed global-norm clip is a blunt instrument: too low and it starves
    learning, too high and it lets spikes through. This clipper tracks the recent
    history of gradient norms and clips to a running percentile, so the threshold
    adapts to the model's actual gradient scale over training. It also reports
    the fraction of recent steps that were clipped, which is a strong early
    warning of instability.
    """

    def __init__(self, percentile: float = 90.0, history: int = 128, eps: float = 1e-6):
        super().__init__()
        self.percentile = percentile
        self.eps = eps
        self._hist: deque = deque(maxlen=history)
        self._clipped: deque = deque(maxlen=history)

    @classmethod
    def from_args(cls, args, **overrides):
        return cls(**overrides)

    @torch.no_grad()
    def clip(self, parameters) -> Dict[str, float]:
        params = [p for p in parameters if p.grad is not None]
        if not params:
            return {"norm": 0.0, "threshold": 0.0, "clipped": False}
        total = torch.sqrt(sum(p.grad.pow(2).sum() for p in params)).item()
        self._hist.append(total)

        if len(self._hist) < 8:
            threshold = total * 2.0                          # warmup: permissive
        else:
            s = sorted(self._hist)
            threshold = s[min(len(s) - 1, int(len(s) * self.percentile / 100.0))]

        clipped = total > threshold
        if clipped:
            scale = threshold / (total + self.eps)
            for p in params:
                p.grad.mul_(scale)
        self._clipped.append(1.0 if clipped else 0.0)
        return {
            "norm": total, "threshold": threshold, "clipped": clipped,
            "clip_rate": sum(self._clipped) / len(self._clipped),
        }

    def forward(self, parameters):
        return self.clip(parameters)


class DynamicLossScaler(ModuleUtilsMixin, nn.Module):
    """
    (14) Mixed-precision dynamic loss scaling with backoff.

    Low-precision training underflows small gradients to zero. This scaler
    multiplies the loss by a factor before backprop and unscales the gradients
    after, raising the factor when things are stable and halving it (skipping the
    step) whenever a non-finite gradient appears. It is the mechanism that makes
    fp16 training converge instead of collapsing.
    """

    def __init__(self, init_scale: float = 2.0 ** 16, growth: float = 2.0,
                 backoff: float = 0.5, growth_interval: int = 2000):
        super().__init__()
        self.register_buffer("scale", torch.tensor(float(init_scale)))
        self.growth = growth
        self.backoff = backoff
        self.growth_interval = growth_interval
        self._good_steps = 0

    @classmethod
    def from_args(cls, args, **overrides):
        return cls(**overrides)

    def scale_loss(self, loss: Tensor) -> Tensor:
        return loss * self.scale

    @torch.no_grad()
    def unscale_and_step(self, parameters) -> Dict[str, Any]:
        params = [p for p in parameters if p.grad is not None]
        finite = all(torch.isfinite(p.grad).all() for p in params)
        if not finite:
            self.scale.mul_(self.backoff).clamp_(min=1.0)
            self._good_steps = 0
            for p in params:
                p.grad = None
            return {"skipped": True, "scale": float(self.scale.item())}
        inv = 1.0 / self.scale
        for p in params:
            p.grad.mul_(inv)
        self._good_steps += 1
        if self._good_steps % self.growth_interval == 0:
            self.scale.mul_(self.growth)
        return {"skipped": False, "scale": float(self.scale.item())}

    def forward(self, loss: Tensor) -> Tensor:
        return self.scale_loss(loss)


class QuantizationAwareProjector(ModuleUtilsMixin, nn.Module):
    """
    (15) Learned quantisation with straight-through estimation.

    A linear projection whose weights are fake-quantised to ``bits`` during the
    forward pass (so the network learns weights that survive quantisation) while
    gradients flow through the rounding as if it were the identity. Per-channel
    scales are learned, and the quantisation error is exposed as an auxiliary
    signal. This is a real QAT layer, not the ``fake_quantize`` helper.
    """

    def __init__(self, in_features: int, out_features: int, bits: int = 8,
                 per_channel: bool = True, bias: bool = True):
        super().__init__()
        if bits < 2 or bits > 16:
            raise ValueError(f"QuantizationAwareProjector: bits must be in [2,16], got {bits}")
        self.bits = bits
        self.levels = 2 ** (bits - 1) - 1
        self.per_channel = per_channel
        self.weight = nn.Parameter(torch.empty(out_features, in_features))
        nn.init.kaiming_uniform_(self.weight, a=math.sqrt(5))
        self.bias = nn.Parameter(torch.zeros(out_features)) if bias else None
        n_scales = out_features if per_channel else 1
        self.log_scale = nn.Parameter(torch.zeros(n_scales, 1))

    @classmethod
    def from_args(cls, args, in_features=None, out_features=None, **overrides):
        d = args.dim
        return cls(in_features or d, out_features or d,
                   bits=int(getattr(args, "weight_quant_bits", 8) or 8), **overrides)

    def _fake_quant(self) -> Tuple[Tensor, Tensor]:
        scale = self.log_scale.exp()
        w = self.weight
        q = torch.clamp(torch.round(w / scale), -self.levels, self.levels)
        w_q = q * scale
        # Straight-through: forward uses w_q, backward sees w.
        w_st = w + (w_q - w).detach()
        error = (w - w_q).detach().abs().mean()
        return w_st, error

    def forward(self, x: Tensor):
        w, error = self._fake_quant()
        out = F.linear(x, w, self.bias)
        return out, error


class ActivationCheckpointRouter(ModuleUtilsMixin, nn.Module):
    """
    (16) Selective activation checkpointing driven by a memory budget.

    Recomputation trades compute for memory, but checkpointing *everything* is
    wasteful. This router decides, per submodule, whether to checkpoint based on
    that module's activation footprint versus a running memory budget: it
    checkpoints the memory-heaviest modules first and lets cheap ones keep their
    activations. It exposes the resulting estimated saving.
    """

    def __init__(self, memory_budget_mb: float = 4096.0):
        super().__init__()
        self.memory_budget = memory_budget_mb * 1e6
        self._costs: Dict[str, float] = {}

    @classmethod
    def from_args(cls, args, **overrides):
        return cls(**overrides)

    def estimate_cost(self, name: str, out_shape: Tuple[int, ...], dtype_bytes: int = 2):
        n = 1
        for s in out_shape:
            n *= s
        self._costs[name] = n * dtype_bytes
        return self._costs[name]

    def should_checkpoint(self, name: str) -> bool:
        """Checkpoint modules whose footprint exceeds a per-module share of the budget."""
        if not self._costs:
            return False
        per_module = self.memory_budget / max(1, len(self._costs))
        return self._costs.get(name, 0) > per_module

    def wrap(self, name: str, fn: Callable, *inputs):
        if self.should_checkpoint(name) and torch.is_grad_enabled():
            return torch.utils.checkpoint.checkpoint(fn, *inputs, use_reentrant=False)
        return fn(*inputs)

    def forward(self, name, fn, *inputs):
        return self.wrap(name, fn, *inputs)


class ExpertParallelDispatcher(ModuleUtilsMixin, nn.Module):
    """
    (17) Capacity-limited MoE dispatch with token dropping and overflow handling.

    A production MoE cannot let a popular expert receive unbounded tokens. This
    dispatcher enforces a per-expert capacity, routes each token to its top-1
    expert, drops (or reroutes) tokens that overflow a full expert, and reports
    the drop rate and per-expert load. It is the piece that makes MoE routing
    actually schedulable rather than a theoretical softmax.
    """

    def __init__(self, dim: int, num_experts: int, capacity_factor: float = 1.25,
                 eps: float = 1e-6):
        super().__init__()
        self.dim = dim
        self.num_experts = num_experts
        self.capacity_factor = capacity_factor
        self.router = nn.Linear(dim, num_experts, bias=False)
        self.experts = nn.ModuleList([
            nn.Sequential(Linear(dim, dim * 2), nn.GELU(), Linear(dim * 2, dim))
            for _ in range(num_experts)
        ])
        self.norm = RMSNorm(dim, eps=eps)

    @classmethod
    def from_args(cls, args, **overrides):
        kwargs = dict(dim=args.dim,
                      num_experts=int(getattr(args, "n_routed_experts", 8)),
                      eps=float(getattr(args, "norm_eps", 1e-6)))
        kwargs.update(overrides)
        return cls(**kwargs)

    def forward(self, x: Tensor) -> Tuple[Tensor, Dict[str, Any]]:
        B, T, D = x.shape
        h = self.norm(x).reshape(-1, D)
        N = h.size(0)
        capacity = int(self.capacity_factor * N / self.num_experts)

        logits = self.router(h)
        gate = F.softmax(logits, dim=-1)
        top = gate.argmax(dim=-1)                             # (N,)
        weight = gate.gather(1, top.unsqueeze(1)).squeeze(1)

        out = torch.zeros_like(h)
        dropped = 0
        load = torch.zeros(self.num_experts, device=x.device)
        for e in range(self.num_experts):
            mask = (top == e).nonzero(as_tuple=True)[0]
            load[e] = mask.numel()
            if mask.numel() == 0:
                continue
            if mask.numel() > capacity:                      # overflow -> drop
                dropped += mask.numel() - capacity
                mask = mask[:capacity]
            out[mask] = self.experts[e](h[mask]) * weight[mask].unsqueeze(-1)

        info = {
            "drop_rate": dropped / max(1, N),
            "load": load / max(1, N),
            "capacity": capacity,
        }
        return out.view(B, T, D) + x, info


class LowRankGradientCompressor(ModuleUtilsMixin, nn.Module):
    """
    (18) Low-rank gradient compression for distributed training (PowerSGD-style).

    Communicating full gradients across workers is the bandwidth bottleneck in
    data-parallel training. This compresses a gradient matrix to a rank-``r``
    factorisation before the all-reduce and reconstructs it after, with an error-
    feedback buffer so the residual is carried forward and no information is
    permanently lost. Compression ratio scales with 1/r.
    """

    def __init__(self, rank: int = 4, n_power_iter: int = 1):
        super().__init__()
        self.rank = rank
        self.n_power_iter = n_power_iter
        self._error: Dict[str, Tensor] = {}

    @classmethod
    def from_args(cls, args, **overrides):
        return cls(**overrides)

    @torch.no_grad()
    def compress(self, name: str, grad: Tensor) -> Tuple[Tensor, Tensor]:
        """Return (P, Q) with grad ≈ P @ Q^T, folding in the error feedback."""
        if grad.dim() != 2:
            grad = grad.reshape(grad.size(0), -1)
        if name in self._error and self._error[name].shape == grad.shape:
            grad = grad + self._error[name]
        m, n = grad.shape
        r = min(self.rank, m, n)
        q = torch.randn(n, r, device=grad.device, dtype=grad.dtype)
        for _ in range(self.n_power_iter):
            p = grad @ q
            p = torch.linalg.qr(p).Q
            q = grad.t() @ p
        approx = p @ q.t()
        self._error[name] = grad - approx                    # error feedback
        return p, q

    def decompress(self, p: Tensor, q: Tensor) -> Tensor:
        return p @ q.t()

    def ratio(self, m: int, n: int) -> float:
        r = min(self.rank, m, n)
        return (r * (m + n)) / max(1, m * n)

    def forward(self, name, grad):
        return self.compress(name, grad)


class ElasticBatchNormalizer(ModuleUtilsMixin, nn.Module):
    """
    (19) Sequence-length-robust normalisation with learned momentum.

    Batch statistics are unreliable when batch or sequence length varies, which
    is common in generation. This normaliser blends instance-level statistics
    (always available, per-sample) with running batch statistics, and *learns*
    the blend and the momentum, so it degrades gracefully to instance norm when
    batches are tiny and toward batch norm when they are large and stable.
    """

    def __init__(self, dim: int, eps: float = 1e-5):
        super().__init__()
        self.dim = dim
        self.eps = eps
        self.gamma = nn.Parameter(torch.ones(dim))
        self.beta = nn.Parameter(torch.zeros(dim))
        self.blend = nn.Parameter(torch.zeros(1))            # sigmoid -> mix weight
        self.log_momentum = nn.Parameter(torch.tensor(-2.3)) # ~0.1
        self.register_buffer("running_mean", torch.zeros(dim))
        self.register_buffer("running_var", torch.ones(dim))

    @classmethod
    def from_args(cls, args, **overrides):
        kwargs = dict(dim=args.dim)
        kwargs.update(overrides)
        return cls(**kwargs)

    def forward(self, x: Tensor) -> Tensor:
        inst_mean = x.mean(dim=tuple(range(1, x.dim() - 1)), keepdim=True)
        inst_var = x.var(dim=tuple(range(1, x.dim() - 1)), keepdim=True, unbiased=False)

        if self.training:
            bmean = x.mean(dim=tuple(range(x.dim() - 1)))
            bvar = x.var(dim=tuple(range(x.dim() - 1)), unbiased=False)
            mom = torch.sigmoid(self.log_momentum)
            with torch.no_grad():
                self.running_mean.mul_(1 - mom).add_(mom * bmean.detach())
                self.running_var.mul_(1 - mom).add_(mom * bvar.detach())
            batch_mean, batch_var = bmean, bvar
        else:
            batch_mean, batch_var = self.running_mean, self.running_var

        a = torch.sigmoid(self.blend)
        mean = a * inst_mean + (1 - a) * batch_mean
        var = a * inst_var + (1 - a) * batch_var
        return self.gamma * (x - mean) / torch.sqrt(var + self.eps) + self.beta


class SharpnessAwareWrapper(ModuleUtilsMixin, nn.Module):
    """
    (20) Sharpness-Aware Minimisation (SAM) helper.

    SAM improves generalisation by seeking parameters that sit in flat loss
    regions: it perturbs the weights toward the worst-case direction in a small
    neighbourhood, measures the loss there, and steps to reduce *that*. This
    wrapper implements the two-phase ascent/descent: ``ascend`` climbs to the
    perturbed point, ``descend`` restores the weights so the real optimiser can
    step on the sharpness-aware gradient.
    """

    def __init__(self, rho: float = 0.05, adaptive: bool = True):
        super().__init__()
        self.rho = rho
        self.adaptive = adaptive
        self._e: Dict[int, Tensor] = {}

    @classmethod
    def from_args(cls, args, **overrides):
        return cls(**overrides)

    @torch.no_grad()
    def ascend(self, parameters):
        """Climb to the worst-case point in the rho-ball around the weights."""
        params = [p for p in parameters if p.grad is not None]
        norm = torch.sqrt(sum(
            ((torch.abs(p) if self.adaptive else 1.0) * p.grad).pow(2).sum()
            for p in params
        )) + 1e-12
        for p in params:
            e = (torch.pow(p, 2) if self.adaptive else 1.0) * p.grad * (self.rho / norm)
            p.add_(e)
            self._e[id(p)] = e

    @torch.no_grad()
    def descend(self, parameters):
        """Restore the original weights (the real optimiser step follows)."""
        for p in parameters:
            e = self._e.pop(id(p), None)
            if e is not None:
                p.sub_(e)

    def forward(self, parameters):
        self.ascend(parameters)
        return parameters



