# ======================================================================


class SelfConsistencyVoter(ModuleUtilsMixin, nn.Module):
    """
    (21) Self-consistency over multiple reasoning samples.

    A single greedy decode is brittle. This module scores several candidate
    reasoning paths (their pooled hidden states), estimates each path's internal
    consistency, and produces a consensus by confidence-weighted voting. It also
    reports the agreement level, which is a usable proxy for how much to trust the
    final answer -- low agreement across samples is a signal to abstain.
    """

    def __init__(self, dim: int, n_paths: int = 5, eps: float = 1e-6):
        super().__init__()
        self.n_paths = n_paths
        self.scorer = nn.Sequential(RMSNorm(dim, eps=eps),
                                    nn.Linear(dim, dim // 2), nn.GELU(),
                                    nn.Linear(dim // 2, 1))
        self.consistency = nn.Linear(dim, dim)

    @classmethod
    def from_args(cls, args, **overrides):
        kwargs = dict(dim=args.dim, eps=float(getattr(args, "norm_eps", 1e-6)))
        kwargs.update(overrides)
        return cls(**kwargs)

    def forward(self, paths: Tensor) -> Dict[str, Tensor]:
        """
        Args:
            paths: (B, P, dim) pooled representation of P candidate paths.
        Returns:
            consensus (B, dim), plus per-path weights and an agreement scalar.
        """
        B, P, D = paths.shape
        conf = self.scorer(paths).squeeze(-1)                     # (B,P)
        w = F.softmax(conf, dim=-1)
        consensus = torch.einsum("bp,bpd->bd", w, paths)

        # Agreement = mean cosine of each path to the consensus.
        proj = self.consistency(paths)
        cons_proj = self.consistency(consensus).unsqueeze(1)
        agreement = F.cosine_similarity(proj, cons_proj, dim=-1).mean(dim=-1)
        return {"consensus": consensus, "weights": w, "agreement": agreement}


class ToolUseController(ModuleUtilsMixin, nn.Module):
    """
    (22) Learned tool-invocation gating.

    Decides *whether* to call an external tool and *which* one, from the hidden
    state, rather than always calling or never calling. It produces a call/no-call
    gate, a distribution over available tools, and an argument latent the tool
    adapter can decode. Crucially it also outputs a confidence the model can use
    to fall back to its own knowledge when no tool is clearly appropriate.
    """

    def __init__(self, dim: int, n_tools: int = 16, arg_dim: int = 64, eps: float = 1e-6):
        super().__init__()
        self.n_tools = n_tools
        self.norm = RMSNorm(dim, eps=eps)
        self.call_gate = nn.Linear(dim, 1)
        self.tool_select = nn.Linear(dim, n_tools)
        self.arg_encoder = nn.Sequential(nn.Linear(dim, dim), nn.GELU(),
                                         nn.Linear(dim, arg_dim))

    @classmethod
    def from_args(cls, args, **overrides):
        kwargs = dict(dim=args.dim, eps=float(getattr(args, "norm_eps", 1e-6)))
        kwargs.update(overrides)
        return cls(**kwargs)

    def forward(self, x: Tensor) -> Dict[str, Tensor]:
        h = self.norm(x)
        pooled = h.mean(dim=1) if h.dim() == 3 else h
        should_call = torch.sigmoid(self.call_gate(pooled)).squeeze(-1)
        tool_logits = self.tool_select(pooled)
        tool_probs = F.softmax(tool_logits, dim=-1)
        confidence = tool_probs.max(dim=-1).values
        return {
            "should_call": should_call,
            "tool_probs": tool_probs,
            "tool": tool_probs.argmax(dim=-1),
            "args": self.arg_encoder(pooled),
            "confidence": confidence,
        }


class ConstitutionalCritic(ModuleUtilsMixin, nn.Module):
    """
    (23) Learned self-critique against a set of principles.

    Scores a hidden state against ``n_principles`` learned principle directions
    (e.g. helpfulness, harmlessness, honesty), producing a per-principle score and
    an overall alignment estimate. Unlike a hard content filter this is a soft,
    differentiable critic that can be trained jointly and can flag *which*
    principle a response is straining, rather than a single opaque pass/fail.

    This is a training-time signal, not a safety guarantee: it is explicitly NOT
    a substitute for real safety review, and its scores must never be presented as
    certified judgements.
    """

    def __init__(self, dim: int, n_principles: int = 8, eps: float = 1e-6):
        super().__init__()
        self.n_principles = n_principles
        self.norm = RMSNorm(dim, eps=eps)
        self.principles = nn.Parameter(torch.randn(n_principles, dim) * 0.02)
        self.principle_head = nn.Linear(dim, n_principles)
        self.aggregate = nn.Linear(n_principles, 1)

    @classmethod
    def from_args(cls, args, **overrides):
        kwargs = dict(dim=args.dim, eps=float(getattr(args, "norm_eps", 1e-6)))
        kwargs.update(overrides)
        return cls(**kwargs)

    def forward(self, x: Tensor) -> Dict[str, Tensor]:
        h = self.norm(x)
        pooled = h.mean(dim=1) if h.dim() == 3 else h
        # Alignment of the representation with each principle direction.
        align = F.cosine_similarity(
            pooled.unsqueeze(1), self.principles.unsqueeze(0), dim=-1
        )                                                          # (B, P)
        scores = torch.sigmoid(self.principle_head(pooled) + align)
        overall = torch.sigmoid(self.aggregate(scores)).squeeze(-1)
        worst = scores.min(dim=-1)
        return {
            "principle_scores": scores,
            "overall": overall,
            "weakest_principle": worst.indices,
            "weakest_score": worst.values,
        }


class AttributionTracer(ModuleUtilsMixin, nn.Module):
    """
    (24) Input-attribution via integrated gradients, built in.

    Interpretability that lives inside the model: given an embedding input and a
    scalar target, it approximates integrated gradients by interpolating from a
    baseline to the input along ``steps`` points and accumulating gradients. The
    result is a per-token, per-dimension attribution map explaining which inputs
    drove the output -- computed on demand, without an external captum dependency.
    """

    def __init__(self, steps: int = 32):
        super().__init__()
        self.steps = steps

    @classmethod
    def from_args(cls, args, **overrides):
        return cls(**overrides)

    def attribute(self, embeddings: Tensor, forward_fn: Callable[[Tensor], Tensor],
                  baseline: Optional[Tensor] = None) -> Tensor:
        """
        Args:
            embeddings: (B, T, D) input embeddings (must be float).
            forward_fn: maps embeddings -> a scalar-per-batch target.
            baseline:   reference input; zeros if None.
        Returns:
            (B, T, D) attribution map.
        """
        if baseline is None:
            baseline = torch.zeros_like(embeddings)
        total_grad = torch.zeros_like(embeddings)
        for s in range(1, self.steps + 1):
            alpha = s / self.steps
            interp = (baseline + alpha * (embeddings - baseline)).detach().requires_grad_(True)
            out = forward_fn(interp).sum()
            grad = torch.autograd.grad(out, interp, retain_graph=False)[0]
            total_grad = total_grad + grad
        avg_grad = total_grad / self.steps
        return (embeddings - baseline) * avg_grad

    def forward(self, embeddings, forward_fn, baseline=None):
        return self.attribute(embeddings, forward_fn, baseline)


class CurriculumScheduler(ModuleUtilsMixin, nn.Module):
    """
    (25) Difficulty-aware curriculum that adapts to model competence.

    Feeds the model easy examples first and harder ones as it improves, but
    *self-paced*: it tracks a running estimate of the model's competence from its
    loss and advances the difficulty ceiling only when competence crosses a
    threshold. It exposes a per-sample acceptance mask so a data loader can filter
    a batch to the currently-appropriate difficulty band.
    """

    def __init__(self, n_levels: int = 10, patience: int = 200,
                 competence_threshold: float = 0.6):
        super().__init__()
        self.n_levels = n_levels
        self.patience = patience
        self.threshold = competence_threshold
        self.register_buffer("level", torch.tensor(1))
        self.register_buffer("competence", torch.tensor(0.0))
        self._loss_hist: deque = deque(maxlen=patience)

    @classmethod
    def from_args(cls, args, **overrides):
        return cls(**overrides)

    @torch.no_grad()
    def update(self, loss: float, baseline_loss: float = 4.0) -> Dict[str, Any]:
        self._loss_hist.append(loss)
        comp = max(0.0, min(1.0, 1.0 - loss / max(1e-6, baseline_loss)))
        self.competence.mul_(0.99).add_(0.01 * comp)
        advanced = False
        if (len(self._loss_hist) >= self.patience and
                float(self.competence) > self.threshold and
                int(self.level) < self.n_levels):
            self.level += 1
            self._loss_hist.clear()
            advanced = True
        return {"level": int(self.level), "competence": float(self.competence),
                "advanced": advanced}

    def accept(self, difficulties: Tensor) -> Tensor:
        """Boolean mask: which samples are within the current difficulty ceiling."""
        return difficulties <= int(self.level)

    def forward(self, difficulties: Tensor) -> Tensor:
        return self.accept(difficulties)


class SpeculativeVerifier(ModuleUtilsMixin, nn.Module):
    """
    (26) Draft-token acceptance for speculative decoding.

    Given draft-model token logits and the target-model logits for the same
    positions, applies the modified-rejection-sampling acceptance rule that makes
    speculative decoding *exact*: it accepts the longest prefix of draft tokens
    consistent with the target distribution and resamples from the corrected
    residual at the first rejection. Returns the accepted length so a decoder can
    advance by more than one token per target forward pass.
    """

    def __init__(self, temperature: float = 1.0):
        super().__init__()
        self.temperature = temperature

    @classmethod
    def from_args(cls, args, **overrides):
        return cls(**overrides)

    @torch.no_grad()
    def verify(self, draft_logits: Tensor, target_logits: Tensor,
               draft_tokens: Tensor) -> Dict[str, Any]:
        """
        Args:
            draft_logits:  (K, V) draft distribution for K proposed tokens.
            target_logits: (K, V) target distribution for the same positions.
            draft_tokens:  (K,) the tokens the draft actually proposed.
        Returns:
            accepted length and the (possibly resampled) correction token.
        """
        t = self.temperature
        p_target = F.softmax(target_logits / t, dim=-1)
        p_draft = F.softmax(draft_logits / t, dim=-1)
        K = draft_tokens.size(0)

        accepted = 0
        correction = None
        for i in range(K):
            tok = draft_tokens[i]
            pt = p_target[i, tok]
            pd = p_draft[i, tok].clamp(min=1e-9)
            ratio = (pt / pd).clamp(max=1.0)
            if torch.rand(1, device=draft_tokens.device) <= ratio:
                accepted += 1
            else:
                # Resample from the positive part of (target - draft).
                residual = (p_target[i] - p_draft[i]).clamp(min=0)
                residual = residual / residual.sum().clamp(min=1e-9)
                correction = torch.multinomial(residual, 1)
                break
        if correction is None and accepted == K:
            correction = torch.multinomial(p_target[-1], 1)
        return {"accepted": accepted, "correction": correction,
                "speedup": (accepted + 1) / max(1, K)}

    def forward(self, draft_logits, target_logits, draft_tokens):
        return self.verify(draft_logits, target_logits, draft_tokens)


class RewardModelHead(ModuleUtilsMixin, nn.Module):
    """
    (27) Preference reward head with Bradley-Terry training.

    A scalar reward head for RLHF/preference learning. It scores a response
    representation and trains on pairwise preferences via the Bradley-Terry
    objective (the chosen response should score above the rejected one). It also
    tracks reward-model calibration -- how often its ranking matches the labelled
    preference -- so reward-hacking drift is observable.
    """

    def __init__(self, dim: int, eps: float = 1e-6):
        super().__init__()
        self.norm = RMSNorm(dim, eps=eps)
        self.head = nn.Sequential(nn.Linear(dim, dim // 2), nn.GELU(),
                                  nn.Linear(dim // 2, 1))
        self.register_buffer("agreement", torch.tensor(0.5))

    @classmethod
    def from_args(cls, args, **overrides):
        kwargs = dict(dim=args.dim, eps=float(getattr(args, "norm_eps", 1e-6)))
        kwargs.update(overrides)
        return cls(**kwargs)

    def score(self, x: Tensor) -> Tensor:
        h = self.norm(x)
        pooled = h.mean(dim=1) if h.dim() == 3 else h
        return self.head(pooled).squeeze(-1)

    def preference_loss(self, chosen: Tensor, rejected: Tensor) -> Dict[str, Tensor]:
        rc = self.score(chosen)
        rr = self.score(rejected)
        # Bradley-Terry: -log sigmoid(r_chosen - r_rejected).
        loss = -F.logsigmoid(rc - rr).mean()
        with torch.no_grad():
            acc = (rc > rr).float().mean()
            self.agreement.mul_(0.99).add_(0.01 * acc)
        return {"loss": loss, "accuracy": acc, "margin": (rc - rr).mean()}

    def forward(self, x: Tensor) -> Tensor:
        return self.score(x)


class LatentDiffusionRefiner(ModuleUtilsMixin, nn.Module):
    """
    (28) Iterative latent refinement by learned denoising.

    Treats representation improvement as denoising: it adds a controllable amount
    of noise to a latent and learns to denoise it conditioned on context, run for
    several steps. Used as a refinement stage, it lets the model iteratively
    polish a representation (e.g. a plan or a draft) instead of committing to a
    single forward pass -- a diffusion process operating in the model's own
    latent space.
    """

    def __init__(self, dim: int, n_steps: int = 4, eps: float = 1e-6):
        super().__init__()
        self.dim = dim
        self.n_steps = n_steps
        self.time_embed = nn.Sequential(nn.Linear(1, dim), nn.SiLU(), nn.Linear(dim, dim))
        self.denoiser = nn.Sequential(RMSNorm(dim * 2, eps=eps),
                                      nn.Linear(dim * 2, dim * 2), nn.GELU(),
                                      nn.Linear(dim * 2, dim))
        self.register_buffer("betas", torch.linspace(1e-4, 0.02, n_steps))

    @classmethod
    def from_args(cls, args, **overrides):
        kwargs = dict(dim=args.dim, eps=float(getattr(args, "norm_eps", 1e-6)))
        kwargs.update(overrides)
        return cls(**kwargs)

    def forward(self, latent: Tensor, context: Optional[Tensor] = None) -> Tensor:
        if context is None:
            context = latent
        x = latent
        for step in reversed(range(self.n_steps)):
            t = torch.full((x.size(0), 1), step / self.n_steps, device=x.device, dtype=x.dtype)
            temb = self.time_embed(t)                            # (B, dim)
            if x.dim() == 3:
                temb = temb.unsqueeze(1)                         # (B,1,dim) -> broadcasts over T
            noise_pred = self.denoiser(torch.cat([x + temb, context], dim=-1))
            beta = self.betas[step]
            x = (x - beta * noise_pred) / math.sqrt(1 - beta)
        return x


class CrossModalAligner(ModuleUtilsMixin, nn.Module):
    """
    (29) Shared-space alignment across modalities (CLIP-style, internal).

    Projects representations from different modalities (text, vision, audio) into
    one shared space and aligns them with a symmetric contrastive objective, so
    matching pairs across modalities land nearby. Provides a single fusion point
    for multimodal inputs and exposes a temperature that is learned, not fixed --
    the standard CLIP trick that stabilises training.
    """

    def __init__(self, dim: int, shared_dim: int = 256, modalities: int = 3,
                 eps: float = 1e-6):
        super().__init__()
        self.modalities = modalities
        self.projectors = nn.ModuleList([
            nn.Sequential(RMSNorm(dim, eps=eps), nn.Linear(dim, shared_dim))
            for _ in range(modalities)
        ])
        self.log_temp = nn.Parameter(torch.tensor(math.log(1 / 0.07)))

    @classmethod
    def from_args(cls, args, **overrides):
        kwargs = dict(dim=args.dim, eps=float(getattr(args, "norm_eps", 1e-6)))
        kwargs.update(overrides)
        return cls(**kwargs)

    def encode(self, x: Tensor, modality: int) -> Tensor:
        h = x.mean(dim=1) if x.dim() == 3 else x
        return F.normalize(self.projectors[modality](h), dim=-1)

    def forward(self, a: Tensor, b: Tensor, modality_a: int = 0,
                modality_b: int = 1) -> Dict[str, Tensor]:
        za = self.encode(a, modality_a)
        zb = self.encode(b, modality_b)
        temp = self.log_temp.exp().clamp(max=100.0)
        logits = za @ zb.t() * temp
        target = torch.arange(za.size(0), device=za.device)
        loss = 0.5 * (F.cross_entropy(logits, target) + F.cross_entropy(logits.t(), target))
        return {"loss": loss, "logits": logits, "temperature": temp}


class NeuralCacheAccelerator(ModuleUtilsMixin, nn.Module):
    """
    (30) Semantic KV-reuse cache for repeated / similar prompts.

    Generation over similar prompts recomputes near-identical prefixes. This
    cache stores (prompt-signature -> hidden-state) entries and, on a new input,
    retrieves the nearest cached prefix by cosine similarity; if similarity
    exceeds ``threshold`` it can seed computation from the cached state instead of
    recomputing from scratch. It uses an LFU eviction policy and reports its hit
    rate, turning repeated structure into a real latency win.
    """

    def __init__(self, dim: int, capacity: int = 512, threshold: float = 0.95):
        super().__init__()
        self.dim = dim
        self.capacity = capacity
        self.threshold = threshold
        self.register_buffer("keys", torch.zeros(capacity, dim))
        self.register_buffer("freq", torch.zeros(capacity))
        self.register_buffer("valid", torch.zeros(capacity, dtype=torch.bool))
        self._values: Dict[int, Tensor] = {}
        self.hits = 0
        self.misses = 0

    @classmethod
    def from_args(cls, args, **overrides):
        kwargs = dict(dim=args.dim)
        kwargs.update(overrides)
        return cls(**kwargs)

    @torch.no_grad()
    def _signature(self, x: Tensor) -> Tensor:
        return F.normalize(x.mean(dim=tuple(range(1, x.dim()))), dim=-1)   # (B?,dim) -> (dim,)

    @torch.no_grad()
    def lookup(self, x: Tensor) -> Optional[Tensor]:
        sig = self._signature(x).reshape(-1)
        if not bool(self.valid.any()):
            self.misses += 1
            return None
        sims = F.cosine_similarity(self.keys[self.valid], sig.unsqueeze(0), dim=-1)
        best = sims.max()
        if float(best) >= self.threshold:
            slot = torch.nonzero(self.valid).squeeze(1)[sims.argmax()]
            self.freq[slot] += 1
            self.hits += 1
            return self._values.get(int(slot))
        self.misses += 1
        return None

    @torch.no_grad()
    def store(self, x: Tensor, state: Tensor):
        sig = self._signature(x).reshape(-1)
        if bool(self.valid.all()):
            slot = int(self.freq.argmin())                       # LFU eviction
        else:
            slot = int(torch.nonzero(~self.valid)[0])
        self.keys[slot] = sig
        self.valid[slot] = True
        self.freq[slot] = 1
        self._values[slot] = state.detach()

    def hit_rate(self) -> float:
        total = self.hits + self.misses
        return self.hits / total if total else 0.0

    def forward(self, x: Tensor) -> Optional[Tensor]:
        return self.lookup(x)



class Transformer(nn.Module):
    def __init__(self, args: ModelArgs):
        super().__init__()
        global world_size, rank, default_dtype, scale_fmt, scale_dtype
        world_size = dist.get_world_size() if dist.is_initialized() else 1
        rank = dist.get_rank() if dist.is_initialized() else 0
        default_dtype = torch.float8_e4m3fn if args.dtype == "fp8" else torch.bfloat16
        scale_fmt = "ue8m0" if args.scale_dtype == "fp8" else args.scale_fmt
        scale_dtype = torch.float8_e8m0fnu if args.scale_dtype == "fp8" else torch.float32

        self.args = args
        self.max_seq_len = args.max_seq_len
        self.norm_eps = args.norm_eps
        self.hc_eps = args.hc_eps
        self.embed = ParallelEmbedding(args.vocab_size, args.dim)

        block_class = DynamicBlock if args.use_dynamic_block else Block
        self.layers = nn.ModuleList([block_class(i, args) for i in range(args.n_layers)])
        self.norm = RMSNorm(args.dim, self.norm_eps)
        self.head = ParallelHead(args.vocab_size, args.dim, self.norm_eps, self.hc_eps)

        self.mtp = nn.ModuleList()
        mtp_class = MTPBlockWithCheckpoint if args.use_checkpoint_mtp else MTPBlock
        for i in range(args.n_mtp_layers):
            mtp = mtp_class.from_args(args.n_layers + i, args)
            mtp.embed = self.embed
            mtp.head = self.head
            self.mtp.append(mtp)

        self.hc_mult = args.hc_mult
        hc_dim = args.hc_mult * args.dim
        with set_dtype(torch.float32):
            self.hc_head_fn = nn.Parameter(torch.empty(args.hc_mult, hc_dim))
            self.hc_head_base = nn.Parameter(torch.empty(args.hc_mult))
            self.hc_head_scale = nn.Parameter(torch.empty(1))
            with torch.no_grad():
                nn.init.normal_(self.hc_head_fn, mean=0.0, std=hc_dim ** -0.5)
                nn.init.zeros_(self.hc_head_base)
                nn.init.ones_(self.hc_head_scale)

        if args.use_task_condition:
            self.task_embedding = TaskEmbedding(1000, args.task_embed_dim)
        else:
            self.task_embedding = None

        if args.use_rationale_decoder:
            self.rationale_decoder = RationaleDecoder(args.dim, args.rationale_vocab_size, args.rationale_max_len)
        else:
            self.rationale_decoder = None

        self._apply_q_conversion(args)

        if args.training_phase == "inference" and args.inference_checkpoint_path is not None:
            self._load_inference_checkpoint(args.inference_checkpoint_path)

        if args.use_meta_learning:
            # Bugfix: this passed `task_encoder_dim=`, which is not a parameter of
            # inject_meta_into_transformer at all. The adapter width is what the
            # injector actually needs.
            inject_meta_into_transformer(
                self,
                num_tasks=args.meta_num_tasks,
                adapter_rank=getattr(args, 'meta_adapter_rank', 128),
            )
            self.meta_enabled = True

        self._init_optional_modules(args, world_size)

    # ------------------------------------------------------------------
    # Mapping from the user-facing ``ModelArgs.q_mode`` vocabulary to the
    # internal ``UnifiedSMMQP`` mode vocabulary.
    #
    # Background / bugfix: the original SmmQP family (SmmQPLinear,
    # SmmQPDeterministic, SmmQPPredictive, SmmQPHierarchical, ...) was merged
    # into the single configurable ``UnifiedSMMQP`` class. The merge kept the
    # replacement API (``UnifiedSMMQP.convert`` / ``UnifiedSMMQP.from_linear``)
    # but the call sites here were never updated: ``_apply_q_conversion`` still
    # invoked five module-level helpers (``convert_to_q_parameters``,
    # ``convert_to_zero_mass``, ``convert_to_adaptive_smmqp``,
    # ``convert_to_smmqp_deterministic``, ``convert_to_smmqp_predictive``) that
    # no longer exist anywhere in the codebase. Because ``_apply_q_conversion``
    # is called unconditionally from ``Transformer.__init__``, *every* q_mode
    # raised ``NameError`` and the model could never be constructed.
    #
    # Each entry below resolves to a concrete UnifiedSMMQP mode plus the extra
    # keyword arguments that make that mode behave like the legacy helper it
    # replaces.
    #   standard      -> a stored base matrix modulated by learned q-scales.
    #   deterministic -> base regenerated from a seed; nothing stored on disk.
    #   predictive    -> q-values predicted by a small network.
    #   hierarchical  -> coarse/fine multi-level q-scales over a stored base.
    #   neural_memory -> stored base plus a low-rank neural-memory correction.
    #   distributed   -> hybrid mode sharded across ranks.
    #   adaptive      -> hybrid mode with rank growth enabled at runtime.
    #   zero_mass     -> fully generative: no base weight mass is ever stored,
    #                    the matrix is synthesised from a latent generator.
    # ------------------------------------------------------------------
    _Q_MODE_TO_UNIFIED_MODE = {
        "standard":      "stored",
        "deterministic": "deterministic",
        "predictive":    "predictive",
        "hierarchical":  "hierarchical",
        "neural_memory": "neural_memory",
        "distributed":   "hybrid",
        "adaptive":      "hybrid",
        "zero_mass":     "generative",
    }

    def _q_conversion_kwargs(self, args: ModelArgs) -> Dict[str, Any]:
        """
        Build the mode-specific keyword arguments handed to ``UnifiedSMMQP``.

        Only options that genuinely exist on the ``UnifiedSMMQP`` constructor
        are emitted, so an unknown/By-typo config value fails loudly at
        construction time rather than being silently ignored.
        """
        q_mode = args.q_mode
        kwargs: Dict[str, Any] = {
            "seed": args.q_seed,
            "store_base": bool(args.save_base_weights),
            "persistent_base": bool(args.base_stored),
        }

        if q_mode == "deterministic":
            # The base is rebuilt from the seed on demand, so storing it is
            # pointless and would waste memory.
            kwargs["store_base"] = False

        elif q_mode == "predictive":
            kwargs["predictive_hidden"] = args.q_metaq_hidden_dim

        elif q_mode == "distributed":
            kwargs["use_distributed"] = True
            kwargs["world_size"] = world_size
            kwargs["rank"] = rank

        elif q_mode == "adaptive":
            # Rank grows at runtime according to the recorded loss signal.
            kwargs["rank_update_interval"] = 8000
            kwargs["rank_update_threshold"] = 1.0 - float(args.q_adaptive_smoothing)
            kwargs["importance_kind"] = (
                "magnitude" if args.q_importance_metric == "weight_std" else args.q_importance_metric
            )

        elif q_mode == "zero_mass":
            # "Zero mass" == carry no stored weight mass at all: the whole
            # matrix is synthesised by the generator from a latent code.
            kwargs["store_base"] = False
            kwargs["persistent_base"] = False
            kwargs["gen_hidden"] = args.q_zero_mass_meta_hidden
            kwargs["gen_mlp_hidden"] = args.q_zero_mass_meta_hidden
            kwargs["latent_dim"] = args.q_zero_mass_latent_dim
            kwargs["codebook_size"] = args.q_zero_mass_memory_size
            kwargs["use_pruning"] = True
            kwargs["pruning_ratio"] = args.q_zero_mass_pruning_ratio
            kwargs["pruning_interval"] = args.q_zero_mass_pruning_interval
            kwargs["use_self_healing"] = True

        return kwargs

    def _apply_q_conversion(self, args: ModelArgs):
        """
        Replace every eligible ``Linear`` in this Transformer with a quantised /
        adapted layer, according to ``args.q_mode``.

        ``zero_mass`` routes to the dedicated :class:`ZeroMassXOX` engine -- the
        one mode that is not a UnifiedSMMQP variant. ZeroMass keeps the base
        weight on disk and trains only a low-rank adapter (~0.5% of the weight at
        production widths), initialised by split-rank SVD so that ``B @ A == 0``
        at step 0 and the pretrained model is preserved exactly while the adapter
        still starts aligned with the weight's dominant singular directions.

        Every other mode maps onto a :class:`UnifiedSMMQP` configuration.
        """
        q_mode = args.q_mode
        if q_mode not in self._Q_MODE_TO_UNIFIED_MODE:
            raise ValueError(
                f"Transformer._apply_q_conversion: unknown q_mode {q_mode!r}. "
                f"Expected one of {sorted(self._Q_MODE_TO_UNIFIED_MODE)}."
            )

        bundle_size = int(args.q_bundle_size)
        if args.q_adaptive:
            bundle_size = max(int(args.q_min_bundle), min(bundle_size, int(args.q_max_bundle)))

        if q_mode == "zero_mass":
            replaced = ZeroMassXOX.convert(
                self,
                skip_names=list(args.q_skip_layer_names),
                mode="hybrid",
                bundle_size=bundle_size,
                cache_size=int(args.q_cache_size),
                seed=int(args.q_seed),
                pruning_ratio=float(args.q_zero_mass_pruning_ratio),
                pruning_interval=int(args.q_zero_mass_pruning_interval),
                self_healing_lr=float(args.q_zero_mass_self_healing_lr),
                side_steps=int(args.q_zero_mass_side_steps),
                meta_hidden=int(args.q_zero_mass_meta_hidden),
                meta_layers=int(args.q_zero_mass_meta_layers),
                latent_dim=int(args.q_zero_mass_latent_dim),
            )
            self.q_converted_layers = replaced
            # The allocator owns cross-layer rank redistribution and the periodic
            # prune / grow / heal tick for every ZeroMass layer in the model.
            self.zeromass_allocator = ZeroMassRankAllocator(self) if replaced else None
            return replaced

        unified_mode = self._Q_MODE_TO_UNIFIED_MODE[q_mode]
        replaced = UnifiedSMMQP.convert(
            self,
            mode=unified_mode,
            bundle_size=bundle_size,
            cache_size=int(args.q_cache_size),
            skip_names=list(args.q_skip_layer_names),
            base_device=torch.device("cpu"),
            base_dtype=torch.float16,
            **self._q_conversion_kwargs(args),
        )
        self.q_converted_layers = replaced
        self.zeromass_allocator = None
        return replaced

    def zeromass_step(self, loss: Optional[float] = None) -> Dict[str, Any]:
        """
        Drive one ZeroMass housekeeping tick across the whole model.

        Call this once per optimiser step when running in ``zero_mass`` mode. It
        feeds the loss to every adapter (which is what detects a plateau and
        triggers rank growth), then runs each layer's prune / grow / self-heal
        schedule. Returns whatever fired, so training loops can log it.
        """
        allocator = getattr(self, "zeromass_allocator", None)
        if allocator is None:
            return {}
        if loss is not None:
            for _, layer in allocator.layers:
                layer.record_loss(loss)
        return allocator.maintenance()

    def _load_inference_checkpoint(self, checkpoint_path: str):
        if not os.path.exists(checkpoint_path):
            raise FileNotFoundError(f"Inference checkpoint not found: {checkpoint_path}")
        ckpt = torch.load(checkpoint_path, map_location='cpu')
        state_dict = ckpt['state_dict'] if 'state_dict' in ckpt else ckpt
        filtered_state_dict = {k: v for k, v in state_dict.items() if 'weight_base' not in k}
        missing, unexpected = self.load_state_dict(filtered_state_dict, strict=False)
        if missing:
            expected_missing = [k for k in missing if 'weight_base' in k or self.args.training_phase == "inference"]
            if len(missing) > len(expected_missing):
                warnings.warn(f"Missing keys beyond weight_base: {set(missing) - set(expected_missing)}")

